(function() {
var jer_ch_1_Verses = [
  {num:1,words:[["O upu a Ieremia, le atalii o Hilikia,", "The words of Jeremiah the son of Hilkiah,"], ["o le tasi o le au faitaulaga, o e na i Anatota i le nuu o Peniamina.", "of the priests that were in Anathoth in the land of Benjamin:"]]},
  {num:2,words:[["Na oo mai le afioga a Ieova ia te ia i ona po o Iosia, le atalii o Amone,", "To whom the word of the LORD came in the days of Josiah the son of Amon king of Judah,"], ["le tupu o Iuta, i le tausaga e sefulu ma le tolu o lana nofoaiga.", "in the thirteenth year of his reign."]]},
  {num:3,words:[["Na oo mai foi i ona po o Ioakima, le atalii o Iosia,", "It came also in the days of Jehoiakim the son of Josiah king of Judah,"], ["le tupu o Iuta, ua oo i le gataaga o le tausaga e sefulu ma le tasi o Setekaia le atalii o Iosia,", "unto the end of the eleventh year of Zedekiah the son of Josiah king of Judah,"], ["le tupu o Iuta, ua oo foi i le tafeaga o Ierusalema i le lima o masina.", "unto the carrying away of Jerusalem captive in the fifth month."]]},
  {num:4,words:[["Na oo mai ia te au le afioga a Ieova,", "Then the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:5,words:[["Na a'u iloa oe a o lei faia oe e a'u i le manava;", "Before I formed thee in the belly I knew thee;"], ["na a'u faapaiaina oe a o lei fanau mai oe,", "and before thou camest forth out of the womb I sanctified thee,"], ["na a'u tofia oe e fai ma perofeta i nuu.", "and I ordained thee a prophet unto the nations."]]},
  {num:6,words:[["Ona a'u fai atu ai lea,", "Then said I,"], ["Aue,", "Ah,"], ["le Alii e Ieova, faauta,", "Lord GOD! behold,"], ["ou te le iloa ona tautala,", "I cannot speak:"], ["auā o a'u o le tama itiiti.", "for I am a child."]]},
  {num:7,words:[["Ona fetalai mai ai lea o Ieova ia te au,", "But the LORD said unto me,"], ["Aua e te faapea, O a'u o le tama itiiti;", "Say not,"], ["auā o i latou uma ou te auina atu i ai oe,", "I am a child:"], ["e te alu lava i ai, o mea uma foi ou te fai atu ai ia te oe,", "for thou shalt go to all that I shall send thee,"], ["e te fai atu ai lava.", "and whatsoever I command thee thou shalt speak."]]},
  {num:8,words:[["Aua e te fefe ia te i latou;", "Be not afraid of their faces:"], ["auā ou te ia te oe e laveai ia te oe,", "for I am with thee to deliver thee,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:9,words:[["Ona faaloaloa ai lea e Ieova o lona aao,", "Then the LORD put forth his hand,"], ["ua pai mai i lo'u gutu;", "and touched my mouth. And the LORD said unto me,"], ["ua fetalai mai foi Ieova ia te au, Faauta,", "Behold,"], ["ua ou tuuina atu a'u upu i lou gutu.", "I have put my words in thy mouth."]]},
  {num:10,words:[["Faauta,", "See,"], ["ua ou tofia oe i le aso nei e pule i nuu ma malo,", "I have this day set thee over the nations and over the kingdoms,"], ["ina ia e liaiina,", "to root out,"], ["ma lepetia,", "and to pull down, and to destroy,"], ["ma faaumatia,", "and to throw down,"], ["ma sŏloia,", "to build,"], ["ia faatuina foi ma totōina.", "and to plant."]]},
  {num:11,words:[["Na oo mai foi le afioga a Ieova ia te au,", "Moreover the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"], ["Ieremia e,", "Jeremiah,"], ["o le a ea le mea ua e vaai i ai? Ona ou fai atu lea,", "what seest thou? And I said,"], ["Ou te vaai atu i le laau o le sekati.", "I see a rod of an almond tree."]]},
  {num:12,words:[["Ona fetalai mai ai lea o Ieova ia te au,", "Then said the LORD unto me,"], ["Ua lelei lau vaai;", "Thou hast well seen:"], ["auā ou te mataala ina ia faia a'u upu.", "for I will hasten my word to perform it."]]},
  {num:13,words:[["Na oo mai foi le afioga a Ieova ia te au,", "And the word of the LORD came unto me the second time,"], ["o le atu lua lea,", "saying,"], ["ua faapea mai, O le a ea le mea ua e vaai i ai? Ona ou faapea atu lea,", "What seest thou? And I said,"], ["Ua ou vaai atu i le ulo ua alu ae ai le ausa,", "I see a seething pot;"], ["o lona gutu foi ua faasaga mai mai le itu i matu.", "and the face thereof is toward the north."]]},
  {num:14,words:[["Ona fetalai mai ai lea o Ieova ia te au,", "Then the LORD said unto me,"], ["O le itu i matu e oso mai ai le leaga i luga o i latou uma lava o e nonofo i le nuu.", "Out of the north an evil shall break forth upon all the inhabitants of the land."]]},
  {num:15,words:[["Auā faauta,", "For,"], ["ou te valaau i aiga uma lava o malo i le itu i matu,", "lo,"], ["ua fetalai mai ai Ieova;", "I will call all the families of the kingdoms of the north,"], ["e o mai foi i latou,", "saith the LORD; and they shall come,"], ["ma latou taitasi ma tuu lona nofoālii i puipui o faitotoa o Ierusalema,", "and they shall set every one his throne at the entering of the gates of Jerusalem,"], ["e lata ane foi i ona pa uma ua soo ai,", "and against all the walls thereof round about,"], ["e lata ane foi i aai uma o Iuta.", "and against all the cities of Judah."]]},
  {num:16,words:[["Ou te faasala foi ia te i latou i a latou amio leaga uma,", "And I will utter my judgments against them touching all their wickedness,"], ["o e ua tuua a'u,", "who have forsaken me,"], ["ma latou faamu mea manogi i atua ese,", "and have burned incense unto other gods,"], ["ma ifo atu i mea na faia i o latou lava lima.", "and worshipped the works of their own hands."]]},
  {num:17,words:[["A o oe,", "Thou therefore gird up thy loins,"], ["ina fusi ia i lou sulugatiti,", "and arise,"], ["ma tulai atu, ma fai atu ia te i latou mea uma ou te fai atu ai ia te oe;", "and speak unto them all that I command thee:"], ["aua e te mata'u ia te i latou,", "be not dismayed at their faces,"], ["ina ne'i ou faamatauina oe i o latou luma.", "lest I confound thee before them."]]},
  {num:18,words:[["Faauta foi,", "For,"], ["o a'u nei ua ou faia oe i le aso nei ma aai nofo 'olo,", "behold,"], ["ma pou uamea,", "I have made thee this day a defenced city,"], ["ma pa 'apa memea e teteeina ai le nuu uma,", "and an iron pillar,"], ["o tupu o Iuta,", "and brasen walls against the whole land, against the kings of Judah,"], ["ma ona alii,", "against the princes thereof,"], ["ma faitaulaga,", "against the priests thereof,"], ["ma tagata o le nuu.", "and against the people of the land."]]},
  {num:19,words:[["Latou te sii mai le taua ia te oe,", "And they shall fight against thee;"], ["a e latou te le manumalo ia te oe;", "but they shall not prevail against thee;"], ["auā o a'u ou te ia oe e laveai ia te oe,", "for I am with thee, saith the LORD,"], ["ua fetalai mai ai Ieova.", "to deliver thee."]]},
];
renderVerseSet(jer_ch_1_Verses, 'jer-ch1-verses');

var jer_ch_2_Verses = [
  {num:1,words:[["Na oo mai foi le afioga a Ieova ia te au,", "Moreover the word of the LORD came to me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Ina alu ia oe,", "Go and cry in the ears of Jerusalem,"], ["ma e valaau atu i Ierusalema,", "saying,"], ["ia faapea atu i ai,", "Thus saith the LORD;"], ["O loo faapea ona fetalai mai o Ieova,", "I remember thee,"], ["Ou te manatua oe, o lou agalelei mai ina o e teine muli,", "the kindness of thy youth,"], ["ma lou alofa i ona po sa e faufautane ai,", "the love of thine espousals,"], ["ma lou mulimuli mai ia te au i le vao,", "when thou wentest after me in the wilderness,"], ["o le nuu e le totōina ai ni mea.", "in a land that was not sown."]]},
  {num:3,words:[["O Isaraelu sa paia o ia mo Ieova,", "Israel was holiness unto the LORD,"], ["o le faapolopolo o ia o ana mea e tutupu. E agasala i latou uma o e aai ai,", "and the firstfruits of his increase:"], ["e oo lava ia te i latou le leaga,", "all that devour him shall offend; evil shall come upon them,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:4,words:[["Le aiga o Iakopo e,", "Hear ye the word of the LORD,"], ["ma itu aiga uma o le aiga o Isaraelu,", "O house of Jacob,"], ["ina faalogologo mai ia outou i le afioga a Ieova.", "and all the families of the house of Israel:"]]},
  {num:5,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Se a ea se amioletonu na iloa ia te au e o outou tamā,", "What iniquity have your fathers found in me,"], ["ina ua latou ō mamao ia te au,", "that they are gone far from me,"], ["ma ua latou mulimuli atu i mea faatauvaa,", "and have walked after vanity,"], ["ma ua amio faatauvaa i latou?", "and are become vain?"]]},
  {num:6,words:[["Ua le fai ane foi i latou,", "Neither said they,"], ["Po o fea o i ai Ieova,", "Where is the LORD that brought us up out of the land of Egypt,"], ["o le na aveina ae i tatou nai le nuu o Aikupito,", "that led us through the wilderness,"], ["ma na ta'ita'i ia te i tatou i le vao,", "through a land of deserts and of pits,"], ["o le nuu naumati e tele ai lua, o le nuu e lailoa ai tagata ,", "through a land of drought,"], ["ua i ai foi le ata o le oti,", "and of the shadow of death,"], ["o le nuu foi e le uia e tagata,", "through a land that no man passed through,"], ["e leai foi se tagata e mau ai?", "and where no man dwelt?"]]},
  {num:7,words:[["Na a'u faaooina mai foi outou i le fanua lafulemu,", "And I brought you into a plentiful country,"], ["ina ia outou aai ai i ona fua ma ana mea lelei;", "to eat the fruit thereof and the goodness thereof;"], ["ua outou o mai foi i lo'u nuu,", "but when ye entered,"], ["ona leaga ai lea ia te outou,", "ye defiled my land,"], ["ma outou faia lo'u tofi ma mea e inosia.", "and made mine heritage an abomination."]]},
  {num:8,words:[["E lei fai ane faitaulaga,", "The priests said not,"], ["Po o fea o i ai Ieova? e lei iloa foi a'u e i latou o e a'oa'o i le tulafono;", "Where is the LORD? and they that handle the law knew me not:"], ["o le au leoleo mamoe ua latou foua a'u,", "the pastors also transgressed against me,"], ["o perofeta foi ua latou vavalo i le igoa o Paala,", "and the prophets prophesied by Baal,"], ["ma latou mulimuli atu i mea e le aoga.", "and walked after things that do not profit."]]},
  {num:9,words:[["O le mea lea ou te toe finau ai lava ma outou,", "Wherefore I will yet plead with you,"], ["ua fetalai mai ai Ieova,", "saith the LORD,"], ["ou te finau ma le fanau a outou fanau.", "and with your children's children will I plead."]]},
  {num:10,words:[["Auā ia o atu outou i nuu tu matafaga o Kitimo,", "For pass over the isles of Chittim,"], ["ma vaavaai i ai;", "and see;"], ["ma ia outou aauina atu nisi i Kitara,", "and send unto Kedar,"], ["ma ia outou matuā mafaufau,", "and consider diligently,"], ["ma vaavaai pe ai se mea e pei o lenei mea.", "and see if there be such a thing."]]},
  {num:11,words:[["Po ua suia ea e se nuu o latou atua,", "Hath a nation changed their gods,"], ["a e le ni atua ia mea? A o lo'u nuu ua suia lo latou mamalu i le mea e le aoga.", "which are yet no gods? but my people have changed their glory for that which doth not profit."]]},
  {num:12,words:[["Le lagi e,", "Be astonished,"], ["ina ofo ia i lenei mea,", "O ye heavens,"], ["ia gatete lava,", "at this, and be horribly afraid,"], ["ma ia matuā fememeai,", "be ye very desolate,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:13,words:[["Auā e lua mea leaga ua faia e lo'u nuu;", "For my people have committed two evils;"], ["ua latou tuua a'u le puna o le vai ola,", "they have forsaken me the fountain of living waters,"], ["a ua latou eli mo i latou o vaieli,", "and hewed them out cisterns, broken cisterns,"], ["o vaieli māvaevae e le tali ai ni vai.", "that can hold no water."]]},
  {num:14,words:[["O le pologa ea Isaraelu? Na fanau ea o ia i le aiga? Se a le mea ua avea ai o ia ma tagata o taua?", "Is Israel a servant? is he a homeborn slave? why is he spoiled?"]]},
  {num:15,words:[["Ua fetagisi atu ia te ia o leona taanoa,", "The young lions roared upon him,"], ["ua leo tetele i latou,", "and yelled,"], ["ma ua latou faatafunaina lona nuu; ua susunuina foi ona aai,", "and they made his land waste:"], ["ua leai se nofo ai.", "his cities are burned without inhabitant."]]},
  {num:16,words:[["O le fanau a Nafi ma Tapenesa, o i latou lava latou te 'aina lou tumuai.", "Also the children of Noph and Tahapanes have broken the crown of thy head."]]},
  {num:17,words:[["Ua e le faia ea lenei mea ia te oe lava,", "Hast thou not procured this unto thyself, in that thou hast forsaken the LORD thy God,"], ["ina ua e tuua Ieova lou Atua i ona po na ta'ita'iina ai oe e ia i le ala?", "when he led thee by the way?"]]},
  {num:18,words:[["O lenei,", "And now what hast thou to do in the way of Egypt,"], ["se a ea sau mea e fai i le ala o Aikupito, e te inu ai i le vai i Seora? se a foi sau mea e fai i le ala o Asuria,", "to drink the waters of Sihor? or what hast thou to do in the way of Assyria,"], ["e te inu ai i le vai o le vaitafe?", "to drink the waters of the river?"]]},
  {num:19,words:[["E aoai ia te oe lau lava amio leaga,", "Thine own wickedness shall correct thee,"], ["e faasala foi ia te oe ou liliu ese; o lenei,", "and thy backslidings shall reprove thee:"], ["ia e iloa,", "know therefore and see that it is an evil thing and bitter,"], ["ma ia e manatu,", "that thou hast forsaken the LORD thy God,"], ["auā o le mea leaga ma le oona ina ua e tuua Ieova lou Atua, ma ua e le mata'u ia te au,", "and that my fear is not in thee,"], ["ua fetalai mai ai le Alii o Ieova o 'au.", "saith the Lord GOD of hosts."]]},
  {num:20,words:[["Auā talu anamua na ou gauia lau amo,", "For of old time I have broken thy yoke,"], ["ma ou motusia ou noanoaga;", "and burst thy bands;"], ["ona e fai mai ai lea, Ou te le auauna atu;", "and thou saidst,"], ["i le ua e taoto i luga o mauga maualuluga uma,", "I will not transgress;"], ["ma lalo o laau lauolaola uma,", "when upon every high hill and under every green tree thou wanderest,"], ["ua e mulilua ai.", "playing the harlot."]]},
  {num:21,words:[["O a'u foi na ou totōina oe o le vine Soreka,", "Yet I had planted thee a noble vine,"], ["o le fua e matuā moni lava;", "wholly a right seed:"], ["ua faapefea foi ona liua o oe ia te au ma lālā leaga o le vine ese?", "how then art thou turned into the degenerate plant of a strange vine unto me?"]]},
  {num:22,words:[["Auā e ui lava ina e fufulu ia te oe i le neteri,", "For though thou wash thee with nitre,"], ["ma e avane ai le moli e tele,", "and take thee much sope,"], ["ua tusia lau agasala i o'u luma,", "yet thine iniquity is marked before me,"], ["ua fetalai mai ai le Alii o Ieova.", "saith the Lord GOD."]]},
  {num:23,words:[["Pe faapefea ona e fai mai,", "How canst thou say,"], ["Ou te lei leaga,", "I am not polluted,"], ["ou te lei mulimuli atu ia Paala? Ina vaavaai atu ia i lou ala i le vanu,", "I have not gone after Baalim? see thy way in the valley,"], ["ia iloa le mea na e faia;", "know what thou hast done:"], ["o le kamela fafine muli e tele vave ua femo'eai i ona ala,", "thou art a swift dromedary traversing her ways;"]]},
  {num:24,words:[["o le asini o le vao ua masani ma le vao,", "A wild ass used to the wilderness,"], ["o le manao o lona loto ua ia sogisogi ai le matagi;", "that snuffeth up the wind at her pleasure;"], ["o ai se na te mafaia ona faafoi ia te ia ai lona manao? E le tigaina so latou o e sailiili ia te ia,", "in her occasion who can turn her away? all they that seek her will not weary themselves;"], ["latou te maua o ia i lona masina.", "in her month they shall find her."]]},
  {num:25,words:[["Taofi ia ou vae ne'i le faaseevaeina,", "Withhold thy foot from being unshod,"], ["ma lou gutu ne'i fiainu;", "and thy throat from thirst:"], ["a ua e fai mai,", "but thou saidst,"], ["E le aoga;", "There is no hope:"], ["e leai lava,", "no;"], ["auā ua ou loto i tane ese,", "for I have loved strangers,"], ["ou te mulimuli foi ia te i latou.", "and after them will I go."]]},
  {num:26,words:[["E pei ona mā o le gaoi ina ua maua o ia,", "As the thief is ashamed when he is found,"], ["e faapea ona faamaina o le aiga o Isaraelu,", "so is the house of Israel ashamed;"], ["o i latou,", "they,"], ["ma o latou tupu,", "their kings,"], ["ma o latou alii,", "their princes,"], ["ma o latou ositaulaga,", "and their priests,"], ["ma o latou perofeta,", "and their prophets,"]]},
  {num:27,words:[["o e fai atu i le laau,", "Saying to a stock,"], ["O lo'u tamā oe;", "Thou art my father;"], ["ma le maa,", "and to a stone,"], ["Ua e fanaua mai a'u;", "Thou hast brought me forth:"], ["auā ua latou u mai ia te au o latou tua,", "for they have turned their back unto me,"], ["a e le o latou mata;", "and not their face:"], ["a o ona po o lo latou malaia e fai mai ai i latou,", "but in the time of their trouble they will say,"], ["Ia e tulai mai,", "Arise,"], ["ma faaola ia te i matou.", "and save us."]]},
  {num:28,words:[["A o ifea ea ou atua na e faia mo oe? Ina tulai ia o i latou,", "But where are thy gods that thou hast made thee? let them arise,"], ["pe a mafaia e i latou ona faaola ia te oe i ona po o lou malaia;", "if they can save thee in the time of thy trouble:"], ["auā, Iuta e,", "for according to the number of thy cities are thy gods,"], ["o le tau aofai o ou aai o le tau aofai lea o ou atua.", "O Judah."]]},
  {num:29,words:[["Se a le mea tou te finau mai ai ia te au? Ua fouvale outou uma ia te au,", "Wherefore will ye plead with me? ye all have transgressed against me,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:30,words:[["Na ou sasaina a outou fanau,", "In vain have I smitten your children;"], ["a e le aoga;", "they received no correction:"], ["e lei talia e i latou le aoaiga; ua faaumatia o outou perofeta i la outou lava pelu,", "your own sword hath devoured your prophets,"], ["e pei o le leona na te faaumatia.", "like a destroying lion."]]},
  {num:31,words:[["Le tupulaga e,", "O generation,"], ["ina mafaufau ia outou i le afioga a Ieova. Ua avea ea a'u ma vao ia Isaraelu? po o se nuu pogisa? Se a foi le mea ua fai mai ai lo'u nuu. Ua sa'oloto i matou,", "see ye the word of the LORD. Have I been a wilderness unto Israel? a land of darkness? wherefore say my people, We are lords;"], ["matou te le toe o atu ia te oe?", "we will come no more unto thee?"]]},
  {num:32,words:[["Pe mafai ea e le taupou ona galo o ana teuga? pe galo ea i le faatoanofotane o ona fusi? A o lo'u nuu e le masino aso ua galo ai a'u ia te i latou.", "Can a maid forget her ornaments, or a bride her attire? yet my people have forgotten me days without number."]]},
  {num:33,words:[["Se a le mea ua e sauniuni ai lau amio e sailiili ina ia manaomia ai oe? O le a foi ua e a'oa'o atu ai ou ala i fafine amio leaga.", "Why trimmest thou thy way to seek love? therefore hast thou also taught the wicked ones thy ways."]]},
  {num:34,words:[["Ua iloa i ou lava pito ofu le toto o le ola o e matitiva e le sala;", "Also in thy skirts is found the blood of the souls of the poor innocents:"], ["e le o le matuā saili na ou iloa ai,", "I have not found it by secret search,"], ["a ua i ai i ia mea uma.", "but upon all these."]]},
  {num:35,words:[["A ua e fai mai,", "Yet thou sayest,"], ["E moni, e liliueseina lona toasa ia te au,", "Because I am innocent,"], ["auā ou te lei agasala.", "surely his anger shall turn from me."], ["Faauta,", "Behold,"], ["ou te faamasino ia te oe,", "I will plead with thee,"], ["ina ua e faapea,", "because thou sayest,"], ["Ou te lei sala.", "I have not sinned."]]},
  {num:36,words:[["Se a le mea e te fealuai soo ai e liliu ai lou ala? E masiasi foi oe ona o Aikupito,", "Why gaddest thou about so much to change thy way? thou also shalt be ashamed of Egypt,"], ["e pei ona e masiasi ona o Asuria.", "as thou wast ashamed of Assyria."]]},
  {num:37,words:[["E te alu atu foi nai lea mea,", "Yea,"], ["ma ou lima i luga o lou ulu;", "thou shalt go forth from him,"], ["auā ua faaleaogaina e Ieova o ou faatuatuaga,", "and thine hands upon thine head: for the LORD hath rejected thy confidences,"], ["e te le manuia ai lava.", "and thou shalt not prosper in them."]]},
];
renderVerseSet(jer_ch_2_Verses, 'jer-ch2-verses');

var jer_ch_3_Verses = [
  {num:1,words:[["Fai mai,", "They say,"], ["Afai e molia e se tagata lana avā,", "If a man put away his wife,"], ["ma ua alu ese o ia ia te ia,", "and she go from him,"], ["a e fai ma avā a se tasi, e toe alu atu ea o ia ia te ia? E le matuā leaga ai ea lena nuu? A o oe,", "and become another man's,"], ["ua e talitane i tane e toatele,", "shall he return unto her again? shall not that land be greatly polluted? but thou hast played the harlot with many lovers;"], ["a ia e toe foi mai ia te au,", "yet return again to me,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:2,words:[["Ina faasaga ae ia ou mata i mauga tula,", "Lift up thine eyes unto the high places,"], ["ma vaavaai,", "and see where thou hast not been lien with. In the ways hast thou sat for them,"], ["po o ifea ea se mea ua e le mulilua ai? ua e lamalama i ala mo i latou, e pei o se tagata Arapi i le vao;", "as the Arabian in the wilderness;"], ["ua leaga ia te oe le nuu i lou talitane ma lau amio leaga.", "and thou hast polluted the land with thy whoredoms and with thy wickedness."]]},
  {num:3,words:[["O le mea lea ua taofia ai le timu,", "Therefore the showers have been withholden,"], ["ua leai foi ni timuga mulimuli;", "and there hath been no latter rain;"], ["a ua ia te oe le muaulu o le fafine talitane,", "and thou hadst a whore's forehead,"], ["e le mafaia ona faamaina o oe.", "thou refusedst to be ashamed."]]},
  {num:4,words:[["E te le valaau mai ea ia te au e amata nei lava,", "Wilt thou not from this time cry unto me,"], ["Lo'u tamā e,", "My father,"], ["o oe lava le ta'ita'i o a'u ina o ou teine muli?", "thou art the guide of my youth?"]]},
  {num:5,words:[["E faamoemoe ea lona toasa e faavavau? pe na te tausia pea lava i ai? Faauta foi, ua e tautala,", "Will he reserve his anger for ever? will he keep it to the end? Behold,"], ["ua e faia foi mea leaga, ma e faamalosi i ai.", "thou hast spoken and done evil things as thou couldest."]]},
  {num:6,words:[["Na fetalai mai Ieova ia te au i ona po o Iosia le tupu, Po ua e iloa ea le mea ua faia e Isaraelu,", "The LORD said also unto me in the days of Josiah the king,"], ["le ua liliu ese? Ua alu ia i luga o mauga maualuluga uma,", "Hast thou seen that which backsliding Israel hath done? she is gone up upon every high mountain and under every green tree,"], ["ma lalo ifo o laau lauolaola uma, ma ua mulilua ai.", "and there hath played the harlot."]]},
  {num:7,words:[["Na ou fai atu foi ina ua uma ona ia faia o ia mea uma, Ina e toe foi mai ia ia te au;", "And I said after she had done all these things,"], ["a e lei toe foi mai lava ia, o lona uso faa'ole'ole foi o Iuta na ia iloa atu i ai.", "Turn thou unto me. But she returned not. And her treacherous sister Judah saw it."]]},
  {num:8,words:[["Ona ou iloa lea,", "And I saw,"], ["e ui lava i na mea uma na mulilua ai Isaraelu le ua liliu ese,", "when for all the causes whereby backsliding Israel committed adultery I had put her away,"], ["na ou aleia ai o ia, ma ou avatu ia te ia le tusi alei,", "and given her a bill of divorce;"], ["a ua le fefe lava lona uso faa'ole'ole o Iuta,", "yet her treacherous sister Judah feared not,"], ["a ua alu ia ua mulilua foi o ia.", "but went and played the harlot also."]]},
  {num:9,words:[["Ona o le leaga o lona mulilua ua ia faaleaga ai le nuu,", "And it came to pass through the lightness of her whoredom, that she defiled the land,"], ["ma ua mulilua i maa ma laau.", "and committed adultery with stones and with stocks."]]},
  {num:10,words:[["A e ui lava i ia mea uma,", "And yet for all this her treacherous sister Judah hath not turned unto me with her whole heart,"], ["e lei foi mai ia te au o lona uso faa'ole'ole o Iuta ma lona loto atoa, a ua pepelo o ia,", "but feignedly,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:11,words:[["Ua fetalai mai Ieova ia te au,", "And the LORD said unto me,"], ["O Isaraelu ua liliu ese ua sili o ia ona amiotonu ia Iuta le ua faa'ole'ole.", "The backsliding Israel hath justified herself more than treacherous Judah."]]},
  {num:12,words:[["Ina alu ia,", "Go and proclaim these words toward the north,"], ["ma e tala'i atu ia upu i le itu i matu,", "and say,"], ["ia faapea atu,", "Return,"], ["Isaraelu e,", "thou backsliding Israel,"], ["le ua liliu ese, ina foi mai ia,", "saith the LORD;"], ["o loo fetalai mai ai Ieova,", "and I will not cause mine anger to fall upon you:"], ["ou te le vaai ma le ita ia te outou;", "for I am merciful,"], ["auā ou te alofa lava a'u o loo fetalai mai ai Ieova,", "saith the LORD,"], ["e le tumau lo'u ita e faavavau.", "and I will not keep anger for ever."]]},
  {num:13,words:[["Tau ina e iloa lau agasala ua e fouvale ai ia Ieova lou Atua,", "Only acknowledge thine iniquity,"], ["ua e fealuai i tane ese i lalo o laau lauolaola uma;", "that thou hast transgressed against the LORD thy God,"], ["ua e le faalogo mai foi i lo'u leo,", "and hast scattered thy ways to the strangers under every green tree, and ye have not obeyed my voice,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:14,words:[["Le fanau liliu ese e,", "Turn,"], ["ina foi mai ia,", "O backsliding children,"], ["o loo fetalai mai ai Ieova;", "saith the LORD;"], ["auā e ui lava ina ou 'ino'ino ia te outou,", "for I am married unto you:"], ["a ou te avea outou,", "and I will take you one of a city,"], ["e taitasi i aai ma le taitoalua i aiga,", "and two of a family,"], ["ma a'u aumaia outou i Siona.", "and I will bring you to Zion:"]]},
  {num:15,words:[["Ou te avatu foi ia te outou leoleo mamoe e tatau ma lo'u loto,", "And I will give you pastors according to mine heart,"], ["latou te fafaga ia te outou i le poto ma le faautauta.", "which shall feed you with knowledge and understanding."]]},
  {num:16,words:[["A oo ina faatoateleina outou,", "And it shall come to pass,"], ["ma faauluolaina i le nuu i ia ona po,", "when ye be multiplied and increased in the land,"], ["o loo fetalai mai ai Ieova,", "in those days,"], ["ona latou le toe fai ane lea,", "saith the LORD,"], ["O le atolaau o le feagaiga a Ieova;", "they shall say no more, The ark of the covenant of the LORD:"], ["e le toe manatua;", "neither shall it come to mind:"], ["e le toe ta'ua foi;", "neither shall they remember it;"], ["e le asiasia;", "neither shall they visit it;"], ["e le toe faia lava.", "neither shall that be done any more."]]},
  {num:17,words:[["O ia ona po e ta'ua ai e i latou o Ierusalema,", "At that time they shall call Jerusalem the throne of the LORD;"], ["O le nofoālii o Ieova;", "and all the nations shall be gathered unto it,"], ["e potopoto nuu ese uma i le suafa o Ieova i Ierusalema;", "to the name of the LORD, to Jerusalem:"], ["latou te le toe savavali foi e tusa ma le finau vale o latou loto leaga.", "neither shall they walk any more after the imagination of their evil heart."]]},
  {num:18,words:[["O ona po ia e savavali faatasi ai le aiga o Iuta ma le aiga o Isaraelu, e o mai faatasi foi i latou mai le nuu i le itu i matu,", "In those days the house of Judah shall walk with the house of Israel,"], ["i le nuu na ou foaiina atu e fai mo outou tamā.", "and they shall come together out of the land of the north to the land that I have given for an inheritance unto your fathers."]]},
  {num:19,words:[["A o a'u,", "But I said,"], ["na ou faapea atu, E faapefea ona ou faatasia oe ma le fanau,", "How shall I put thee among the children,"], ["ma avatu ia te oe le nuu lelei,", "and give thee a pleasant land,"], ["o le tofi e matagofie,", "a goodly heritage of the hosts of nations? and I said,"], ["o 'au o atu nuu? Ona ou faapea ai lea,", "Thou shalt call me,"], ["E te valaau mai ia te au, Lo'u tamā e;", "My father;"], ["e te le toe liliu ese foi ia te au.", "and shalt not turn away from me."]]},
  {num:20,words:[["E moni,", "Surely as a wife treacherously departeth from her husband,"], ["e pei o le fafine ona amio faa'ole'ole i lana tane,", "so have ye dealt treacherously with me,"], ["ua faapea ona amio faa'ole'ole ia te au o outou, le aiga o Isaraelu e,", "O house of Israel,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:21,words:[["Na lagona le leo i luga o mauga tula,", "A voice was heard upon the high places,"], ["o le tagi ma le aioi atu o le fanauga a Isaraelu;", "weeping and supplications of the children of Israel:"], ["auā na latou faapiopio lo latou ala,", "for they have perverted their way,"], ["ua galo ia te i latou o Ieova lo latou Atua.", "and they have forgotten the LORD their God."]]},
  {num:22,words:[["Ina toe foi mai ia outou,", "Return,"], ["le fanau liliu ese e,", "ye backsliding children,"], ["ou te faamaloloina o outou liliu ese; silasila mai ia te i matou,", "and I will heal your backslidings. Behold,"], ["matou te o atu ia te oe,", "we come unto thee;"], ["auā o oe Ieova lo matou Atua.", "for thou art the LORD our God."]]},
  {num:23,words:[["E moni, e le aoga ona faatuatua i mauga,", "Truly in vain is salvation hoped for from the hills,"], ["ma le tele o atu mauga;", "and from the multitude of mountains:"], ["e moni, o loo ia Ieova lo matou Atua ona faaolaina o Isaraelu.", "truly in the LORD our God is the salvation of Israel."]]},
  {num:24,words:[["Ua 'aina e le mea e masiasi ai o mea sa tautigaina ai o matou tamā talu ina o matou o taulelea;", "For shame hath devoured the labour of our fathers from our youth;"], ["o a latou lafu mamoe ma a latou lafu povi,", "their flocks and their herds,"], ["o latou atalii ma o latou afafine.", "their sons and their daughters."]]},
  {num:25,words:[["Ua matou taooto ma lo matou masiasi,", "We lie down in our shame,"], ["ua ufitia lava i matou i lo matou mā;", "and our confusion covereth us:"], ["auā ua matou agasala ia Ieova lo matou Atua,", "for we have sinned against the LORD our God,"], ["o i matou atoa ma o matou tamā,", "we and our fathers,"], ["talu ina o matou o taulelea ua oo lava i nei ona po,", "from our youth even unto this day,"], ["e lei faalogo foi i matou i le siufofoga o Ieova lo matou Atua.", "and have not obeyed the voice of the LORD our God."]]},
];
renderVerseSet(jer_ch_3_Verses, 'jer-ch3-verses');

var jer_ch_4_Verses = [
  {num:1,words:[["Isaraelu e,", "If thou wilt return,"], ["afai e te fia foi mai,", "O Israel,"], ["ina foi mai ia ia te au,", "saith the LORD,"], ["o loo fetalai mai ai Ieova;", "return unto me:"], ["afai foi e te tuuesea au mea e inosia i o'u luma,", "and if thou wilt put away thine abominations out of my sight,"], ["ona e le taase lava lea;", "then shalt thou not remove."]]},
  {num:2,words:[["e te tauto foi i le faamaoni,", "And thou shalt swear,"], ["ma le amio sa'o,", "The LORD liveth,"], ["ma le amiotonu,", "in truth, in judgment,"], ["O loo soifua Ieova;", "and in righteousness;"], ["o nuu ese foi e ta'uamuia i latou e i latou ona o ia,", "and the nations shall bless themselves in him,"], ["ma latou mitamita ona o ia.", "and in him shall they glory."]]},
  {num:3,words:[["Auā o loo faapea ona fetalai mai o Ieova i tagata o Iuta ma Ierusalema,", "For thus saith the LORD to the men of Judah and Jerusalem,"], ["ina suatia ia lo outou fanua vaoa,", "Break up your fallow ground,"], ["aua foi ne'i lulu a outou saito i laau tuitui.", "and sow not among thorns."]]},
  {num:4,words:[["Ia faaperitomeina outou mo Ieova,", "Circumcise yourselves to the LORD,"], ["ma ave ese le pa'u o outou loto,", "and take away the foreskins of your heart,"], ["outou tagata o Iuta, ma e o nonofo i Ierusalema;", "ye men of Judah and inhabitants of Jerusalem:"], ["ne'i alu atu lo'u ita e pei o le afi,", "lest my fury come forth like fire,"], ["ne'i mu foi a e le matineia e se tasi,", "and burn that none can quench it,"], ["ona o le leaga o a outou amioga.", "because of the evil of your doings."]]},
  {num:5,words:[["Ia outou ta'u atu i Iuta,", "Declare ye in Judah,"], ["ma ia outou faailoa atu i Ierusalema;", "and publish in Jerusalem;"], ["ia faapea atu,", "and say,"], ["Ia ilia le pu i le nuu,", "Blow ye the trumpet in the land:"], ["ia alalaga tele,", "cry, gather together,"], ["ma fai atu ai,", "and say,"], ["Ina faapotopoto mai ia,", "Assemble yourselves,"], ["se'i tatou o atu ia i aai nofo 'olo.", "and let us go into the defenced cities."]]},
  {num:6,words:[["Ia faatuina le tagavai i Siona;", "Set up the standard toward Zion:"], ["ia outou sosola,", "retire,"], ["aua ne'i tutū mai;", "stay not:"], ["auā o a'u ou te aumaia le malaia mai le itu i matu,", "for I will bring evil from the north,"], ["ma le olopalaina e tele.", "and a great destruction."]]},
  {num:7,words:[["Ua alu ae le leona ai le vao filifili na i ai,", "The lion is come up from his thicket,"], ["o loo faasaga mai foi le na te faaumatia nuu ese;", "and the destroyer of the Gentiles is on his way;"], ["o loo sau ia ai le mea sa i ai e faatafunaina lou nuu;", "he is gone forth from his place to make thy land desolate;"], ["e fai ma mea tuufua ou aai,", "and thy cities shall be laid waste,"], ["e leai se nofo ai.", "without an inhabitant."]]},
  {num:8,words:[["Ia outou fusi ia te outou i ie talatala ona o lea mea,", "For this gird you with sackcloth,"], ["ma taufaitagitu'i, ma uio;", "lament and howl:"], ["auā e le liliueseina ia te i tatou le toasa tele o Ieova.", "for the fierce anger of the LORD is not turned back from us."]]},
  {num:9,words:[["O loo fetalai mai Ieova,", "And it shall come to pass at that day,"], ["O lea aso e matuā vaivai ai le loto o le tupu,", "saith the LORD,"], ["ma loto o alii;", "that the heart of the king shall perish, and the heart of the princes;"], ["e segia foi mauli o faitaulaga,", "and the priests shall be astonished,"], ["ma fememeai perofeta.", "and the prophets shall wonder."]]},
  {num:10,words:[["Ona ou fai atu lea,", "Then said I,"], ["Aue! le Alii e Ieova, e moni,", "Ah,"], ["ua e matuā olegia lenei,", "Lord GOD! surely thou hast greatly deceived this people and Jerusalem,"], ["nuu ma Ierusalema,", "saying,"], ["ua faapea mai, E ia te outou le filemu,", "Ye shall have peace;"], ["a ua oo lava le pelu i le loto.", "whereas the sword reacheth unto the soul."]]},
  {num:11,words:[["O ia ona po e fai mai ai i lenei nuu ma Ierusalema,", "At that time shall it be said to this people and to Jerusalem,"], ["O le matagi vevela i mauga tula i le vao,", "A dry wind of the high places in the wilderness toward the daughter of my people,"], ["i le ala o le tama fafine a lo'u nuu, a e le se matagi e faasavili a'i saito ,", "not to fan,"], ["pe faamamā a'i;", "nor to cleanse,"]]},
  {num:12,words:[["e oo mai ia te au le matagi e sili ona tele i ia matagi; o lenei foi,", "Even a full wind from those places shall come unto me:"], ["ou te faasala ia te i latou.", "now also will I give sentence against them."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["e alu ae o ia e pei o ao,", "he shall come up as clouds,"], ["ma ona kariota e pei o le asiosio; e sili ona tele vavave o ana solofanua i aeto;", "and his chariots shall be as a whirlwind:"], ["o i talofa ia te i tatou! auā ua faatafunaina i tatou.", "his horses are swifter than eagles. Woe unto us! for we are spoiled."]]},
  {num:14,words:[["Ierusalema e,", "O Jerusalem,"], ["ina fufulu ia lou loto ai le leaga, ina ia faaolaina oe;", "wash thine heart from wickedness,"], ["pe tumau seia afea ou mafaufauga leaga i totonu ia te oe?", "that thou mayest be saved. How long shall thy vain thoughts lodge within thee?"]]},
  {num:15,words:[["Auā ua fai mai le leo o le tasi mai Tanu,", "For a voice declareth from Dan,"], ["ua faailoa mai foi le malaia mai le mauga o Efaraima.", "and publisheth affliction from mount Ephraim."]]},
  {num:16,words:[["Ia outou fai atu i nuu ese;", "Make ye mention to the nations;"], ["faauta,", "behold,"], ["ia outou faailoa atu ia Ierusalema;", "publish against Jerusalem,"], ["o loo o mai mai le nuu mamao,", "that watchers come from a far country,"], ["o e vagaia o ia latou te alalaga foi i aai o Iuta.", "and give out their voice against the cities of Judah."]]},
  {num:17,words:[["Latou te siosioina o ia e pei o e leoleo fanua;", "As keepers of a field,"], ["auā ua ia fouvale ia te au,", "are they against her round about; because she hath been rebellious against me,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:18,words:[["O lou ala,", "Thy way and thy doings have procured these things unto thee;"], ["ma au amioga ua oo mai ai ia mea ia te oe;", "this is thy wickedness,"], ["o lau amio leaga lenei; auā o le mea oona lea ,", "because it is bitter,"], ["ua oo lava i lou loto.", "because it reacheth unto thine heart."]]},
  {num:19,words:[["Lo'u manava e,", "My bowels,"], ["lo'u manava e! ua tiga lo'u loto i totonu ia te au;", "my bowels! I am pained at my very heart;"], ["ua tagi lo'u loto;", "my heart maketh a noise in me;"], ["ou te le mafaalologo;", "I cannot hold my peace, because thou hast heard,"], ["auā lo'u agaga e,", "O my soul,"], ["ua e faalogo i le leo o le pu,", "the sound of the trumpet,"], ["ma le vāvāō o le taua.", "the alarm of war."]]},
  {num:20,words:[["Ua alalaga mai,", "Destruction upon destruction is cried;"], ["o lea mea ua sofaia ma lea mea ua sofaia;", "for the whole land is spoiled:"], ["auā ua faatafunaina le nuu uma; na faafuasei ona faatafunaina o o'u fale ie;", "suddenly are my tents spoiled,"], ["ma o'u ie puipui i le emo o le mata.", "and my curtains in a moment."]]},
  {num:21,words:[["Seia afea ona ou iloa ai le tagavai,", "How long shall I see the standard,"], ["ma ou faalogo atu i le leo o le pu?", "and hear the sound of the trumpet?"]]},
  {num:22,words:[["Auā ua faavalelea lo'u nuu;", "For my people is foolish,"], ["ua latou le iloa lava a'u;", "they have not known me;"], ["o le fanau vālea lava i latou,", "they are sottish children,"], ["e leai foi so latou mafaufau;", "and they have none understanding:"], ["e popoto i latou i fai mea leaga,", "they are wise to do evil,"], ["a e latou te le iloa ona fai o mea lelei.", "but to do good they have no knowledge."]]},
  {num:23,words:[["Na ou vaai atu i le nuu,", "I beheld the earth,"], ["faauta,", "and, lo,"], ["ua tuufua ma le gaogao;", "it was without form,"], ["na ou vaai atu i le lagi,", "and void; and the heavens,"], ["ua leai foi se malamalama.", "and they had no light."]]},
  {num:24,words:[["Na ou vaai atu i le atu mauga,", "I beheld the mountains,"], ["faauta foi,", "and,"], ["ua luluina,", "lo, they trembled,"], ["ua faagateteina foi o mauga uma.", "and all the hills moved lightly."]]},
  {num:25,words:[["Na ou vaai atu,", "I beheld,"], ["faauta foi,", "and,"], ["e leai se tagata,", "lo, there was no man,"], ["ua lele ese foi manu felelei uma.", "and all the birds of the heavens were fled."]]},
  {num:26,words:[["Na ou vaai atu,", "I beheld, and,"], ["faauta foi,", "lo,"], ["o le fanua sa lafulemu ua avea ma vao lafua;", "the fruitful place was a wilderness,"], ["o ona aai uma foi ua fulisia i luma o Ieova ma lona toasa tele.", "and all the cities thereof were broken down at the presence of the LORD, and by his fierce anger."]]},
  {num:27,words:[["Auā ua faapea ona fetalai mai o Ieova,", "For thus hath the LORD said,"], ["E faatafunaina le nuu uma,", "The whole land shall be desolate;"], ["a ou te le matuā faaumatia.", "yet will I not make a full end."]]},
  {num:28,words:[["O le mea lea e faanoanoa ai le nuu,", "For this shall the earth mourn,"], ["e pouliuli ai le lagi i luga;", "and the heavens above be black:"], ["auā ua ou fai ane,", "because I have spoken it,"], ["ua ou manatu lava i ai e fai,", "I have purposed it,"], ["ou te le salamo ai,", "and will not repent,"], ["ou te le liliu ese ai.", "neither will I turn back from it."]]},
  {num:29,words:[["E sosola aai uma ona o le vāvāō o e tietie i solofanua ma e fanafana i u;", "The whole city shall flee for the noise of the horsemen and bowmen;"], ["latou te o i le vao matua,", "they shall go into thickets,"], ["ma feaei i luga o papa;", "and climb up upon the rocks:"], ["e tuua aai uma,", "every city shall be forsaken,"], ["e le nofo ai foi se tagata.", "and not a man dwell therein."]]},
  {num:30,words:[["O oe na foi le ua faatafunaina,", "And when thou art spoiled,"], ["se a se mea e te faia? E ui lava ina e ofu oe i ofu mūmū;", "what wilt thou do? Though thou clothest thyself with crimson,"], ["e ui lava ina e teuteu ia te oe i teuga i auro;", "though thou deckest thee with ornaments of gold,"], ["e ui lava ina masae ou mata i le vali,", "though thou rentest thy face with painting,"], ["e te faalalelei fua ia te oe;", "in vain shalt thou make thyself fair;"], ["e inosia oe e i latou sa mananao ia te oe,", "thy lovers will despise thee,"], ["latou te sailiili foi e fasioti ia te oe.", "they will seek thy life."]]},
  {num:31,words:[["Auā ua ou faalogo i le leo e pei o se fafine ua faatiga,", "For I have heard a voice as of a woman in travail,"], ["o le tiga e pei o le fafine a fanau mai lana tama ulumatua;", "and the anguish as of her that bringeth forth her first child,"], ["o le leo o le tama fafine a Siona;", "the voice of the daughter of Zion,"], ["o loo gae ia, o loo faaloaloa e ia ona lima;", "that bewaileth herself,"], ["ua faapea ane,", "that spreadeth her hands,"], ["Aue! talofa lava ia te au,", "saying,"], ["auā ua vaivai lo'u loto ona o e fasioti tagata.", "Woe is me now! for my soul is wearied because of murderers."]]},
];
renderVerseSet(jer_ch_4_Verses, 'jer-ch4-verses');

var jer_ch_5_Verses = [
  {num:1,words:[["Ia outou fetaufetuliai i ala o Ierusalema,", "Run ye to and fro through the streets of Jerusalem,"], ["ma ia vaavaai,", "and see now,"], ["ma ia iloa,", "and know,"], ["ma ia outou sailiili i ona malae,", "and seek in the broad places thereof,"], ["pe tou te maua ai se tagata,", "if ye can find a man,"], ["pe ai se tasi ua ia faia le mea tonu,", "if there be any that executeth judgment,"], ["ma ua taumafai ina ia faamaoni,", "that seeketh the truth;"], ["ona ou faamagaloina ai lea o le aai .", "and I will pardon it."]]},
  {num:2,words:[["E ui lava ina ua latou faapea mai,", "And though they say,"], ["O loo soifua Ieova;", "The LORD liveth;"], ["a ua latou tauto pepelo lava.", "surely they swear falsely."]]},
  {num:3,words:[["Ieova e,", "O LORD,"], ["e le silasila ea ou fofoga i le ua faamaoni? Ua e sasaina i latou,", "are not thine eyes upon the truth? thou hast stricken them,"], ["a ua le tiga i latou;", "but they have not grieved;"], ["ua e faaumatia i latou,", "thou hast consumed them,"], ["a ua latou le mafafai ona talia o le aoaiga;", "but they have refused to receive correction:"], ["ua latou faamaaa o latou mata e sili i le papa,", "they have made their faces harder than a rock;"], ["ua latou le mafafai ona toe foi mai.", "they have refused to return."]]},
  {num:4,words:[["Ona ou fai ane ai lea,", "Therefore I said,"], ["Ai lava o tagata lautele i latou,", "Surely these are poor;"], ["e valelea i latou;", "they are foolish:"], ["auā latou te le iloa le ala o Ieova,", "for they know not the way of the LORD,"], ["ma le faamasinoga a lo latou Atua.", "nor the judgment of their God."]]},
  {num:5,words:[["Ou te alu lava a'u i alii,", "I will get me unto the great men,"], ["ou te tautala atu ia te i latou;", "and will speak unto them;"], ["auā o i latou ua latou iloa le ala o Ieova, ma le faamasinoga a lo latou Atua;", "for they have known the way of the LORD,"], ["a e peitai o i latou,", "and the judgment of their God:"], ["ua latou gausia lava le amo,", "but these have altogether broken the yoke,"], ["ma latou motusi ese i noanoaga.", "and burst the bonds."]]},
  {num:6,words:[["O le mea lea e oti ai i latou i le leona mai le vao,", "Wherefore a lion out of the forest shall slay them,"], ["e fano i latou i le luko o le afiafi;", "and a wolf of the evenings shall spoil them,"], ["e lamalama le nameri i o latou aai;", "a leopard shall watch over their cities:"], ["o i latou uma e o atu ai e saeia lava i latou;", "every one that goeth out thence shall be torn in pieces:"], ["auā ua tele o latou solitulafono,", "because their transgressions are many,"], ["ua atu lasi o latou liliu ese.", "and their backslidings are increased."]]},
  {num:7,words:[["E faapefea ona ou faamagalo ia te oe i lenei mea? Ua tuua a'u e lau fanau,", "How shall I pardon thee for this? thy children have forsaken me,"], ["a ua latou tauto i mea e le ni atua;", "and sworn by them that are no gods:"], ["na ou fafaga ia te i latou ua maoona,", "when I had fed them to the full, they then committed adultery,"], ["a ua latou mulilulua ma latou faapotopoto atu i le fale o le fafine talitane.", "and assembled themselves by troops in the harlots' houses."]]},
  {num:8,words:[["Ua ni solofanua poa e pepeti i latou i le taeao,", "They were as fed horses in the morning:"], ["ua latou taitasi ma tagi i le avā a lē la te tuaoi.", "every one neighed after his neighbour's wife."]]},
  {num:9,words:[["Ou te le taui atu ea ia te i latou ona o ia mea, o loo fetalai mai ai Ieova;", "Shall I not visit for these things? saith the LORD:"], ["e le taui atu ea ma sui e lo'u agaga i le nuu faapena?", "and shall not my soul be avenged on such a nation as this?"]]},
  {num:10,words:[["Ina aea ia e outou o ona pa,", "Go ye up upon her walls,"], ["ma outou lepetia ai;", "and destroy;"], ["a e aua tou te matuā faaumatia;", "but make not a full end:"], ["ina aveeseina ia ona moemoe,", "take away her battlements;"], ["auā e le o a Ieova ia.", "for they are not the LORD'S."]]},
  {num:11,words:[["Auā ua matuā amio faa'ole'ole mai ia te au le aiga o Isaraelu, ma le aiga o Iuta,", "For the house of Israel and the house of Judah have dealt very treacherously against me,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:12,words:[["Ua latou faafiti ia Ieova,", "They have belied the LORD,"], ["ma latou fai atu,", "and said,"], ["E leai o ia; e le oo mai foi ia te i matou se leaga,", "It is not he;"], ["o le iloa foi e i matou le pelu,", "neither shall evil come upon us;"], ["po o le oge;", "neither shall we see sword nor famine:"]]},
  {num:13,words:[["e fai foi perofeta ma matagi,", "And the prophets shall become wind,"], ["e leai foi se upu ia te i latou;", "and the word is not in them:"], ["e faapea ona faia ia te i latou.", "thus shall it be done unto them."]]},
  {num:14,words:[["Lenei la,", "Wherefore thus saith the LORD God of hosts,"], ["o loo faapea ona fetalai mai o Ieova, le Atua o 'au,", "Because ye speak this word,"], ["Ua outou fai mai lenei upu,", "behold,"], ["faauta mai,", "I will make my words in thy mouth fire,"], ["o le mea lea ou te fai ai a'u upu i lou gutu ma afi, e fai foi lenei nuu ma fafie,", "and this people wood,"], ["e susunuina lava i latou.", "and it shall devour them."]]},
  {num:15,words:[["Faauta,", "Lo,"], ["le aiga o Isaraelu e,", "I will bring a nation upon you from far,"], ["o loo ou aumaia se nuu ai le mea mamao e tau ma outou,", "O house of Israel,"], ["o loo fetalai mai ai Ieova;", "saith the LORD:"], ["o le nuu malosi lea,", "it is a mighty nation,"], ["o le nuu o le vavau,", "it is an ancient nation,"], ["o le nuu foi tou te le iloa la latou gagana,", "a nation whose language thou knowest not,"], ["tou te le lagona foi se mea latou te fai mai ai.", "neither understandest what they say."]]},
  {num:16,words:[["O la latou utu u fanafana e pei o se tuugamau ua faamaga;", "Their quiver is as an open sepulchre,"], ["o toa i latou uma.", "they are all mighty men."]]},
  {num:17,words:[["Latou te 'aina lau saito ma au mea e 'ai,", "And they shall eat up thine harvest, and thy bread,"], ["o mea e 'ai ia a ou atalii ma ou afafine;", "which thy sons and thy daughters should eat:"], ["latou te 'aina au lafu mamoe ma au lafu povi;", "they shall eat up thy flocks and thine herds: they shall eat up thy vines and thy fig trees:"], ["latou te 'aina ou vine ma ou mati;", "they shall impoverish thy fenced cities,"], ["latou te faatafunaina i le pelu ou aai nofo 'olo ua e faatuatua i ai.", "wherein thou trustedst, with the sword."]]},
  {num:18,words:[["A o ia ona po ou te le matuā faaumatia ai outou,", "Nevertheless in those days, saith the LORD,"], ["o loo fetalai mai ai Ieova.", "I will not make a full end with you."]]},
  {num:19,words:[["A outou fai mai,", "And it shall come to pass,"], ["Ona o le a ea ua faia e Ieova lo tatou Atua o ia mea uma ia te i tatou? Ona e fai atu ai lea ia te i latou,", "when ye shall say,"], ["E pei ona outou tuua o a'u,", "Wherefore doeth the LORD our God all these things unto us? then shalt thou answer them, Like as ye have forsaken me,"], ["ma outou auauna i atua ese i lo outou nuu,", "and served strange gods in your land,"], ["e faapea foi ona outou auauna atu i tagata ese i le nuu e le o lo outou.", "so shall ye serve strangers in a land that is not your's."]]},
  {num:20,words:[["Ina ta'u atu ia lenei mea i le aiga o Iakopo,", "Declare this in the house of Jacob,"], ["ma faailoa atu ai i Iuta,", "and publish it in Judah,"], ["ia faapea atu,", "saying,"]]},
  {num:21,words:[["Ina faalogologo mai ia i lenei mea,", "Hear now this,"], ["o outou le nuu vālea ma le le mafaufau;", "O foolish people,"], ["e fai o latou mata,", "and without understanding; which have eyes,"], ["a e le vaai i latou;", "and see not;"], ["e fai foi o latou taliga,", "which have ears,"], ["a e le faalogo i latou.", "and hear not:"]]},
  {num:22,words:[["Tou te le fefefe ea ia te au? o loo fetalai mai ai Ieova;", "Fear ye not me? saith the LORD:"], ["tou te le gatete ea i o'u luma? o a'u na ou tuuina le oneone e fai ma tuaoi o le sami;", "will ye not tremble at my presence,"], ["o le tulafono e faavavau lea,", "which have placed the sand for the bound of the sea by a perpetual decree,"], ["e le masopoia;", "that it cannot pass it:"], ["e ui ina fāti tetele mai ona galu,", "and though the waves thereof toss themselves,"], ["e le mafaia lava;", "yet can they not prevail;"], ["e ui ina taalili mai,", "though they roar,"], ["e le masopoia lava.", "yet can they not pass over it?"]]},
  {num:23,words:[["A o lenei nuu, ua i ai le loto vaogata ma le fouvale;", "But this people hath a revolting and a rebellious heart;"], ["ua liliu ese i latou, ma ua latou o.", "they are revolted and gone."]]},
  {num:24,words:[["Ua latou le fai ifo foi i o latou loto,", "Neither say they in their heart,"], ["Se'i tatou matatau ia Ieova lo tatou Atua,", "Let us now fear the LORD our God,"], ["o le na te foai mai le ua,", "that giveth rain, both the former and the latter,"], ["o le uaga muamua ma le uaga mulimuli i ona lava aso;", "in his season:"], ["o le na te tausia foi mo i tatou ona vaiasosa ua atofaina e fai ai le seleselegāsaito.", "he reserveth unto us the appointed weeks of the harvest."]]},
  {num:25,words:[["O a outou amio leaga ua liliueseina ai ia mea;", "Your iniquities have turned away these things,"], ["o a outou agasala foi ua taofia ai mea lelei ai ia te outou.", "and your sins have withholden good things from you."]]},
  {num:26,words:[["Auā ua i ai i lo'u nuu o tagata amio leaga;", "For among my people are found wicked men:"], ["ua latou lamalama e pei ona faapuga o e mailei manu;", "they lay wait,"], ["ua latou tuu le mailei,", "as he that setteth snares; they set a trap,"], ["ua latou maua tagata.", "they catch men."]]},
  {num:27,words:[["E pei ona tumu o le āoa i manu felelei,", "As a cage is full of birds,"], ["e faapea ona tutumu o latou fale i le tau'ole'ole;", "so are their houses full of deceit:"], ["o le mea lea ua faasilisiliina ai i latou,", "therefore they are become great,"], ["ma faatamaoaigaina ai.", "and waxen rich."]]},
  {num:28,words:[["Ua puputa i latou,", "They are waxen fat,"], ["ua usiusi;", "they shine:"], ["ua silimusa i latou ona fai amio leaga;", "yea,"], ["ua latou le fai le finauga,", "they overpass the deeds of the wicked: they judge not the cause,"], ["o le finauga lava a le ua aumatuā,", "the cause of the fatherless,"], ["a ua manuia i latou;", "yet they prosper;"], ["o le faamasinoga foi a e matitiva ua latou le faamasinoina.", "and the right of the needy do they not judge."]]},
  {num:29,words:[["Ou te le taui atu ea ia te i latou ona o ia mea? o loo fetalai mai ai Ieova;", "Shall I not visit for these things? saith the LORD:"], ["e le taui atu ea ma sui e lo'u agaga i le nuu faapena?", "shall not my soul be avenged on such a nation as this?"]]},
  {num:30,words:[["Ua faia i le nuu le mea e ofo ai ma le inosia;", "A wonderful and horrible thing is committed in the land;"]]},
  {num:31,words:[["ua vavalo le au perofeta i mea pepelo,", "The prophets prophesy falsely,"], ["ua pule foi le au faitaulaga ma le usiusitai ia te i latou;", "and the priests bear rule by their means;"], ["ua loto foi lo'u nuu ina ia faapea; ia,", "and my people love to have it so:"], ["se a se mea tou te faia i ona iuga?", "and what will ye do in the end thereof?"]]},
];
renderVerseSet(jer_ch_5_Verses, 'jer-ch5-verses');

var jer_ch_6_Verses = [
  {num:1,words:[["O outou le fanauga a Peniamina e,", "O ye children of Benjamin,"], ["ia outou sosola nai totonu o Ierusalema;", "gather yourselves to flee out of the midst of Jerusalem,"], ["ia outou ilia le pu i Tikoa,", "and blow the trumpet in Tekoa, and set up a sign of fire in Beth-haccerem:"], ["ma faatu le faailoga i luga o Peteakarema;", "for evil appeareth out of the north,"], ["auā o loo faasaga mai le malaia ma le olopalaina e tele mai le itu i matu.", "and great destruction."]]},
  {num:2,words:[["Ou te faaumatia le tama fafine a Siona, o le ua matagofie ma le faapelepeleina.", "I have likened the daughter of Zion to a comely and delicate woman."]]},
  {num:3,words:[["E o mai ia te ia leoleo mamoe ma a latou lafu;", "The shepherds with their flocks shall come unto her;"], ["latou te faatuina o latou fale ie e faataaliolio ai ia te ia;", "they shall pitch their tents against her round about;"], ["o mamoe latou te taitasi ma 'ai i le mea e nofo ai.", "they shall feed every one in his place."]]},
  {num:4,words:[["Ina sauniuni ia e sii atu i ai le taua;", "Prepare ye war against her;"], ["tulai ia,", "arise,"], ["ina tatou o ae i le aoauli. Oi talofa ia te i tatou! auā ua faliu le la,", "and let us go up at noon. Woe unto us! for the day goeth away,"], ["ua lafoia ata i le afiafi.", "for the shadows of the evening are stretched out."]]},
  {num:5,words:[["Tulai ia,", "Arise,"], ["ina tatou o ae i le po,", "and let us go by night,"], ["ma tatou faaumatia ona maota.", "and let us destroy her palaces."]]},
  {num:6,words:[["Auā o loo faapea ona fetalai mai o Ieova o 'au,", "For thus hath the LORD of hosts said,"], ["Ina ta mai ia laau,", "Hew ye down trees,"], ["ma tanu ai le mea mautietie e tau ma Ierusalema;", "and cast a mount against Jerusalem:"], ["o le aai lea e faasalaina;", "this is the city to be visited;"], ["ua i totonu ia te ia o sauaga uma.", "she is wholly oppression in the midst of her."]]},
  {num:7,words:[["E pei ona puna mai o le punāvai lona suāvai,", "As a fountain casteth out her waters,"], ["e faapea ona faapunaia mai e ia o lona leaga;", "so she casteth out her wickedness:"], ["ua lagona i totonu ia te ia le faasaua ma le faatafunaga;", "violence and spoil is heard in her;"], ["ua i ai pea i o'u luma le ma'i ma le manua.", "before me continually is grief and wounds."]]},
  {num:8,words:[["Ierusalema e,", "Be thou instructed,"], ["ia e talia le aoaiga,", "O Jerusalem,"], ["ina ne'i te'a ese lo'u loto ia te oe;", "lest my soul depart from thee;"], ["ina ne'i ou faia oe ma faatafunaga,", "lest I make thee desolate,"], ["o le nuu e le āina.", "a land not inhabited."]]},
  {num:9,words:[["Ua faapea ona fetalai mai o Ieova o 'au, E faapei ona latou matuā aoao i le vine,", "Thus saith the LORD of hosts,"], ["e faapea foi i e o totoe i Isaraelu;", "They shall throughly glean the remnant of Israel as a vine:"], ["ina toe tuu mai ia lou lima, e pei o le ua tau vine ona toe tuu mai lona lima i ato.", "turn back thine hand as a grapegatherer into the baskets."]]},
  {num:10,words:[["Po o ai ea ou te fai atu i ai,", "To whom shall I speak,"], ["ma aoai atu i ai,", "and give warning,"], ["ina ia latou faalogo mai? Faauta,", "that they may hear? behold,"], ["e lei peritomeina o latou taliga,", "their ear is uncircumcised,"], ["e le mafaia e i latou ona faalogo mai;", "and they cannot hearken:"], ["faauta,", "behold,"], ["ua fai le afioga a Ieova ma mea e tauemu i ai i latou;", "the word of the LORD is unto them a reproach;"], ["ua latou le fiafia i ai.", "they have no delight in it."]]},
  {num:11,words:[["O le mea lea ua tumu ai a'u i le toasa o Ieova;", "Therefore I am full of the fury of the LORD;"], ["ua ou le lavā faatoatoa;", "I am weary with holding in:"], ["ou te liligi ifo ai i luga o tama iti i fafo,", "I will pour it out upon the children abroad,"], ["e faatasi foi ma le faapotopotoga o taulelea;", "and upon the assembly of young men together:"], ["e maua foi le tane atoa ma lana avā,", "for even the husband with the wife shall be taken,"], ["o le toeaina atoa ma le ua tuu tulu'i ona tausaga.", "the aged with him that is full of days."]]},
  {num:12,words:[["E avea o latou fale mo nisi,", "And their houses shall be turned unto others,"], ["atoa foi ma fanua,", "with their fields and wives together:"], ["ma avā; auā ou te faaloaloa lo'u lima i luga o e nonofo i le nuu,", "for I will stretch out my hand upon the inhabitants of the land,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:13,words:[["Auā o latou tagatānuu atoa ma o latou alii ua matapeapea i oloa i latou uma;", "For from the least of them even unto the greatest of them every one is given to covetousness;"], ["o perofeta foi atoa ma ositaulaga ua amio pepelo i latou uma.", "and from the prophet even unto the priest every one dealeth falsely."]]},
  {num:14,words:[["Ua latou fofo faatauvaa le manua o le tama fafine a lo'u nuu,", "They have healed also the hurt of the daughter of my people slightly,"], ["ua faapea ane,", "saying,"], ["E manuia,", "Peace,"], ["e manuia;", "peace;"], ["a e leai se manuia.", "when there is no peace."]]},
  {num:15,words:[["Ua latou mamā ea ona o le mea inosia ua latou faia? ua matuā le mamā lava i latou,", "Were they ashamed when they had committed abomination? nay,"], ["ua latou le iloa lava le masiasi;", "they were not at all ashamed,"], ["o le mea lea e pauu ai i latou faatasi ma e ua pauu;", "neither could they blush:"], ["o ona po ou te asiasi ai ia te i latou,", "therefore they shall fall among them that fall:"], ["latou te tausuai ai,", "at the time that I visit them they shall be cast down,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:16,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Ia outou tutū i ala,", "Stand ye in the ways,"], ["ma vaavaai,", "and see,"], ["ma fesili i ala o le vavau,", "and ask for the old paths,"], ["po o i fea le ala lelei,", "where is the good way,"], ["ma ia outou savavali ai,", "and walk therein,"], ["ona maua lea e outou o le malologa mo outou agaga. A ua latou fai mai,", "and ye shall find rest for your souls. But they said,"], ["Matou te le savavali i ai .", "We will not walk therein."]]},
  {num:17,words:[["Ua ou tofia foi tagata vaai mo outou,", "Also I set watchmen over you,"], ["o e ua faapea mai ,", "saying,"], ["Ina faalogo ia i le leo o le pu. A ua latou fai mai,", "Hearken to the sound of the trumpet. But they said,"], ["Matou te le faalogo i ai .", "We will not hearken."]]},
  {num:18,words:[["O lenei,", "Therefore hear,"], ["ina faalogologo mai ia outou nuu ese,", "ye nations,"], ["ia outou iloa foi o outou le faapotopotoga,", "and know, O congregation,"], ["le mea e ia te i latou.", "what is among them."]]},
  {num:19,words:[["Le lalolagi e,", "Hear,"], ["ina faalogologo mai ia,", "O earth:"], ["faauta,", "behold,"], ["o a'u nei ou te faaooina atu le malaia i lenei nuu,", "I will bring evil upon this people, even the fruit of their thoughts,"], ["o le fua o latou lava mafaufauga,", "because they have not hearkened unto my words,"], ["auā ua latou le faalogo i a'u upu;", "nor to my law,"], ["o la'u tulafono foi ua latou lafoaiina lea.", "but rejected it."]]},
  {num:20,words:[["Se a le mea ua au mai ai ia te au pulu lipano mai Seepa,", "To what purpose cometh there to me incense from Sheba,"], ["ma kani manogi mai le nuu mamao? O a outou taulaga mu e le talia ia,", "and the sweet cane from a far country? your burnt offerings are not acceptable,"], ["ma a outou taulaga ou te le fiafia i ai.", "nor your sacrifices sweet unto me."]]},
  {num:21,words:[["O le mea lea ua faapea ona fetalai mai ai o Ieova,", "Therefore thus saith the LORD,"], ["Faauta,", "Behold,"], ["ou te tuuina atu i luma o lenei nuu o mea e tausuai ai,", "I will lay stumblingblocks before this people,"], ["e tausuai ai tamā faatasi ma o latou atalii;", "and the fathers and the sons together shall fall upon them;"], ["e fano foi le tagata atoa ma lana uo.", "the neighbour and his friend shall perish."]]},
  {num:22,words:[["Ua faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Faauta,", "Behold,"], ["o le a o mai tagata mai le nuu i le itu i matu,", "a people cometh from the north country,"], ["o le a lagaina mai le nuu tele mai tuluiga o le lalolagi;", "and a great nation shall be raised from the sides of the earth."]]},
  {num:23,words:[["latou te tagofia le aufana ma le tao;", "They shall lay hold on bow and spear;"], ["ua saua i latou,", "they are cruel,"], ["ma latou le alolofa;", "and have no mercy;"], ["e taalili o latou leo e pei o le sami; ua latou tietie foi i solofanua,", "their voice roareth like the sea;"], ["ua sauniuni e pei o tagata i le taua,", "and they ride upon horses,"], ["latou te tau ma oe,", "set in array as men for war against thee,"], ["le tama fafine a Siona e.", "O daughter of Zion."]]},
  {num:24,words:[["Ua tatou lagona le tala i ai;", "We have heard the fame thereof:"], ["ua vaivai ai o tatou lima;", "our hands wax feeble:"], ["ua maua i tatou i le puapuaga,", "anguish hath taken hold of us, and pain,"], ["o le tiga e pei o le fafine o le a fanau mai.", "as of a woman in travail."]]},
  {num:25,words:[["Aua tou te o i le fanua,", "Go not forth into the field,"], ["aua foi le ui ane i le ala; auā ua i ai le pelu a le ua ita mai,", "nor walk by the way;"], ["ma le mata'u i itu uma.", "for the sword of the enemy and fear is on every side."]]},
  {num:26,words:[["Le tama fafine a lo'u nuu e,", "O daughter of my people,"], ["ia e fusi ia te oe i le ie talatala,", "gird thee with sackcloth,"], ["ma ia e taafili i le lefulefu;", "and wallow thyself in ashes: make thee mourning,"], ["ia e faanoanoa e pei ona faanoanoa se tasi i lona atalii e toatasi,", "as for an only son,"], ["o le tagitu'i lotulotu;", "most bitter lamentation:"], ["auā e faafuasei ona oo mai ia te i tatou le na te faatafunaina.", "for the spoiler shall suddenly come upon us."]]},
  {num:27,words:[["Ua ou tofia oe o le tofotofo i lo'u nuu, o le 'olo,", "I have set thee for a tower and a fortress among my people,"], ["ina ia e iloa, ma tofotofo i lo latou ala.", "that thou mayest know and try their way."]]},
  {num:28,words:[["Ua matuā vaogatata i latou uma;", "They are all grievous revolters,"], ["ua feoai i latou ma feaveaveai;", "walking with slanders:"], ["o 'apa memea ma uamea i latou;", "they are brass and iron;"], ["o i latou uma ua latou faataumaoi mea.", "they are all corrupters."]]},
  {num:29,words:[["Ua mu le tapili,", "The bellows are burned,"], ["ua faaumatia le pulu i le afi;", "the lead is consumed of the fire;"], ["o lē fai mea uamea na te faateaeseina fua le otaota;", "the founder melteth in vain:"], ["auā e le faateaeseina tagata amio leaga.", "for the wicked are not plucked away."]]},
  {num:30,words:[["E ta'ua i latou o ario ua lafoaiina,", "Reprobate silver shall men call them,"], ["auā ua lafoaiina i latou e Ieova.", "because the LORD hath rejected them."]]},
];
renderVerseSet(jer_ch_6_Verses, 'jer-ch6-verses');

var jer_ch_7_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova ua faapea mai,", "The word that came to Jeremiah from the LORD, saying,"]]},
  {num:2,words:[["Ina tulai ia i le faitotoa o le fale o Ieova,", "Stand in the gate of the LORD'S house,"], ["ma tala'i atu ai lenei upu,", "and proclaim there this word,"], ["ia faapea atu,", "and say,"], ["Ina faalogologo mai ia i le afioga a Ieova,", "Hear the word of the LORD,"], ["o outou o Iuta uma,", "all ye of Judah,"], ["o e ulu mai i nei faitotoa e ifo atu ai ia Ieova.", "that enter in at these gates to worship the LORD."]]},
  {num:3,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["Ia outou sauni lelei i o outou ala ma a outou amio,", "Amend your ways and your doings,"], ["ona ou faatumauina ai lea o outou i lenei mea.", "and I will cause you to dwell in this place."]]},
  {num:4,words:[["Aua tou te faatuatua i upu pepelo,", "Trust ye not in lying words,"], ["o loo faapea,", "saying,"], ["O le malumalu o Ieova,", "The temple of the LORD, The temple of the LORD,"], ["O le malumalu o Ieova,", "The temple of the LORD,"], ["O le malumalu o Ieova lenei.", "are these."]]},
  {num:5,words:[["Auā afai tou te matuā sauni lelei i o outou ala ma a outou amio;", "For if ye throughly amend your ways and your doings;"], ["afai foi tou te matuā faia le faamasinoga i le tasi tagata ma le tasi tagata;", "if ye throughly execute judgment between a man and his neighbour;"]]},
  {num:6,words:[["afai foi tou te le faasaua atu i le tagata ese,", "If ye oppress not the stranger,"], ["ma le ua aumatuā,", "the fatherless,"], ["ma le fafine ua oti lana tane,", "and the widow,"], ["ma outou le faamaligi le toto o e ua le sala i lenei mea,", "and shed not innocent blood in this place,"], ["ma outou le mulimuli atu i atua ese e i ai le malaia;", "neither walk after other gods to your hurt:"]]},
  {num:7,words:[["ona ou faatumauina ai lea o outou i lenei mea,", "Then will I cause you to dwell in this place, in the land that I gave to your fathers,"], ["o le nuu na ou foaiina atu i o outou tamā e faavavau faavavau lava.", "for ever and ever."]]},
  {num:8,words:[["Faauta,", "Behold,"], ["ua outou faatuatua i upu pepelo,", "ye trust in lying words,"], ["e le aoga.", "that cannot profit."]]},
  {num:9,words:[["Tou te gaoi ea,", "Will ye steal,"], ["ma fasioti tagata,", "murder,"], ["ma mulilua,", "and commit adultery,"], ["ma tauto pepelo,", "and swear falsely,"], ["ma faamu mea manogi ia Paala,", "and burn incense unto Baal,"], ["ma mulimuli atu i atua ese ua outou le iloa;", "and walk after other gods whom ye know not;"]]},
  {num:10,words:[["ma outou o mai, ma tutū i o'u luma i lenei fale,", "And come and stand before me in this house,"], ["o loo ta'ua ai lo'u igoa,", "which is called by my name,"], ["ma outou fai mai,", "and say,"], ["Ua laveaiina i matou, ina ia faia nei mea inosia uma?", "We are delivered to do all these abominations?"]]},
  {num:11,words:[["O lenei fale foi ua ta'ua ai lo'u igoa ua avea ea lea ma ana o tagata faasaua i o outou manatu? Faauta mai,", "Is this house, which is called by my name,"], ["o a'u nei lava ua ou vaai atu i ai,", "become a den of robbers in your eyes? Behold,"], ["o loo fetalai mai ai Ieova.", "even I have seen it, saith the LORD."]]},
  {num:12,words:[["A ia outou o i le mea sa a'u i ai i Sailo,", "But go ye now unto my place which was in Shiloh,"], ["na ou tuu ai lo'u igoa i le amataga,", "where I set my name at the first,"], ["ma ia outou matamata i mea na ou fai i ai ona o le amio leaga a lo'u nuu o Isaraelu.", "and see what I did to it for the wickedness of my people Israel."]]},
  {num:13,words:[["O lenei,", "And now,"], ["ua outou faia ia mea uma,", "because ye have done all these works,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["ua ou tautala atu foi ia te outou,", "and I spake unto you,"], ["na ou ala tautala atu lava,", "rising up early and speaking,"], ["a ua outou le faalogo mai;", "but ye heard not;"], ["na ou valaau atu foi ia te outou,", "and I called you,"], ["a ua outou le tali mai ai;", "but ye answered not;"]]},
  {num:14,words:[["o le mea lea ou te fai ai i le fale ua ta'ua ai lo'u igoa,", "Therefore will I do unto this house,"], ["o le fale ua outou faatuatua i ai,", "which is called by my name,"], ["ma le nuu ua ou foaiina atu ia te outou ma o outou tamā,", "wherein ye trust, and unto the place which I gave to you and to your fathers,"], ["e pei ona ou faia i Sailo.", "as I have done to Shiloh."]]},
  {num:15,words:[["Ou te lafoai foi ia te ia outou i o'u luma,", "And I will cast you out of my sight,"], ["e pei ona ou lafoaiina o outou uso uma,", "as I have cast out all your brethren,"], ["o le fanauga uma a Efaraima.", "even the whole seed of Ephraim."]]},
  {num:16,words:[["O oe na foi, aua e te faatoga mai mo lenei nuu,", "Therefore pray not thou for this people,"], ["aua foi e te faia se auega,", "neither lift up cry nor prayer for them,"], ["po o se faatoga mo i latou,", "neither make intercession to me:"], ["aua e te fautua mai ia te au; auā ou te le faalogo lava ia te oe.", "for I will not hear thee."]]},
  {num:17,words:[["Ua e iloa atu ea mea ua latou faia i aai o Iuta, ma ala o Ierusalema?", "Seest thou not what they do in the cities of Judah and in the streets of Jerusalem?"]]},
  {num:18,words:[["Ua fai fafie e le fanau,", "The children gather wood,"], ["ua tafu le afi e o latou tamā,", "and the fathers kindle the fire,"], ["ua lomi le paluga falaoa e fafine e fai a'i faapapā areto mā le tupu fafine o le lagi,", "and the women knead their dough, to make cakes to the queen of heaven,"], ["ua liligi foi taulaga i mea e inu i atua ese,", "and to pour out drink offerings unto other gods,"], ["ina ia latou faaonoono mai ai ia te au.", "that they may provoke me to anger."]]},
  {num:19,words:[["O a'u ea ua latou faaonoono i ai? o loo fetalai mai ai Ieova; e le o i latou lava ea,", "Do they provoke me to anger? saith the LORD:"], ["ina ia masiasi ai i latou?", "do they not provoke themselves to the confusion of their own faces?"]]},
  {num:20,words:[["O le mea lea o loo faapea ona fetalai mai ai o le Alii o Ieova,", "Therefore thus saith the Lord GOD;"], ["Faauta,", "Behold,"], ["ou te liligi ifo i luga o lenei mea lo'u ita ma lo'u tiga,", "mine anger and my fury shall be poured out upon this place,"], ["i luga o tagata,", "upon man,"], ["ma luga o manu,", "and upon beast,"], ["i luga foi o laau i le fanua,", "and upon the trees of the field,"], ["ma le fua o le laueleele;", "and upon the fruit of the ground;"], ["e mu ai,", "and it shall burn,"], ["a e le tineia lava.", "and shall not be quenched."]]},
  {num:21,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["o le Atua o Isaraelu,", "the God of Israel;"], ["Ia outou faaopoopo a outou taulaga mu i a outou taulaga,", "Put your burnt offerings unto your sacrifices,"], ["ma ia outou aai i tufaaga.", "and eat flesh."]]},
  {num:22,words:[["Auā na ou le fai atu i o outou tamā,", "For I spake not unto your fathers,"], ["ma a'u le poloai atu ia te i latou i le aso na ou au mai ai ia te i latou ai le nuu o Aikupito,", "nor commanded them in the day that I brought them out of the land of Egypt,"], ["se upu i taulaga mu ma taulaga.", "concerning burnt offerings or sacrifices:"]]},
  {num:23,words:[["A o le mea lava lenei na ou poloai atu ai ia te i latou,", "But this thing commanded I them,"], ["ua faapea atu,", "saying,"], ["Ia outou faalogo mai i lo'u leo,", "Obey my voice,"], ["ona fai ai lea o a'u mo outou Atua,", "and I will be your God,"], ["e fai foi outou mo'u nuu;", "and ye shall be my people:"], ["ma ia outou savavali i le ala uma na ou poloai atu ai ia te outou,", "and walk ye in all the ways that I have commanded you,"], ["ina ia manuia ai outou.", "that it may be well unto you."]]},
  {num:24,words:[["A ua latou le faalogo mai,", "But they hearkened not,"], ["ma ua le uai mai o latou taliga,", "nor inclined their ear,"], ["a ua latou savavali i mafaufauga ma le finau vale o latou loto leaga,", "but walked in the counsels and in the imagination of their evil heart,"], ["ua latou tuumuli i tua,", "and went backward,"], ["a ua le savavali i luma.", "and not forward."]]},
  {num:25,words:[["Talu le aso na o mai ai o outou tamā ai le nuu o Aikupito, e oo i le aso nei,", "Since the day that your fathers came forth out of the land of Egypt unto this day I have even sent unto you all my servants the prophets,"], ["na ou aauina atu ai ia te outou a'u auauna uma o perofeta, na ou ala aauina atu i latou i lea aso ma lea aso;", "daily rising up early and sending them:"]]},
  {num:26,words:[["a ua latou le faalogo mai ia te au,", "Yet they hearkened not unto me,"], ["ma ua le uai mai o latou taliga,", "nor inclined their ear,"], ["a ua latou faamaaa o latou ua;", "but hardened their neck:"], ["ua amio leaga i latou e sili i o latou tamā.", "they did worse than their fathers."]]},
  {num:27,words:[["E te fai atu lava ia upu uma ia te i latou,", "Therefore thou shalt speak all these words unto them;"], ["a e latou te le faalogo mai ia te oe;", "but they will not hearken to thee:"], ["e te valaau atu foi ia te i latou,", "thou shalt also call unto them;"], ["a e latou te le tali mai ia te oe.", "but they will not answer thee."]]},
  {num:28,words:[["A ia e fai atu ia te i latou,", "But thou shalt say unto them,"], ["O le nuu lava lenei ua le faalogo mai i le leo o Ieova lo latou Atua;", "This is a nation that obeyeth not the voice of the LORD their God,"], ["ua le talia foi e i latou le aoaiga;", "nor receiveth correction:"], ["ua fano le faamaoni,", "truth is perished,"], ["ma ua te'a lava i o latou gutu.", "and is cut off from their mouth."]]},
  {num:29,words:[["Ina sele mamā ia lou lauulu,", "Cut off thine hair,"], ["ma lafoai,", "O Jerusalem,"], ["ma ia e faia i mauga tula le pese e aualofa a'i;", "and cast it away, and take up a lamentation on high places;"], ["auā ua teena e Ieova ma lafoaiina le tupulaga ua ia toasa i ai.", "for the LORD hath rejected and forsaken the generation of his wrath."]]},
  {num:30,words:[["Auā ua faia le mea leaga e le fanauga a Iuta i o'u luma,", "For the children of Judah have done evil in my sight,"], ["o loo fetalai mai ai Ieova;", "saith the LORD:"], ["ua tuuina e i latou a latou mea e inosia i le fale ua ta'ua ai lo'u igoa,", "they have set their abominations in the house which is called by my name,"], ["ina ia latou faaleagaina ai.", "to pollute it."]]},
  {num:31,words:[["Ua faia foi e i latou mea maualuluga i Tofeta,", "And they have built the high places of Tophet,"], ["ua i le vanu o le atalii o Hinoma,", "which is in the valley of the son of Hinnom,"], ["e susunu ai o latou atalii ma o latou afafine i le afi;", "to burn their sons and their daughters in the fire;"], ["o le mea ou te lei poloai atu ai,", "which I commanded them not,"], ["ou te lei manatu foi i ai.", "neither came it into my heart."]]},
  {num:32,words:[["O le mea lea,", "Therefore,"], ["faauta,", "behold,"], ["o le a oo mai ai ona po,", "the days come,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["e le toe igoa ai lea mea o Tofeta,", "that it shall no more be called Tophet, nor the valley of the son of Hinnom,"], ["po o le vanu o le atalii o Hinoma,", "but the valley of slaughter:"], ["a o le vanu o le fasi;", "for they shall bury in Tophet,"], ["latou te tanumia foi i Tofeta seia le toe ofi.", "till there be no place."]]},
  {num:33,words:[["E fai foi tino ua oti o lenei nuu ma mea e 'ai a manu felelei ma manu e tataa;", "And the carcases of this people shall be meat for the fowls of the heaven, and for the beasts of the earth;"], ["e leai foi se na te tulia.", "and none shall fray them away."]]},
  {num:34,words:[["Ou te faaiuina foi i aai o Iuta ma ala o Ierusalema le leo fiafia ma le leo olioli,", "Then will I cause to cease from the cities of Judah, and from the streets of Jerusalem,"], ["o le leo o le faatoafaiavā ma le leo o le faatoanofotane;", "the voice of mirth, and the voice of gladness, the voice of the bridegroom,"], ["auā e fai ma faatafunaga lenei nuu.", "and the voice of the bride: for the land shall be desolate."]]},
];
renderVerseSet(jer_ch_7_Verses, 'jer-ch7-verses');

var jer_ch_8_Verses = [
  {num:1,words:[["O loo fetalai mai Ieova,", "At that time,"], ["O ia ona po e au mai ai ivi o tupu o Iuta,", "saith the LORD, they shall bring out the bones of the kings of Judah,"], ["ma ivi o ona alii,", "and the bones of his princes,"], ["ma ivi o faitaulaga,", "and the bones of the priests,"], ["ma ivi o perofeta,", "and the bones of the prophets, and the bones of the inhabitants of Jerusalem,"], ["ma ivi o e nonofo i Ierusalema ai o latou tuugamau;", "out of their graves:"]]},
  {num:2,words:[["latou te folasia ai foi i le la,", "And they shall spread them before the sun,"], ["ma le masina,", "and the moon,"], ["ma 'au uma a le lagi,", "and all the host of heaven,"], ["o mea na latou loto i ai,", "whom they have loved,"], ["ma latou auauna i ai,", "and whom they have served,"], ["ma latou mulimuli atu i ai,", "and after whom they have walked,"], ["ma latou sailiili i ai,", "and whom they have sought,"], ["ma latou ifo i ai;", "and whom they have worshipped:"], ["e le aofia ia ivi ,", "they shall not be gathered,"], ["e le tanumia foi,", "nor be buried;"], ["a e fai ma otaota i luga o le laueleele.", "they shall be for dung upon the face of the earth."]]},
  {num:3,words:[["E sili le fia oti i le fia ola i e totoe uma,", "And death shall be chosen rather than life by all the residue of them that remain of this evil family,"], ["o e totoe o lenei aiga leaga, o e totoe i mea uma o le a ou tulia ai i latou,", "which remain in all the places whither I have driven them,"], ["o loo fetalai mai ai Ieova o 'au.", "saith the LORD of hosts."]]},
  {num:4,words:[["Ia e fai atu foi ia te i latou,", "Moreover thou shalt say unto them,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Latou te pauu ea,", "Shall they fall,"], ["a e le toe tutū mai? E liliu ese ea o ia,", "and not arise? shall he turn away,"], ["a e le toe liliu mai?", "and not return?"]]},
  {num:5,words:[["Se a ea le mea ua liliu ese ai lenei nuu o Ierusalema ma le liliu ese e le aunoa? Ua latou taofi mau i mea pepelo,", "Why then is this people of Jerusalem slidden back by a perpetual backsliding? they hold fast deceit,"], ["ma latou le mafafai ona toe liliu mai.", "they refuse to return."]]},
  {num:6,words:[["Ua liliu atu o'u taliga ,", "I hearkened and heard,"], ["ma ou faalogologo atu;", "but they spake not aright:"], ["ua latou le tautala faamaoni; e leai se tagata ua salamo i lana amio leaga,", "no man repented him of his wickedness,"], ["ua faapea mai,", "saying,"], ["Se a le mea ua ou faia? Ua latou taitasi ma liliu atu i o latou taufetuliga,", "What have I done? every one turned to his course,"], ["e pei ona oso atu o le solofanua i le taua.", "as the horse rusheth into the battle."]]},
  {num:7,words:[["Ua iloa e le kasita i le lagi ona lava po; o le manutagi foi,", "Yea,"], ["ma le pe'ape'a,", "the stork in the heaven knoweth her appointed times;"], ["ma le akuru,", "and the turtle and the crane and the swallow observe the time of their coming;"], ["ua latou tausia le tau latou te o mai ai; a ua le iloa e lo'u nuu le faamasinoga a Ieova.", "but my people know not the judgment of the LORD."]]},
  {num:8,words:[["Pe faapefea ona outou fai mai,", "How do ye say,"], ["Ua popoto i matou,", "We are wise,"], ["ua ia te i matou foi le tulafono a Ieova? Faauta, e moni,", "and the law of the LORD is with us? Lo,"], ["ua na faia fua lava;", "certainly in vain made he it;"], ["o le peni a e tusiupu ua fai fua lea .", "the pen of the scribes is in vain."]]},
  {num:9,words:[["Ua faamāina ē popoto,", "The wise men are ashamed,"], ["ua matatau i latou,", "they are dismayed and taken:"], ["ma ua maua; faauta,", "lo,"], ["ua latou lafoai le afioga a Ieova;", "they have rejected the word of the LORD;"], ["se a foi se poto ua ia te i latou?", "and what wisdom is in them?"]]},
  {num:10,words:[["O le mea lea ou te avatu ai a latou avā i nisi,", "Therefore will I give their wives unto others,"], ["ma o latou fanua i e latou te tulia i latou;", "and their fields to them that shall inherit them:"], ["auā o tagatānuu atoa ma alii ua matapeapea i oloa i latou uma,", "for every one from the least even unto the greatest is given to covetousness,"], ["o perofeta atoa ma ositaulaga ua amio pepelo i latou uma.", "from the prophet even unto the priest every one dealeth falsely."]]},
  {num:11,words:[["Ua latou fofo faatauvaa le manua o le tama fafine a lo'u nuu,", "For they have healed the hurt of the daughter of my people slightly,"], ["ua faapea ane,", "saying,"], ["E manuia,", "Peace,"], ["e manuia;", "peace;"], ["a e leai se manuia.", "when there is no peace."]]},
  {num:12,words:[["Ua latou mamā ea ona o le mea inosia ua latou faia? ua matuā le mamā lava i latou,", "Were they ashamed when they had committed abomination? nay,"], ["ua latou le iloa lava le masiasi;", "they were not at all ashamed,"], ["o le mea lea e pauu ai i latou faatasi ma e ua pauu;", "neither could they blush: therefore shall they fall among them that fall:"], ["o ona po e asiasia ai i latou latou te tausuai ai,", "in the time of their visitation they shall be cast down,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:13,words:[["Ou te matuā faaumatia i latou,", "I will surely consume them,"], ["ua fetalai mai ai Ieova;", "saith the LORD:"], ["e leai ni fuifui i le vine,", "there shall be no grapes on the vine,"], ["e leai foi ni mati i le mati,", "nor figs on the fig tree,"], ["e mamae foi lau;", "and the leaf shall fade;"], ["o mea foi na ou foaiina atu ia te i latou e mavae ese ia ia te i latou.", "and the things that I have given them shall pass away from them."]]},
  {num:14,words:[["Se a ea le mea ua tatou nofonofo ai? Ia outou potopoto,", "Why do we sit still? assemble yourselves,"], ["ma tatou o i aai nofo 'olo,", "and let us enter into the defenced cities,"], ["ma tatou nofo faalologo ai;", "and let us be silent there:"], ["auā o Ieova lo tatou Atua ua faalologo ai i tatou,", "for the LORD our God hath put us to silence,"], ["ua na faainumia foi i tatou i le vai oona,", "and given us water of gall to drink,"], ["auā ua tatou agasala ia Ieova.", "because we have sinned against the LORD."]]},
  {num:15,words:[["Sa tatou faatalitali i le manuia,", "We looked for peace,"], ["a e leai se lelei na maua;", "but no good came;"], ["sa faatalitali foi i ona po e faamaloloina ai, faauta foi,", "and for a time of health,"], ["o le mata'u.", "and behold trouble!"]]},
  {num:16,words:[["Ua lagona mai i Tanu le faafogifogi o ona solofanua;", "The snorting of his horses was heard from Dan:"], ["o le leo o le tagi o ona solofanua malolosi ua gatete ai le laueleele uma;", "the whole land trembled at the sound of the neighing of his strong ones;"], ["ua oo mai foi i latou,", "for they are come,"], ["ua latou faaumatia le nuu,", "and have devoured the land,"], ["ma mea ua tumu ai,", "and all that is in it;"], ["o le aai foi,", "the city,"], ["ma e nonofo ai.", "and those that dwell therein."]]},
  {num:17,words:[["Auā faauta,", "For,"], ["ou te aauina atu ia te outou o gata,", "behold, I will send serpents,"], ["o gata uogo,", "cockatrices,"], ["e le mafai ona faaoleoleina i latou,", "among you,"], ["latou te feutia outou,", "which will not be charmed, and they shall bite you,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:18,words:[["Ua fai lo'u olioli ma faanoanoa i totonu ia te au,", "When I would comfort myself against sorrow,"], ["ua vaivai lo'u loto i totonu ia te au.", "my heart is faint in me."]]},
  {num:19,words:[["Faauta,", "Behold the voice of the cry of the daughter of my people because of them that dwell in a far country:"], ["o le leo o le alaga o le tama fafine a lo'u nuu ai nuu mamao. E le o i Siona ea Ieova? e le o i ai ea lona Tupu? Se a ea le mea ua latou faaonoono mai ai ia te au i a latou tupua ua te,", "Is not the LORD in Zion? is not her king in her? Why have they provoked me to anger with their graven images,"], ["ma mea ese e faatauvaa?", "and with strange vanities?"]]},
  {num:20,words:[["Ua mavae ona po o le seleselegāsaito,", "The harvest is past,"], ["ua uma le tausaga vevela,", "the summer is ended,"], ["a e le faaolaina i tatou.", "and we are not saved."]]},
  {num:21,words:[["Ua momomo lo'u loto ona ua tu'imomoia o le tama fafine a lo'u nuu;", "For the hurt of the daughter of my people am I hurt;"], ["ua ou faanoanoa;", "I am black;"], ["ua maua a'u i le fememeai.", "astonishment hath taken hold on me."]]},
  {num:22,words:[["E leai ea ni pulu pasama i Kiliata? e le o i ai ea se fomai? Se a foi le mea ua le faamaloloina ai le tama fafine a lo'u nuu?", "Is there no balm in Gilead; is there no physician there? why then is not the health of the daughter of my people recovered?"]]},
];
renderVerseSet(jer_ch_8_Verses, 'jer-ch8-verses');

var jer_ch_9_Verses = [
  {num:1,words:[["E! fia liua lo'u ulu ma suāvai,", "Oh that my head were waters,"], ["ma o'u mata ma punaloimata,", "and mine eyes a fountain of tears,"], ["ina ia ou tagi i le ao ma le po ona o e ua fasiotia o le tama fafine a lo'u nuu.", "that I might weep day and night for the slain of the daughter of my people!"]]},
  {num:2,words:[["E! ta fia maua i le vao se fale apitaga e api ai malaga;", "Oh that I had in the wilderness a lodging place of wayfaring men;"], ["ina ia ou tuua lo'u nuu,", "that I might leave my people,"], ["ma alu ese ai; auā o tagata mulilulua i latou uma,", "and go from them! for they be all adulterers,"], ["o le faapotopotoga o tagata faa'ole'ole.", "an assembly of treacherous men."]]},
  {num:3,words:[["Ua latou lolo'u o latou laulaufaiva e pei o latou aufana,", "And they bend their tongues like their bow for lies:"], ["e tala pepelo ai;", "but they are not valiant for the truth upon the earth;"], ["latou te le totoa i fai mea faamaoni i le nuu; auā ua alualu la latou amio leaga,", "for they proceed from evil to evil,"], ["ma latou le iloa a'u,", "and they know not me,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:4,words:[["Ia outou taitasi ma faaeteete o ia ia te ia i lana uo,", "Take ye heed every one of his neighbour,"], ["aua foi ne'i faatuatua i se uso e tasi;", "and trust ye not in any brother:"], ["auā o uso uma e taitoatasi ma matuā sisio i lona uso ,", "for every brother will utterly supplant,"], ["ma uo uma e taitasi ma fealualuai ma feaveaveai.", "and every neighbour will walk with slanders."]]},
  {num:5,words:[["E taitoatasi i latou ma pepelo i lana uo,", "And they will deceive every one his neighbour,"], ["e le tautala foi i latou ma le faamaoni;", "and will not speak the truth:"], ["ua latou faamasani o latou laulaufaiva i tautala pepelo,", "they have taught their tongue to speak lies,"], ["ua tautiga i latou i fai mea faapiopio.", "and weary themselves to commit iniquity."]]},
  {num:6,words:[["O le mea e te nofo ai o loo i totonu o le nuu faa'ole'ole lea;", "Thine habitation is in the midst of deceit;"], ["o le faa'ole'ole latou te le mafafai ai ona iloa o a'u,", "through deceit they refuse to know me,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:7,words:[["O le mea lea,", "Therefore thus saith the LORD of hosts,"], ["o loo faapea ona fetalai mai ai o Ieova o 'au,", "Behold,"], ["Faauta, ou te suesue ia te i latou,", "I will melt them,"], ["ma tofotofo ia te i latou;", "and try them;"], ["auā pe se a se isi mea ou te faia i le tama fafine a lo'u nuu?", "for how shall I do for the daughter of my people?"]]},
  {num:8,words:[["O latou laulaufaiva o u fanafana ia e oti ai;", "Their tongue is as an arrow shot out;"], ["e tautalatala faa'ole'ole;", "it speaketh deceit:"], ["e taitasi ma tautala ma le filemu i lana uo i lona gutu,", "one speaketh peaceably to his neighbour with his mouth,"], ["a o lona loto ua lamalama ia te ia .", "but in heart he layeth his wait."]]},
  {num:9,words:[["Ou te le taui atu ea ia te i latou ona o ia mea;", "Shall I not visit them for these things? saith the LORD:"], ["o loo fetalai mai ai Ieova. E le taui atu ea ma sui e lo'u agaga i le nuu faapena?", "shall not my soul be avenged on such a nation as this?"]]},
  {num:10,words:[["Ona o le atu mauga ou te faia le tagi ma le auega,", "For the mountains will I take up a weeping and wailing,"], ["o le pese foi e aualofa a'i ona o mea i le vao o tataa ai manu,", "and for the habitations of the wilderness a lamentation,"], ["auā ua susunuina,", "because they are burned up,"], ["ua le uia e tagata;", "so that none can pass through them;"], ["e le lagona ai le leo o manu;", "neither can men hear the voice of the cattle;"], ["ua sosola manu felelei atoa ma manu vaefa,", "both the fowl of the heavens and the beast are fled;"], ["ua latou o.", "they are gone."]]},
  {num:11,words:[["Ou te faia foi Ierusalema ma faupuegāmaa,", "And I will make Jerusalem heaps,"], ["o le mea e fale ai tanimo;", "and a den of dragons;"], ["ou te faatafunaina lava aai o Iuta,", "and I will make the cities of Judah desolate,"], ["e le nofo ai se tasi.", "without an inhabitant."]]},
  {num:12,words:[["Po o ai le tagata poto,", "Who is the wise man,"], ["ia lagona e ia lenei mea? po o ai foi ua fetalai mai ia te ia le fofoga o Ieova,", "that may understand this? and who is he to whom the mouth of the LORD hath spoken,"], ["ia na faailoa mai ai le mea ua faaumatia ai le laueleele,", "that he may declare it,"], ["ua susunuina e pei o le vao,", "for what the land perisheth and is burned up like a wilderness,"], ["ua le uia e se tasi?", "that none passeth through?"]]},
  {num:13,words:[["Ua fetalai mai foi Ieova,", "And the LORD saith,"], ["Ua latou lafoaiina la'u tulafono na ou tuuina atu i o latou uma,", "Because they have forsaken my law which I set before them,"], ["ma latou le faalogo i lo'u leo,", "and have not obeyed my voice,"], ["ma latou le savavali i ai;", "neither walked therein;"]]},
  {num:14,words:[["a ua latou mulimuli atu i o latou loto finau vale,", "But have walked after the imagination of their own heart,"], ["atoa ma Paala,", "and after Baalim,"], ["na a'oa'oina ai i latou e o latou tamā;", "which their fathers taught them:"]]},
  {num:15,words:[["o le mea lea,", "Therefore thus saith the LORD of hosts,"], ["o loo faapea ona fetalai mai ai o Ieova o 'au,", "the God of Israel;"], ["le Atua o Isaraelu,", "Behold,"], ["Faauta, ou te fafaga ia te i latou,", "I will feed them,"], ["o lenei lava nuu,", "even this people,"], ["i le laena,", "with wormwood,"], ["ma faainumia i latou i le vai oona.", "and give them water of gall to drink."]]},
  {num:16,words:[["Ou te faataapeapeina i latou i nuu ese na le iloa e i latou,", "I will scatter them also among the heathen,"], ["po o latou tamā;", "whom neither they nor their fathers have known:"], ["ou te auina atu foi le pelu e mulimuli ia te i latou,", "and I will send a sword after them,"], ["seia ou faaumatia i latou.", "till I have consumed them."]]},
  {num:17,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["Ina mafaufau ia outou,", "Consider ye,"], ["ma ia outou aami atu i fafine pepese,", "and call for the mourning women,"], ["ina ia latou o mai,", "that they may come;"], ["ma ia outou feauina atu i fafine popoto,", "and send for cunning women,"], ["ina ia o mai foi i latou;", "that they may come:"]]},
  {num:18,words:[["ia latou faataalise mai,", "And let them make haste,"], ["ma ia latou lagi le pese e aualofa a'i mo i tatou,", "and take up a wailing for us,"], ["ia tafe ifo loimata i o tatou mata,", "that our eyes may run down with tears,"], ["ma ia maligi ifo le suāvai i o tatou laumata.", "and our eyelids gush out with waters."]]},
  {num:19,words:[["Auā ua lagona atu le leo o le auega i Siona,", "For a voice of wailing is heard out of Zion,"], ["E,", "How are we spoiled! we are greatly confounded,"], ["ua faatafunaina i tatou! ua matuā mā lava i tatou, auā ua tuua e i tatou lo tatou laueleele,", "because we have forsaken the land,"], ["auā ua latou lepetia o tatou fale.", "because our dwellings have cast us out."]]},
  {num:20,words:[["O lenei,", "Yet hear the word of the LORD,"], ["o outou fafine,", "O ye women,"], ["ina faalogologo mai ia i le afioga a Ieova, ia lagona e o outou taliga le upu mai lona fofoga,", "and let your ear receive the word of his mouth,"], ["ma ia outou a'oa'o atu i a outou tama fafine se fatu,", "and teach your daughters wailing,"], ["ia taitasi foi ma a'oa'o atu i lana uo se pese e aualofa a'i.", "and every one her neighbour lamentation."]]},
  {num:21,words:[["Auā ua alu ae le oti i o tatou faamalama,", "For death is come up into our windows,"], ["ua ulufale mai i o tatou maota,", "and is entered into our palaces,"], ["e fano ai tama iti i le ala,", "to cut off the children from without,"], ["ma taulelea i malae.", "and the young men from the streets."]]},
  {num:22,words:[["Ina fai atu ia,", "Speak,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["E pauu tino o tagata oti, e pei o otaota i luga o le laueleele,", "Even the carcases of men shall fall as dung upon the open field,"], ["e pei o le fusi saito foi i tua o lē selesele,", "and as the handful after the harvestman,"], ["a e leai se na te faaputuina.", "and none shall gather them."]]},
  {num:23,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Aua ne'i mitamita le tagata poto i lona poto,", "Let not the wise man glory in his wisdom,"], ["aua ne'i mitamita le tagata malosi i lona malosi,", "neither let the mighty man glory in his might,"], ["aua ne'i mitamita foi le mauoa i ana oloa;", "let not the rich man glory in his riches:"]]},
  {num:24,words:[["a o lē mitamita,", "But let him that glorieth glory in this,"], ["ina mitamita ia o ia i lenei mea,", "that he understandeth and knoweth me,"], ["ina ua mafaufau o ia, ma ua iloa a'u,", "that I am the LORD which exercise lovingkindness,"], ["o a'u lava o Ieova,", "judgment,"], ["o lē faia le alofa,", "and righteousness,"], ["ma le faamasinoga, ma le amiotonu i le lalolagi;", "in the earth:"], ["auā o mea ia ou te fiafia i ai,", "for in these things I delight,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:25,words:[["Faauta,", "Behold,"], ["e oo mai ona po,", "the days come,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["ou te taui atu ai ia te i latou uma o e ua peritomeina faatasi ma e ua le peritomeina;", "that I will punish all them which are circumcised with the uncircumcised;"]]},
  {num:26,words:[["o Aikupito,", "Egypt,"], ["ma Iuta,", "and Judah,"], ["ma Etoma,", "and Edom,"], ["ma le fanauga a Amoni,", "and the children of Ammon,"], ["o Moapi foi,", "and Moab,"], ["ma i latou uma o e sala a latou pito 'ava ,", "and all that are in the utmost corners,"], ["o e nonofo i le vao;", "that dwell in the wilderness:"], ["auā o ia nuu uma ua le peritomeina,", "for all these nations are uncircumcised,"], ["ma le aiga uma o Isaraelu e lei peritomeina o latou loto.", "and all the house of Israel are uncircumcised in the heart."]]},
];
renderVerseSet(jer_ch_9_Verses, 'jer-ch9-verses');

var jer_ch_10_Verses = [
  {num:1,words:[["Ina faalogologo mai ia i le afioga ua fetalaia mai e Ieova ia te outou le aiga o Isaraelu;", "Hear ye the word which the LORD speaketh unto you, O house of Israel:"]]},
  {num:2,words:[["o loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Aua ne'i a'oa'o outou i tu a nuu ese,", "Learn not the way of the heathen,"], ["aua foi ne'i matatau i faailoga i le lagi;", "and be not dismayed at the signs of heaven;"], ["auā ua matatau i ai nuu ese.", "for the heathen are dismayed at them."]]},
  {num:3,words:[["Auā ua faatauvaa lava tu a nuu ese;", "For the customs of the people are vain:"], ["auā ua ta e se tasi le laau i le vao,", "for one cutteth a tree out of the forest, the work of the hands of the workman,"], ["o le galuega a lima o le tufuga e fai i le mătau.", "with the axe."]]},
  {num:4,words:[["Ua latou faamatagofieina i ario ma auro,", "They deck it with silver and with gold;"], ["ma latou faamauina ai i fao ma samala,", "they fasten it with nails and with hammers,"], ["ina ia le gaoioi.", "that it move not."]]},
  {num:5,words:[["E pei o le pama ua togitogi faamamanuina ia mea;", "They are upright as the palm tree,"], ["latou te le tautala foi;", "but speak not:"], ["e tauave i latou,", "they must needs be borne,"], ["auā latou te le mafai ona savavali. Aua tou te fefefe ia te i latou;", "because they cannot go. Be not afraid of them;"], ["auā latou te le mafai ona agaleaga mai,", "for they cannot do evil,"], ["e le mafai foi ona agalelei mai.", "neither also is it in them to do good."]]},
  {num:6,words:[["E leai lava sē tusa ma oe,", "Forasmuch as there is none like unto thee,"], ["Ieova e;", "O LORD;"], ["e sili lava oe,", "thou art great,"], ["ma lou suafa e sili lea ona malosi.", "and thy name is great in might."]]},
  {num:7,words:[["O ai ea se le mata'u ia te oe,", "Who would not fear thee,"], ["le Tupu o nuu e? Auā e ono lea ia te oe;", "O King of nations? for to thee doth it appertain:"], ["auā e leai sē tusa ma oe i e popoto uma i nuu,", "forasmuch as among all the wise men of the nations, and in all their kingdoms,"], ["ma o latou malo uma.", "there is none like unto thee."]]},
  {num:8,words:[["A e peitai ua valelea i latou uma, o vale lava;", "But they are altogether brutish and foolish:"], ["o le ogālaau o ia lava le aoai atu i mea faatauvaa.", "the stock is a doctrine of vanities."]]},
  {num:9,words:[["Ua aumaia mai Tasesa le ario ua faasalafalafaina,", "Silver spread into plates is brought from Tarshish,"], ["ma le auro mai Upasa,", "and gold from Uphaz,"], ["o le galuega a le tufuga,", "the work of the workman,"], ["o le galuega foi a lima o le tufuga fai mea uamea;", "and of the hands of the founder:"], ["o le ie uli ma le pāuli ua oofu ai;", "blue and purple is their clothing:"], ["o galuega a e popoto ia mea uma lava.", "they are all the work of cunning men."]]},
  {num:10,words:[["A o Ieova o le Atua moni ia,", "But the LORD is the true God,"], ["o ia lava le Atua soifua,", "he is the living God,"], ["ma le Tupu e faavavau;", "and an everlasting king:"], ["o lona toasa e gatete ai le lalolagi,", "at his wrath the earth shall tremble,"], ["e le lavā foi e nuu ona tali o lona toatamai.", "and the nations shall not be able to abide his indignation."]]},
  {num:11,words:[["Ia faapea ona outou fai atu ia te i latou,", "Thus shall ye say unto them,"], ["O atua na le faia le lagi ma le lalolagi,", "The gods that have not made the heavens and the earth, even they shall perish from the earth,"], ["e fano i latou i le lalolagi ma lalo foi o lena lagi.", "and from under these heavens."]]},
  {num:12,words:[["Na faia e ia le lalolagi i lona mana,", "He hath made the earth by his power,"], ["na faatumauina e ia le atu laulau i lona poto,", "he hath established the world by his wisdom,"], ["na fofolaina foi e ia le lagi i lona faautauta.", "and hath stretched out the heavens by his discretion."]]},
  {num:13,words:[["Ua tŭlei mai lona siufofoga,", "When he uttereth his voice,"], ["ona tele ai lea o le vai i le lagi;", "there is a multitude of waters in the heavens,"], ["e avae foi e ia o le ausa mai tuluiga o le lalolagi;", "and he causeth the vapours to ascend from the ends of the earth;"], ["e faia e ia le uila atoa ma le ua,", "he maketh lightnings with rain,"], ["e aumaia foi e ia le matagi mai ana mea e teu ai oloa.", "and bringeth forth the wind out of his treasures."]]},
  {num:14,words:[["Ua taitasi ma valea tagata uma e leai so latou poto;", "Every man is brutish in his knowledge:"], ["ua taitasi ma faamaina foi tufuga fai mea uamea ona o le tupua ua ta;", "every founder is confounded by the graven image:"], ["auā o le mea pepelo lana tupua uamea,", "for his molten image is falsehood,"], ["e leai foi se mānava ia te i latou.", "and there is no breath in them."]]},
  {num:15,words:[["E faatauvaa ia mea,", "They are vanity,"], ["o le galuega e tauemua;", "and the work of errors:"], ["e fano lava i latou i ona po e tauia ai i latou.", "in the time of their visitation they shall perish."]]},
  {num:16,words:[["E le pei o ia mea le tofi o Iakopo;", "The portion of Jacob is not like them:"], ["auā o ia lava na faia mea uma;", "for he is the former of all things;"], ["o Isaraelu foi o le tootoo lea o lona tofi;", "and Israel is the rod of his inheritance:"], ["o Ieova o 'au o lona suafa lea.", "The LORD of hosts is his name."]]},
  {num:17,words:[["Ina faapotopotoina ia o au mea mai le nuu,", "Gather up thy wares out of the land,"], ["o oe na lē nofo i le 'olo.", "O inhabitant of the fortress."]]},
  {num:18,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD,"], ["Faauta,", "Behold,"], ["o ona po nei lava,", "I will sling out the inhabitants of the land at this once,"], ["ou te sasau ai i le maata e o nonofo i le nuu,", "and will distress them,"], ["ma ou siosio ia te i latou ina ia maua i latou.", "that they may find it so."]]},
  {num:19,words:[["Oi talofa ia te au i lo'u manua; e matuā leaga lo'u manua;", "Woe is me for my hurt! my wound is grievous:"], ["o a'u foi, na ou faapea ane,", "but I said,"], ["E moni,", "Truly this is a grief,"], ["o le puapuaga lava lenei, a e ou te faatoatoa pea i ai.", "and I must bear it."]]},
  {num:20,words:[["Ua faatafunaina lo'u fale ie,", "My tabernacle is spoiled,"], ["ua motusia a'u maea uma,", "and all my cords are broken:"], ["ua o ese la'u fanau ia te au,", "my children are gone forth of me,"], ["o i latou foi ua leai;", "and they are not:"], ["e leai foi se tasi na te toe toina lo'u fale ie,", "there is none to stretch forth my tent any more,"], ["ma avae o'u ie puipui.", "and to set up my curtains."]]},
  {num:21,words:[["Auā ua valelea le au leoleo mamoe,", "For the pastors are become brutish,"], ["ma latou le saili ia Ieova;", "and have not sought the LORD:"], ["o le mea lea e le manuia ai i latou,", "therefore they shall not prosper,"], ["e faataapeapeaina foi ia latou lafu mamoe uma.", "and all their flocks shall be scattered."]]},
  {num:22,words:[["O le logo o le tala,", "Behold,"], ["faauta,", "the noise of the bruit is come,"], ["ua oo mai, o le vāvāō tele foi mai le nuu i le itu i matu,", "and a great commotion out of the north country,"], ["e faia foi aai o Iuta ma mea e faatafunaina,", "to make the cities of Judah desolate,"], ["o le mea e fale ai luko.", "and a den of dragons."]]},
  {num:23,words:[["Ieova e,", "O LORD,"], ["ua ou iloa e le o i le tagata lona ala,", "I know that the way of man is not in himself:"], ["e le o i le tagata e savali ona faatonuina le mea e ui ai o ia.", "it is not in man that walketh to direct his steps."]]},
  {num:24,words:[["Ieova e,", "O LORD,"], ["ia e aoai mai ia te au,", "correct me,"], ["tau lava ina faia ma le faatatau;", "but with judgment;"], ["a e aua ma lou toasa,", "not in thine anger,"], ["ina ne'i e faatoaitiitia o a'u.", "lest thou bring me to nothing."]]},
  {num:25,words:[["Ia e sasaaina atu lou toasa i luga o atu nuu ua le iloa oe,", "Pour out thy fury upon the heathen that know thee not,"], ["i luga foi o aiga ua le valaau atu i lou suafa;", "and upon the families that call not on thy name:"], ["auā ua latou 'aina Iakopo,", "for they have eaten up Jacob,"], ["ua latou 'aina lava o ia,", "and devoured him,"], ["ma ua faaumatia o ia,", "and consumed him,"], ["ma le mea sa nofo ai o ia ua latou faatafunaina.", "and have made his habitation desolate."]]},
];
renderVerseSet(jer_ch_10_Verses, 'jer-ch10-verses');

var jer_ch_11_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova,", "The word that came to Jeremiah from the LORD,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Ina faalogologo mai ia outou i upu o lenei feagaiga,", "Hear ye the words of this covenant,"], ["ma ia outou fai atu ai i tagata o Iuta,", "and speak unto the men of Judah,"], ["ma e o nonofo i Ierusalema;", "and to the inhabitants of Jerusalem;"]]},
  {num:3,words:[["ma ia e fai atu ia te i latou,", "And say thou unto them,"], ["O loo faapea ona fetalai mai o Ieova le Atua o Isaraelu,", "Thus saith the LORD God of Israel;"], ["Ia malaia le tagata o le na te le faalogo i upu o lenei feagaiga,", "Cursed be the man that obeyeth not the words of this covenant,"]]},
  {num:4,words:[["na ou poloai atu ai i o outou tamā i le aso na ou au mai ai i latou mai le nuu o Aikupito,", "Which I commanded your fathers in the day that I brought them forth out of the land of Egypt,"], ["mai le ogāumu e tunu ai uamea,", "from the iron furnace,"], ["ua faapea atu,", "saying,"], ["Ina faalogo mai ia i lo'u leo,", "Obey my voice,"], ["ma ia outou faia ia mea,", "and do them,"], ["e tusa ma mea uma ua ou poloai atu ai ia te outou;", "according to all which I command you:"], ["na fai ai lea o outou mo'u nuu,", "so shall ye be my people,"], ["e fai foi a'u mo outou Atua;", "and I will be your God:"]]},
  {num:5,words:[["ina ia ou faataunuuina le tautoga,", "That I may perform the oath which I have sworn unto your fathers,"], ["na ou tauto ai i o outou tamā, e foai atu ia te i latou le nuu ua tafe ai le suāsusu ma le meli,", "to give them a land flowing with milk and honey,"], ["e pei ona fai i le aso nei.", "as it is this day."], ["Ona ou tali atu ai lea,", "Then answered I,"], ["ua faapea atu,", "and said,"], ["Ieova e,", "So be it,"], ["ina fai ia o lea.", "O LORD."]]},
  {num:6,words:[["Ona fetalai mai ai lea o Ieova ia te au,", "Then the LORD said unto me,"], ["Ina tala'i atu ia nei upu uma i aai o Iuta,", "Proclaim all these words in the cities of Judah,"], ["ma ala o Ierusalema,", "and in the streets of Jerusalem,"], ["ia faapea atu,", "saying,"], ["Ia outou faalogo i upu o lenei feagaiga,", "Hear ye the words of this covenant,"], ["ma ia outou faia.", "and do them."]]},
  {num:7,words:[["Auā na ou matuā fai atu i o outou tamā i le aso na ou aveina ae ai i latou mai le nuu o Aikupito,", "For I earnestly protested unto your fathers in the day that I brought them up out of the land of Egypt,"], ["ua oo lava i le aso nei,", "even unto this day,"], ["ua ou ala fai atu lava,", "rising early and protesting, saying,"], ["ua faapea atu. Ina faalogo mai ia i lo'u leo.", "Obey my voice."]]},
  {num:8,words:[["A ua latou le faalogo mai,", "Yet they obeyed not,"], ["ua le uai mai foi o latou taliga,", "nor inclined their ear,"], ["a ua latou taitasi ma savali e tusa ma le finau vale o latou loto leaga;", "but walked every one in the imagination of their evil heart: therefore I will bring upon them all the words of this covenant,"], ["o lea ua ou faaoo ai i luga ia te i latou o upu uma o lenei feagaiga na ou poloai atu ai ia latou faia;", "which I commanded them to do;"], ["a ua latou le faia lava.", "but they did them not."]]},
  {num:9,words:[["Ona fetalai mai lea o Ieova ia te au,", "And the LORD said unto me,"], ["Ua iloa le fouvale i tagata o Iuta,", "A conspiracy is found among the men of Judah,"], ["ma e o nonofo i Ierusalema.", "and among the inhabitants of Jerusalem."]]},
  {num:10,words:[["Ua latou liliu atu i amio leaga a o latou tamā anamua,", "They are turned back to the iniquities of their forefathers,"], ["o e na le mafafai ona faalogo i a'u upu;", "which refused to hear my words;"], ["ma ua latou mulimuli atu i atua ese e auauna ia te i latou;", "and they went after other gods to serve them:"], ["ua solia e le aiga o Isaraelu ma le aiga o Iuta la'u feagaiga na a'u osia ma o latou tamā.", "the house of Israel and the house of Judah have broken my covenant which I made with their fathers."]]},
  {num:11,words:[["O le mea lea,", "Therefore thus saith the LORD,"], ["o loo faapea ona fetalai mai ai o Ieova,", "Behold,"], ["Faauta, ou te faaoo le malaia ia te i latou,", "I will bring evil upon them,"], ["latou te le mafaia ona sao ai;", "which they shall not be able to escape;"], ["e ui lava ina latou alalaga mai ia te au,", "and though they shall cry unto me,"], ["ou te le faalogo lava ia te i latou.", "I will not hearken unto them."]]},
  {num:12,words:[["Ona o ai lea o aai o Iuta ma e o nonofo i Ierusalema,", "Then shall the cities of Judah and inhabitants of Jerusalem go,"], ["ma latou alalaga i atua na latou faamu i ai mea manogi;", "and cry unto the gods unto whom they offer incense:"], ["a e latou te le faaola lava ia te i latou i ona po o lo latou malaia.", "but they shall not save them at all in the time of their trouble."]]},
  {num:13,words:[["Auā Iuta e,", "For according to the number of thy cities were thy gods,"], ["o le tau aofai o ou aai o le tau aofai lea o ou atua;", "O Judah;"], ["ua outou faatuina foi fata faitaulaga mo le mea e masiasi ai, o fata faitaulaga lava e faamu ai mea manogi ia Paala,", "and according to the number of the streets of Jerusalem have ye set up altars to that shameful thing,"], ["e faatatau i le tau aofai o ala i Ierusalema.", "even altars to burn incense unto Baal."]]},
  {num:14,words:[["O oe na foi, aua e te faatoga mai mo lenei nuu,", "Therefore pray not thou for this people,"], ["aua foi e te faia se auega,", "neither lift up a cry or prayer for them:"], ["po o se faatoga mo i latou; auā ou te le faalogo ia te i latou i ona po latou te valaau mai ai ia te au ona o lo latou malaia.", "for I will not hear them in the time that they cry unto me for their trouble."]]},
  {num:15,words:[["O a mea e fai e la'u pele i lo'u fale,", "What hath my beloved to do in mine house,"], ["a o faia e ia amio leaga e tele? ua mavae foi le tufaaga paia ia te oe;", "seeing she hath wrought lewdness with many,"], ["a ē fai mea leaga,", "and the holy flesh is passed from thee? when thou doest evil,"], ["ona e fiafia ai lea.", "then thou rejoicest."]]},
  {num:16,words:[["Na faaigoa oe e Ieova,", "The LORD called thy name,"], ["O le olive lauolaola,", "A green olive tree,"], ["e matagofie,", "fair,"], ["e lalelei ona fua;", "and of goodly fruit:"], ["o le taalili tele lava ua faamuina ai ona lau i le afi,", "with the noise of a great tumult he hath kindled fire upon it,"], ["ua gauia ona la.", "and the branches of it are broken."]]},
  {num:17,words:[["Auā o Ieova o 'au,", "For the LORD of hosts,"], ["o le na totōina oe,", "that planted thee,"], ["ua fetalai mai e ia le malaia o le a oo ia te oe,", "hath pronounced evil against thee,"], ["ona o le amio leaga a le aiga o Isaraelu ma le aiga o Iuta,", "for the evil of the house of Israel and of the house of Judah,"], ["na latou faia ia te i latou lava e faaonoono ia te au i lo latou faamu mea manogi ia Paala.", "which they have done against themselves to provoke me to anger in offering incense unto Baal."]]},
  {num:18,words:[["Ua faailoa mai e Ieova ia te au ina ia ou iloa;", "And the LORD hath given me knowledge of it, and I know it:"], ["ona e faaalia mai ai lea ia te au o a latou amioga.", "then thou shewedst me their doings."]]},
  {num:19,words:[["A o a'u,", "But I was like a lamb or an ox that is brought to the slaughter;"], ["ua pei o se tamai mamoe lata ua ta'ita'iina ia fasia;", "and I knew not that they had devised devices against me,"], ["na ou le iloa foi ua mafaufau e i latou i ni togafiti e leaga ai a'u, ua faapea ,", "saying,"], ["Se'i tatou faaumatia le laau ma ona fua,", "Let us destroy the tree with the fruit thereof,"], ["ma tatou vavaeeseina o ia ai le nuu o tagata ola,", "and let us cut him off from the land of the living,"], ["ina ia le toe manatua lava lona igoa.", "that his name may be no more remembered."]]},
  {num:20,words:[["A o oe,", "But,"], ["Ieova o 'au,", "O LORD of hosts,"], ["o le faamasino amiotonu,", "that judgest righteously,"], ["o le tofotofo i le manatu ma le loto,", "that triest the reins and the heart,"], ["e iloa e a'u lau taui ma sui ia te i latou;", "let me see thy vengeance on them:"], ["auā ua ou faaalia la'u finauga ia te oe.", "for unto thee have I revealed my cause."]]},
  {num:21,words:[["O le mea lea,", "Therefore thus saith the LORD of the men of Anathoth,"], ["o loo faapea ona fetalai mai ai o Ieova i tagata o Anatota,", "that seek thy life,"], ["o e sailiili e fasioti ia te oe, ua faapea,", "saying,"], ["Aua e te vavalo mai i le suafa o Ieova,", "Prophesy not in the name of the LORD,"], ["ina ne'i oti oe i o matou lima.", "that thou die not by our hand:"]]},
  {num:22,words:[["O le mea lea o loo faapea ona fetalai mai ai o Ieova o 'au,", "Therefore thus saith the LORD of hosts,"], ["Faauta,", "Behold,"], ["ou te taui atu ia te i latou;", "I will punish them:"], ["e oti taulelea i le pelu;", "the young men shall die by the sword;"], ["e oti foi o latou atalii ma o latou afafine i le oge.", "their sons and their daughters shall die by famine:"]]},
  {num:23,words:[["E leai ni o latou e totoe;", "And there shall be no remnant of them:"], ["auā ou te faaoo le malaia i tagata o Anatota,", "for I will bring evil upon the men of Anathoth,"], ["o le tausaga lava e tauia ai i latou.", "even the year of their visitation."]]},
];
renderVerseSet(jer_ch_11_Verses, 'jer-ch11-verses');

var jer_ch_12_Verses = [
  {num:1,words:[["Ieova e,", "Righteous art thou,"], ["e amiotonu oe,", "O LORD,"], ["pe a ou finau atu ia te oe;", "when I plead with thee:"], ["tau ina ou tautala atu ia te oe i au faamasinoga. Se a ea le mea ua manuia ai le ala o tagata amio leaga,", "yet let me talk with thee of thy judgments:"], ["ua saogalemu i latou uma o e matuā faa'ole'ole?", "Wherefore doth the way of the wicked prosper? wherefore are all they happy that deal very treacherously?"]]},
  {num:2,words:[["Ua e totōina i latou,", "Thou hast planted them,"], ["ua mau aa foi i latou;", "yea, they have taken root:"], ["ua tutupu i latou,", "they grow,"], ["ma ua latou fua mai;", "yea,"], ["ua latalata oe i o latou gutu,", "they bring forth fruit: thou art near in their mouth,"], ["a e mamao i o latou manatu.", "and far from their reins."]]},
  {num:3,words:[["A o oe,", "But thou,"], ["Ieova e,", "O LORD,"], ["o loo e silafia a'u,", "knowest me:"], ["ua e sisila mai ia te au,", "thou hast seen me,"], ["ua e tofotofoina foi lo'u loto ua ia te oe;", "and tried mine heart toward thee:"], ["ia e vavaeeseina i latou e pei o mamoe a fāsia,", "pull them out like sheep for the slaughter,"], ["ia e faasaina i latou mo le aso e fafasi ai.", "and prepare them for the day of slaughter."]]},
  {num:4,words:[["Seia afea e faanoanoa ai le nuu,", "How long shall the land mourn, and the herbs of every field wither,"], ["ma magumagu ai le vao iti o fanua uma ona o le amio leaga a e nonofo ai? Ua faaumatia manu vaefa ma manu felelei;", "for the wickedness of them that dwell therein? the beasts are consumed,"], ["auā ua latou fai ane,", "and the birds;"], ["E le vaaia e ia lo latou iuga.", "because they said, He shall not see our last end."]]},
  {num:5,words:[["Afai ua e taufetuli ma tagata e femoei i le eleele,", "If thou hast run with the footmen, and they have wearied thee,"], ["ma ua e lailoa ia te i latou,", "then how canst thou contend with horses? and if in the land of peace,"], ["pe faapefea ona e tausinio ma solofanua? Afai ua e nofo ma le le mata'u i le nuu e filemu ai,", "wherein thou trustedst,"], ["se a se mea e te faia i le matagofie o Ioritana?", "they wearied thee, then how wilt thou do in the swelling of Jordan?"]]},
  {num:6,words:[["Auā o ou uso lava ma le aiga o lou tamā,", "For even thy brethren,"], ["o i latou lava ua latou faa'ole'ole ia te oe;", "and the house of thy father, even they have dealt treacherously with thee;"], ["o i latou lava ua latou alalaga tele i ou tua;", "yea,"], ["e ui ina latou tautala lelei ia te oe,", "they have called a multitude after thee: believe them not,"], ["aua ne'i e faatuatua ia te i latou.", "though they speak fair words unto thee."]]},
  {num:7,words:[["Ua ou tuua lo'u fale,", "I have forsaken mine house,"], ["ua ou lafoaiina lo'u tofi;", "I have left mine heritage;"], ["ua ou tuuina atu le pele a lo'u loto i lima o e ita ia te ia.", "I have given the dearly beloved of my soul into the hand of her enemies."]]},
  {num:8,words:[["Ua avea lo'u tofi ia te au pei se leona i le vao;", "Mine heritage is unto me as a lion in the forest;"], ["ua leo tele mai o ia ia te au,", "it crieth out against me:"], ["o le mea lea ua ou 'ino'ino ai ia te ia.", "therefore have I hated it."]]},
  {num:9,words:[["O lo'u tofi ua ia te au pei o le manu feai,", "Mine heritage is unto me as a speckled bird,"], ["o le sapua;", "the birds round about are against her;"], ["o manu feai o i ona itu uma ua ita ia te ia; o mai ia,", "come ye,"], ["ina faapotopoto mai ia o mea ola uma o le vao,", "assemble all the beasts of the field,"], ["ma aumaia i latou e aai ai.", "come to devour."]]},
  {num:10,words:[["Ua faaumatia la'u tovine e leoleo mamoe e toatele,", "Many pastors have destroyed my vineyard,"], ["ua solia e i latou lo'u tofi,", "they have trodden my portion under foot,"], ["o lo'u tofi matagofie ua latou faia ma mea tuufua ua faatafunaina.", "they have made my pleasant portion a desolate wilderness."]]},
  {num:11,words:[["Ua faia ma mea faatafunaina,", "They have made it desolate,"], ["ua faanoanoa ia i o'u luma ina ua faatafunaina;", "and being desolate it mourneth unto me;"], ["ua faatafunaina le nuu uma,", "the whole land is made desolate,"], ["a e leai se tagata ua mafaufau i ai.", "because no man layeth it to heart."]]},
  {num:12,words:[["Ua o ae tagata faatafuna i mauga tula uma i le vao;", "The spoilers are come upon all high places through the wilderness:"], ["ua 'ai le pelu a Ieova e afua mai i le tasi pito nuu e oo i le tasi pito nuu;", "for the sword of the LORD shall devour from the one end of the land even to the other end of the land:"], ["e leai se filemu i se tagata e toatasi.", "no flesh shall have peace."]]},
  {num:13,words:[["Ua latou luluina saito,", "They have sown wheat,"], ["a e latou te selesele mai ai laau tuitui;", "but shall reap thorns:"], ["ua faatigaina i latou e i latou, a e le aoga ia te i latou;", "they have put themselves to pain,"], ["e mā foi i latou i mea e maua ia te outou,", "but shall not profit:"], ["ona o le toasa tele o Ieova.", "and they shall be ashamed of your revenues because of the fierce anger of the LORD."]]},
  {num:14,words:[["O loo faapea ona fetalai mai o Ieova i tagata amio leaga uma ua tuaoi ma a'u,", "Thus saith the LORD against all mine evil neighbours,"], ["o e pai atu i le tofi na a'u tofia ai lo'u nuu o Isaraelu,", "that touch the inheritance which I have caused my people Israel to inherit;"], ["Faauta,", "Behold,"], ["ou te liaiina i latou ai lo latou laueleele,", "I will pluck them out of their land,"], ["ou te liaiina foi le aiga o Iuta ai totonu ia te i latou.", "and pluck out the house of Judah from among them."]]},
  {num:15,words:[["A mavae ona ou liaiina o i latou,", "And it shall come to pass,"], ["ona ou toe alofa mutimutivale lea ia te i latou,", "after that I have plucked them out I will return,"], ["ma ou faafoisia mai i latou,", "and have compassion on them, and will bring them again,"], ["e taitoatasi i lona tofi,", "every man to his heritage,"], ["e taitoatasi foi i lona nuu.", "and every man to his land."]]},
  {num:16,words:[["Afai e matuā a'oa'o lava i latou i ala o lo'u nuu,", "And it shall come to pass,"], ["ia tauto i latou i lo'u igoa,", "if they will diligently learn the ways of my people,"], ["e faapea ,", "to swear by my name,"], ["O loo soifua Ieova;", "The LORD liveth;"], ["e pei ona latou a'oa'o atu i lo'u nuu ia tauto ia Paala;", "as they taught my people to swear by Baal;"], ["ona atiina ae lea o i latou i totonu o lo'u nuu.", "then shall they be built in the midst of my people."]]},
  {num:17,words:[["A e afai latou te le faalogo mai,", "But if they will not obey,"], ["ona ou matuā liaiina lea o lea nuu, ma ou faaumatia,", "I will utterly pluck up and destroy that nation,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
];
renderVerseSet(jer_ch_12_Verses, 'jer-ch12-verses');

var jer_ch_13_Verses = [
  {num:1,words:[["Ua faapea ona fetalai mai o Ieova ia te au,", "Thus saith the LORD unto me,"], ["Alu ia,", "Go and get thee a linen girdle,"], ["ia e fai mo oe le fusi lino, ma fusi a'i lou sulugatiti,", "and put it upon thy loins,"], ["aua foi e te tuu i le vai.", "and put it not in water."]]},
  {num:2,words:[["Ona ou maua lea o le fusi e tusa ma le afioga a Ieova,", "So I got a girdle according to the word of the LORD,"], ["ma ou fusi a'i lo'u sulugatiti.", "and put it on my loins."]]},
  {num:3,words:[["Ona foi faalua mai ai lea o le afioga a Ieova ia te au,", "And the word of the LORD came unto me the second time,"], ["ua faapea mai,", "saying,"]]},
  {num:4,words:[["Ia e ave le fusi ua e maua o i ai i lou sulugatiti,", "Take the girdle that thou hast got,"], ["ma e tulai,", "which is upon thy loins,"], ["ma alu i Eufirate,", "and arise, go to Euphrates,"], ["ma nanā ai i lea mea i se mea māvae o le papa.", "and hide it there in a hole of the rock."]]},
  {num:5,words:[["Ona ou alu ai lea,", "So I went,"], ["ma nanā ai i Eufirate,", "and hid it by Euphrates,"], ["e pei ona fetalai mai ai o Ieova ia te au.", "as the LORD commanded me."]]},
  {num:6,words:[["Ua mavae aso e tele,", "And it came to pass after many days,"], ["ona faapea mai ai lea o Ieova ia te au,", "that the LORD said unto me,"], ["Ina tulai ia,", "Arise, go to Euphrates,"], ["alu i Eufirate,", "and take the girdle from thence,"], ["ma au mai ai le fusi na ou fai atu ai ia te oe e nanā i lea mea.", "which I commanded thee to hide there."]]},
  {num:7,words:[["Ona a'u alu ai lea i Eufirate,", "Then I went to Euphrates,"], ["ma a'u eli,", "and digged,"], ["ma avae nai lea mea le fusi na ou nanā ai;", "and took the girdle from the place where I had hid it: and,"], ["faauta foi,", "behold,"], ["ua leaga le fusi,", "the girdle was marred,"], ["ua le aoga i se mea e tasi.", "it was profitable for nothing."]]},
  {num:8,words:[["Ona tulei mai lea o le afioga a Ieova ia te au,", "Then the word of the LORD came unto me,"], ["ua faapea mai.", "saying,"]]},
  {num:9,words:[["Ua faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["E faapena ona ou faaleagaina le faamaualuga o Iuta,", "After this manner will I mar the pride of Judah,"], ["ma le faamaualuga tele o Ierusalema.", "and the great pride of Jerusalem."]]},
  {num:10,words:[["O lenei nuu amio leaga,", "This evil people,"], ["ua le mafafai i latou ona faalogo mai i a'u upu,", "which refuse to hear my words,"], ["ua savavali ma le loto finau vale,", "which walk in the imagination of their heart,"], ["ma mulimuli atu i atua ese,", "and walk after other gods, to serve them,"], ["e auauna ma ifo ia te i latou,", "and to worship them,"], ["e avea lava i latou e pei o lenei fusi,", "shall even be as this girdle,"], ["e le aoga i se mea e tasi.", "which is good for nothing."]]},
  {num:11,words:[["Auā e pei ona pipii le fusi i le sulugatiti o le tagata,", "For as the girdle cleaveth to the loins of a man,"], ["sa faapea ona a'u faapipii ia te au o le aiga uma o Isaraelu,", "so have I caused to cleave unto me the whole house of Israel and the whole house of Judah,"], ["ma le aiga uma o Iuta,", "saith the LORD;"], ["o loo fetalai mai ai Ieova;", "that they might be unto me for a people,"], ["ina ia fai i latou mo'u nuu, ia fai foi ma igoa,", "and for a name,"], ["ma viiga,", "and for a praise,"], ["ma matagofie;", "and for a glory:"], ["a ua latou le faalogo mai.", "but they would not hear."]]},
  {num:12,words:[["O le upu foi lenei e te fai atu ai ia te i latou,", "Therefore thou shalt speak unto them this word;"], ["O loo faapea ona fetalai mai o Ieova le Atua o Isaraelu,", "Thus saith the LORD God of Israel,"], ["E faatutumuina fagu uma i le uaina;", "Every bottle shall be filled with wine:"], ["latou te fai mai foi ia te oe,", "and they shall say unto thee,"], ["E le ua matou matuā iloa ea e faatutumuina fagu uma i le uaina?", "Do we not certainly know that every bottle shall be filled with wine?"]]},
  {num:13,words:[["Ona e fai atu lea ia te i latou,", "Then shalt thou say unto them,"], ["o loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Faauta,", "Behold,"], ["ou te faatutumuina i le onaga o i latou uma o e nonofo i lenei nuu,", "I will fill all the inhabitants of this land,"], ["o tupu o e nonofo i le nofoālii o Tavita,", "even the kings that sit upon David's throne, and the priests,"], ["atoa ma faitaulaga,", "and the prophets,"], ["ma perofeta,", "and all the inhabitants of Jerusalem,"], ["ma i latou uma o e nonofo i Ierusalema.", "with drunkenness."]]},
  {num:14,words:[["Ou te faafeto'ai i latou,", "And I will dash them one against another,"], ["o le tasi i le tasi,", "even the fathers and the sons together,"], ["o tamā foi atoa ma fanau,", "saith the LORD:"], ["o loo fetalai mai ai Ieova; ou te le faapelepele ia te i latou,", "I will not pity,"], ["pe faasaoina,", "nor spare,"], ["pe alofa atu,", "nor have mercy,"], ["a e faaumatia i latou.", "but destroy them."]]},
  {num:15,words:[["Ia outou faalogologo mai,", "Hear ye,"], ["ma uai mai o outou taliga;", "and give ear;"], ["aua tou te faamaualuga,", "be not proud:"], ["auā ua fetalai mai Ieova.", "for the LORD hath spoken."]]},
  {num:16,words:[["Ia avatu le viiga ia Ieova lo outou Atua,", "Give glory to the LORD your God,"], ["manū o lei faapouliuligia e ia,", "before he cause darkness,"], ["manū o lei tausuai o outou vae i luga o mauga pouliuli,", "and before your feet stumble upon the dark mountains, and,"], ["ma outou faatalitali i le malamalama,", "while ye look for light,"], ["a ua liua lea e ia ma ata o le oti,", "he turn it into the shadow of death,"], ["ua fai ma pogisa tele.", "and make it gross darkness."]]},
  {num:17,words:[["A e afai tou te le faalogo mai,", "But if ye will not hear it,"], ["ona tagi ai lea o lo'u loto i mea lilo ona o lo outou faamaualuga,", "my soul shall weep in secret places for your pride;"], ["ma ou matuā tagi lava,", "and mine eye shall weep sore,"], ["e tafe ifo liomata i o'u mata,", "and run down with tears,"], ["auā ua tāfea le lafu mamoe a Ieova.", "because the LORD'S flock is carried away captive."]]},
  {num:18,words:[["Ia fai atu i le tupu ma le sa'o tamaitai,", "Say unto the king and to the queen, Humble yourselves,"], ["Ia oulua faamaulalo,", "sit down:"], ["ia nofo i lalo auā e pauu ifo o oulua palealii matagofie i o oulua ao.", "for your principalities shall come down, even the crown of your glory."]]},
  {num:19,words:[["Ua punitia aai o i le itu i toga,", "The cities of the south shall be shut up,"], ["e le tatalaina e se tasi;", "and none shall open them:"], ["ua tāfea Iuta uma,", "Judah shall be carried away captive all of it,"], ["ua tāfea atoa uma lava.", "it shall be wholly carried away captive."]]},
  {num:20,words:[["Ia e tepa ae,", "Lift up your eyes,"], ["ma vaavaai atu i e ua o mai mai le itu i matu,", "and behold them that come from the north:"], ["Po o ifea le lafu mamoe na avatu ia te oe,", "where is the flock that was given thee,"], ["o au mamoe matagofie?", "thy beautiful flock?"]]},
  {num:21,words:[["Pe se a ea lau na e te fai atu ai pe a tauia oe e ia? Auā na e a'oa'o atu ia te i latou e fai ma alii sili e pule ia te oe. E le maua ea oe e le tiga e pei o le fafine a fanau?", "What wilt thou say when he shall punish thee? for thou hast taught them to be captains, and as chief over thee: shall not sorrows take thee, as a woman in travail?"]]},
  {num:22,words:[["Afai foi e te fai ifo i lou loto,", "And if thou say in thine heart,"], ["Pe se a le mea ua oo mai ai ia te au ia mea? O le tele o lau agasala ua susueina ae ai ou pito ofu,", "Wherefore come these things upon me? For the greatness of thine iniquity are thy skirts discovered,"], ["ma faasaunoa ai i ou mulivae.", "and thy heels made bare."]]},
  {num:23,words:[["E mafai ea ona liua e le Aitiope o lona pa'u,", "Can the Ethiopian change his skin,"], ["pe liua e le nameri ona ila? A mafai lea ,", "or the leopard his spots? then may ye also do good,"], ["ona mafai foi lea ona amio lelei o outou ua masani i amio leaga.", "that are accustomed to do evil."]]},
  {num:24,words:[["Ou te faataapeape ia te i latou e pei o aputi o saito ua lelea i le matagi mai le vao.", "Therefore will I scatter them as the stubble that passeth away by the wind of the wilderness."]]},
  {num:25,words:[["O lou tofi lenei,", "This is thy lot,"], ["o le tofi mai ia te au ua fuatia mo oe,", "the portion of thy measures from me,"], ["o loo fetalai mai ai Ieova;", "saith the LORD;"], ["auā ua e faagalogalo ia te au,", "because thou hast forgotten me,"], ["a ua e faatuatua i le mea pepelo.", "and trusted in falsehood."]]},
  {num:26,words:[["O a'u lava, ou te susueina ae ou pito ofu i luga i ou mata,", "Therefore will I discover thy skirts upon thy face,"], ["ina ia iloa ai lou mā.", "that thy shame may appear."]]},
  {num:27,words:[["Ua ou iloa au muliluaga,", "I have seen thine adulteries,"], ["ma au tagi faasolofanua,", "and thy neighings,"], ["ma le leaga o lou talitane,", "the lewdness of thy whoredom,"], ["ma au mea faasoesa i luga o mauga i le vao.", "and thine abominations on the hills in the fields."], ["Ierusalema e, talofa ia te oe;", "Woe unto thee,"], ["e le faamamāina ea oe seia afea?", "O Jerusalem! wilt thou not be made clean? when shall it once be?"]]},
];
renderVerseSet(jer_ch_13_Verses, 'jer-ch13-verses');

var jer_ch_14_Verses = [
  {num:1,words:[["O le afioga a Ieova na oo mai ia Ieremia ona o le la mala.", "The word of the LORD that came to Jeremiah concerning the dearth."]]},
  {num:2,words:[["Ua faanoanoa Iuta,", "Judah mourneth,"], ["ma ua faavaivai ona faitotoa;", "and the gates thereof languish;"], ["ua faavauvau i latou ua punou i le eleele,", "they are black unto the ground;"], ["ma ua alu ae le alaga o Ierusalema.", "and the cry of Jerusalem is gone up."]]},
  {num:3,words:[["Ua aauina atu e o latou alii o latou tagata i le vai;", "And their nobles have sent their little ones to the waters:"], ["ua latou o atu i vaieli,", "they came to the pits,"], ["ua le maua ni vai;", "and found no water;"], ["ua latou toe foi mai ma a latou ipu e le iio;", "they returned with their vessels empty;"], ["ua mamā i latou ma masiasi,", "they were ashamed and confounded,"], ["ua latou ufiufi foi i o latou ulu.", "and covered their heads."]]},
  {num:4,words:[["Ua mamā i latou o e gālue fanua,", "Because the ground is chapt,"], ["ua ufiufi i o latou ulu ona o le laueleele ua mavaevae,", "for there was no rain in the earth, the plowmen were ashamed,"], ["auā ua leai se ua i le nuu.", "they covered their heads."]]},
  {num:5,words:[["O le aila lava ua fanau ia i le vao,", "Yea,"], ["ma ua tuua lana tama ,", "the hind also calved in the field, and forsook it,"], ["auā ua leai se vao mua.", "because there was no grass."]]},
  {num:6,words:[["O asini foi o le vao ua tutū i mauga tula,", "And the wild asses did stand in the high places,"], ["na latou sogisogi i le matagi e pei o luko;", "they snuffed up the wind like dragons;"], ["ua avea o latou mata,", "their eyes did fail,"], ["auā e leai ni vao iti.", "because there was no grass."]]},
  {num:7,words:[["Ieova e,", "O LORD,"], ["e ui lava ina ua molimau a matou agasala ia te i matou,", "though our iniquities testify against us,"], ["ia e faia lava ona o lou suafa;", "do thou it for thy name's sake:"], ["auā ua tele lo matou liliu ese;", "for our backslidings are many;"], ["ua matou agasala ia te oe.", "we have sinned against thee."]]},
  {num:8,words:[["Le faamoemoega o Isaraelu e,", "O the hope of Israel,"], ["o lē faaola ia te ia i ona po o le puapuaga,", "the saviour thereof in time of trouble,"], ["se a le mea ua avea ai oe e pei o le tagata ese i le nuu,", "why shouldest thou be as a stranger in the land,"], ["e pei o le tagata alu malaga foi ua afe ane e moe i le po?", "and as a wayfaring man that turneth aside to tarry for a night?"]]},
  {num:9,words:[["Se a le mea ua avea ai oe e pei o le tagata ua segia lona mauli,", "Why shouldest thou be as a man astonied,"], ["e pei o le toa e le mafaia ona faaola? a o oe,", "as a mighty man that cannot save? yet thou,"], ["Ieova e,", "O LORD,"], ["ua e ia te i matou lava,", "art in the midst of us,"], ["ua ta'ua i matou i lou suafa;", "and we are called by thy name;"], ["aua e te tuua i matou.", "leave us not."]]},
  {num:10,words:[["O loo faapea ona fetalai mai o Ieova i lenei nuu,", "Thus saith the LORD unto this people,"], ["Ua fia feoai naua i latou,", "Thus have they loved to wander,"], ["ua latou le taofia o latou vae,", "they have not refrained their feet,"], ["o le mea lea e le fiafia ai Ieova ia te i latou;", "therefore the LORD doth not accept them;"], ["e manatua nei e ia o a latou amio leaga,", "he will now remember their iniquity,"], ["ma tauia a latou agasala.", "and visit their sins."]]},
  {num:11,words:[["Ona faapea mai ai lea o Ieova ia te au,", "Then said the LORD unto me,"], ["Aua le tatalo mo lenei nuu ina ia lelei ai i latou .", "Pray not for this people for their good."]]},
  {num:12,words:[["E ui ina latou anapopogi,", "When they fast,"], ["ou te le faalogo i lo latou alaga;", "I will not hear their cry;"], ["e ui ina latou osia taulaga mu ma taulaga i mea e 'ai,", "and when they offer burnt offering and an oblation,"], ["ou te le talia;", "I will not accept them:"], ["a ou te faaumatia i latou i le pelu,", "but I will consume them by the sword,"], ["ma le oge,", "and by the famine,"], ["ma le faamai.", "and by the pestilence."]]},
  {num:13,words:[["Ona ou faapea atu ai lea,", "Then said I,"], ["Aue! le Alii e Ieova,", "Ah,"], ["faauta,", "Lord GOD! behold,"], ["ua fai mai perofeta ia te i latou,", "the prophets say unto them,"], ["Tou te le iloa e pelu,", "Ye shall not see the sword,"], ["e le oo foi le oge ia te outou,", "neither shall ye have famine;"], ["a ou te tuuina atu ia te outou le manuia faamaoni i lenei mea.", "but I will give you assured peace in this place."]]},
  {num:14,words:[["Ona fetalai mai lea o Ieova ia te au,", "Then the LORD said unto me,"], ["O loo vavalo mai perofeta i mea pepelo i lo'u igoa;", "The prophets prophesy lies in my name:"], ["ua ou le aauina atu i latou,", "I sent them not,"], ["ma ou le poloai atu ia te i latou,", "neither have I commanded them,"], ["ma a'u le tautala atu ia te i latou; ua latou vavalo ia te outou le faaaliga pepelo,", "neither spake unto them:"], ["ma le faataulāitu,", "they prophesy unto you a false vision and divination,"], ["ma le mea faatauvaa,", "and a thing of nought,"], ["ma le pepelo o latou loto.", "and the deceit of their heart."]]},
  {num:15,words:[["O le mea lea o loo faapea ona fetalai mai ai o Ieova i perofeta ua vavalo i lo'u igoa,", "Therefore thus saith the LORD concerning the prophets that prophesy in my name,"], ["a o a'u ua ou le aauina atu i latou;", "and I sent them not,"], ["a ua latou fai ane,", "yet they say,"], ["E le oo mai le pelu ma le oge i lenei nuu;", "Sword and famine shall not be in this land;"], ["o le pelu ma le oge e faaumatia ai ia lava perofeta.", "By sword and famine shall those prophets be consumed."]]},
  {num:16,words:[["A o le nuu ua latou vavalo i ai,", "And the people to whom they prophesy shall be cast out in the streets of Jerusalem because of the famine and the sword;"], ["e lafoaiina i latou i ala o Ierusalema ona o le oge ma le pelu;", "and they shall have none to bury them,"], ["e leai se na te tanua i latou,", "them,"], ["o i latou, atoa ma a latou avā,", "their wives,"], ["ma o latou atalii,", "nor their sons,"], ["ma o latou afafine;", "nor their daughters:"], ["ou te sasaaina atu foi a latou amio leaga i luga ia te i latou.", "for I will pour their wickedness upon them."]]},
  {num:17,words:[["O le upu nei e te fai atu ai ia te i latou,", "Therefore thou shalt say this word unto them;"], ["Ia tafe ifo loimata i o'u mata i le po atoa ma le ao,", "Let mine eyes run down with tears night and day,"], ["aua le mapu;", "and let them not cease:"], ["auā ua tu'imomoia le tama teine taupou a lo'u nuu i le tu'imomomo e tele,", "for the virgin daughter of my people is broken with a great breach,"], ["o le manua e matuā leaga lava.", "with a very grievous blow."]]},
  {num:18,words:[["Afai ou te alu atu i le vao, faauta foi,", "If I go forth into the field,"], ["o e ua fāsia i le pelu; a e afai ou te alu i le aai,", "then behold the slain with the sword! and if I enter into the city,"], ["faauta foi, o e ua vaivai i le oge;", "then behold them that are sick with famine! yea,"], ["auā o perofeta atoa ma faitaulaga, ua latou feoai i le nuu ua latou le iloa.", "both the prophet and the priest go about into a land that they know not."]]},
  {num:19,words:[["Ua e matuā lafoaiina ea Iuta? Ua inosia ea Siona i lou finagalo? Se a le mea ua e sasaina ai i matou,", "Hast thou utterly rejected Judah? hath thy soul lothed Zion? why hast thou smitten us,"], ["ua leai foi se togafiti e malolo ai i matou? Na matou faatalitali i le manuia,", "and there is no healing for us? we looked for peace,"], ["a e leai se lelei na maua; na faatalitali foi i ona po e faamaloloina ai,", "and there is no good;"], ["faauta foi,", "and for the time of healing,"], ["o le mata'u.", "and behold trouble!"]]},
  {num:20,words:[["Ieova e,", "We acknowledge,"], ["ua matou iloa la matou amio leaga,", "O LORD,"], ["ma le amioletonu a o matou tamā;", "our wickedness, and the iniquity of our fathers:"], ["auā ua matou agasala ia te oe.", "for we have sinned against thee."]]},
  {num:21,words:[["Aua e te 'ino'ino mai ia te i matou ,", "Do not abhor us,"], ["auā o lou suafa;", "for thy name's sake,"], ["aua e te faainosia le nofoālii o lou mamalu;", "do not disgrace the throne of thy glory:"], ["ia e manatua,", "remember,"], ["aua le tatalaina la tatou feagaiga ma oe.", "break not thy covenant with us."]]},
  {num:22,words:[["Pe ai se tasi o mea faatauvaa o i nuu ese e mafaia ona faatotōina ifo o le ua? pe mafaia ea e le lagi ona tuuina mai o timuga? E le o oe ea lea,", "Are there any among the vanities of the Gentiles that can cause rain? or can the heavens give showers? art not thou he,"], ["Ieova e, lo matou Atua? O le mea lea matou te faatalitali ai ia te oe;", "O LORD our God? therefore we will wait upon thee:"], ["auā o oe lava ua e faia ia mea uma.", "for thou hast made all these things."]]},
];
renderVerseSet(jer_ch_14_Verses, 'jer-ch14-verses');

var jer_ch_15_Verses = [
  {num:1,words:[["Ua faapea mai foi Ieova ia te au,", "Then said the LORD unto me,"], ["Afai ana tutū mai o Mose ma Samuelu i o'u luma,", "Though Moses and Samuel stood before me,"], ["ou te le loto lava i lenei nuu;", "yet my mind could not be toward this people:"], ["ina tutuli ia ia te i latou i o'u luma,", "cast them out of my sight,"], ["ia latou o ese.", "and let them go forth."]]},
  {num:2,words:[["Afai latou te fai mai ia te oe,", "And it shall come to pass, if they say unto thee,"], ["Matou te o ea ifea? Ona e fai atu ai lea ia te i latou,", "Whither shall we go forth? then thou shalt tell them,"], ["Ua faapea ona fetalai mai o Ieova,", "Thus saith the LORD; Such as are for death,"], ["O e ua tuu mo le oti tuu ia i le oti;", "to death; and such as are for the sword,"], ["o e ua tuu mo le pelu tuu ia i le pelu;", "to the sword; and such as are for the famine,"], ["o e ua tuu mo le oge tuu ia i le oge;", "to the famine;"], ["ma e ua tuu mo le tafeaga tuu ia i le tafeaga.", "and such as are for the captivity, to the captivity."]]},
  {num:3,words:[["Ou te tofia mea eseese e fa e oo ia te i latou,", "And I will appoint over them four kinds,"], ["o loo fetalai mai ai Ieova;", "saith the LORD:"], ["o le pelu e fasi a'i,", "the sword to slay, and the dogs to tear,"], ["ma ulī e fesaei a'i,", "and the fowls of the heaven,"], ["ma manu felelei,", "and the beasts of the earth,"], ["ma manu e tataa e aai ai ma faaumatia ai i latou .", "to devour and destroy."]]},
  {num:4,words:[["Ou te tuuina atu i latou ia faaatuatuvaleina i malo uma o le lalolagi,", "And I will cause them to be removed into all kingdoms of the earth,"], ["ona o Manase le atalii o Esekia le tupu o Iuta,", "because of Manasseh the son of Hezekiah king of Judah,"], ["auā o mea na ia faia i Ierusalema.", "for that which he did in Jerusalem."]]},
  {num:5,words:[["Auā Ierusalema e,", "For who shall have pity upon thee,"], ["po o ai ea se alofa atu ia te oe? po o ai foi se faanoanoa ona o oe? po o ai foi se afe ane e ofo alofa ia te oe?", "O Jerusalem? or who shall bemoan thee? or who shall go aside to ask how thou doest?"]]},
  {num:6,words:[["Ua e lafoaiina a'u,", "Thou hast forsaken me,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["ua e tuumuli i tua;", "thou art gone backward:"], ["o lea ou te faaloaloa ai lo'u lima i luga ia te oe,", "therefore will I stretch out my hand against thee,"], ["ma ou faaumatia ai oe;", "and destroy thee;"], ["ua ou lailoa i salamo.", "I am weary with repenting."]]},
  {num:7,words:[["Ou te faasaviligia i latou i le mea e faasavili a'i saito i faitotoa o le nuu;", "And I will fan them with a fan in the gates of the land;"], ["e aufanaua i latou ia te au,", "I will bereave them of children,"], ["ou te faaumatia lo'u nuu,", "I will destroy my people,"], ["ina ua latou le toe foi mai i o latou ala.", "since they return not from their ways."]]},
  {num:8,words:[["E toatele i o'u luma o latou fafine ua oti a latou tane,", "Their widows are increased to me above the sand of the seas:"], ["e sili i le oneone o le sami;", "I have brought upon them against the mother of the young men a spoiler at noonday:"], ["ou te aumaia ia te i latou e tau ma le tinā, le taulealea na te faatafunaina i le tutonu o le la;", "I have caused him to fall upon it suddenly,"], ["e faafuasei ona a'u faaosoina atu ia te i latou o le mata'u ma le atuatuvale.", "and terrors upon the city."]]},
  {num:9,words:[["Ua vaivai o ia le na fanau mai ai le toafitu;", "She that hath borne seven languisheth:"], ["ua to lana mānava;", "she hath given up the ghost;"], ["ua goto lona la a o ao lava; ua mā,", "her sun is gone down while it was yet day:"], ["ma masiasi o ia;", "she hath been ashamed and confounded:"], ["o e o totoe ia te i latou ou te tuuina atu i latou i le pelu i luma o e ita mai ia te i latou,", "and the residue of them will I deliver to the sword before their enemies,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:10,words:[["Oi talofa ia te au,", "Woe is me,"], ["lo'u tinā e,", "my mother,"], ["ina ua e fanaua mai a'u o le tagata finau ma le tagata e tupu ai misa i le nuu uma. Ua le talia e a'u le totogi faasili,", "that thou hast borne me a man of strife and a man of contention to the whole earth! I have neither lent on usury,"], ["ua ou le avatu foi le totogi faasili ia te i latou;", "nor men have lent to me on usury;"], ["a ua faafano mai i latou uma ia te au.", "yet every one of them doth curse me."]]},
  {num:11,words:[["Ua faapea mai Ieova, E moni,", "The LORD said,"], ["ou te laveaiina oe ia e manuia ai; e moni,", "Verily it shall be well with thy remnant;"], ["o a'u lava e ala ai ona faatoga mai ia te oe o lē ita mai, i ona po o le leaga ma ona po o le puapuaga.", "verily I will cause the enemy to entreat thee well in the time of evil and in the time of affliction."]]},
  {num:12,words:[["E mafai ea ona gauia o le uamea, o le uamea mai le itu i matu, ma le 'apa memea?", "Shall iron break the northern iron and the steel?"]]},
  {num:13,words:[["O au mea e tamaoaiga ai ma au oloa ou te tuuina atu ai e fai ma vete,", "Thy substance and thy treasures will I give to the spoil without price,"], ["e le o le taui,", "and that for all thy sins,"], ["a e peitai ona o au agasala uma i lou nuu uma.", "even in all thy borders."]]},
  {num:14,words:[["Ou te ta'ita'iina e ua ita ia te oe i le nuu ua e le iloa;", "And I will make thee to pass with thine enemies into a land which thou knowest not:"], ["auā ua tugia le afi i lo'u ita,", "for a fire is kindled in mine anger,"], ["e mu ai i luga ia te outou.", "which shall burn upon you."]]},
  {num:15,words:[["Ieova e,", "O LORD,"], ["ua e silafia e oe;", "thou knowest:"], ["ia e manatua mai a'u,", "remember me,"], ["ma asiasi mai ia te au,", "and visit me,"], ["ia e taui atu ona o a'u i e ua faasaua mai ia te au;", "and revenge me of my persecutors;"], ["o lou faatoatoa ia te i latou aua le aveeseina ai a'u;", "take me not away in thy longsuffering:"], ["ia e silafia ua ou onosai i le faalumaina ona o oe.", "know that for thy sake I have suffered rebuke."]]},
  {num:16,words:[["Na maua au afioga,", "Thy words were found,"], ["ona ou 'ai ai lea;", "and I did eat them;"], ["sa ia te au lau afioga e fai ma mea e olioli ai ma fiafia ai lo'u loto; auā ua ta'ua a'u i lou suafa,", "and thy word was unto me the joy and rejoicing of mine heart:"], ["Ieova e,", "for I am called by thy name,"], ["le Atua o 'au.", "O LORD God of hosts."]]},
  {num:17,words:[["Ou te lei nofo i le faapotopotoga o e tauemu,", "I sat not in the assembly of the mockers,"], ["ma ou le fiafia i ai;", "nor rejoiced;"], ["ua ou nofo toatasi ona o lou aao;", "I sat alone because of thy hand:"], ["auā ua e faatumuina a'u i le ita.", "for thou hast filled me with indignation."]]},
  {num:18,words:[["Se a le mea e tumau ai pea lo'u tiga,", "Why is my pain perpetual,"], ["ma lo'u manua ua leaga lava,", "and my wound incurable,"], ["e le mafai ona faamamafuina? Ua avea lava oe ia te au e peiseai ua pepelo,", "which refuseth to be healed? wilt thou be altogether unto me as a liar,"], ["o le vai ua pē.", "and as waters that fail?"]]},
  {num:19,words:[["O le mea lea ua faapea ona fetalai mai ai o Ieova,", "Therefore thus saith the LORD,"], ["Afai e te toe foi mai,", "If thou return,"], ["ona ou toe faafoisia mai lea o oe,", "then will I bring thee again,"], ["e te tu i o'u luma;", "and thou shalt stand before me:"], ["afai foi e te faateaeseina le lelei i le leaga,", "and if thou take forth the precious from the vile,"], ["e avea oe e pei o lo'u gutu;", "thou shalt be as my mouth:"], ["e toe foi mai i latou ia te oe,", "let them return unto thee;"], ["a o oe e te le toe foi atu ia te i latou.", "but return not thou unto them."]]},
  {num:20,words:[["Ou te fai foi oe ma pa 'apa memea malosi i lenei nuu;", "And I will make thee unto this people a fenced brasen wall:"], ["latou te sii mai le taua ia te oe, a e latou te le manumalo ia te oe;", "and they shall fight against thee,"], ["auā o a'u nei,", "but they shall not prevail against thee:"], ["ou te ia te oe e faaola ia te oe, ma laveai ia te oe,", "for I am with thee to save thee and to deliver thee,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:21,words:[["Ou te laveai ia te oe ai lima o e amio leaga ma ou faaolaina oe ai lima o e saua.", "And I will deliver thee out of the hand of the wicked, and I will redeem thee out of the hand of the terrible."]]},
];
renderVerseSet(jer_ch_15_Verses, 'jer-ch15-verses');

var jer_ch_16_Verses = [
  {num:1,words:[["Na oo mai le afioga a Ieova ia te au,", "The word of the LORD came also unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Aua e te fai avā,", "Thou shalt not take thee a wife,"], ["aua ne'i i ai foi ia te oe o atalii po o afafine i lenei mea.", "neither shalt thou have sons or daughters in this place."]]},
  {num:3,words:[["Auā ua faapea ona fetalai mai o Ieova i atalii ma afafine ua fananau i lenei mea,", "For thus saith the LORD concerning the sons and concerning the daughters that are born in this place,"], ["ma o latou tinā o e na fananau mai ai i latou,", "and concerning their mothers that bare them,"], ["ma o latou tamā ua fanaua i latou i lenei nuu;", "and concerning their fathers that begat them in this land;"]]},
  {num:4,words:[["e oti i latou i ma'i e oti ai;", "They shall die of grievous deaths;"], ["e leai ni e taufaitagitu'i ia te i latou;", "they shall not be lamented;"], ["e le tanumia foi i latou;", "neither shall they be buried;"], ["e avea i latou ma otaota i luga o le laueleele;", "but they shall be as dung upon the face of the earth: and they shall be consumed by the sword,"], ["e faaumatia i latou i le pelu,", "and by famine;"], ["ma le oge,", "and their carcases shall be meat for the fowls of heaven,"], ["e fai foi o latou tino ua oti ma mea e 'ai mā manu felelei ma manu e tataa.", "and for the beasts of the earth."]]},
  {num:5,words:[["Auā ua faapea ona fetalai mai o Ieova,", "For thus saith the LORD,"], ["Aua e te ulufale i le fale o i ai le auega, aua foi e te alu e tagitu'i ai,", "Enter not into the house of mourning,"], ["aua foi e te faanoanoa ia te i latou;", "neither go to lament nor bemoan them:"], ["auā ua ou aveeseina lo'u manuia i lenei nuu,", "for I have taken away my peace from this people,"], ["o le alofa lava, ma le alofa mutimutivale,", "saith the LORD,"], ["o loo fetalai mai ai Ieova.", "even lovingkindness and mercies."]]},
  {num:6,words:[["E oti alii atoa ma tagata nuu i lenei nuu;", "Both the great and the small shall die in this land:"], ["e le tanumia i latou,", "they shall not be buried,"], ["e le taufaitagitu'i nisi ona o i latou,", "neither shall men lament for them,"], ["e le selei foi o latou tino ,", "nor cut themselves,"], ["e le sele mamā foi o latou ulu ona o i latou;", "nor make themselves bald for them:"]]},
  {num:7,words:[["e le tofitofia mea e 'ai o le faanoanoa ona o i latou e fai ma faamafanafana ia te i latou ona o le ua oti;", "Neither shall men tear themselves for them in mourning,"], ["latou te le avatu ia te i latou le ipu o le faamafanafanaga latou te inu ai ona o latou tamā,", "to comfort them for the dead;"], ["po o latou tinā.", "neither shall men give them the cup of consolation to drink for their father or for their mother."]]},
  {num:8,words:[["E te le ulufale foi i le fale e fai ai le tausamiga,", "Thou shalt not also go into the house of feasting,"], ["e le nonofo ma i latou e 'ai ai ma inu ai.", "to sit with them to eat and to drink."]]},
  {num:9,words:[["Auā ua faapea ona fetalai mai o Ieova o 'au,", "For thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Faauta,", "Behold,"], ["ou te faaiuina le leo fiafia,", "I will cause to cease out of this place in your eyes,"], ["ma le leo olioli,", "and in your days, the voice of mirth,"], ["o le leo o le faatoafaiavā,", "and the voice of gladness,"], ["ma le leo o le faatoanofotane ai lenei mea i o outou luma,", "the voice of the bridegroom,"], ["a o ola mai outou.", "and the voice of the bride."]]},
  {num:10,words:[["A uma ona ē faaali atu i lenei nuu ia upu uma,", "And it shall come to pass,"], ["ua latou fai mai ia te oe,", "when thou shalt shew this people all these words, and they shall say unto thee,"], ["Se a le mea ua fai mai ai Ieova ia te i matou lenei malaia uma e tele? pe se a ea sa matou amioletonu? pe se a foi sa matou agasala ua matou agasala atu ai ia Ieova lo matou Atua?", "Wherefore hath the LORD pronounced all this great evil against us? or what is our iniquity? or what is our sin that we have committed against the LORD our God?"]]},
  {num:11,words:[["Ona e faapea atu ai lea ia te i latou,", "Then shalt thou say unto them,"], ["Auā ua lafoaiina a'u e o outou tamā,", "Because your fathers have forsaken me,"], ["o loo fai mai ai Ieova,", "saith the LORD,"], ["a ua latou mulimuli atu i atua ese,", "and have walked after other gods,"], ["ma auauna i ai,", "and have served them,"], ["ma ifo atu ia te i latou,", "and have worshipped them,"], ["a ua lafoaiina a'u,", "and have forsaken me,"], ["ma ua le anaana i latou i la'u tulafono.", "and have not kept my law;"]]},
  {num:12,words:[["A o outou,", "And ye have done worse than your fathers;"], ["ua faia e outou amio leaga e sili i o outou tamā;", "for,"], ["faauta foi,", "behold,"], ["ua taitasi le tagata ma savali i le finau vale o lona loto leaga,", "ye walk every one after the imagination of his evil heart,"], ["ua le faalogo mai ia te au.", "that they may not hearken unto me:"]]},
  {num:13,words:[["O lea ou te tutuli ai ia te outou ai lenei nuu i le nuu ua outou le iloa;", "Therefore will I cast you out of this land into a land that ye know not,"], ["o outou po o outou tamā;", "neither ye nor your fathers;"], ["tou te auauna foi i lea mea i atua ese i le ao ma le po;", "and there shall ye serve other gods day and night;"], ["auā ou te le alofa ia te outou.", "where I will not shew you favour."]]},
  {num:14,words:[["A e ui i lea faauta,", "Therefore,"], ["e oo mai ai ona po,", "behold,"], ["o loo fetalai mai ai Ieova,", "the days come, saith the LORD,"], ["e le toe fai ane ai tagata ,", "that it shall no more be said,"], ["O loo soifua Ieova,", "The LORD liveth,"], ["o le na aveina ae le fanauga a Isaraelu nai le nuu o Aikupito;", "that brought up the children of Israel out of the land of Egypt;"]]},
  {num:15,words:[["a e faapea ,", "But,"], ["O loo soifua Ieova,", "The LORD liveth,"], ["o le na aveina ae le fanauga a Isaraelu nai le nuu i le itu i matu, ma nuu uma na ia tulia ai i latou;", "that brought up the children of Israel from the land of the north,"], ["auā ou te faafoisia mai i latou i lo latou laueleele,", "and from all the lands whither he had driven them:"], ["na a'u foaiina atu ai i o latou tamā.", "and I will bring them again into their land that I gave unto their fathers."]]},
  {num:16,words:[["Faauta,", "Behold,"], ["ou te aauina atu tagata fai faiva e toatele,", "I will send for many fishers,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["latou te fai faiva ia te i latou;", "and they shall fish them;"], ["e mulimuli ane ou te aauina atu tagata tuli manu e toatele,", "and after will I send for many hunters,"], ["latou te tutuli ia te i latou mai atu mauga uma,", "and they shall hunt them from every mountain,"], ["ma mauga uma,", "and from every hill,"], ["ma mavaevae o papa.", "and out of the holes of the rocks."]]},
  {num:17,words:[["Auā ua ou vaai i o latou ala uma;", "For mine eyes are upon all their ways:"], ["e le lilo i latou i o'u luma,", "they are not hid from my face,"], ["e le natia foi la latou amioletonu ia te au.", "neither is their iniquity hid from mine eyes."]]},
  {num:18,words:[["A e muamua ona ou taui faaluaina atu la latou amioletonu, ma la latou agasala;", "And first I will recompense their iniquity and their sin double;"], ["auā ua latou faaleagaina lo'u nuu,", "because they have defiled my land,"], ["ua latou faatumuina lo'u tofi i tino o a latou mea leaga, ma a latou mea e inosia.", "they have filled mine inheritance with the carcases of their detestable and abominable things."]]},
  {num:19,words:[["Ieova e,", "O LORD,"], ["o lo'u malosi ma lo'u 'olo,", "my strength,"], ["o lo'u malu foi i le aso o le puapuaga,", "and my fortress,"], ["e o mai ia te oe nuu mai tuluiga o le lalolagi,", "and my refuge in the day of affliction,"], ["ma latou fai mai,", "the Gentiles shall come unto thee from the ends of the earth,"], ["E moni,", "and shall say,"], ["ua fai ma tofi o matou tamā mea pepelo,", "Surely our fathers have inherited lies,"], ["ma mea faatauvaa,", "vanity,"], ["ma mea e le o i ai se aoga.", "and things wherein there is no profit."]]},
  {num:20,words:[["E faia ea e le tagata o atua mo ia,", "Shall a man make gods unto himself,"], ["a e le ni atua i latou?", "and they are no gods?"]]},
  {num:21,words:[["O le mea lea,", "Therefore,"], ["faauta,", "behold,"], ["ou te faailoa atu ai ia te i latou, e atu tasi lava,", "I will this once cause them to know,"], ["ou te faailoa atu ia te i latou lo'u lima ma lo'u malosi;", "I will cause them to know mine hand and my might;"], ["latou te iloa ai o Ieova o lo'u igoa lea.", "and they shall know that my name is The LORD."]]},
];
renderVerseSet(jer_ch_16_Verses, 'jer-ch16-verses');

var jer_ch_17_Verses = [
  {num:1,words:[["Ua tusia le agasala a Iuta i le peni uamea ma le mata o le samira;", "The sin of Judah is written with a pen of iron,"], ["ua togitogi i le papatusi o latou loto,", "and with the point of a diamond: it is graven upon the table of their heart,"], ["ma nifo o outou fata faitaulaga;", "and upon the horns of your altars;"]]},
  {num:2,words:[["a o manatua e a latou fanau o latou fata faitaulaga, ma o latou tupua o Asaira i laau lauolaola i luga o mauga maualuluga.", "Whilst their children remember their altars and their groves by the green trees upon the high hills."]]},
  {num:3,words:[["Lo'u mauga e o i le vao,", "O my mountain in the field,"], ["ou te avatua au mea ma au oloa uma e fai ma vete,", "I will give thy substance and all thy treasures to the spoil, and thy high places for sin,"], ["atoa ma au mea maualuluga e fai ai agasala i lou nuu uma.", "throughout all thy borders."]]},
  {num:4,words:[["O oe lava e tuua ai e oe lou tofi na ou foaiina atu ai ia te oe;", "And thou, even thyself,"], ["ou te tuuina atu foi oe e auauna i e ita ia te oe i le nuu ua e le iloa;", "shalt discontinue from thine heritage that I gave thee; and I will cause thee to serve thine enemies in the land which thou knowest not:"], ["auā ua tugia e outou le afi i lo'u ita e mu ai e faavavau.", "for ye have kindled a fire in mine anger, which shall burn for ever."]]},
  {num:5,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Ia malaia le tagata e faatuatua i tagata,", "Cursed be the man that trusteth in man, and maketh flesh his arm,"], ["ma ua fai tagata mona lima a ua liliu ese lona loto ia Ieova.", "and whose heart departeth from the LORD."]]},
  {num:6,words:[["E avea o ia pei o le tula i le vao,", "For he shall be like the heath in the desert,"], ["na te le iloa foi pe a oo mai mea lelei;", "and shall not see when good cometh;"], ["e mau ai o ia i mea paaa i le vao,", "but shall inhabit the parched places in the wilderness,"], ["o le nuu naumati ma le le āina.", "in a salt land and not inhabited."]]},
  {num:7,words:[["Amuia le tagata o lē faatuatua ia Ieova,", "Blessed is the man that trusteth in the LORD,"], ["o le ua fai Ieova mona faatuatuaga.", "and whose hope the LORD is."]]},
  {num:8,words:[["Auā o ia e faapei o le laau ua totō i tafatafa ane o le vai,", "For he shall be as a tree planted by the waters,"], ["ua sosolo atu ona aa i tafatafa ane o le vaitafe,", "and that spreadeth out her roots by the river,"], ["na te le iloa foi pe a oo mai le vevela,", "and shall not see when heat cometh,"], ["a e lauolaola ona lau;", "but her leaf shall be green;"], ["e le atuatuvale i le tausaga o le la mala,", "and shall not be careful in the year of drought,"], ["e fua mai pea lava ona fua.", "neither shall cease from yielding fruit."]]},
  {num:9,words:[["E sili le faa'ole'ole o le loto i mea uma,", "The heart is deceitful above all things,"], ["ma ua matuā leaga lava;", "and desperately wicked:"], ["po o ai na te mafaia ona iloa?", "who can know it?"]]},
  {num:10,words:[["O a'u o Ieova o lē suesue i le loto,", "I the LORD search the heart,"], ["o lē tofotofo i manatu,", "I try the reins,"], ["ina ia tuuina atu i tagata taitasi e tusa ma ona ala,", "even to give every man according to his ways,"], ["e tusa foi ma le fua o ana amioga.", "and according to the fruit of his doings."]]},
  {num:11,words:[["Ua moe le koli i fua ,", "As the partridge sitteth on eggs,"], ["a e le ni ona fua;", "and hatcheth them not;"], ["e faapea o ia e maua le oa,", "so he that getteth riches,"], ["a e le maua i le amiotonu,", "and not by right,"], ["e tuu e ia ana oa i le tautuluaga o ona aso,", "shall leave them in the midst of his days,"], ["a e avea o ia ma vale i lona gataaga.", "and at his end shall be a fool."]]},
  {num:12,words:[["O le mea o i ai lo tatou malumalu, o le nofoālii mamalu lea ma le maualuga mai le amataga.", "A glorious high throne from the beginning is the place of our sanctuary."]]},
  {num:13,words:[["Ieova e,", "O LORD,"], ["le faamoemoe o Isaraelu,", "the hope of Israel,"], ["e faamaina i latou uma o e lafoai ia te oe;", "all that forsake thee shall be ashamed, and they that depart from me shall be written in the earth,"], ["o i latou e liliu ese ia te au e tusia i latou i le eleele,", "because they have forsaken the LORD,"], ["auā ua lafoaiina e i latou o Ieova le puna o vai ola.", "the fountain of living waters."]]},
  {num:14,words:[["Ieova e,", "Heal me,"], ["ia e faamalolo mai ia te au,", "O LORD,"], ["ona malolo ai lea o a'u;", "and I shall be healed;"], ["ia e faaola mai ia te au,", "save me,"], ["ona faaolaina ai lea o a'u;", "and I shall be saved:"], ["auā o oe ou te vivii i ai.", "for thou art my praise."]]},
  {num:15,words:[["Faauta,", "Behold,"], ["ua latou fai mai ia te au,", "they say unto me,"], ["O fea o i ai le afioga a Ieova? Se'i oo mai lava.", "Where is the word of the LORD? let it come now."]]},
  {num:16,words:[["A o a'u nei,", "As for me,"], ["ua ou le popole ina ia le fai a'u ma leoleo mamoe e mulimuli atu ia te oe;", "I have not hastened from being a pastor to follow thee:"], ["ua ou le manao foi le aso vale, ua silafia e oe;", "neither have I desired the woeful day;"], ["o le mea ua alu atu i o'u laugutu;", "thou knowest:"], ["ua i ou luma lea.", "that which came out of my lips was right before thee."]]},
  {num:17,words:[["Aua ne'i fai oe ma faamatau ia te au;", "Be not a terror unto me:"], ["o oe lo'u malu i le aso vale.", "thou art my hope in the day of evil."]]},
  {num:18,words:[["Ia faamaina i latou o e tuliloa mai ia te au,", "Let them be confounded that persecute me,"], ["a e aua le faamaina a'u;", "but let not me be confounded:"], ["ia matatau i latou,", "let them be dismayed,"], ["a e aua le mata'u o a'u;", "but let not me be dismayed:"], ["ia faaootia ia te i latou le aso vale,", "bring upon them the day of evil,"], ["ma ia faaumatia i latou i le malaia e sautualua.", "and destroy them with double destruction."]]},
  {num:19,words:[["Ua faapea ona fetalai mai o Ieova ia te au,", "Thus said the LORD unto me;"], ["Alu ia,", "Go and stand in the gate of the children of the people,"], ["ina tu i le faitotoa o tagata o le nuu,", "whereby the kings of Judah come in,"], ["e ulu mai ai tupu o Iuta ma o atu ai i latou;", "and by the which they go out,"], ["ia e tu foi i faitotoa uma o Ierusalema;", "and in all the gates of Jerusalem;"]]},
  {num:20,words:[["ma ia e faapea atu ia te i latou,", "And say unto them,"], ["Ia outou faalogologo mai i le afioga a Ieova,", "Hear ye the word of the LORD,"], ["o outou tupu o Iuta,", "ye kings of Judah, and all Judah,"], ["ma Iuta uma atoa ma outou uma o e o nonofo i Ierusalema,", "and all the inhabitants of Jerusalem,"], ["o e ulu mai i nei faitotoa;", "that enter in by these gates:"]]},
  {num:21,words:[["o loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Ia outou ia te outou,", "Take heed to yourselves,"], ["ina ne'i ave se avega i le aso sapati,", "and bear no burden on the sabbath day,"], ["aua foi le au mai ai i faitotoa o Ierusalema;", "nor bring it in by the gates of Jerusalem;"]]},
  {num:22,words:[["aua foi ne'i avatua se avega nai o outou fale i le aso sapati,", "Neither carry forth a burden out of your houses on the sabbath day,"], ["aua foi tou te fai ai se galuega e tasi,", "neither do ye any work,"], ["a ia faapaiaina e outou le aso sapati,", "but hallow ye the sabbath day,"], ["e pei ona ou fai atu ai i o outou tamā.", "as I commanded your fathers."]]},
  {num:23,words:[["A ua latou le faalogo mai,", "But they obeyed not,"], ["ma ua le uai mai o latou taliga,", "neither inclined their ear,"], ["a ua latou faamaaa o latou ua,", "but made their neck stiff,"], ["ina ia latou le faalogo mai,", "that they might not hear,"], ["ma ia le talia mai le aoaiga.", "nor receive instruction."]]},
  {num:24,words:[["Afai foi tou te matuā faalogo mai ia te au,", "And it shall come to pass,"], ["o loo fetalai mai ai Ieova,", "if ye diligently hearken unto me,"], ["ma outou le aumaia se avega i faitotoa o lenei aai i le aso sapati,", "saith the LORD, to bring in no burden through the gates of this city on the sabbath day,"], ["a e faapaiaina e outou le aso sapati,", "but hallow the sabbath day,"], ["ma outou le fai ai se galuega e tasi;", "to do no work therein;"]]},
  {num:25,words:[["ona o mai ai lea i faitotoa o lenei aai o tupu ma alii o nonofo i le nofoālii o Tavita,", "Then shall there enter into the gates of this city kings and princes sitting upon the throne of David,"], ["o tietie i nofoa faataavalevale ma solofanua,", "riding in chariots and on horses,"], ["o i latou,", "they,"], ["ma o latou alii,", "and their princes,"], ["o tagata o Iuta,", "the men of Judah,"], ["ma e o nonofo i Ierusalema;", "and the inhabitants of Jerusalem:"], ["e āina foi lenei aai e faavavau.", "and this city shall remain for ever."]]},
  {num:26,words:[["E o mai i latou mai aai o Iuta,", "And they shall come from the cities of Judah,"], ["ma mea ua vagavagai i Ierusalema,", "and from the places about Jerusalem,"], ["ma le nuu o Peniamina,", "and from the land of Benjamin,"], ["ma le nuu maulalo,", "and from the plain,"], ["ma mauga,", "and from the mountains,"], ["ma le itu i toga,", "and from the south, bringing burnt offerings,"], ["latou te aumaia taulaga mu,", "and sacrifices,"], ["ma taulaga,", "and meat offerings,"], ["ma taulaga i mea e 'ai,", "and incense,"], ["ma pulu lipano,", "and bringing sacrifices of praise,"], ["o i latou foi e au mai taulaga faaneenee i le fale o Ieova.", "unto the house of the LORD."]]},
  {num:27,words:[["A e afai tou te le faalogo mai ia te au,", "But if ye will not hearken unto me to hallow the sabbath day,"], ["ma outou le faapaiaina le aso sapati,", "and not to bear a burden,"], ["a ua ave ai se avega,", "even entering in at the gates of Jerusalem on the sabbath day;"], ["ma ua ulu mai i faitotoa o Ierusalema i le aso sapati;", "then will I kindle a fire in the gates thereof,"], ["ona ou tŭtŭina ai lea o le afi i ona faitotoa e susunuina ai maota o Ierusalema,", "and it shall devour the palaces of Jerusalem,"], ["e le tineia lava.", "and it shall not be quenched."]]},
];
renderVerseSet(jer_ch_17_Verses, 'jer-ch17-verses');

var jer_ch_18_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova,", "The word which came to Jeremiah from the LORD,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Ina tulai ia,", "Arise,"], ["ma alu ifo i le fale o le fai ipu omea,", "and go down to the potter's house,"], ["ona ou faailoa atu ai lea ia te oe i lea mea o a'u upu.", "and there I will cause thee to hear my words."]]},
  {num:3,words:[["Ona ou alu ifo ai lea i le fale o le fai ipu omea,", "Then I went down to the potter's house,"], ["faauta foi,", "and, behold,"], ["o fai e ia lana galuega i luga o mea taavilivili.", "he wrought a work on the wheels."]]},
  {num:4,words:[["Ua leaga le ipu na ia faia i le omea i le lima o le fai ipu omea;", "And the vessel that he made of clay was marred in the hand of the potter: so he made it again another vessel,"], ["ona toe fai ai lea e ia o le tasi ipu e tusa ma le manatu o le fai ipu omea ona fai.", "as seemed good to the potter to make it."]]},
  {num:5,words:[["Ona oo mai lea o le afioga a Ieova ia te au,", "Then the word of the LORD came to me,"], ["ua faapea mai,", "saying,"]]},
  {num:6,words:[["Le aiga o Isaraelu e,", "O house of Israel,"], ["ou te le mafaia ea ona fai ia te outou e pei o lena fai ipu omea? o loo fetalai mai ai Ieova. Faauta,", "cannot I do with you as this potter? saith the LORD. Behold,"], ["le aiga o Isaraelu e,", "as the clay is in the potter's hand,"], ["e pei o le omea i le lima o le fai ipu omea,", "so are ye in mine hand,"], ["e faapea foi outou i lo'u lima.", "O house of Israel."]]},
  {num:7,words:[["O le itu aso ou te tautala atu ai i se nuu,", "At what instant I shall speak concerning a nation,"], ["po o se malo,", "and concerning a kingdom,"], ["ia liaiina,", "to pluck up,"], ["ma lepetia,", "and to pull down,"], ["ma faaumatia;", "and to destroy it;"]]},
  {num:8,words:[["pe afai e liliu mai lea nuu na ou tautala i ai,", "If that nation,"], ["nai la latou amio leaga,", "against whom I have pronounced, turn from their evil,"], ["ona ou salamo ai lea i le malaia na ou manatu e faaoo i ai.", "I will repent of the evil that I thought to do unto them."]]},
  {num:9,words:[["O le itu aso foi ou te tautala atu ai i se nuu,", "And at what instant I shall speak concerning a nation,"], ["po o se malo,", "and concerning a kingdom,"], ["e atiina ae ma faatotōina;", "to build and to plant it;"]]},
  {num:10,words:[["a faia e i latou le amio leaga i o'u luma,", "If it do evil in my sight,"], ["ma latou le faalogo i lo'u leo,", "that it obey not my voice, then I will repent of the good,"], ["ona ou salamo ai lea i le manuia na a'u fai atu ai ou te faamanuiaina ai i latou.", "wherewith I said I would benefit them."]]},
  {num:11,words:[["O lenei,", "Now therefore go to,"], ["ia e fai atu i tagata o Iuta ma e o nonofo i Ierusalema,", "speak to the men of Judah,"], ["ia faapea atu, Ua faapea ona fetalai mai o Ieova,", "and to the inhabitants of Jerusalem,"], ["Faauta,", "saying,"], ["o a'u nei,", "Thus saith the LORD;"], ["ou te sauni atu le malaia ia te outou,", "Behold,"], ["ou te mafaufau foi i se togafiti ia leaga ai outou;", "I frame evil against you,"], ["o lenei, ia outou toe foi mai,", "and devise a device against you:"], ["taitasi le tagata ai lona ala leaga,", "return ye now every one from his evil way,"], ["ma ia outou sauni lelei o outou ala ma a outou amioga.", "and make your ways and your doings good."]]},
  {num:12,words:[["A ua latou fai mai,", "And they said,"], ["E le aoga;", "There is no hope:"], ["auā matou te mulimuli atu i o matou mafaufauga,", "but we will walk after our own devices,"], ["e taitasi foi ma fai e tusa ma le finau vale o lona loto leaga.", "and we will every one do the imagination of his evil heart."]]},
  {num:13,words:[["O le mea lea o loo faapea ona fetalai mai ai o Ieova,", "Therefore thus saith the LORD;"], ["Ia outou fesili atu i nuu ese,", "Ask ye now among the heathen, who hath heard such things:"], ["po o ai ua faalogo i mea faapenei? ua faia e le taupou o Isaraelu le mea e matuā inosia.", "the virgin of Israel hath done a very horrible thing."]]},
  {num:14,words:[["E tuua ea e le kiona o Lepanona le papa i le vao? E pē ea le vai ese, ua mālulu, ua tafe mai?", "Will a man leave the snow of Lebanon which cometh from the rock of the field? or shall the cold flowing waters that come from another place be forsaken?"]]},
  {num:15,words:[["A ua faagalogaloina a'u e lo'u nuu,", "Because my people hath forgotten me,"], ["ua latou faamu mea manogi i le mea faatauvaa,", "they have burned incense to vanity,"], ["ma ua faatausuaiina i latou i o latou ala, o ala o le vavau,", "and they have caused them to stumble in their ways from the ancient paths,"], ["ina ia savavali i ala 'alo,", "to walk in paths,"], ["o le ala e le tanua;", "in a way not cast up;"]]},
  {num:16,words:[["ina ia faia lo latou nuu ma faatafunaga,", "To make their land desolate,"], ["ma mea e uisa ai e faavavau;", "and a perpetual hissing;"], ["o i latou uma e ui ane ai e taitasi ma ofo,", "every one that passeth thereby shall be astonished,"], ["ma lialiai lona ulu.", "and wag his head."]]},
  {num:17,words:[["E pei o le matagi mai sasae ou te faataapeapeina ai i latou i luma o e ita mai;", "I will scatter them as with an east wind before the enemy;"], ["ou te u atu ia te i latou lo'u tua,", "I will shew them the back, and not the face,"], ["a e le o o'u mata i le aso o lo latou malaia.", "in the day of their calamity."]]},
  {num:18,words:[["Ona latou fai ane lea,", "Then said they,"], ["O mai ia,", "Come,"], ["ia tatou filifilia ni togafiti e leaga ai Ieremia;", "and let us devise devices against Jeremiah;"], ["auā e le te'a le tulafono ai le faitaulaga,", "for the law shall not perish from the priest,"], ["po o le mafaufau ai le tagata poto,", "nor counsel from the wise,"], ["po o le upu ai le perofeta. O mai ia,", "nor the word from the prophet. Come,"], ["ia tatou taia o ia i o tatou laulaufaiva;", "and let us smite him with the tongue,"], ["aua foi le liliu atu o tatou taliga i sana upu e tasi.", "and let us not give heed to any of his words."]]},
  {num:19,words:[["Ieova e,", "Give heed to me,"], ["ia liliu mai ou fofoga ia te au,", "O LORD,"], ["ma e faafofoga mai i le leo o e finau mai ia te au.", "and hearken to the voice of them that contend with me."]]},
  {num:20,words:[["E tauia ea le lelei i le leaga? auā ua latou elia le lua ia ou oti ia. Ia e manatua na ou tu i ou luma e tautala mo i latou ia manuia ai,", "Shall evil be recompensed for good? for they have digged a pit for my soul. Remember that I stood before thee to speak good for them,"], ["ina ia faaliliu ese lou toasa ia te i latou.", "and to turn away thy wrath from them."]]},
  {num:21,words:[["O le mea lea ia e tuuina atu ai a latou fanau i le oge,", "Therefore deliver up their children to the famine,"], ["ia tuuina atu foi i latou i le malosi o le pelu;", "and pour out their blood by the force of the sword;"], ["ma ia avea a latou avā ma fafine ua aufanaua,", "and let their wives be bereaved of their children,"], ["ma ia oti a latou tane;", "and be widows;"], ["ma ia fasiotia a latou tane;", "and let their men be put to death;"], ["ma ia fasia o latou taulelea i le pelu i le taua.", "let their young men be slain by the sword in battle."]]},
  {num:22,words:[["Ia lagona le alaga i o latou fale,", "Let a cry be heard from their houses,"], ["pe a e faaoo faafuasei mai le 'au ia te i latou;", "when thou shalt bring a troop suddenly upon them:"], ["auā ua elia e i latou le lua e maua ai a'u,", "for they have digged a pit to take me,"], ["ma ua latou nanā mailei mo o'u vae.", "and hid snares for my feet."]]},
  {num:23,words:[["A o oe,", "Yet,"], ["Ieova e,", "LORD,"], ["ua e silafia a latou pulega uma ia te au ia o'u oti;", "thou knowest all their counsel against me to slay me:"], ["aua le ufitia a latou amioletonu,", "forgive not their iniquity,"], ["aua foi e te sōloiesea a latou agasala i ou luma,", "neither blot out their sin from thy sight,"], ["a ia faatausuaiina i latou i ou luma;", "but let them be overthrown before thee;"], ["ia faapea ona fai ia te i latou i ona po o lou toasa.", "deal thus with them in the time of thine anger."]]},
];
renderVerseSet(jer_ch_18_Verses, 'jer-ch18-verses');

var jer_ch_19_Verses = [
  {num:1,words:[["Ua faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Alu ia,", "Go and get a potter's earthen bottle,"], ["ia e saili se fagu omea a le fai ipu omea, tou te o foi ma nisi toeaina o le nuu,", "and take of the ancients of the people,"], ["ma nisi toeaina o le au faitaulaga;", "and of the ancients of the priests;"]]},
  {num:2,words:[["ma ia alu atu i le vanu o le atalii o Hinoma,", "And go forth unto the valley of the son of Hinnom,"], ["i le mea e ui ai i le faitotoa o le fai ipu omea,", "which is by the entry of the east gate,"], ["ma ia e tala'i atu i lea mea o upu ou te fai atu ai ia te oe.", "and proclaim there the words that I shall tell thee,"]]},
  {num:3,words:[["Ia e faapea atu,", "And say,"], ["O outou tupu o Iuta,", "Hear ye the word of the LORD,"], ["ma e o nonofo i Ierusalema,", "O kings of Judah,"], ["ia outou faalogologo mai i le afioga a Ieova;", "and inhabitants of Jerusalem;"], ["o loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts, the God of Israel;"], ["le Atua o Isaraelu,", "Behold,"], ["Faauta,", "I will bring evil upon this place,"], ["ou te faaoo mai le malaia i lenei mea,", "the which whosoever heareth,"], ["e taitasi uma o e faalogologo ai ma taalili ai ona taliga.", "his ears shall tingle."]]},
  {num:4,words:[["Aua ua latou tuua a'u,", "Because they have forsaken me,"], ["ua latou liua foi lenei mea,", "and have estranged this place,"], ["ma ua latou faamu ai mea manogi i atua ese na latou le iloa, o i latou,", "and have burned incense in it unto other gods,"], ["po o latou tamā,", "whom neither they nor their fathers have known,"], ["po o tupu o Iuta;", "nor the kings of Judah,"], ["ma ua latou faatumuina lenei mea i le toto o e le sala.", "and have filled this place with the blood of innocents;"]]},
  {num:5,words:[["Ua faia e i latou o mea maualuluga a Paala e susunu ai a latou fanau i le afi e fai ma taulaga mu ia Paala;", "They have built also the high places of Baal,"], ["o le mea na ou le poloai atu ai,", "to burn their sons with fire for burnt offerings unto Baal,"], ["pe fai atu ai,", "which I commanded not, nor spake it,"], ["ou te lei manatu foi i ai.", "neither came it into my mind:"]]},
  {num:6,words:[["O le mea lea faauta,", "Therefore,"], ["o le a oo mai ai ona po,", "behold,"], ["o loo fetalai mai ai Ieova,", "the days come, saith the LORD,"], ["e le toe igoa ai lea mea o Tofeta,", "that this place shall no more be called Tophet,"], ["po o le vanu o le atalii o Hinoma,", "nor The valley of the son of Hinnom,"], ["a o le vanu o le fasi.", "but The valley of slaughter."]]},
  {num:7,words:[["Ou te faaleaogaina le pule a Iuta ma Ierusalema i lenei mea;", "And I will make void the counsel of Judah and Jerusalem in this place;"], ["ou te tuuina foi i latou ia fāsia i le pelu i luma o e ita ia i latou,", "and I will cause them to fall by the sword before their enemies,"], ["ma lima o e sailiili ia i latou ia oti;", "and by the hands of them that seek their lives: and their carcases will I give to be meat for the fowls of the heaven,"], ["ou te tuuina atu foi o latou tino ua oti e fai ma mea e 'ai a manu felelei ma manu e tataa.", "and for the beasts of the earth."]]},
  {num:8,words:[["Ou te fai foi lenei aai ma faatafunaga,", "And I will make this city desolate,"], ["ma mea e uisa ai;", "and an hissing;"], ["o i latou uma e ui ane ai e taitasi ma ofo ma uisa i ona mala uma.", "every one that passeth thereby shall be astonished and hiss because of all the plagues thereof."]]},
  {num:9,words:[["Ou te fagaina i latou i tino o latou atalii ma tino o latou afafine,", "And I will cause them to eat the flesh of their sons and the flesh of their daughters,"], ["e taitasi foi o i latou ma 'ai i le tino o le tasi ina ua siosioina,", "and they shall eat every one the flesh of his friend in the siege and straitness,"], ["ma tigaina e faatigateleina ai i latou e i latou ua ita mai,", "wherewith their enemies, and they that seek their lives,"], ["ma e ua saili ia i latou ia oti.", "shall straiten them."]]},
  {num:10,words:[["Ona e nutililii ai lea o le fagu i luma o tagata latou te o ma oe,", "Then shalt thou break the bottle in the sight of the men that go with thee,"]]},
  {num:11,words:[["ma e fai atu ia te i latou,", "And shalt say unto them,"], ["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts;"], ["E faapea lava ona ou nutililii i lenei nuu ma lenei aai,", "Even so will I break this people and this city, as one breaketh a potter's vessel,"], ["e pei ona nutililii e se tasi le ipu a le fai ipu omea,", "that cannot be made whole again:"], ["e le mafai ona toe faia;", "and they shall bury them in Tophet,"], ["e tanumia foi i latou i Tofeta seia le toe ai se mea e tanu ai.", "till there be no place to bury."]]},
  {num:12,words:[["E faapea ona ou faia i lenei nuu,", "Thus will I do unto this place,"], ["ma e o nonofo ai,", "saith the LORD,"], ["o loo fetalai mai ai Ieova,", "and to the inhabitants thereof,"], ["ma ou faia lenei aai ia pei o Tofeta;", "and even make this city as Tophet:"]]},
  {num:13,words:[["e avea foi fale o Ierusalema,", "And the houses of Jerusalem,"], ["ma maota o tupu o Iuta,", "and the houses of the kings of Judah,"], ["e pei o le mea e ta'ua o Tofeta,", "shall be defiled as the place of Tophet,"], ["ua leaga ia auā ua latou faamu mea manogi i luga o latou fale uma i 'au uma o le lagi,", "because of all the houses upon whose roofs they have burned incense unto all the host of heaven,"], ["ma ua latou liligi atu taulaga i mea e inu i atua ese.", "and have poured out drink offerings unto other gods."]]},
  {num:14,words:[["Ona sau ai lea o Ieremia mai Tofeta na auina atu ai o ia e Ieova e vavalo ai;", "Then came Jeremiah from Tophet,"], ["na tu o ia i le lotoā o le fale o Ieova,", "whither the LORD had sent him to prophesy; and he stood in the court of the LORD'S house;"], ["ma ua fai atu i le nuu uma.", "and said to all the people,"]]},
  {num:15,words:[["Ua faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Faauta, ou te faaoo mai i lenei aai,", "Behold,"], ["ma ona faoa aai uma le malaia uma na ou fai atu ai;", "I will bring upon this city and upon all her towns all the evil that I have pronounced against it,"], ["auā ua latou faamaaa o latou ua,", "because they have hardened their necks,"], ["ina ia latou le faalogologo ai i a'u upu.", "that they might not hear my words."]]},
];
renderVerseSet(jer_ch_19_Verses, 'jer-ch19-verses');

var jer_ch_20_Verses = [
  {num:1,words:[["Ua faalogologo Pasura, le atalii o Imere,", "Now Pashur the son of Immer the priest,"], ["le faitaulaga,", "who was also chief governor in the house of the LORD,"], ["o le matai sili ia i le fale o Ieova, ua vavalo Ieremia i ia upu.", "heard that Jeremiah prophesied these things."]]},
  {num:2,words:[["Ona taia lea o le perofeta o Ieremia e Pasura,", "Then Pashur smote Jeremiah the prophet,"], ["ma ua tuuina o ia i laau faamau, sa i le faitotoa aupitoaluga o Peniamina,", "and put him in the stocks that were in the high gate of Benjamin,"], ["e lata ane i le fale o Ieova.", "which was by the house of the LORD."]]},
  {num:3,words:[["Ua oo i le taeao,", "And it came to pass on the morrow,"], ["ona aumaia lea e Pasura o Ieremia nai laau faamau. Ona fai atu lea o Ieremia ia te ia,", "that Pashur brought forth Jeremiah out of the stocks. Then said Jeremiah unto him,"], ["Ua le ta'ua lou igoa e Ieova o Pasura,", "The LORD hath not called thy name Pashur,"], ["a o Makoru-misapipa.", "but Magor-missabib."]]},
  {num:4,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD,"], ["Faauta,", "Behold,"], ["ou te faia oe ma mata'u ia te oe,", "I will make thee a terror to thyself,"], ["ma au uo uma;", "and to all thy friends:"], ["e oti i latou i le pelu a ē ita mai ia te i latou,", "and they shall fall by the sword of their enemies,"], ["e iloa foi e ou mata;", "and thine eyes shall behold it:"], ["ou te tuuina atu foi Iuta uma i le lima o le tupu o Papelonia,", "and I will give all Judah into the hand of the king of Babylon,"], ["e tāfea foi i latou e ia i Papelonia,", "and he shall carry them captive into Babylon,"], ["ma fasia i latou i le pelu.", "and shall slay them with the sword."]]},
  {num:5,words:[["Ou te tuuina atu foi le oloa uma o lenei aai,", "Moreover I will deliver all the strength of this city,"], ["ma mea uma o i ai sa tautigaina ai,", "and all the labours thereof,"], ["ma oloa tāua uma o i ai,", "and all the precious things thereof,"], ["ma oa uma a tupu o Iuta ou te tuuina atu lava i lima o e ita mai ia te i latou,", "and all the treasures of the kings of Judah will I give into the hand of their enemies,"], ["latou te vetea,", "which shall spoil them,"], ["ma avea,", "and take them,"], ["ma la'u atu ai i Papelonia.", "and carry them to Babylon."]]},
  {num:6,words:[["A o oe,", "And thou,"], ["Pasura e,", "Pashur,"], ["ma lou 'au aiga uma,", "and all that dwell in thine house shall go into captivity:"], ["e ō outou i le tafeaga;", "and thou shalt come to Babylon,"], ["e oo foi oe i Papelonia,", "and there thou shalt die,"], ["e te oti ai lava,", "and shalt be buried there,"], ["e tanumia foi oe i lea mea,", "thou,"], ["o oe ma au uo uma,", "and all thy friends,"], ["o i latou na e vavalo i ai mea pepelo.", "to whom thou hast prophesied lies."]]},
  {num:7,words:[["Ieova e,", "O LORD,"], ["ua e faaoleole ia te au,", "thou hast deceived me,"], ["ona faaoleoleina lea o a'u;", "and I was deceived:"], ["ua sili ona e malosi ia te au,", "thou art stronger than I,"], ["ma ua e manumalo;", "and hast prevailed:"], ["ua fai a'u ma mea e tapisa ai i aso uma,", "I am in derision daily,"], ["ua tauemu mai ia te au tagata uma.", "every one mocketh me."]]},
  {num:8,words:[["Auā a ou tautala atu,", "For since I spake,"], ["ua ou alaga,", "I cried out,"], ["ua ou valaau,", "I cried violence and spoil;"], ["o le saua ma le faatafunaga;", "because the word of the LORD was made a reproach unto me,"], ["auā ua avea le afioga a Ieova ma mea e faalumaina ai a'u,", "and a derision,"], ["ma tauemua i aso uma.", "daily."]]},
  {num:9,words:[["Ona ou fai atu lea,", "Then I said,"], ["Ou te le ta'uta'uina o ia,", "I will not make mention of him,"], ["ma ou le toe tautala i lona suafa.", "nor speak any more in his name."], ["A o lo'u loto e peiseai o se afi mumū sa i ai,", "But his word was in mine heart as a burning fire shut up in my bones,"], ["ua punitia i o'u ivi, ua lailoa a'u i onosai,", "and I was weary with forbearing,"], ["ua ou le mafaia lava.", "and I could not stay."]]},
  {num:10,words:[["Auā ua ou faalogo i le faaleaga mai a le toatele,", "For I heard the defaming of many,"], ["ua siomia a'u i le mata'u,", "fear on every side. Report,"], ["ua fai ane i latou ,", "say they,"], ["Ina outou ta'uta'uina atu o ia,", "and we will report it. All my familiars watched for my halting,"], ["matou te ta'uta'uina atu foi o ia. O tagata uma o a'u uo o lamalama mai pea ia te au, ua faapea,", "saying,"], ["Atonu e faaoleoleina o ia,", "Peradventure he will be enticed,"], ["ma tatou manumalo ia te ia,", "and we shall prevail against him,"], ["ma tatou taui ma sui ia te ia.", "and we shall take our revenge on him."]]},
  {num:11,words:[["A ua ia te au Ieova e pei o le toa e matautia;", "But the LORD is with me as a mighty terrible one:"], ["o le mea lea e tausuai ai e o tuliloa mai ia te au,", "therefore my persecutors shall stumble,"], ["e le manumalo i latou;", "and they shall not prevail:"], ["e matuā faamaina i latou;", "they shall be greatly ashamed;"], ["auā e le manuia i latou;", "for they shall not prosper:"], ["e le faagalogaloina lo latou masiasi e faavavau.", "their everlasting confusion shall never be forgotten."]]},
  {num:12,words:[["Ieova o 'au e,", "But,"], ["o lē tofotofo i e ua amiotonu,", "O LORD of hosts,"], ["o lē silasila i manatu ma loto,", "that triest the righteous, and seest the reins and the heart,"], ["ia ou iloa lau taui ma sui ia te i latou;", "let me see thy vengeance on them:"], ["auā ua ou faaalia la'u finauga ia te oe.", "for unto thee have I opened my cause."]]},
  {num:13,words:[["Ina pepese ia ia Ioeva,", "Sing unto the LORD,"], ["ia outou vivii atu ia Ieova;", "praise ye the LORD:"], ["auā ua laveaiina e ia ia ola le ua mativa ai lima o e amio leaga.", "for he hath delivered the soul of the poor from the hand of evildoers."]]},
  {num:14,words:[["Ia faafanoina le aso na fanau mai ai a'u;", "Cursed be the day wherein I was born:"], ["aua le faamanuiaina le aso na fanauina ai a'u e lo'u tinā.", "let not the day wherein my mother bare me be blessed."]]},
  {num:15,words:[["Ia faafanoina le tagata na avatu le tala i lo'u tamā,", "Cursed be the man who brought tidings to my father,"], ["na faapea atu,", "saying,"], ["Ua fanau ia te oe le tama tane;", "A man child is born unto thee;"], ["ua matuā faafiafia ia te ia.", "making him very glad."]]},
  {num:16,words:[["Ia avea lea tagata e pei o aai na faaumatia e Ieova,", "And let that man be as the cities which the LORD overthrew,"], ["ma ua le salamo ai o ia;", "and repented not:"], ["ia faalogo foi e ia i le alaga i le taeao,", "and let him hear the cry in the morning,"], ["ma le vāvāō i le tutonu o le la;", "and the shouting at noontide;"]]},
  {num:17,words:[["auā na le fasiotia a'u ina o i le manava;", "Because he slew me not from the womb;"], ["po ua avea lo'u tinā ma tuugamau ia te au,", "or that my mother might have been my grave,"], ["ma lona manava e to pea e faavavau.", "and her womb to be always great with me."]]},
  {num:18,words:[["Se a le mea na ou sau ai mai le manava e iloa ai le tiga ma le faanoanoa,", "Wherefore came I forth out of the womb to see labour and sorrow,"], ["e mavae ai foi o'u aso ma le mā?", "that my days should be consumed with shame?"]]},
];
renderVerseSet(jer_ch_20_Verses, 'jer-ch20-verses');

var jer_ch_21_Verses = [
  {num:1,words:[["O le afioga a Ieova na oo ia Ieremia,", "The word which came unto Jeremiah from the LORD,"], ["ina o aauina atu ia te ia e le tupu o Setekaia o Pasura le atalii o Malekia,", "when king Zedekiah sent unto him Pashur the son of Melchiah,"], ["atoa ma Sefanaia le atalii o Maaseia le faitaulaga,", "and Zephaniah the son of Maaseiah the priest,"], ["ua faapea atu,", "saying,"]]},
  {num:2,words:[["Se'i e fesili atu ia Ieova mo i tatou;", "Enquire, I pray thee,"], ["auā o loo ua sii mai le taua ia te i tatou e Nepukanesa le tupu o Papelonia;", "of the LORD for us;"], ["atonu e faia e Ieova ia te i tatou e tusa ma ona vavega uma,", "for Nebuchadrezzar king of Babylon maketh war against us;"], ["ina ia alu ese ai o ia ia te i tatou.", "if so be that the LORD will deal with us according to all his wondrous works, that he may go up from us."]]},
  {num:3,words:[["Ona fai mai ai lea o Ieremia ia te i latou,", "Then said Jeremiah unto them,"], ["Ia faapea ona outou fai atu ia Setekaia,", "Thus shall ye say to Zedekiah:"]]},
  {num:4,words:[["O loo faapea ona fetalai mai o Ieova le Atua o Isaraelu,", "Thus saith the LORD God of Israel;"], ["Faauta,", "Behold,"], ["ou te faaliliueseina auupega o le taua o i o outou lima,", "I will turn back the weapons of war that are in your hands, wherewith ye fight against the king of Babylon,"], ["ua outou tau a'i ma le tupu o Papelonia ma tagata o Kaletaia,", "and against the Chaldeans,"], ["o e vagaia outou i tuapa,", "which besiege you without the walls,"], ["ma ou faapotopoto ia te i latou i totonu o lenei aai.", "and I will assemble them into the midst of this city."]]},
  {num:5,words:[["O a'u nei foi, ou te tau ma outou i le lima faaloaloa,", "And I myself will fight against you with an outstretched hand and with a strong arm,"], ["ma le lima malosi,", "even in anger,"], ["o le tiga foi,", "and in fury,"], ["ma le ita, ma le ita tele.", "and in great wrath."]]},
  {num:6,words:[["Ou te taia e o nonofo i lenei aai,", "And I will smite the inhabitants of this city,"], ["o tagata atoa ma manu,", "both man and beast:"], ["e oti i latou i le faamai tele.", "they shall die of a great pestilence."]]},
  {num:7,words:[["O loo fetalai mai Ieova,", "And afterward,"], ["E mulimuli ane ou te tuuina atu Setekaia le tupu o Iuta,", "saith the LORD,"], ["ma ana auauna,", "I will deliver Zedekiah king of Judah,"], ["ma le nuu,", "and his servants,"], ["ma e o totoe i lenei aai i le faamai,", "and the people,"], ["ma le pelu,", "and such as are left in this city from the pestilence,"], ["ma le oge,", "from the sword, and from the famine,"], ["i le lima o Nepukanesa le tupu o Papelonia,", "into the hand of Nebuchadrezzar king of Babylon,"], ["ma lima o e ita ia te i latou,", "and into the hand of their enemies,"], ["ma lima o e sailiili ia te i latou ia oti;", "and into the hand of those that seek their life:"], ["e fasia i latou i le pelu,", "and he shall smite them with the edge of the sword;"], ["e le faasaoina e ia o i latou,", "he shall not spare them,"], ["e le faapelepele,", "neither have pity,"], ["e le alofa lava.", "nor have mercy."]]},
  {num:8,words:[["E te fai atu foi i lenei nuu,", "And unto this people thou shalt say,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Faauta,", "Behold,"], ["ou te tuuina atu i o outou luma le ala o le ola,", "I set before you the way of life,"], ["ma le ala o le oti.", "and the way of death."]]},
  {num:9,words:[["O lē nofo i lenei aai e oti o ia i le pelu,", "He that abideth in this city shall die by the sword,"], ["ma le oge,", "and by the famine,"], ["ma le faamai;", "and by the pestilence:"], ["a o lē alu atu,", "but he that goeth out,"], ["ma vavae atu i tagata o Kaletaia o e vagaia outou,", "and falleth to the Chaldeans that besiege you,"], ["e ola o ia,", "he shall live,"], ["e avea foi lona ola ma ana vete.", "and his life shall be unto him for a prey."]]},
  {num:10,words:[["Auā ou te faasaga atu i lenei aai ia leaga ai,", "For I have set my face against this city for evil,"], ["a e le ina ia manuia ai,", "and not for good,"], ["o loo fetalai mai ai Ieova;", "saith the LORD:"], ["e tuuina atu ai i le lima o le tupu o Papelonia,", "it shall be given into the hand of the king of Babylon,"], ["e susunuina foi e ia i le afi.", "and he shall burn it with fire."]]},
  {num:11,words:[["A ia e fai atu i le aiga o le tupu o Iuta,", "And touching the house of the king of Judah, say,"], ["Ina faalogologo ia outou i le afioga a Ieova;", "Hear ye the word of the LORD;"]]},
  {num:12,words:[["Le aiga o Tavita e,", "O house of David,"], ["o loo faapea ona fetalai mai o Ieova,", "thus saith the LORD;"], ["Ia faia le faamasinoga i le taeao,", "Execute judgment in the morning,"], ["ma ia laveaiina le ua faoa ana mea ai le lima o le tagata saua, ina ne'i alu atu lo'u ita e pei o le afi,", "and deliver him that is spoiled out of the hand of the oppressor,"], ["ma mu ai,", "lest my fury go out like fire,"], ["a e le mafai ona tineia e se tasi,", "and burn that none can quench it,"], ["ona o le leaga o a outou amioga.", "because of the evil of your doings."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["o oe lē nofo i le vanu,", "I am against thee,"], ["o le papa o i le mea laugatasi,", "O inhabitant of the valley,"], ["ua ou tiga ia te oe,", "and rock of the plain,"], ["o loo fetalai mai ai Ieova;", "saith the LORD;"], ["o e fai ane,", "which say,"], ["Po o ai ea e o ifo e tau ma i tatou? po o ai foi e ulufale mai i o tatou fale?", "Who shall come down against us? or who shall enter into our habitations?"]]},
  {num:14,words:[["Ou te taui atu ia te outou e tusa ma le fua o a outou amioga,", "But I will punish you according to the fruit of your doings,"], ["o loo fetalai mai ai Ieova;", "saith the LORD:"], ["ou te faamuina foi le afi i lona vao,", "and I will kindle a fire in the forest thereof,"], ["e faaumatia ai foi ona itu uma.", "and it shall devour all things round about it."]]},
];
renderVerseSet(jer_ch_21_Verses, 'jer-ch21-verses');

var jer_ch_22_Verses = [
  {num:1,words:[["Ua faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Ina e alu ifo ia i le fale o le tupu o Iuta,", "Go down to the house of the king of Judah,"], ["ma ia e fai atu lenei upu i lea mea,", "and speak there this word,"]]},
  {num:2,words:[["ia e faapea atu,", "And say,"], ["Ia outou faalogologo mai i le afioga a Ieova,", "Hear the word of the LORD,"], ["o oe le tupu o Iuta,", "O king of Judah, that sittest upon the throne of David,"], ["o lē tietie i le nofoālii o Tavita,", "thou,"], ["ma au auauna,", "and thy servants,"], ["ma lou nuu o e ulu mai i nei faitotoa;", "and thy people that enter in by these gates:"]]},
  {num:3,words:[["o loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Ia outou faia le faamasinoga ma le amiotonu,", "Execute ye judgment and righteousness,"], ["ma ia laveaiina le ua faoa ana mea ai le lima o le tagata saua;", "and deliver the spoiled out of the hand of the oppressor:"], ["aua le agaleaga atu,", "and do no wrong,"], ["aua le faasaua atu i le tagata ese,", "do no violence to the stranger,"], ["ma le ua mātuaoti,", "the fatherless,"], ["ma le fafine ua oti lana tane;", "nor the widow,"], ["aua foi tou te faamaligiina i lenei mea le toto o e ua le sala.", "neither shed innocent blood in this place."]]},
  {num:4,words:[["Auā afai tou te matuā faia lenei mea,", "For if ye do this thing indeed,"], ["ona ulufale mai ai lea i faitotoa o lenei fale o tupu o e tietie i le nofoālii o Tavita,", "then shall there enter in by the gates of this house kings sitting upon the throne of David,"], ["o tietie i nofoa faataavalevale ma solofanua,", "riding in chariots and on horses, he,"], ["e taitasi ma ana auauna,", "and his servants,"], ["ma lona nuu.", "and his people."]]},
  {num:5,words:[["A e afai tou te le faalogo i nei upu,", "But if ye will not hear these words,"], ["ou te tauto a'u ia te au,", "I swear by myself,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["e avea lenei fale ma faatafunaga.", "that this house shall become a desolation."]]},
  {num:6,words:[["Auā ua faapea ona fetalai mai o Ieova,", "For thus saith the LORD unto the king's house of Judah;"], ["i mea a oo i le aiga o le tupu o Iuta, Ua o Kiliata oe ia te au,", "Thou art Gilead unto me,"], ["o le tumutumu o Lepanona;", "and the head of Lebanon:"], ["a e peitai e moni, ou te faia oe ma vao,", "yet surely I will make thee a wilderness,"], ["o aai e le āina.", "and cities which are not inhabited."]]},
  {num:7,words:[["Ou te tofia tagata faaumatia mea ia tiga ai oe,", "And I will prepare destroyers against thee,"], ["e taitasi le tagata ma ana auupega;", "every one with his weapons:"], ["latou te tatuuina o ou arasi silisili,", "and they shall cut down thy choice cedars,"], ["ma lafo i le afi.", "and cast them into the fire."]]},
  {num:8,words:[["E tele nuu e ui ane i lenei aai,", "And many nations shall pass by this city,"], ["ma fai ane le tasi i le tasi,", "and they shall say every man to his neighbour,"], ["Se a le mea ua faapea ai ona fai e Ieova i lenei aai tele?", "Wherefore hath the LORD done thus unto this great city?"]]},
  {num:9,words:[["Ona fai atu ai lea e i latou,", "Then they shall answer,"], ["Auā ua tuua e i latou le feagaiga a Ieova lo latou Atua,", "Because they have forsaken the covenant of the LORD their God,"], ["a ua latou ifo i atua ese,", "and worshipped other gods,"], ["ma auauna i ai.", "and served them."]]},
  {num:10,words:[["Aua tou te fetagisi ona o le ua oti,", "Weep ye not for the dead,"], ["aua le faanoanoa ona o ia;", "neither bemoan him:"], ["a ia tagi tele ona o lē alu ese;", "but weep sore for him that goeth away:"], ["auā e le toe foi mai o ia,", "for he shall return no more,"], ["e le toe iloa foi e ia le nuu na fanau ai o ia.", "nor see his native country."]]},
  {num:11,words:[["Auā ua faapea ona fetalai mai o Ieova ia Saluma le atalii o Iosia le tupu o Iuta,", "For thus saith the LORD touching Shallum the son of Josiah king of Judah,"], ["o le na fai ma tupu e sui a'i Iosia lona tamā,", "which reigned instead of Josiah his father,"], ["o le ua alu atu nai le mea nei;", "which went forth out of this place;"], ["e le toe foi mai o ia i lea mea;", "He shall not return thither any more:"]]},
  {num:12,words:[["auā e oti o ia i le mea ua latou avea ai o ia,", "But he shall die in the place whither they have led him captive,"], ["a e le toe iloa mai e ia lenei nuu.", "and shall see this land no more."]]},
  {num:13,words:[["Oi talofa i le ua faia lona fale ma le amioletonu,", "Woe unto him that buildeth his house by unrighteousness,"], ["ma ua faia ona potu aupitoaluga ma le amio le tatau;", "and his chambers by wrong;"], ["ua fai fua e ia mana auauna lē la te tuaoi,", "that useth his neighbour's service without wages,"], ["ma ua le avatu ia te ia lona totogi;", "and giveth him not for his work;"]]},
  {num:14,words:[["ua faapea ane o ia,", "That saith,"], ["Ou te faia mo a'u le fale tele,", "I will build me a wide house and large chambers,"], ["ma potualuga e tetele; ua faia foi faamalama mo ia,", "and cutteth him out windows;"], ["ma ua tapapa i arasi,", "and it is cieled with cedar,"], ["ma vali i le vali mūmū.", "and painted with vermilion."]]},
  {num:15,words:[["E fai ea oe ma tupu ina ua e finau e fai fale arasi? O lou tamā na le 'ai ea o ia ma inu,", "Shalt thou reign, because thou closest thyself in cedar? did not thy father eat and drink,"], ["ma faia le faamasinoga ma le amiotonu? ona manuia ai lea o ia.", "and do judgment and justice, and then it was well with him?"]]},
  {num:16,words:[["Na faatonuina e ia le finauga o e ua puapuagaina ma e ua matitiva;", "He judged the cause of the poor and needy; then it was well with him:"], ["ona manuia ai lea o ia. E le o le iloa ea o a'u lena? o loo fetalai mai ai Ieova.", "was not this to know me? saith the LORD."]]},
  {num:17,words:[["A ua na ona faasaga o ou mata ma lou loto i lau oloa,", "But thine eyes and thine heart are not but for thy covetousness,"], ["ma le faamaligiina o le toto o le ua le sala,", "and for to shed innocent blood,"], ["ma le faasaua,", "and for oppression,"], ["ma le faatigaina,", "and for violence,"], ["ia faia.", "to do it."]]},
  {num:18,words:[["O le mea lea o loo faapea ona fetalai mai ai o Ieova i mea a oo ia Ioakima le atalii o Iosia,", "Therefore thus saith the LORD concerning Jehoiakim the son of Josiah king of Judah;"], ["le tupu o Iuta,", "They shall not lament for him, saying,"], ["Latou te le taufaitagitu'i ia te ia,", "Ah my brother! or,"], ["e faapea ,", "Ah sister! they shall not lament for him,"], ["Aue! lo'u uso e. Aue! le tuafafine e. Latou te le taufaitagitu'i ia te ia e faapea ,", "saying, Ah lord! or,"], ["Aue! le alii e. Aue! le mamalu e.", "Ah his glory!"]]},
  {num:19,words:[["E tanumia o ia e pei ona tanua o le asini;", "He shall be buried with the burial of an ass,"], ["e tosina ma tiaiina i tua o faitotoa o Ierusalema.", "drawn and cast forth beyond the gates of Jerusalem."]]},
  {num:20,words:[["Ina alu ae ia i Lepanona,", "Go up to Lebanon,"], ["ma alaga,", "and cry;"], ["ia e leo tele i Vasana,", "and lift up thy voice in Bashan,"], ["ia e alaga foi mai Aperima;", "and cry from the passages:"], ["auā ua faaumatia o i latou uma sa mananao ia te oe.", "for all thy lovers are destroyed."]]},
  {num:21,words:[["Na a'u fai atu ia te oe ina o ē manuia;", "I spake unto thee in thy prosperity;"], ["a ua e fai mai,", "but thou saidst,"], ["Ou te le faalogo atu. O lau masani lea talu ina e itiiti,", "I will not hear. This hath been thy manner from thy youth,"], ["ua e le faalogo i lo'u leo.", "that thou obeyedst not my voice."]]},
  {num:22,words:[["E fagaina au leoleo mamoe uma i le matagi;", "The wind shall eat up all thy pastors,"], ["e ō i le tafeaga o e mananao ia te oe; ona e mā ai lava lea,", "and thy lovers shall go into captivity:"], ["ma masiasi ona o au amio leaga uma.", "surely then shalt thou be ashamed and confounded for all thy wickedness."]]},
  {num:23,words:[["O oe na lē mau i Lepanona,", "O inhabitant of Lebanon,"], ["ma fai lou ofaga i arasi,", "that makest thy nest in the cedars,"], ["talofa lava ia te oe pe a oo ia te oe le faatiga,", "how gracious shalt thou be when pangs come upon thee,"], ["o le tiga e pei o le fafine a fanau mai.", "the pain as of a woman in travail!"]]},
  {num:24,words:[["O loo fetalai mai Ieova,", "As I live,"], ["O loo ola a'u,", "saith the LORD,"], ["pe afai ana fai Konia le atalii o Ioakima le tupu o Iuta ma faamaufaailoga i lo'u lima taumatau;", "though Coniah the son of Jehoiakim king of Judah were the signet upon my right hand,"], ["a ou te se'iesea oe ai lea mea.", "yet would I pluck thee thence;"]]},
  {num:25,words:[["Ou te tuuina atu foi oe i lima o e saili ia te oe ia oti,", "And I will give thee into the hand of them that seek thy life,"], ["ma lima o i latou ua e mata'u i ai,", "and into the hand of them whose face thou fearest,"], ["o le lima foi o Nepukanesa le tupu o Papelonia,", "even into the hand of Nebuchadrezzar king of Babylon,"], ["ma lima o tagata o Kaletaia.", "and into the hand of the Chaldeans."]]},
  {num:26,words:[["Ou te tutuli ia te oulua ma lou tinā na fanaua oe e ō i le nuu ese na le fananau ai oulua;", "And I will cast thee out, and thy mother that bare thee,"], ["e oti foi oulua i lea mea.", "into another country, where ye were not born; and there shall ye die."]]},
  {num:27,words:[["A o le nuu ua naunau o latou loto e toe foi mai i ai,", "But to the land whereunto they desire to return,"], ["latou te le toe foi mai lava i ai.", "thither shall they not return."]]},
  {num:28,words:[["O le ipu inosia ea ma le taeia lenei tagata o Konia? O le ipu ea o ia ua le fiafia i ai? Se a le mea ua tulia ai i latou,", "Is this man Coniah a despised broken idol? is he a vessel wherein is no pleasure? wherefore are they cast out,"], ["o ia, ma lana fanau,", "he and his seed,"], ["ma ua lafoaiina i latou i le nuu na latou le iloa?", "and are cast into a land which they know not?"]]},
  {num:29,words:[["Le lalolagi e,", "O earth,"], ["le lalolagi e,", "earth,"], ["le lalolagi e,", "earth,"], ["ina faalogologo mai ia i le afioga a Ieova.", "hear the word of the LORD."]]},
  {num:30,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Ia outou tusia lenei tagata e aufanaua,", "Write ye this man childless,"], ["o le tagata e le manuia i lona olaga;", "a man that shall not prosper in his days:"], ["auā e le manuia se tasi o lana fanau,", "for no man of his seed shall prosper,"], ["e le tietie i le nofoālii o Tavita,", "sitting upon the throne of David,"], ["pe toe pule i Iuta.", "and ruling any more in Judah."]]},
];
renderVerseSet(jer_ch_22_Verses, 'jer-ch22-verses');

var jer_ch_23_Verses = [
  {num:1,words:[["Oi talofa i le au leoleo mamoe o e ua fano ai ma faataapeapeina mamoe na ou fagaina! o loo fetalai mai ai Ieova.", "Woe be unto the pastors that destroy and scatter the sheep of my pasture! saith the LORD."]]},
  {num:2,words:[["O le mea lea ua faapea ona fetalai mai ai o Ieova le Atua o Isaraelu i le au leoleo mamoe o e leoleo i lo'u nuu,", "Therefore thus saith the LORD God of Israel against the pastors that feed my people;"], ["Ua outou faataapeapeina la'u lafu mamoe,", "Ye have scattered my flock,"], ["ma tulia i latou,", "and driven them away,"], ["ma ua le asiasi ia te i latou;", "and have not visited them:"], ["faauta,", "behold,"], ["ou te taui atu ia te outou ona o le leaga o a outou amioga,", "I will visit upon you the evil of your doings,"], ["o loo fetalai mai ai Ieova,", "saith the LORD."]]},
  {num:3,words:[["Ou te faapotopoto foi i e totoe o la'u lafu mamoe mai nuu uma na ou tulia ai i latou,", "And I will gather the remnant of my flock out of all countries whither I have driven them,"], ["ma ou toe faafoi mai ia te i latou i o latou lotoā;", "and will bring them again to their folds;"], ["latou te fanafanau ai ma uluola ai.", "and they shall be fruitful and increase."]]},
  {num:4,words:[["Ou te tofia foi mo i latou o leoleo mamoe e leoleo ia te i latou;", "And I will set up shepherds over them which shall feed them:"], ["latou te le toe fefefe,", "and they shall fear no more,"], ["latou te le matatau foi,", "nor be dismayed, neither shall they be lacking,"], ["e leai so latou e le iloa o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["e oo mai ona aso,", "the days come,"], ["o loo fetalai mai ai Ieova, ou te faatupuina ai mo Tavita le La laau amiotonu,", "saith the LORD,"], ["e pule foi le Tupu,", "that I will raise unto David a righteous Branch,"], ["e manuia o ia,", "and a King shall reign and prosper,"], ["e faia foi e ia le faamasinoga ma le amiotonu i le lalolagi.", "and shall execute judgment and justice in the earth."]]},
  {num:6,words:[["O lana nofoaiga e faaolaina ai Iuta,", "In his days Judah shall be saved,"], ["e nofo foi Isaraelu ma le filemu;", "and Israel shall dwell safely:"], ["o le suafa foi lenei e ta'ua ai o ia,", "and this is his name whereby he shall be called,"], ["O Ieova la tatou amiotonu .", "THE LORD OUR RIGHTEOUSNESS."]]},
  {num:7,words:[["O le mea lea faauta,", "Therefore,"], ["o loo fetalai mai ai Ieova,", "behold, the days come,"], ["e oo mai ona po e le toe fai ane ai tagata ,", "saith the LORD,"], ["O loo soifua Ieova,", "that they shall no more say, The LORD liveth,"], ["o le na aveina ae le fanauga a Isaraelu nai le nuu o Aikupito;", "which brought up the children of Israel out of the land of Egypt;"]]},
  {num:8,words:[["a e faapea ,", "But,"], ["O loo soifua Ieova,", "The LORD liveth,"], ["o le na aveina ae, ma le na aumaia le fanau a le aiga o Isaraelu mai le nuu i le itu i matu,", "which brought up and which led the seed of the house of Israel out of the north country,"], ["ma nuu uma na a'u tulia ai i latou;", "and from all countries whither I had driven them;"], ["e nonofo foi i latou i lo latou laueleele.", "and they shall dwell in their own land."]]},
  {num:9,words:[["Ua momomo lo'u loto i totonu ia te au ona o perofeta;", "Mine heart within me is broken because of the prophets;"], ["ua gatete o'u ivi uma;", "all my bones shake;"], ["ua avea a'u e pei o le tagata onā,", "I am like a drunken man, and like a man whom wine hath overcome,"], ["e pei o le tagata ua faiaina i le uaina,", "because of the LORD,"], ["ona o Ieova ma ana afioga paia.", "and because of the words of his holiness."]]},
  {num:10,words:[["Auā ua tumu le nuu i e mulilulua;", "For the land is full of adulterers;"], ["auā ua faanoanoa le nuu ona ua faafanoina;", "for because of swearing the land mourneth;"], ["ua magumagu mea i le vao e tataa ai manu,", "the pleasant places of the wilderness are dried up,"], ["auā ua leaga lo latou taufetuliga,", "and their course is evil,"], ["ua le tonu foi lo latou malosi.", "and their force is not right."]]},
  {num:11,words:[["Auā o perofeta atoa ma faitaulaga ua faalematau i latou;", "For both prophet and priest are profane;"], ["ua iloa e a'u la latou amio leaga i lo'u lava fale,", "yea, in my house have I found their wickedness,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:12,words:[["O le mea lea e avea ai lo latou ala ia te i latou e pei o mea maseesee i le pouliuli;", "Wherefore their way shall be unto them as slippery ways in the darkness:"], ["e tulia i latou,", "they shall be driven on,"], ["ma latou pauu i ai;", "and fall therein:"], ["auā ou te faaooina le malaia i luga ia te i latou,", "for I will bring evil upon them,"], ["o le tausaga lea e asiasia mai ai i latou,", "even the year of their visitation,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:13,words:[["Ua ou iloa le faavalea o perofeta o Samaria;", "And I have seen folly in the prophets of Samaria;"], ["ua latou vavalo i le igoa o Paala,", "they prophesied in Baal,"], ["ma faaseseina lo'u nuu o Isaraelu.", "and caused my people Israel to err."]]},
  {num:14,words:[["Ua ou iloa foi le mea e inosia i perofeta o Ierusalema;", "I have seen also in the prophets of Jerusalem an horrible thing:"], ["ua latou mulilulua,", "they commit adultery,"], ["ma savavali ma le pepelo;", "and walk in lies:"], ["ua faamalolosia foi e i latou lima o e amio leaga,", "they strengthen also the hands of evildoers,"], ["ina ia le toe foi mai se tasi ai lana amio leaga;", "that none doth return from his wickedness:"], ["ua avea i latou uma ia te au e pei o Sotoma,", "they are all of them unto me as Sodom,"], ["ma e o nonofo ai e pei o Komoro.", "and the inhabitants thereof as Gomorrah."]]},
  {num:15,words:[["O le mea lea ua faapea ona fetalai mai ai o Ieova o 'au i perofeta,", "Therefore thus saith the LORD of hosts concerning the prophets;"], ["Faauta,", "Behold,"], ["ou te fafaga ia te i latou i le laena,", "I will feed them with wormwood,"], ["ma faainu ia te i latou i vai oona;", "and make them drink the water of gall:"], ["auā o perofeta o Ierusalema ua oo atu ai le amio faalematau i le nuu uma.", "for from the prophets of Jerusalem is profaneness gone forth into all the land."]]},
  {num:16,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["Aua tou te faalogologo i upu a perofeta o e vavalo ia te outou;", "Hearken not unto the words of the prophets that prophesy unto you:"], ["ua latou faasese ia te outou e fai mea faatauvaa;", "they make you vain:"], ["ua latou tautala atu i le faaaliga mai o latou lava loto,", "they speak a vision of their own heart,"], ["a e le mai le fofoga o Ieova.", "and not out of the mouth of the LORD."]]},
  {num:17,words:[["O loo tautala atu pea i latou i e 'ino'ino mai ia te au,", "They say still unto them that despise me,"], ["O loo fetalai mai Ieova,", "The LORD hath said,"], ["E manuia outou;", "Ye shall have peace;"], ["ma ua latou faapea atu ia te i latou uma o e savavali e tusa ma le finau vale o latou loto,", "and they say unto every one that walketh after the imagination of his own heart,"], ["E le oo ia te outou se malaia.", "No evil shall come upon you."]]},
  {num:18,words:[["A o ai ea ua tu atu a o fai le pule a Ieova,", "For who hath stood in the counsel of the LORD,"], ["ma ua iloa ma faalogologo i lana afioga? Po o ai ua uai atu ona taliga i ana afioga,", "and hath perceived and heard his word? who hath marked his word,"], ["ma faalogologo i ai?", "and heard it?"]]},
  {num:19,words:[["Faauta,", "Behold,"], ["ua alu atu le afā mai ia Ieova i le toasa,", "a whirlwind of the LORD is gone forth in fury,"], ["o le afā fulifaō;", "even a grievous whirlwind:"], ["e pesi tetele mai i luga o ulu o e amio leaga.", "it shall fall grievously upon the head of the wicked."]]},
  {num:20,words:[["E le toe liliu le toasa o Ieova,", "The anger of the LORD shall not return,"], ["seia faia e ia,", "until he have executed,"], ["seia faataunuuina foi e ia manatu o lona finagalo;", "and till he have performed the thoughts of his heart:"], ["tou te matuā mafaufau i ai i aso amuli.", "in the latter days ye shall consider it perfectly."]]},
  {num:21,words:[["Ua ou le aauina atu o ia perofeta,", "I have not sent these prophets,"], ["a ua latou taufetuli;", "yet they ran:"], ["ua ou le tautala atu ia te i latou,", "I have not spoken to them,"], ["a ua latou vavalo.", "yet they prophesied."]]},
  {num:22,words:[["A e afai ana latou tutu mai a o fai la'u pule,", "But if they had stood in my counsel,"], ["po ua latou faailoa atu a'u upu i lo'u nuu,", "and had caused my people to hear my words,"], ["ma latou faafoi ia te i latou ai o latou ala leaga,", "then they should have turned them from their evil way,"], ["ma le leaga o a latou amioga.", "and from the evil of their doings."]]},
  {num:23,words:[["O a'u ea o le Atua e latalata,", "Am I a God at hand, saith the LORD,"], ["a e le o le Atua e mamao? o loo fetalai mai ai Ieova.", "and not a God afar off?"]]},
  {num:24,words:[["Pe mafai ea e se tagata ona lafi i mea lilo, ou te le iloa ai o ia? o loo fetalai mai ai Ieova.", "Can any hide himself in secret places that I shall not see him? saith the LORD."], ["E le o tutumu ea le lagi ma le lalolagi ia te au? o loo fetalai mai ai Ieova.", "Do not I fill heaven and earth? saith the LORD."]]},
  {num:25,words:[["Ua ou faalogo i mea ua fai atu ai perofeta,", "I have heard what the prophets said,"], ["o e ua vavalo ma le pepelo i lo'u igoa,", "that prophesy lies in my name,"], ["ua faapea atu,", "saying,"], ["Ua fai la'u miti,", "I have dreamed,"], ["ua fai la'u miti.", "I have dreamed."]]},
  {num:26,words:[["E i ai lenei mea seia afea i loto o perofeta, o e vavalo mai ma le pepelo,", "How long shall this be in the heart of the prophets that prophesy lies? yea,"], ["o perofeta lava i latou o le pepelo ua i o latou loto?", "they are prophets of the deceit of their own heart;"]]},
  {num:27,words:[["o loo manatu i latou ia faagaloina e lo'u nuu o lo'u igoa i a latou miti ua latou talatala atu ai o le tasi i le tasi,", "Which think to cause my people to forget my name by their dreams which they tell every man to his neighbour,"], ["e pei ona faagalogalo e o latou tamā o lo'u igoa ona o Paala.", "as their fathers have forgotten my name for Baal."]]},
  {num:28,words:[["O le perofeta ua na fai le miti,", "The prophet that hath a dream,"], ["ia talatala atu lana miti;", "let him tell a dream;"], ["ma le ua ia te ia la'u upu,", "and he that hath my word,"], ["ia talatala atu e ia la'u upu ma le faamaoni. E tusa ea le 'au o saito i le fua o le saito? o loo fetalai mai ai Ieova.", "let him speak my word faithfully. What is the chaff to the wheat? saith the LORD."]]},
  {num:29,words:[["E le pei o le afi ea la'u upu? o loo fetalai mai ai Ieova;", "Is not my word like as a fire? saith the LORD;"], ["e le pei o le samala foi e tu'imomoia ai le papa?", "and like a hammer that breaketh the rock in pieces?"]]},
  {num:30,words:[["O le mea lea faauta,", "Therefore,"], ["e fai ai mo'u fili o perofeta,", "behold,"], ["o e o fegaoiai a'u upu,", "I am against the prophets, saith the LORD,"], ["o loo fetalai mai ai Ieova.", "that steal my words every one from his neighbour."]]},
  {num:31,words:[["O loo fetalai mai Ieova,", "Behold,"], ["Faauta,", "I am against the prophets,"], ["e fai mo'u fili o perofeta,", "saith the LORD,"], ["o e tautala i o latou laulaufaiva,", "that use their tongues,"], ["ua faapea atu,", "and say,"], ["Ua fetalai mai o ia.", "He saith."]]},
  {num:32,words:[["Faauta,", "Behold,"], ["e fai mo'u fili i latou o e vavalo i miti pepelo,", "I am against them that prophesy false dreams,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["ma latou talatala atu ai,", "and do tell them,"], ["ma faaseseina ai lo'u nuu i a latou upu pepelo,", "and cause my people to err by their lies,"], ["ma lo latou mitamita vale;", "and by their lightness;"], ["a o a'u na ou le aauina atu i latou,", "yet I sent them not,"], ["ma a'u lei fai atu ia te i latou;", "nor commanded them:"], ["o le mea lea e le aoga ai lava i latou i lenei nuu,", "therefore they shall not profit this people at all,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:33,words:[["A fesili mai foi ia te oe lenei nuu,", "And when this people,"], ["po o le perofeta,", "or the prophet,"], ["po o le faitaulaga,", "or a priest,"], ["e faapea mai,", "shall ask thee, saying,"], ["Se a ea le avega mai ia Ieova? Ona e tali atu ai lea ia te i latou,", "What is the burden of the LORD? thou shalt then say unto them,"], ["Se a se avega? Ou te lafoaiina outou,", "What burden? I will even forsake you,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:34,words:[["A o le perofeta,", "And as for the prophet,"], ["po o le faitaulaga,", "and the priest,"], ["po o le nuu,", "and the people,"], ["e fai mai,", "that shall say,"], ["O le avega mai ia Ieova;", "The burden of the LORD,"], ["ou te taui atu lava i lena tagata atoa ma lona aiga.", "I will even punish that man and his house."]]},
  {num:35,words:[["Ia faapea ona outou tautala atu,", "Thus shall ye say every one to his neighbour,"], ["o le tagata i lē la te tuaoi,", "and every one to his brother,"], ["ma le tagata i lona uso,", "What hath the LORD answered? and,"], ["Se a le tali mai ia Ieova? se a foi le afioga mai ia Ieova?", "What hath the LORD spoken?"]]},
  {num:36,words:[["Tou te le toe ta'uta'ua foi le avega mai ia Ieova;", "And the burden of the LORD shall ye mention no more:"], ["auā e taitasi le tagata ma fai lana lava upu ma avega ia te ia;", "for every man's word shall be his burden;"], ["auā ua faauigaeseina e outou afioga a le Atua soifua, o Ieova o 'au,", "for ye have perverted the words of the living God,"], ["lo tatou Atua.", "of the LORD of hosts our God."]]},
  {num:37,words:[["Ia faapea ona e fai atu i le perofeta,", "Thus shalt thou say to the prophet, What hath the LORD answered thee? and,"], ["Se a le tali mai ia Ieova ia te oe? se a foi le afioga mai ia Ieova?", "What hath the LORD spoken?"]]},
  {num:38,words:[["A e afai tou te fai ane,", "But since ye say,"], ["O le avega mai ia Ieova;", "The burden of the LORD;"], ["o le mea lea ua faapea ona fetalai mai ai o Ieova,", "therefore thus saith the LORD;"], ["Auā ua outou fai ane lenei upu,", "Because ye say this word,"], ["O le avega mai ia Ieova,", "The burden of the LORD,"], ["a ua ou avatu le feau ia te outou,", "and I have sent unto you,"], ["ua faapea atu,", "saying,"], ["Aua tou te fai ane,", "Ye shall not say,"], ["O le avega mai ia Ieova;", "The burden of the LORD;"]]},
  {num:39,words:[["o le mea lea faauta,", "Therefore, behold,"], ["ou te matuā faagaloina ai outou,", "I, even I,"], ["ma ou lafoaiina ai outou ai o'u luma,", "will utterly forget you, and I will forsake you,"], ["atoa ma le aai na ou foaiina atu ia te outou ma o outou tamā.", "and the city that I gave you and your fathers, and cast you out of my presence:"]]},
  {num:40,words:[["Ou te faaeeina atu foi ia te outou le luma e faavavau,", "And I will bring an everlasting reproach upon you,"], ["ma le masiasi e faavavau,", "and a perpetual shame,"], ["e le galo lava.", "which shall not be forgotten."]]},
];
renderVerseSet(jer_ch_23_Verses, 'jer-ch23-verses');

var jer_ch_24_Verses = [
  {num:1,words:[["Ua faaali mai e Ieova ia te au,", "The LORD shewed me,"], ["faauta foi,", "and,"], ["o ato mati e lua, ua tuu i luma o le malumalu o Ieova,", "behold,"], ["ina ua mavae ona tāfea e Nepukanesa le tupu o Papelonia,", "two baskets of figs were set before the temple of the LORD,"], ["o Iekonia le atalii o Ioakima le tupu o Iuta,", "after that Nebuchadrezzar king of Babylon had carried away captive Jeconiah the son of Jehoiakim king of Judah,"], ["ma alii o Iuta,", "and the princes of Judah,"], ["atoa ma tufuga, ma e galulue i uamea,", "with the carpenters and smiths,"], ["mai Ierusalema,", "from Jerusalem,"], ["ma ua avea i latou i Papelonia.", "and had brought them to Babylon."]]},
  {num:2,words:[["O le tasi ato mati e matuā lelei,", "One basket had very good figs,"], ["e pei o mati muai otata;", "even like the figs that are first ripe:"], ["a o le tasi ato mati e matuā leaga,", "and the other basket had very naughty figs, which could not be eaten,"], ["e le mafai ona 'aina ina ua leaga.", "they were so bad."]]},
  {num:3,words:[["Ona faapea mai lea o Ieova ia te au,", "Then said the LORD unto me,"], ["Ieremia e,", "What seest thou,"], ["se a ea se mea ua e iloa? Ona ou faapea atu lea,", "Jeremiah? And I said,"], ["O mati;", "Figs;"], ["o mati lelei,", "the good figs,"], ["e matuā lelei ia;", "very good;"], ["a o mati leaga,", "and the evil,"], ["e matuā leaga ia,", "very evil,"], ["e le mafai ona 'aina,", "that cannot be eaten,"], ["ina ua leaga.", "they are so evil."]]},
  {num:4,words:[["Ona oo mai ai lea o le afioga a Ieova ia te au,", "Again the word of the LORD came unto me,"], ["ua faapea mai,", "saying,"]]},
  {num:5,words:[["Ua faapea ona fetalai mai o Ieova le Atua o Isaraelu,", "Thus saith the LORD,"], ["E pei o ia mati lelei,", "the God of Israel;"], ["e faapea ona ou faailogaina o le tafeaga o Iuta,", "Like these good figs,"], ["ua ou aauina atu nai lenei mea i le nuu o Kaletaia,", "so will I acknowledge them that are carried away captive of Judah,"], ["ina ia lelei ai i latou .", "whom I have sent out of this place into the land of the Chaldeans for their good."]]},
  {num:6,words:[["Ou te faasaga atu o'u mata ia te i latou ia lelei ai,", "For I will set mine eyes upon them for good,"], ["ma ou faafoisia mai i latou i lenei nuu;", "and I will bring them again to this land:"], ["ou te atiina ae i latou,", "and I will build them,"], ["a e le lepetia;", "and not pull them down;"], ["ou te totōina i latou,", "and I will plant them,"], ["a e le liaiina.", "and not pluck them up."]]},
  {num:7,words:[["Ou te avatu foi ia te i latou le loto e iloa ai a'u,", "And I will give them an heart to know me,"], ["o a'u lava o Ieova;", "that I am the LORD:"], ["e fai foi i latou mo'u nuu,", "and they shall be my people,"], ["e fai foi a'u mo latou Atua;", "and I will be their God:"], ["pe a latou toe foi mai ia te au ma o latou loto atoa.", "for they shall return unto me with their whole heart."]]},
  {num:8,words:[["E pei o mati leaga,", "And as the evil figs,"], ["e le mafai ona 'aina,", "which cannot be eaten,"], ["ina ua leaga;", "they are so evil;"], ["ua faapea ona fetalai mai ai o Ieova,", "surely thus saith the LORD,"], ["E faapea ona ou tuuina atu o Setekaia le tupu o Iuta,", "So will I give Zedekiah the king of Judah,"], ["ma alii ua ia te ia,", "and his princes,"], ["ma e o totoe i Ierusalema,", "and the residue of Jerusalem,"], ["o e o totoe i lenei nuu,", "that remain in this land,"], ["ma e o nonofo i le nuu o Aikupito;", "and them that dwell in the land of Egypt:"]]},
  {num:9,words:[["ou te tuuina atu i latou ia faaatuatuvaleina, ma ia malaia i malo uma o le lalolagi,", "And I will deliver them to be removed into all the kingdoms of the earth for their hurt,"], ["e fai a'i luma, ma upu faatusa,", "to be a reproach and a proverb,"], ["ma tauemuga,", "a taunt and a curse,"], ["ma faafanoga, i mea uma ou te tulia ai i latou.", "in all places whither I shall drive them."]]},
  {num:10,words:[["Ou te aauina atu ia te i latou le pelu,", "And I will send the sword,"], ["ma le oge,", "the famine,"], ["ma le faamai,", "and the pestilence, among them,"], ["seia faaumatia i latou i le laueleele na ou foaiina atu ai ia te i latou ma o latou tamā.", "till they be consumed from off the land that I gave unto them and to their fathers."]]},
];
renderVerseSet(jer_ch_24_Verses, 'jer-ch24-verses');

var jer_ch_25_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia i le nuu uma o Iuta i le fa o tausaga o Ioakima le atalii o Iosia, le tupu o Iuta,", "The word that came to Jeremiah concerning all the people of Judah in the fourth year of Jehoiakim the son of Josiah king of Judah,"], ["o le tausaga muamua lea o Nepukanesa le tupu o Papelonia,", "that was the first year of Nebuchadrezzar king of Babylon;"]]},
  {num:2,words:[["na fai atu ai le perofeta o Ieremia i le nuu uma o Iuta ma i latou uma sa nonofo i Ierusalema,", "The which Jeremiah the prophet spake unto all the people of Judah, and to all the inhabitants of Jerusalem,"], ["ua faapea atu,", "saying,"]]},
  {num:3,words:[["E afua i le tausaga e sefulu ma le tolu o Iosia le atalii o Amone,", "From the thirteenth year of Josiah the son of Amon king of Judah,"], ["le tupu o Iuta,", "even unto this day,"], ["e oo i le aso nei,", "that is the three and twentieth year,"], ["o tausaga ia e lua sefulu ma le tolu, ua oo mai ai ia te au le afioga a Ieova,", "the word of the LORD hath come unto me,"], ["ua ou fai atu ai foi ia te outou,", "and I have spoken unto you,"], ["ua ou ala fai atu lava;", "rising early and speaking;"], ["a ua outou le faalogo mai.", "but ye have not hearkened."]]},
  {num:4,words:[["Ua aauina atu ia te outou e Ieova o ana auauna uma, o perofeta,", "And the LORD hath sent unto you all his servants the prophets,"], ["ua ala aauina atu lava i latou;", "rising early and sending them;"], [";", "but ye have not hearkened,"], ["a ua outou le faalogo mai, ma ua le uai mai o outou taliga e faalogologo mai ai.", "nor inclined your ear to hear."]]},
  {num:5,words:[["Ua latou faapea atu,", "They said,"], ["Ia outou taitasi ma liliu mai i lona ala leaga,", "Turn ye again now every one from his evil way,"], ["ma le leaga o a outou amioga,", "and from the evil of your doings,"], ["tou te nonofo ai i le laueleele ua foaiina mai e Ieova ia te outou ma o outou tamā mai le vavau e oo i le faavavau.", "and dwell in the land that the LORD hath given unto you and to your fathers for ever and ever:"]]},
  {num:6,words:[["Aua le mulimuli atu i atua ese e auauna i ai,", "And go not after other gods to serve them,"], ["ma ifo i ai;", "and to worship them,"], ["aua ne'i faaonoono foi ia te au i mea e faia e o outou lima,", "and provoke me not to anger with the works of your hands;"], ["ona ou le faatigaina lea o outou;", "and I will do you no hurt."]]},
  {num:7,words:[["a ua outou le faalogo mai ia te au,", "Yet ye have not hearkened unto me,"], ["o loo fetalai mai ai Ieova; o lea ua outou faaonoono mai ai ia te au i mea e faia e o outou lima,", "saith the LORD;"], ["ia tiga ai outou.", "that ye might provoke me to anger with the works of your hands to your own hurt."]]},
  {num:8,words:[["O le mea lea ua faapea ona fetalai mai ai o Ieova o 'au,", "Therefore thus saith the LORD of hosts;"], ["Ua outou le faalogo mai i a'u upu,", "Because ye have not heard my words,"]]},
  {num:9,words:[["o loo fetalai mai ai Ieova,", "Behold,"], ["faauta,", "I will send and take all the families of the north,"], ["o le mea lea ou te avatu ai le feau,", "saith the LORD,"], ["ma aami atu i aiga uma o i le itu i matu,", "and Nebuchadrezzar the king of Babylon,"], ["ma Nepukanesa le tupu o Papelonia la'u auauna,", "my servant,"], ["ou te aumaia foi i latou e tau ma lenei nuu,", "and will bring them against this land,"], ["ma e o nonofo ai,", "and against the inhabitants thereof,"], ["ma ia nuu uma ua vagavagai,", "and against all these nations round about,"], ["e faaumatia lava i latou,", "and will utterly destroy them,"], ["ma faia i latou ma mea faatafunaina,", "and make them an astonishment,"], ["ma mea e uisa ai,", "and an hissing,"], ["ma mea gaogao e faavavau.", "and perpetual desolations."]]},
  {num:10,words:[["Ou te faaumatia le leo fiafia ia te i latou,", "Moreover I will take from them the voice of mirth,"], ["ma le leo olioli,", "and the voice of gladness,"], ["o le leo o le faatoafaiavā,", "the voice of the bridegroom,"], ["ma le leo o le faatoanofotane,", "and the voice of the bride,"], ["o le taalili o maaolo,", "the sound of the millstones,"], ["ma le malamalama o le lamepa.", "and the light of the candle."]]},
  {num:11,words:[["E avea lenei laueleele uma ma mea gaogao,", "And this whole land shall be a desolation,"], ["ma mea faatafunaina;", "and an astonishment;"], ["a e auauna ia nuu i le tupu o Papelonia i tausaga e fitugafulu.", "and these nations shall serve the king of Babylon seventy years."]]},
  {num:12,words:[["A faaatoatoaina tausaga e fitugafulu,", "And it shall come to pass,"], ["ona ou taui atu ai lea i le tupu o Papelonia,", "when seventy years are accomplished,"], ["ma lena nuu,", "that I will punish the king of Babylon,"], ["o loo fetalai mai o Ieova,", "and that nation, saith the LORD,"], ["ona o la latou agasala;", "for their iniquity,"], ["o le laueleele lava o Kaletaia,", "and the land of the Chaldeans,"], ["ou te faia lea ma mea faatafunaina e faavavau.", "and will make it perpetual desolations."]]},
  {num:13,words:[["Ou te faaoo foi i lena nuu o a'u upu uma na ou fai atu e oo i ai,", "And I will bring upon that land all my words which I have pronounced against it, even all that is written in this book,"], ["o upu uma lava ua tusia i lenei tusi na valoia e Ieremia i atu nuu uma.", "which Jeremiah hath prophesied against all the nations."]]},
  {num:14,words:[["Auā e faapologaina i latou, o i latou lava,", "For many nations and great kings shall serve themselves of them also:"], ["o atu nuu e tele, ma tupu sili,", "and I will recompense them according to their deeds,"], ["ou te taui atu foi ia te i latou e tusa ma la latou amioga, e tusa foi ma mea ua faia e o latou lima.", "and according to the works of their own hands."]]},
  {num:15,words:[["Auā ua faapea ona fetalai mai o Ieova le Atua o Isaraelu ia te au,", "For thus saith the LORD God of Israel unto me; Take the wine cup of this fury at my hand,"], ["Ia e ave le ipu uaina o lo'u nei ita ai lo'u lima,", "and cause all the nations,"], ["ma faainu a'i atu nuu uma ou te auina atu ai oe ia te i latou.", "to whom I send thee, to drink it."]]},
  {num:16,words:[["Latou te feinu,", "And they shall drink,"], ["ma tautevateva,", "and be moved,"], ["ma faavālea,", "and be mad,"], ["ona o le pelu ou te auina atu ai ia te i latou.", "because of the sword that I will send among them."]]},
  {num:17,words:[["Ona ou talia ai lea o le ipu ai le aao o Ieova,", "Then took I the cup at the LORD'S hand, and made all the nations to drink,"], ["ma ou faainu a'i atu nuu uma na auina i ai a'u e Ieova;", "unto whom the LORD had sent me:"]]},
  {num:18,words:[["o Ierusalema,", "To wit,"], ["ma aai o Iuta,", "Jerusalem,"], ["ma ona tupu,", "and the cities of Judah, and the kings thereof,"], ["ma ona alii,", "and the princes thereof,"], ["e faia i latou ma mea gaogao,", "to make them a desolation,"], ["ma mea faatafunaina,", "an astonishment, an hissing,"], ["ma mea e uisa ai,", "and a curse;"], ["ma faafanoga e pei ona fai i le aso nei;", "as it is this day;"]]},
  {num:19,words:[["o Farao,", "Pharaoh king of Egypt,"], ["o le tupu o Aikupito,", "and his servants,"], ["ma ana auauna, ma alii ua ia te ia,", "and his princes,"], ["ma lona nuu uma;", "and all his people;"]]},
  {num:20,words:[["o tagata eseese uma,", "And all the mingled people,"], ["ma tupu uma o le nuu o Usa,", "and all the kings of the land of Uz,"], ["ma tupu uma o le nuu o Filisitia,", "and all the kings of the land of the Philistines,"], ["ma Asekelona,", "and Ashkelon,"], ["ma Kasa,", "and Azzah,"], ["ma Ekerona,", "and Ekron,"], ["ma e o totoe o Asetota;", "and the remnant of Ashdod,"]]},
  {num:21,words:[["o Etoma,", "Edom,"], ["ma Moapi,", "and Moab,"], ["ma le fanauga a Amoni;", "and the children of Ammon,"]]},
  {num:22,words:[["o tupu uma foi o Turo,", "And all the kings of Tyrus,"], ["ma tupu uma o Saitonu,", "and all the kings of Zidon,"], ["ma tupu o nuu tu matafaga i tala atu o le sami;", "and the kings of the isles which are beyond the sea,"]]},
  {num:23,words:[["o Titana,", "Dedan,"], ["ma Tema,", "and Tema,"], ["ma Pusa,", "and Buz,"], ["ma i latou uma o e sala a latou pito 'ava;", "and all that are in the utmost corners,"]]},
  {num:24,words:[["o tupu uma foi o Arapi,", "And all the kings of Arabia,"], ["ma tupu uma o tagata eseese o e mau i le vao;", "and all the kings of the mingled people that dwell in the desert,"]]},
  {num:25,words:[["o tupu uma foi o Semeri,", "And all the kings of Zimri,"], ["ma tupu uma o Elama,", "and all the kings of Elam,"], ["ma tupu uma o Metai;", "and all the kings of the Medes,"]]},
  {num:26,words:[["ma tupu uma o le itu i matu,", "And all the kings of the north,"], ["o e latalata ma e mamao,", "far and near,"], ["o le tasi ma le tasi,", "one with another, and all the kingdoms of the world,"], ["ma malo uma o le lalolagi o i le fogāeleele;", "which are upon the face of the earth:"], ["a e mulia'i inu le tupu o Sesaka ia te i latou.", "and the king of Sheshach shall drink after them."]]},
  {num:27,words:[["E te fai atu foi ia te i latou,", "Therefore thou shalt say unto them,"], ["Ua faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Ia feinu outou,", "Drink ye,"], ["ma ia onā,", "and be drunken,"], ["ma ia puai,", "and spue,"], ["ma ia pauū,", "and fall,"], ["aua foi le toe tutū,", "and rise no more,"], ["ona o le pelu ou te auina atu ai ia te outou.", "because of the sword which I will send among you."]]},
  {num:28,words:[["A e afai latou te le mafafai ona tali i le ipu ai lou lima e feinu ai,", "And it shall be,"], ["ona e fai atu ai lea ia te i latou,", "if they refuse to take the cup at thine hand to drink,"], ["O loo faapea ona fetalai mai o Ieova o 'au,", "then shalt thou say unto them, Thus saith the LORD of hosts;"], ["Tou te matuā feinu lava.", "Ye shall certainly drink."]]},
  {num:29,words:[["Auā faauta,", "For,"], ["ou te amata ona faaoo o le malaia i le aai ua igoa i lo'u igoa,", "lo,"], ["a o outou,", "I begin to bring evil on the city which is called by my name,"], ["e faasaoina ea outou? E le faasaoina lava outou;", "and should ye be utterly unpunished? Ye shall not be unpunished:"], ["auā ou te valaau atu i le pelu e oo ia te i latou uma o e ua nonofo i le lalolagi,", "for I will call for a sword upon all the inhabitants of the earth,"], ["o loo fetalai mai ai Ieova o 'au.", "saith the LORD of hosts."]]},
  {num:30,words:[["O oe foi,", "Therefore prophesy thou against them all these words,"], ["ia e vavalo ia te i latou i nei upu uma,", "and say unto them,"], ["ma e faapea atu ia te i latou,", "The LORD shall roar from on high,"], ["E leo tele mai Ieova mai lugā,", "and utter his voice from his holy habitation;"], ["ma tŭlei mai lona siufofoga ai lona afioaga paia; e matuā leo tele mai i lona afioaga;", "he shall mightily roar upon his habitation;"], ["e alaga o ia,", "he shall give a shout,"], ["e pei o i latou o e soli fua vine ,", "as they that tread the grapes,"], ["ia te i latou uma o e nonofo i le lalolagi.", "against all the inhabitants of the earth."]]},
  {num:31,words:[["E oo le vāvāō i tuluiga o le lalolagi;", "A noise shall come even to the ends of the earth;"], ["auā o loo ia Ieova le finauga ma nuu ese,", "for the LORD hath a controversy with the nations,"], ["e faamasinoina e ia tagata uma;", "he will plead with all flesh;"], ["e tuuina atu e ia o e amio leaga i le pelu,", "he will give them that are wicked to the sword,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:32,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["Faauta,", "Behold,"], ["e alu atu le malaia e afua i le tasi nuu e oo atu i le tasi nuu,", "evil shall go forth from nation to nation,"], ["e tupu mai le afā tele mai tuluiga o le lalolagi.", "and a great whirlwind shall be raised up from the coasts of the earth."]]},
  {num:33,words:[["O le fasi a Ieova i lea aso e afua mai i le tasi pito lalolagi e oo atu i le tasi pito lalolagi;", "And the slain of the LORD shall be at that day from one end of the earth even unto the other end of the earth:"], ["e leai ni e taufaitagitu'i ia te i latou,", "they shall not be lamented,"], ["e le aofia i latou,", "neither gathered,"], ["e le tanumia foi i latou;", "nor buried;"], ["e fai i latou ma otaota i luga o le laueleele.", "they shall be dung upon the ground."]]},
  {num:34,words:[["Outou leoleo mamoe,", "Howl,"], ["ia outou uio,", "ye shepherds,"], ["ma alalaga;", "and cry;"], ["outou tā'ita'i o le lafu,", "and wallow yourselves in the ashes,"], ["ia outou taafili i le lefulefu ,", "ye principal of the flock:"], ["auā ua oo i o outou aso e fāsia ma faataapeapeina ai outou;", "for the days of your slaughter and of your dispersions are accomplished;"], ["e pauū outou e pei o le ipu matagofie.", "and ye shall fall like a pleasant vessel."]]},
  {num:35,words:[["E le maua e leoleo mamoe se mea e sola i ai,", "And the shepherds shall have no way to flee,"], ["e le sao foi tā'ita'i o le lafu.", "nor the principal of the flock to escape."]]},
  {num:36,words:[["E lagona le leo o le alaga o leoleo mamoe,", "A voice of the cry of the shepherds,"], ["ma le uio o tā'ita'i o le lafu;", "and an howling of the principal of the flock, shall be heard:"], ["auā ua faaumatia e Ieova o mea e tataa ai o latou lafu .", "for the LORD hath spoiled their pasture."]]},
  {num:37,words:[["O mea sa tataa ai manu ma le filemu, ua faaumatia ia ona o le toasa tele o Ieova.", "And the peaceable habitations are cut down because of the fierce anger of the LORD."]]},
  {num:38,words:[["Ua tuua lona apitaga,", "He hath forsaken his covert,"], ["e pei o le leona;", "as the lion:"], ["auā e avea lo latou nuu ma faatafunaga ona o le ita faasaua,", "for their land is desolate because of the fierceness of the oppressor,"], ["ma lona ita tele lava.", "and because of his fierce anger."]]},
];
renderVerseSet(jer_ch_25_Verses, 'jer-ch25-verses');

var jer_ch_26_Verses = [
  {num:1,words:[["O le amataga o le nofoaiga a Ioakima le atalii a Iosia, le tupu o Iuta,", "In the beginning of the reign of Jehoiakim the son of Josiah king of Judah came this word from the LORD,"], ["na oo mai ai lenei afioga mai ia Ieova, ua faapea mai,", "saying,"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Ia e tu atu i le lotoā o le fale o Ieova,", "Stand in the court of the LORD'S house,"], ["ma fai atu i aai uma o Iuta,", "and speak unto all the cities of Judah,"], ["o e o mai e tapuai i le fale o Ieova,", "which come to worship in the LORD'S house,"], ["upu uma ou te poloai atu ai ia te oe e fai atu ia te i latou,", "all the words that I command thee to speak unto them;"], ["aua lava le tuua se upu;", "diminish not a word:"]]},
  {num:3,words:[["atonu pe latou te faalogo ai,", "If so be they will hearken,"], ["ma latou taitasi ma liliu ese i lona ala leaga,", "and turn every man from his evil way,"], ["ina ia ou salamo i le malaia ua ou manatu e faaoo ia te i latou,", "that I may repent me of the evil,"], ["ona o le leaga o a latou amioga.", "which I purpose to do unto them because of the evil of their doings."]]},
  {num:4,words:[["E te fai atu foi ia te i latou,", "And thou shalt say unto them,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Afai tou te le faalogo mai ia te au,", "If ye will not hearken to me, to walk in my law,"], ["ma le savavali e tusa ma la'u tulafono ua ou tuuina i o outou luma,", "which I have set before you,"]]},
  {num:5,words:[["e le faalogo i upu a a'u auauna le au perofeta,", "To hearken to the words of my servants the prophets,"], ["na aauina e a'u ia te outou;", "whom I sent unto you,"], ["na ou ala aauina i latou ,", "both rising up early, and sending them,"], ["a ua outou le faalogo mai;", "but ye have not hearkened;"]]},
  {num:6,words:[["ona ou faia lea o lenei fale ia pei o Sailo,", "Then will I make this house like Shiloh,"], ["ou te faia foi lenei aai ma faafanoga i atu nuu uma o le lalolagi.", "and will make this city a curse to all the nations of the earth."]]},
  {num:7,words:[["Ua faalogo le au faitaulaga, ma perofeta, ma le nuu uma, ia Ieremia, o loo fai atu ia upu i le fale o Ieova.", "So the priests and the prophets and all the people heard Jeremiah speaking these words in the house of the LORD."]]},
  {num:8,words:[["Ua uma ona fai atu e Ieremia o mea uma na poloai mai ai Ieova na te fai atu i le nuu uma,", "Now it came to pass,"], ["ona pue atu ai lea ia te ia e le au faitaulaga,", "when Jeremiah had made an end of speaking all that the LORD had commanded him to speak unto all the people,"], ["ma perofeta, ma le nuu uma,", "that the priests and the prophets and all the people took him,"], ["ua faapea atu,", "saying,"], ["E oti lava oe.", "Thou shalt surely die."]]},
  {num:9,words:[["Se a ea le mea ua e vavalo mai ai i le suafa o Ieova,", "Why hast thou prophesied in the name of the LORD,"], ["ua faapea mai,", "saying,"], ["E avea lenei fale e pei o Sailo, o lenei aai foi e faatafunaina ia,", "This house shall be like Shiloh,"], ["e leai se nofo ai? Ua faapotopotoina le nuu uma ia Ieremia i le fale o Ieova.", "and this city shall be desolate without an inhabitant? And all the people were gathered against Jeremiah in the house of the LORD."]]},
  {num:10,words:[["Ua faalogo alii o Iuta i ia mea,", "When the princes of Judah heard these things,"], ["ona latou o ae ai lea mai le fale o le tupu, i le fale o Ieova,", "then they came up from the king's house unto the house of the LORD,"], ["ma latou nonofo i le mea e ui ai i le faitotoa fou o le fale o Ieova;", "and sat down in the entry of the new gate of the LORD'S house."]]},
  {num:11,words:[["ona fai atu ai lea o faitaulaga ma perofeta i alii ma le nuu uma,", "Then spake the priests and the prophets unto the princes and to all the people,"], ["ua faapea atu,", "saying,"], ["E tatau ona oti o lenei tagata,", "This man is worthy to die;"], ["auā ua na vavalo i mea leaga e oo i lenei aai,", "for he hath prophesied against this city,"], ["e pei ona faafofoga i ai o outou.", "as ye have heard with your ears."]]},
  {num:12,words:[["Ona fai atu ai lea o Ieremia i alii uma ma le nuu uma,", "Then spake Jeremiah unto all the princes and to all the people,"], ["ua faapea atu,", "saying,"], ["Ua auina mai a'u e Ieova e vavalo i lenei fale ma lenei aai i upu uma ua outou faalogo i ai.", "The LORD sent me to prophesy against this house and against this city all the words that ye have heard."]]},
  {num:13,words:[["O lenei,", "Therefore now amend your ways and your doings,"], ["ia outou sauni lelei o outou ala ma a outou amioga, ma ia outou faalogo i le suifofoga o Ieova lo outou Atua;", "and obey the voice of the LORD your God;"], ["ona salamo ai lea o Ieova i le malaia na ia fetalaia mai e oo ia te outou.", "and the LORD will repent him of the evil that he hath pronounced against you."]]},
  {num:14,words:[["A o a'u nei,", "As for me,"], ["faauta,", "behold,"], ["ua i o outou lima a'u;", "I am in your hand:"], ["ia outou faia ia te au e pei ona lelei ma tonu ia te outou,", "do with me as seemeth good and meet unto you."]]},
  {num:15,words:[["tau ina ia outou matuā iloa,", "But know ye for certain,"], ["afai tou te fasioti ia te au,", "that if ye put me to death,"], ["ona outou faaee ai lea o le toto o le tagata ua le sala i luga ia te outou, atoa ma lenei aai,", "ye shall surely bring innocent blood upon yourselves,"], ["ma e o nonofo ai;", "and upon this city,"], ["auā e moni lava,", "and upon the inhabitants thereof:"], ["ua auina mai a'u e Ieova ia te outou e fai atu ia upu uma i o outou luma.", "for of a truth the LORD hath sent me unto you to speak all these words in your ears."]]},
  {num:16,words:[["Ona fai atu ai lea o alii ma le nuu uma i faitaulaga ma perofeta,", "Then said the princes and all the people unto the priests and to the prophets;"], ["E le tatau ona oti o lenei tagata,", "This man is not worthy to die:"], ["auā ua tautala mai o ia ia te i tatou i le suafa o Ieova lo tatou Atua.", "for he hath spoken to us in the name of the LORD our God."]]},
  {num:17,words:[["Ona tulai mai ai lea o isi tagata,", "Then rose up certain of the elders of the land,"], ["o toeaina o le nuu, ma latou fai atu i le faapotopotoga uma o le nuu,", "and spake to all the assembly of the people,"], ["ua faapea atu,", "saying,"]]},
  {num:18,words:[["Na vavalo mai Mika le Morese,", "Micah the Morasthite prophesied in the days of Hezekiah king of Judah,"], ["i ona po o Esekia le tupu o Iuta, ua na fai mai foi i le nuu uma o Iuta,", "and spake to all the people of Judah,"], ["ua faapea mai,", "saying,"], ["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts;"], ["E fai Siona ma fanua e suatia,", "Zion shall be plowed like a field,"], ["e fai foi Ierusalema ma faupuegāmaa, o le mauga foi o i ai le fale,", "and Jerusalem shall become heaps,"], ["e fai lea ma mea maualuluga i le vao matua.", "and the mountain of the house as the high places of a forest."]]},
  {num:19,words:[["Pe na fasiotia lava ea o ia e Esekia le tupu o Iuta ma Iuta uma? Na le mata'u ea o ia ia Ieova,", "Did Hezekiah king of Judah and all Judah put him at all to death? did he not fear the LORD,"], ["ma aioi atu i luma o Ieova; ona salamo ai lea o Ieova i le malaia na ia fetalaia mai ia te i latou? A faapea,", "and besought the LORD,"], ["ona agasala tele ai lea o i tatou i o tatou agaga.", "and the LORD repented him of the evil which he had pronounced against them? Thus might we procure great evil against our souls."]]},
  {num:20,words:[["Sa i ai foi le tasi tagata na vavalo mai i le suafa o Ieova, o Uria,", "And there was also a man that prophesied in the name of the LORD,"], ["le atalii o Semaia, mai Kiriata-iarima,", "Urijah the son of Shemaiah of Kirjath-jearim,"], ["na vavalo mai o ia i mea leaga e oo i lenei aai, ma lenei nuu e pei o upu uma a Ieremia;", "who prophesied against this city and against this land according to all the words of Jeremiah:"]]},
  {num:21,words:[["na faafofoga i ana upu o Ioakima le tupu,", "And when Jehoiakim the king,"], ["ma toa uma sa ia te ia,", "with all his mighty men,"], ["ma alii uma,", "and all the princes,"], ["ona saili ai lea le tupu e fasioti ia te ia;", "heard his words,"], ["a ua faalogo i ai Uria,", "the king sought to put him to death: but when Urijah heard it,"], ["ona mata'u ai lea o ia,", "he was afraid,"], ["ua sola,", "and fled,"], ["ma alu atu i Aikupito.", "and went into Egypt;"]]},
  {num:22,words:[["Ona aauina atu lea e Ioakima le tupu nisi tagata i Aikupito,", "And Jehoiakim the king sent men into Egypt,"], ["o Elenatana le atalii o Akepora,", "namely, Elnathan the son of Achbor,"], ["ma nisi tagata faatasi ma ia i Aikupito.", "and certain men with him into Egypt."]]},
  {num:23,words:[["Na latou aumaia Uria mai Aikupito,", "And they fetched forth Urijah out of Egypt,"], ["ma latou au mai ia te ia i le tupu o Ioakima;", "and brought him unto Jehoiakim the king;"], ["ona ia fasi lea ia te ia i le pelu,", "who slew him with the sword,"], ["ma na tuuina atu lona tino ua oti i tuugamau o tagatānuu.", "and cast his dead body into the graves of the common people."]]},
  {num:24,words:[["A ua fesoasoani Aikamo le atalii o Safana ia Ieremia,", "Nevertheless the hand of Ahikam the son of Shaphan was with Jeremiah,"], ["ina ia le tuuina atu o ia i lima o le nuu e fasioti ia te ia.", "that they should not give him into the hand of the people to put him to death."]]},
];
renderVerseSet(jer_ch_26_Verses, 'jer-ch26-verses');

var jer_ch_27_Verses = [
  {num:1,words:[["O le amataga o le nofoaiga a Ioakima le atalii o Iosia, le tupu o Iuta,", "In the beginning of the reign of Jehoiakim the son of Josiah king of Judah came this word unto Jeremiah from the LORD,"], ["na oo mai ai lenei afioga ia Ieremia mai ia Ieova, ua faapea mai,", "saying,"]]},
  {num:2,words:[["Ua faapea ona fetalai mai o Ieova ia te au,", "Thus saith the LORD to me;"], ["Ia e faia mo oe noanoaga ma amo,", "Make thee bonds and yokes,"], ["ma faaee ai i luga o lou ua;", "and put them upon thy neck,"]]},
  {num:3,words:[["ia e avatu ai foi i le tupu o Etoma,", "And send them to the king of Edom,"], ["ma le tupu o Moapi,", "and to the king of Moab,"], ["ma le tupu o le fanauga a Amoni, ma le tupu o Turo,", "and to the king of the Ammonites,"], ["ma le tupu o Saitonu,", "and to the king of Tyrus,"], ["i lima o sāvali,", "and to the king of Zidon,"], ["o e o mai i Ierusalema ia Setekaia le tupu o Iuta;", "by the hand of the messengers which come to Jerusalem unto Zedekiah king of Judah;"]]},
  {num:4,words:[["ia e fai atu foi ia te i latou,", "And command them to say unto their masters,"], ["ia latou faapea atu i o latou alii,", "Thus saith the LORD of hosts,"], ["O loo faapea ona fetalai mai o Ieova o 'au, le Atua o Isaraelu,", "the God of Israel;"], ["Ia faapea ona outou fai atu i o outou alii,", "Thus shall ye say unto your masters;"]]},
  {num:5,words:[["O a'u nei, ua ou faia le lalolagi,", "I have made the earth,"], ["o tagata ma manu ua i luga o le fogāeleele,", "the man and the beast that are upon the ground,"], ["i lo'u mana tele,", "by my great power and by my outstretched arm,"], ["ma lo'u lima faaloaloa; ua ou tuuina atu ai foi i le ua tatau ma lo'u manatu.", "and have given it unto whom it seemed meet unto me."]]},
  {num:6,words:[["O lenei, ua ou tuuina atu e a'u o ia nuu uma i le lima o Nepukanesa le tupu o Papelonia,", "And now have I given all these lands into the hand of Nebuchadnezzar the king of Babylon,"], ["la'u auauna;", "my servant;"], ["o manu feai foi ua ou tuuina atu ai ia te ia, e auauna ia te ia.", "and the beasts of the field have I given him also to serve him."]]},
  {num:7,words:[["E auauna lava atu nuu uma ia te ia,", "And all nations shall serve him,"], ["ma lona atalii,", "and his son,"], ["ma le atalii o lona atalii,", "and his son's son,"], ["seia oo i ona lava po o lona nuu;", "until the very time of his land come:"], ["ona auauna lea o ia i nuu e tele ma tupu sili.", "and then many nations and great kings shall serve themselves of him."]]},
  {num:8,words:[["A o le nuu ma le malo e le mafai ona auauna i lena Nepukanesa le tupu o Papelonia,", "And it shall come to pass,"], ["e le tuuina atu foi o latou ua i le amo a le tupu o Papelonia,", "that the nation and kingdom which will not serve the same Nebuchadnezzar the king of Babylon, and that will not put their neck under the yoke of the king of Babylon,"], ["ou te taui atu i lena nuu i le pelu,", "that nation will I punish,"], ["ma le oge,", "saith the LORD,"], ["ma le faamai,", "with the sword,"], ["o loo fetalai mai ai Ieova,", "and with the famine, and with the pestilence,"], ["seia ou faaumatia i latou i lona lima.", "until I have consumed them by his hand."]]},
  {num:9,words:[["O lenei,", "Therefore hearken not ye to your prophets,"], ["aua ne'i outou faalogo i o outou perofeta,", "nor to your diviners,"], ["ma o outou taulāitu,", "nor to your dreamers,"], ["ma o outou fai miti,", "nor to your enchanters,"], ["ma o outou tagata e iite i ao o le lagi, ma e fai togafiti faataulāitu ia te outou,", "nor to your sorcerers,"], ["o i latou o e fai atu ia te outou,", "which speak unto you,"], ["ua faapea atu,", "saying,"], ["E le fai ma auauna outou i le tupu o Papelonia.", "Ye shall not serve the king of Babylon:"]]},
  {num:10,words:[["Auā o mea pepelo ua latou vavalo ai ia te outou,", "For they prophesy a lie unto you,"], ["ina ia avemamaoina outou i lo outou laueleele;", "to remove you far from your land;"], ["ia ou tulia foi outou,", "and that I should drive you out,"], ["ma ia faaumatia outou.", "and ye should perish."]]},
  {num:11,words:[["A o le nuu,", "But the nations that bring their neck under the yoke of the king of Babylon,"], ["e tuuina o latou ua i le amo a le tupu o Papelonia,", "and serve him,"], ["ma auauna ia te ia, ou te tuuina atu i latou ia nofo pea i lo latou laueleele,", "those will I let remain still in their own land,"], ["o loo fetalai mai ai Ieova,", "saith the LORD;"], ["latou te galulue ai,", "and they shall till it,"], ["ma latou nonofo ai.", "and dwell therein."]]},
  {num:12,words:[["Na a'u fai atu foi ia Setekaia,", "I spake also to Zedekiah king of Judah according to all these words,"], ["le tupu o Iuta, e tusa ma ia upu uma,", "saying,"], ["ua faapea atu,", "Bring your necks under the yoke of the king of Babylon,"], ["Ia outou tuuina o outou ua i le amo a le tupu o Papelonia, ma auauna ia te ia ma lona nuu,", "and serve him and his people,"], ["ia ola ai outou.", "and live."]]},
  {num:13,words:[["Se a ea le mea tou te fia oti ai,", "Why will ye die,"], ["o oe ma lou nuu,", "thou and thy people,"], ["i le pelu,", "by the sword,"], ["ma le oge,", "by the famine,"], ["ma le faamai,", "and by the pestilence,"], ["e pei ona fetalai mai ai o Ieova i le nuu e le auauna i le tupu o Papelonia?", "as the LORD hath spoken against the nation that will not serve the king of Babylon?"]]},
  {num:14,words:[["Aua tou te faafofoga i upu a perofeta,", "Therefore hearken not unto the words of the prophets that speak unto you,"], ["o e fai mai ia te outou,", "saying,"], ["ua faapea mai, E le fai outou ma auauna i le tupu o Papelonia;", "Ye shall not serve the king of Babylon:"], ["auā o mea pepelo ua latou vavalo ai ia te outou.", "for they prophesy a lie unto you."]]},
  {num:15,words:[["Auā o loo fetalai mai Ieova,", "For I have not sent them,"], ["ua ou le aauina atu i latou,", "saith the LORD,"], ["a ua latou vavalo i le pepelo i lo'u igoa;", "yet they prophesy a lie in my name;"], ["ina ia ou tulia outou,", "that I might drive you out,"], ["ma ia faaumatia outou,", "and that ye might perish,"], ["o outou,", "ye,"], ["ma perofeta o e vavalo ia te outou.", "and the prophets that prophesy unto you."]]},
  {num:16,words:[["Na ou fai atu foi i faitaulaga ma lenei nuu uma,", "Also I spake to the priests and to all this people,"], ["ua faapea atu,", "saying,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Aua tou te faalogo i upu a o outou perofeta,", "Hearken not to the words of your prophets that prophesy unto you,"], ["o e vavalo ia te outou, ua faapea mai,", "saying,"], ["Faauta,", "Behold,"], ["e taalise ona toe aumaia mai Papelonia o ipu o le fale o Ieova;", "the vessels of the LORD'S house shall now shortly be brought again from Babylon:"], ["auā o mea pepelo ua latou vavalo ai ia te outou.", "for they prophesy a lie unto you."]]},
  {num:17,words:[["Aua tou te faalogo ia te i latou;", "Hearken not unto them;"], ["ia outou auauna i le tupu o Papelonia,", "serve the king of Babylon,"], ["ia ola ai outou;", "and live:"], ["se a le mea e fai ai lenei aai ma faatafunaga?", "wherefore should this city be laid waste?"]]},
  {num:18,words:[["Afai foi o perofeta i latou,", "But if they be prophets,"], ["pe afai foi ua ia te i latou le afioga a Ieova,", "and if the word of the LORD be with them,"], ["se'i latou faatoga atu ia Ieova o 'au,", "let them now make intercession to the LORD of hosts, that the vessels which are left in the house of the LORD,"], ["ina ia le oo atu i Papelonia o ipu o totoe i le fale o Ieova,", "and in the house of the king of Judah,"], ["ma le fale o le tupu o Iuta,", "and at Jerusalem,"], ["ma Ierusalema.", "go not to Babylon."]]},
  {num:19,words:[["Auā o loo faapea ona fetalai mai o Ieova o 'au,", "For thus saith the LORD of hosts concerning the pillars,"], ["i pou,", "and concerning the sea,"], ["ma le vai, ma tuuga taelega ,", "and concerning the bases,"], ["ma toe ipu ua tuu i lenei aai,", "and concerning the residue of the vessels that remain in this city,"]]},
  {num:20,words:[["o mea ia na le avea ai e Nepukanesa le tupu o Papelonia i lona ave faatagataotaua ia Iekonia le atalii o Ioakima,", "Which Nebuchadnezzar king of Babylon took not,"], ["le tupu o Iuta,", "when he carried away captive Jeconiah the son of Jehoiakim king of Judah from Jerusalem to Babylon,"], ["ma alii uma o Iuta ma Ierusalema mai Ierusalema i Papelonia.", "and all the nobles of Judah and Jerusalem;"]]},
  {num:21,words:[["Auā o loo faapea ona fetalai mai o Ieova o 'au,", "Yea,"], ["le Atua o Isaraelu,", "thus saith the LORD of hosts,"], ["i ipu ua totoe i le fale o Ieova,", "the God of Israel,"], ["ma le fale o le tupu o Iuta,", "concerning the vessels that remain in the house of the LORD,"], ["ma Ierusalema,", "and in the house of the king of Judah and of Jerusalem;"]]},
  {num:22,words:[["e aveina atu ia mea i Papelonia,", "They shall be carried to Babylon,"], ["e i ai foi i lea mea seia oo i le aso ou te asiasi atu i ai,", "and there shall they be until the day that I visit them,"], ["o loo fetalai mai ai Ieova;", "saith the LORD;"], ["ona ou toe aumaia lea,", "then will I bring them up,"], ["ma faafoisia mai ia mea i lenei mea.", "and restore them to this place."]]},
];
renderVerseSet(jer_ch_27_Verses, 'jer-ch27-verses');

var jer_ch_28_Verses = [
  {num:1,words:[["O lea lava tausaga,", "And it came to pass the same year,"], ["o le amataga o le nofoaiga a Setekaia,", "in the beginning of the reign of Zedekiah king of Judah,"], ["le tupu o Iuta,", "in the fourth year,"], ["o lona fa o tausaga,", "and in the fifth month,"], ["ma le lima o masina, na fai mai ai ia te au o Hanania le atalii o Asura le perofeta,", "that Hananiah the son of Azur the prophet,"], ["o le Kipeona,", "which was of Gibeon,"], ["i le fale o Ieova,", "spake unto me in the house of the LORD,"], ["i luma o faitaulaga ma le nuu uma,", "in the presence of the priests and of all the people,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus speaketh the LORD of hosts,"], ["le Atua o Isaraelu. ua faapea mai,", "the God of Israel, saying,"], ["Ua ou gauia le amo a le tupu o Papelonia.", "I have broken the yoke of the king of Babylon."]]},
  {num:3,words:[["A o lei mavae tausaga e lua ou te toe aumaia i lenei mea o ipu uma o le fale o Ieova,", "Within two full years will I bring again into this place all the vessels of the LORD'S house,"], ["na aveesea e Nepukanesa le tupu o Papelonia ai lenei mea,", "that Nebuchadnezzar king of Babylon took away from this place,"], ["ma na avatu ai i Papelonia;", "and carried them to Babylon:"]]},
  {num:4,words:[["ou te faafoisia mai foi i lenei mea o Iekonia,", "And I will bring again to this place Jeconiah the son of Jehoiakim king of Judah,"], ["le atalii o Ioakima, le tupu o Iuta,", "with all the captives of Judah,"], ["ma le tafeaga uma a Iuta,", "that went into Babylon,"], ["na o atu i Papelonia, o loo fetalai mai ai Ieova;", "saith the LORD:"], ["auā ou te gauia le amo a le tupu o Papelonia.", "for I will break the yoke of the king of Babylon."]]},
  {num:5,words:[["Ona fai atu ai lea o Ieremia le perofeta ia Hanania le perofeta i luma o faitaulaga,", "Then the prophet Jeremiah said unto the prophet Hananiah in the presence of the priests,"], ["ma luma o le nuu uma o e na tutū mai i le fale o Ieova;", "and in the presence of all the people that stood in the house of the LORD,"]]},
  {num:6,words:[["ua fai atu lava Ieremia le perofeta,", "Even the prophet Jeremiah said,"], ["Amene;", "Amen:"], ["ia faapea ona fai e Ieova;", "the LORD do so: the LORD perform thy words which thou hast prophesied,"], ["ia faamauina e Ieova au upu ua e vavalo ai,", "to bring again the vessels of the LORD'S house,"], ["i le toe aumaia ipu o le fale o Ieova,", "and all that is carried away captive,"], ["ma le tafeaga uma mai Papelonia i lenei mea.", "from Babylon into this place."]]},
  {num:7,words:[["A se'i e faalogo mai i lenei upu ou te fai atu ai nei i ou luma,", "Nevertheless hear thou now this word that I speak in thine ears,"], ["ma luma o le nuu uma,", "and in the ears of all the people;"]]},
  {num:8,words:[["O perofeta na muamua ia te au, na muamua foi ia te oe,", "The prophets that have been before me and before thee of old prophesied both against many countries,"], ["talu mai anamua lava,", "and against great kingdoms,"], ["ua latou vavalo i nuu e tele, ma malo tetele,", "of war,"], ["i taua,", "and of evil,"], ["ma malaia, ma faamai;", "and of pestilence."]]},
  {num:9,words:[["o le perofeta ua vavalo i le manuia,", "The prophet which prophesieth of peace,"], ["a taunuu le upu a lea perofeta,", "when the word of the prophet shall come to pass,"], ["ona iloa ai lea, e moni,", "then shall the prophet be known,"], ["o le perofeta lea ua auina mai e Ieova.", "that the LORD hath truly sent him."]]},
  {num:10,words:[["Ona tago ai lea o Hanania le perofeta i le amo nai le ua o Ieremia le perofeta,", "Then Hananiah the prophet took the yoke from off the prophet Jeremiah's neck,"], ["ma na gauia.", "and brake it."]]},
  {num:11,words:[["Ona fai mai ai lea o Hanania i luma o le nuu uma,", "And Hananiah spake in the presence of all the people,"], ["ua faapea mai,", "saying,"], ["O loo faapea ona fetalai mai o Ieova, E faapea lava ona ou gauia le amo a Nepukanesa le tupu a Papelonia i ua o nuu uma,", "Thus saith the LORD;"], ["a o lei mavae tausaga e lua.", "Even so will I break the yoke of Nebuchadnezzar king of Babylon from the neck of all nations within the space of two full years."], ["Ona alu ese ai lea o Ieremia le perofeta.", "And the prophet Jeremiah went his way."]]},
  {num:12,words:[["A ua oo mai le afioga a Ieova ia Ieremia,", "Then the word of the LORD came unto Jeremiah the prophet,"], ["ina ua mavae ona gauia e Hanania le perofeta o le amo nai le ua o Ieremia le perofeta,", "after that Hananiah the prophet had broken the yoke from off the neck of the prophet Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:13,words:[["Ina alu ia ma fai atu ia Hanania,", "Go and tell Hananiah,"], ["ia faapea atu,", "saying,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Ua e gauia amo laau;", "Thou hast broken the yokes of wood;"], ["a e te faia amo uamea e sui a'i.", "but thou shalt make for them yokes of iron."]]},
  {num:14,words:[["Auā o loo faapea ona fetalai mai o Ieova o 'au,", "For thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Ua ou faaeetia le amo uamea i ua o ia nuu uma,", "I have put a yoke of iron upon the neck of all these nations,"], ["ina ia latou auauna ia Nepukanesa le tupu o Papelonia;", "that they may serve Nebuchadnezzar king of Babylon;"], ["latou te auauna foi ia te ia;", "and they shall serve him:"], ["ua ou tuuina atu foi ia te ia o manu feai.", "and I have given him the beasts of the field also."]]},
  {num:15,words:[["Ona fai atu ai lea o Ieremia le perofeta ia Hanania le perofeta,", "Then said the prophet Jeremiah unto Hananiah the prophet,"], ["Hanania e,", "Hear now,"], ["ina faalogologo mai ia;", "Hananiah;"], ["e lei auina mai oe e Ieova;", "The LORD hath not sent thee;"], ["a ua e faatupuina i lenei nuu le faatuatua i le pepelo.", "but thou makest this people to trust in a lie."]]},
  {num:16,words:[["O le mea lea,", "Therefore thus saith the LORD;"], ["o loo faapea ona fetalai mai ai o Ieova,", "Behold,"], ["Faauta, ou te lafoai ia te oe ai le fogāeleele,", "I will cast thee from off the face of the earth:"], ["e te oti i le tausaga nei;", "this year thou shalt die,"], ["auā ua e tautala i le fouvale ia Ieova.", "because thou hast taught rebellion against the LORD."]]},
  {num:17,words:[["Ona oti ai lea o Hanania le perofeta i lea lava tausaga, i le fitu o masina.", "So Hananiah the prophet died the same year in the seventh month."]]},
];
renderVerseSet(jer_ch_28_Verses, 'jer-ch28-verses');

var jer_ch_29_Verses = [
  {num:1,words:[["O upu nei a le tusi na avatua e Ieremia le perofeta ai Ierusalema i e na totoe o toeaina na tāfea,", "Now these are the words of the letter that Jeremiah the prophet sent from Jerusalem unto the residue of the elders which were carried away captives,"], ["ma faitaulaga,", "and to the priests,"], ["ma perofeta, ma le nuu uma lava,", "and to the prophets,"], ["na tāfea ia Nepukanesa mai Ierusalema i Papelonia;", "and to all the people whom Nebuchadnezzar had carried away captive from Jerusalem to Babylon;"]]},
  {num:2,words:[["ina ua mavae ona o atu nai Ierusalema o Iekonia le tupu,", "(After that Jeconiah the king,"], ["ma le sa'o tamaitai,", "and the queen, and the eunuchs,"], ["ma eunuka,", "the princes of Judah and Jerusalem,"], ["ma alii o Iuta ma Ierusalema,", "and the carpenters,"], ["o tufuga foi,", "and the smiths, were departed from Jerusalem;"], ["ma e galulue i uamea.", ")"]]},
  {num:3,words:[["Na ave e Eliasa le atalii o Safana,", "By the hand of Elasah the son of Shaphan,"], ["ma Kemaria le atalii o Hilikia,", "and Gemariah the son of Hilkiah,"], ["o e na aauina e Setekaia le tupu o Iuta i Papelonia ia Nepukanesa le tupu o Papelonia ua faapea,", "(whom Zedekiah king of Judah sent unto Babylon to Nebuchadnezzar king of Babylon) saying,"]]},
  {num:4,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["i le tafeaga uma,", "unto all that are carried away captives,"], ["na ou faatāfea mai Ierusalema i Papelonia,", "whom I have caused to be carried away from Jerusalem unto Babylon;"]]},
  {num:5,words:[["Ia outou fāi fale,", "Build ye houses,"], ["ma nonofo ai;", "and dwell in them;"], ["ma ia outou totōina faatoaga,", "and plant gardens,"], ["ma aai ai ona fua;", "and eat the fruit of them;"]]},
  {num:6,words:[["ina fai avā ia outou,", "Take ye wives,"], ["ma ia fananau ai atalii ma afafine ia te outou;", "and beget sons and daughters;"], ["ia outou aumaia foi avā mā o outou atalii,", "and take wives for your sons,"], ["ma fai ni tane mā o outou afafine,", "and give your daughters to husbands,"], ["ina ia latou fananau mai tama ma teine;", "that they may bear sons and daughters;"], ["ia faatoateleina outou i lea mea,", "that ye may be increased there,"], ["a e aua le faatoaitiitia.", "and not diminished."]]},
  {num:7,words:[["Ia outou sailiili foi ia manuia le aai ua ou faatāfea ai outou;", "And seek the peace of the city whither I have caused you to be carried away captives,"], ["ma ia outou tatalo atu ia Ieova mo lena aai;", "and pray unto the LORD for it:"], ["auā o lona manuia e manuia ai outou.", "for in the peace thereof shall ye have peace."]]},
  {num:8,words:[["Auā o loo faapea ona fetalai mai o Ieova o 'au,", "For thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Aua ne'i faaseseina outou e o outou perofeta ua ia te outou,", "Let not your prophets and your diviners,"], ["ma o outou taulāitu;", "that be in the midst of you,"], ["aua foi ne'i faalogo i miti,", "deceive you,"], ["ua faia talu outou;", "neither hearken to your dreams which ye cause to be dreamed."]]},
  {num:9,words:[["auā ua latou vavalo i le pepelo ia te outou i lo'u igoa;", "For they prophesy falsely unto you in my name:"], ["ou te lei aauina atu i latou,", "I have not sent them,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:10,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD,"], ["A faaatoatoaina tausaga e fitugafulu i Papelonia,", "That after seventy years be accomplished at Babylon I will visit you,"], ["ona ou asiasi ai lea ia te outou, ma ou faataunuuina la'u upu lelei ia te outou,", "and perform my good word toward you,"], ["i le faafoisia mai outou i lenei mea.", "in causing you to return to this place."]]},
  {num:11,words:[["Auā o a'u nei,", "For I know the thoughts that I think toward you,"], ["ua ou iloa manatu ua ou manatu ai ia te outou,", "saith the LORD,"], ["o manatu i le manuia, a e le o le malaia,", "thoughts of peace,"], ["o loo fetalai mai ai Ieova,", "and not of evil,"], ["e foaiina atu ia te outou le iuga e i ai le faamoemoe.", "to give you an expected end."]]},
  {num:12,words:[["Ona outou valaau ai lea ia te au,", "Then shall ye call upon me,"], ["e ō foi outou ma tatalo ia te au,", "and ye shall go and pray unto me,"], ["ou te faalogo foi ia te outou.", "and I will hearken unto you."]]},
  {num:13,words:[["E saili mai outou ia te au,", "And ye shall seek me,"], ["tou te maua foi,", "and find me,"], ["pe a outou saili mai ia te au ma outou loto atoa.", "when ye shall search for me with all your heart."]]},
  {num:14,words:[["E maua lava a'u e outou,", "And I will be found of you,"], ["o loo fetalai mai ai Ieova;", "saith the LORD:"], ["ou te faafoisia la outou tafeaga,", "and I will turn away your captivity,"], ["ma ou faapotopotoina outou ai nuu uma,", "and I will gather you from all the nations,"], ["ma mea uma na ou tulia ai outou,", "and from all the places whither I have driven you,"], ["o loo fetalai mai ai Ieova;", "saith the LORD;"], ["ou te faafoisia foi outou i le mea ua ou faatāfea ai outou.", "and I will bring you again into the place whence I caused you to be carried away captive."]]},
  {num:15,words:[["Ua outou fai ane,", "Because ye have said,"], ["Ua faatuina mo i tatou e Ieova o perofeta i Papelonia;", "The LORD hath raised us up prophets in Babylon;"]]},
  {num:16,words:[["o le mea lea o loo faapea ona fetalai mai ai o Ieova i le tupu,", "Know that thus saith the LORD of the king that sitteth upon the throne of David,"], ["o lē tietie i le nofoālii o Tavita, ma le nuu uma o loo nonofo i lenei aai,", "and of all the people that dwelleth in this city,"], ["o outou uso ia e na le o atu faatasi ma outou i le tafeaga;", "and of your brethren that are not gone forth with you into captivity;"]]},
  {num:17,words:[["o loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts;"], ["Faauta,", "Behold,"], ["ou te aauina atu ia te i latou o le pelu,", "I will send upon them the sword,"], ["ma le oge,", "the famine,"], ["ma le faamai,", "and the pestilence,"], ["ou te faia foi i latou ia pei o mati e matuā leaga,", "and will make them like vile figs,"], ["e le mafai ona 'aina,", "that cannot be eaten,"], ["ina ua leaga.", "they are so evil."]]},
  {num:18,words:[["Ou te tuliloa foi ia te i latou i le pelu,", "And I will persecute them with the sword,"], ["ma le oge,", "with the famine,"], ["ma le faamai,", "and with the pestilence,"], ["ou te tuuina atu foi i latou ia faaatuatuvaleina i malo uma o le lalolagi,", "and will deliver them to be removed to all the kingdoms of the earth,"], ["e fai ma faafanoga,", "to be a curse,"], ["ma mea e ofo ai,", "and an astonishment,"], ["ma uisa ai,", "and an hissing,"], ["ma fai a'i luma,", "and a reproach,"], ["i nuu uma ua ou tulia ai i latou.", "among all the nations whither I have driven them:"]]},
  {num:19,words:[["Auā ua latou le faalogo i a'u upu,", "Because they have not hearkened to my words,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["na ou avatua ia te i latou i a'u auauna o le au perofeta,", "which I sent unto them by my servants the prophets,"], ["na ala aauina i latou;", "rising up early and sending them;"], ["a ua outou le faalogo lava,", "but ye would not hear,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:20,words:[["A o outou,", "Hear ye therefore the word of the LORD,"], ["ia outou faalogo mai i le afioga a Ieova,", "all ye of the captivity,"], ["o outou uma o le tafeaga e na aauina atu e a'u mai Ierusalema i Papelonia.", "whom I have sent from Jerusalem to Babylon:"]]},
  {num:21,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["ia Aapo le atalii o Kulaia,", "of Ahab the son of Kolaiah,"], ["ma Setekaia le atalii o Maaseia,", "and of Zedekiah the son of Maaseiah,"], ["o e vavalo i le pepelo ia te outou i lo'u igoa,", "which prophesy a lie unto you in my name;"], ["Faauta,", "Behold,"], ["ou te tuuina i laua i le lima o Nepukanesa le tupu o Papelonia,", "I will deliver them into the hand of Nebuchadrezzar king of Babylon;"], ["na te fasiotia i laua i o outou luma;", "and he shall slay them before your eyes;"]]},
  {num:22,words:[["e avea foi i laua e fai a'i faafanoga e le tafeaga uma o Iuta,", "And of them shall be taken up a curse by all the captivity of Judah which are in Babylon,"], ["o i Papelonia,", "saying,"], ["e faapea, Ia faia oe e Ieova ia pei o Setekaia,", "The LORD make thee like Zedekiah and like Ahab,"], ["ma ia pei o Aapo o e na tunua e le tupu o Papelonia i le afi;", "whom the king of Babylon roasted in the fire;"]]},
  {num:23,words:[["auā na la fai le mea leaga i Isaraelu,", "Because they have committed villany in Israel,"], ["ma la mulilulua ma avā a ē sa latou tuaoi,", "and have committed adultery with their neighbours' wives,"], ["ma la fai upu i lo'u igoa i le pepelo,", "and have spoken lying words in my name, which I have not commanded them;"], ["na ou le poloai atu ai ia te i laua;", "even I know,"], ["ua ou iloa ma molimau ai,", "and am a witness,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:24,words:[["Ia e fai atu foi ia Semaia o le Neelami,", "Thus shalt thou also speak to Shemaiah the Nehelamite,"], ["ia faapea atu,", "saying,"]]},
  {num:25,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus speaketh the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["ua faapea mai,", "saying,"], ["Auā ua e aumaia tusi i lou igoa i le nuu uma o loo i Ierusalema, ma Sefanaia,", "Because thou hast sent letters in thy name unto all the people that are at Jerusalem,"], ["le atalii o Maaseia le faitaulaga,", "and to Zephaniah the son of Maaseiah the priest,"], ["ma faitaulaga uma,", "and to all the priests,"], ["ua faapea atu,", "saying,"]]},
  {num:26,words:[["Ua tofia oe e Ieova e fai ma faitaulaga e sui a'i Ioiata le faitaulaga,", "The LORD hath made thee priest in the stead of Jehoiada the priest,"], ["ina ia faia ni e pule i le fale o Ieova,", "that ye should be officers in the house of the LORD,"], ["i tagata e taitoatasi ua valea,", "for every man that is mad,"], ["ma fai o ia e ia ma perofeta,", "and maketh himself a prophet,"], ["ma ia e tuuina atu o ia i laau faamau,", "that thou shouldest put him in prison,"], ["ma le fale puipui.", "and in the stocks."]]},
  {num:27,words:[["O lenei, se a le mea ua e le aoai atu ai ia Ieremia le Anatota,", "Now therefore why hast thou not reproved Jeremiah of Anathoth,"], ["o le ua fai o ia e ia ma perofeta ia te outou?", "which maketh himself a prophet to you?"]]},
  {num:28,words:[["Auā lava ua au mai ai lana feau ia te i matou i Papelonia,", "For therefore he sent unto us in Babylon,"], ["ua faapea mai,", "saying,"], ["E tuai lenei tafeaga;", "This captivity is long:"], ["ia outou fāi fale,", "build ye houses,"], ["ma nonofo ai,", "and dwell in them;"], ["ma ia outou totōina faatoaga,", "and plant gardens,"], ["ma aai ai o latou fua.", "and eat the fruit of them."]]},
  {num:29,words:[["Ua faitau e Sefanaia le faitaulaga lenei tusi i taliga o Ieremia le perofeta.", "And Zephaniah the priest read this letter in the ears of Jeremiah the prophet."]]},
  {num:30,words:[["Ona oo mai ai lea o le afioga a Ieova ia Ieremia,", "Then came the word of the LORD unto Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:31,words:[["Ia e avatu le feau ia te i latou uma o le tafeaga,", "Send to all them of the captivity,"], ["ia faapea atu, O loo faapea ona fetalai mai o Ieova ia Semaia,", "saying,"], ["le Neelami,", "Thus saith the LORD concerning Shemaiah the Nehelamite;"], ["Ua vavalo ia te outou Semaia,", "Because that Shemaiah hath prophesied unto you,"], ["a o a'u, na ou le auina atu o ia,", "and I sent him not,"], ["ua faatupuina foi e ia ia te outou le faatuatua i le pepelo;", "and he caused you to trust in a lie:"]]},
  {num:32,words:[["o le mea lea o loo faapea ona fetalai mai ai o Ieova,", "Therefore thus saith the LORD;"], ["Faauta,", "Behold,"], ["ou te taui atu ia Semaia le Neelami,", "I will punish Shemaiah the Nehelamite,"], ["ma lana fanau;", "and his seed:"], ["e le i ai ia te ia se tasi e nofo faatasi ma lenei nuu;", "he shall not have a man to dwell among this people;"], ["e le iloa foi e ia le manuia ou te faia mo lo'u nuu,", "neither shall he behold the good that I will do for my people,"], ["o loo fetalai mai ai Ieova;", "saith the LORD;"], ["auā ua ia tautala i le fouvale ia Ieova.", "because he hath taught rebellion against the LORD."]]},
];
renderVerseSet(jer_ch_29_Verses, 'jer-ch29-verses');

var jer_ch_30_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova ua faapea mai,", "The word that came to Jeremiah from the LORD, saying,"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova, le Atua o Isaraelu,", "Thus speaketh the LORD God of Israel,"], ["ua faapea mai,", "saying,"], ["Ina tusi ia i le tusi, o upu uma ua ou fai atu ai ia te oe.", "Write thee all the words that I have spoken unto thee in a book."]]},
  {num:3,words:[["Auā o loo fetalai mai Ieova,", "For,"], ["Faauta,", "lo,"], ["o le a oo mai ona po,", "the days come,"], ["ou te faafoisia mai ai le tafeaga o lo'u nuu o Isaraelu ma Iuta,", "saith the LORD, that I will bring again the captivity of my people Israel and Judah,"], ["o loo faapea mai ai Ieova;", "saith the LORD:"], ["ou te toe faafoisia mai i latou i le laueleele na ou foaiina atu ai i o latou tamā,", "and I will cause them to return to the land that I gave to their fathers,"], ["e fai foi lea mo i latou.", "and they shall possess it."]]},
  {num:4,words:[["O upu foi nei ua fetalai mai ai Ieova ia Isaraelu ma Iuta.", "And these are the words that the LORD spake concerning Israel and concerning Judah."]]},
  {num:5,words:[["E moni,", "For thus saith the LORD;"], ["o loo faapea ona fetalai mai o Ieova,", "We have heard a voice of trembling,"], ["Ua tatou lagona le taalili o le gatete, o i ai le mata'u,", "of fear,"], ["a e le o le filemu.", "and not of peace."]]},
  {num:6,words:[["O le mea lea ina fesili atu ai ia, ma ia outou vaavaai,", "Ask ye now,"], ["pe fanau ea se tane? O le a ea le mea ou te iloa atu ai i tane uma, e taitasi ma ona lima i ona itu,", "and see whether a man doth travail with child? wherefore do I see every man with his hands on his loins,"], ["e pei o se fafine a fanau;", "as a woman in travail,"], ["o mata uma foi ua liua, ua matamata vale lava?", "and all faces are turned into paleness?"]]},
  {num:7,words:[["Aue! auā o le aso tele lea,", "Alas! for that day is great,"], ["e leai sona tusa;", "so that none is like it:"], ["o ona po lava ia o le puapuaga o Iakopo;", "it is even the time of Jacob's trouble;"], ["a e faaolaina ai o ia.", "but he shall be saved out of it."]]},
  {num:8,words:[["O loo fetalai mai foi Ieova o 'au,", "For it shall come to pass in that day,"], ["O le aso lava lea ou te gauia ai lana amo i lou ua,", "saith the LORD of hosts,"], ["ou te motusiesea foi ou noanoaga,", "that I will break his yoke from off thy neck, and will burst thy bonds,"], ["e le toe auauna foi o ia i tagata ese.", "and strangers shall no more serve themselves of him:"]]},
  {num:9,words:[["A e latou te auauna ia Ieova lo latou Atua,", "But they shall serve the LORD their God,"], ["ma Tavita lo latou tupu,", "and David their king,"], ["ou te faatuina ai mo i latou.", "whom I will raise up unto them."]]},
  {num:10,words:[["O oe foi,", "Therefore fear thou not,"], ["Iakopo e,", "O my servant Jacob,"], ["la'u auauna,", "saith the LORD;"], ["aua e te fefe,", "neither be dismayed,"], ["o loo fetalai mai ai Ieova;", "O Israel:"], ["aua foi e te mata'u o oe Isaraelu e;", "for,"], ["auā faauta,", "lo,"], ["ou te faaola ia te oe ai le nuu mamao,", "I will save thee from afar,"], ["ma lau fanau ai le nuu ua tāfea ai i latou;", "and thy seed from the land of their captivity;"], ["e foi mai lava Iakopo,", "and Jacob shall return,"], ["e toto'a foi o ia,", "and shall be in rest,"], ["ma nofo filemu,", "and be quiet,"], ["e leai foi se tasi e faamatau ia te ia .", "and none shall make him afraid."]]},
  {num:11,words:[["Auā o loo fetalai mai Ieova,", "For I am with thee,"], ["ou te ia te oe e faaola ia te oe;", "saith the LORD,"], ["e ui lava ina ou matuā faaumatia nuu uma na ou faataapeapeina ai oe,", "to save thee: though I make a full end of all nations whither I have scattered thee,"], ["a e ou te le matuā faaumatia oe,", "yet will I not make a full end of thee:"], ["ou te aoai faatatau foi ia te oe,", "but I will correct thee in measure,"], ["a e ou te le matuā faasaoina oe.", "and will not leave thee altogether unpunished."]]},
  {num:12,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD,"], ["E le mafai ona fōia lou manua,", "Thy bruise is incurable,"], ["e matuā leaga lou manua.", "and thy wound is grievous."]]},
  {num:13,words:[["E leai se tasi e faia lau finauga,", "There is none to plead thy cause,"], ["ia fusia lou manua;", "that thou mayest be bound up:"], ["e le ia te oe ni fusi e malolo ai.", "thou hast no healing medicines."]]},
  {num:14,words:[["Ua faagalogaloina oe e i latou uma sa mananao ia te oe;", "All thy lovers have forgotten thee;"], ["ua latou le saili ia te oe;", "they seek thee not;"], ["auā ua ou taia oe i le ta a le ua ita,", "for I have wounded thee with the wound of an enemy,"], ["ma le aoaiga a le ua saua,", "with the chastisement of a cruel one,"], ["ona o le tele o lau amioletonu;", "for the multitude of thine iniquity;"], ["ua faateleina au agasala.", "because thy sins were increased."]]},
  {num:15,words:[["Pe se a le mea ua e alaga mai ai ona o lou manua? E matuā tele lou tiga ona o le tele o lau amioletonu;", "Why criest thou for thine affliction? thy sorrow is incurable for the multitude of thine iniquity:"], ["ua faateleina au agasala,", "because thy sins were increased,"], ["o le mea lea na ou faia ai ia mea ia te oe.", "I have done these things unto thee."]]},
  {num:16,words:[["A e ui i lea e faaumatia ai i latou uma o e faaumatia oe;", "Therefore all they that devour thee shall be devoured;"], ["o i latou uma foi ua saua ia te oe,", "and all thine adversaries,"], ["e ō lava i latou uma i le tafeaga; o e ua faoa au mea,", "every one of them,"], ["e faoa lava a latou mea;", "shall go into captivity;"], ["o i latou uma ua vetea oe,", "and they that spoil thee shall be a spoil,"], ["ou te tuuina atu ia vetea i latou.", "and all that prey upon thee will I give for a prey."]]},
  {num:17,words:[["Auā ou te faamaloloina oe,", "For I will restore health unto thee,"], ["ou te fofōina ou manua,", "and I will heal thee of thy wounds,"], ["o loo fetalai mai ai Ieova;", "saith the LORD;"], ["auā ua latou ta'ua oe,", "because they called thee an Outcast,"], ["O le ua tulia;", "saying,"], ["O Siona lena,", "This is Zion,"], ["e leai se tasi ua saili atu i ai.", "whom no man seeketh after."]]},
  {num:18,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Faauta,", "Behold,"], ["ou te toe faafoisia mai le tafeaga o fale ie o Iakopo,", "I will bring again the captivity of Jacob's tents,"], ["ma ou alofa atu i ana mea e nofo ai;", "and have mercy on his dwellingplaces;"], ["e faatuina foi le aai i le mea maupuepue sa i ai,", "and the city shall be builded upon her own heap,"], ["e āina foi le maota e pei o ona tuga tuai.", "and the palace shall remain after the manner thereof."]]},
  {num:19,words:[["E tupu mai ai foi le viiga,", "And out of them shall proceed thanksgiving and the voice of them that make merry:"], ["ma le leo o e sisiva;", "and I will multiply them,"], ["ou te faatoateleina i latou, a e le faatoaitiitina i latou;", "and they shall not be few;"], ["ou te faatupuina foi lo latou mamalu,", "I will also glorify them,"], ["a e le faaleaogaina i latou.", "and they shall not be small."]]},
  {num:20,words:[["O a latou fanau e pei o anamua i latou ,", "Their children also shall be as aforetime,"], ["ou te faatumauina foi i o'u luma lo latou faapotopotoga,", "and their congregation shall be established before me,"], ["ma ou taui atu ia te i latou uma o e faasaua ia te i latou.", "and I will punish all that oppress them."]]},
  {num:21,words:[["O lo latou alii o lo latou lava ia,", "And their nobles shall be of themselves,"], ["ma le na te pule ia te i latou e tupu mai o ia mai ia te i latou;", "and their governor shall proceed from the midst of them;"], ["ou te faalatalataina mai o ia,", "and I will cause him to draw near,"], ["ona faalatalata mai ai lea o ia ia te au;", "and he shall approach unto me:"], ["auā o ai ea o ia ua faamalosi i lona loto e faalatalata mai ia te au? o loo fetalai mai ai Ieova.", "for who is this that engaged his heart to approach unto me? saith the LORD."]]},
  {num:22,words:[["E fai foi outou mo'u nuu,", "And ye shall be my people,"], ["o a'u foi e fai mo outou Atua.", "and I will be your God."]]},
  {num:23,words:[["Faauta,", "Behold,"], ["ua alu atu le afā mai ia Ieova i le toasa,", "the whirlwind of the LORD goeth forth with fury,"], ["o le afā fulifaō;", "a continuing whirlwind:"], ["e pesi tetele mai i luga o ulu o e amio leaga.", "it shall fall with pain upon the head of the wicked."]]},
  {num:24,words:[["E le toe liliu le toasa tele o Ieova,", "The fierce anger of the LORD shall not return,"], ["seia faia e ia,", "until he have done it,"], ["seia faataunuuina foi e ia manatu o lona finagalo;", "and until he have performed the intents of his heart:"], ["tou te mafaufau i ai i aso amuli.", "in the latter days ye shall consider it."]]},
];
renderVerseSet(jer_ch_30_Verses, 'jer-ch30-verses');

var jer_ch_31_Verses = [
  {num:1,words:[["O loo fetalai mai Ieova,", "At the same time,"], ["O ona po ia e fai a'u ma Atua i aiga uma o Isaraelu,", "saith the LORD, will I be the God of all the families of Israel,"], ["e fai foi i latou mo'u nuu.", "and they shall be my people."]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Na maua le alofa i le vao e le nuu na totoe i le pelu,", "The people which were left of the sword found grace in the wilderness;"], ["o Isaraelu lava,", "even Israel,"], ["ina ua ou alu atu e faanofo filemu ia te ia.", "when I went to cause him to rest."]]},
  {num:3,words:[["Na faaali mai Ieova ia te au anamua,", "The LORD hath appeared of old unto me,"], ["ua faapea mai ,", "saying,"], ["O le alofa e faavavau,", "Yea,"], ["ua ou alofa atu ai ia te oe;", "I have loved thee with an everlasting love:"], ["o le mea lea ua ou faafualoaina ai lo'u alofa ia te oe.", "therefore with lovingkindness have I drawn thee."]]},
  {num:4,words:[["Le taupou o Isaraelu e,", "Again I will build thee,"], ["ou te toe ati ae ia te oe,", "and thou shalt be built,"], ["ona atiina ae ai lea o oe;", "O virgin of Israel:"], ["e te toe teuteu ia te oe i au topa,", "thou shalt again be adorned with thy tabrets,"], ["e te alu atu foi e siva faatasi ma i latou o e sisiva.", "and shalt go forth in the dances of them that make merry."]]},
  {num:5,words:[["E te toe totō tovine i mauga o Samaria;", "Thou shalt yet plant vines upon the mountains of Samaria:"], ["e totō ai mea e tagata gālue fanua,", "the planters shall plant,"], ["ma latou faatatagaina ai.", "and shall eat them as common things."]]},
  {num:6,words:[["Auā e oo i le aso e valaau ai tagata leoleo i le mauga o Efaraima,", "For there shall be a day,"], ["Ina tulai ia outou,", "that the watchmen upon the mount Ephraim shall cry, Arise ye,"], ["se'i tatou o ae i Siona ia Ieova lo tatou Atua.", "and let us go up to Zion unto the LORD our God."]]},
  {num:7,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD;"], ["Ia outou alalaga ma le olioli ia Iakopo,", "Sing with gladness for Jacob,"], ["ma ia outou alalaga,", "and shout among the chief of the nations:"], ["i le nuu e sili;", "publish ye,"], ["ina faailoa atu ia, ia outou vivii atu,", "praise ye,"], ["ma ia outou fai atu,", "and say,"], ["Ieova e,", "O LORD,"], ["ia e faaola i lou nuu,", "save thy people,"], ["o e ua totoe ia Isaraelu.", "the remnant of Israel."]]},
  {num:8,words:[["Faauta,", "Behold,"], ["ou te aumaia i latou ai le nuu i le itu i matu,", "I will bring them from the north country,"], ["ma ou faapotopoto ia te i latou ai tuluiga o le lalolagi;", "and gather them from the coasts of the earth,"], ["e faatasi foi ma i latou le tauaso ma le pipili,", "and with them the blind and the lame,"], ["o le fafine ua to e faatasi ma le fafine o le a fanau;", "the woman with child and her that travaileth with child together:"], ["e toe foi mai iinei le faapotopotoga e toatele lava.", "a great company shall return thither."]]},
  {num:9,words:[["Latou te o mai ma le tagi,", "They shall come with weeping,"], ["ou te ta'ita'iina foi i latou o latou aioi mai;", "and with supplications will I lead them:"], ["ou te aumaia i latou i vaitafe i le ala sa'o, latou te le tausuai ai;", "I will cause them to walk by the rivers of waters in a straight way,"], ["auā o a'u,", "wherein they shall not stumble:"], ["o le tamā a'u o Isaraelu,", "for I am a father to Israel,"], ["o Efaraima foi o la'u ulumatua ia.", "and Ephraim is my firstborn."]]},
  {num:10,words:[["Ina faalogologo mai ia i le afioga a Ieova,", "Hear the word of the LORD,"], ["outou nuu e,", "O ye nations,"], ["ma ia outou ta'u atu ai i nuu tu matafaga e mamao,", "and declare it in the isles afar off,"], ["ia faapea atu,", "and say,"], ["O le na faataapeapeina Isaraelu,", "He that scattered Israel will gather him,"], ["na te faapotopotoina i latou,", "and keep him,"], ["ma leoleo ia te i latou e pei o le leoleo mamoe i lona lafu.", "as a shepherd doth his flock."]]},
  {num:11,words:[["Auā ua laveaiina Iakopo e Ieova,", "For the LORD hath redeemed Jacob,"], ["ua na faatauina foi o ia ai le lima o le ua sili lona malosi ia te ia.", "and ransomed him from the hand of him that was stronger than he."]]},
  {num:12,words:[["E o mai foi i latou ma latou alalaga fiafia i le mea maualuga o Siona,", "Therefore they shall come and sing in the height of Zion,"], ["latou te gasolo ane i mea lelei a Ieova,", "and shall flow together to the goodness of the LORD,"], ["ia maua ai le saito,", "for wheat,"], ["ma le uaina,", "and for wine,"], ["ma le suāuu, o tamai mamoe foi,", "and for oil,"], ["ma tamai povi;", "and for the young of the flock and of the herd:"], ["o latou loto foi e pei o se faatoaga ua faasūsūina;", "and their soul shall be as a watered garden;"], ["e le toe vaivai lava i latou.", "and they shall not sorrow any more at all."]]},
  {num:13,words:[["Ona olioli ai lea o le taupou i le siva,", "Then shall the virgin rejoice in the dance,"], ["o taulelea foi faatasi ma toeaina;", "both young men and old together:"], ["ou te liua foi lo latou faanoanoa i le fiafia,", "for I will turn their mourning into joy,"], ["ma ou faamatalaloto ia te i latou,", "and will comfort them,"], ["ou te faafiafia ia te i latou sa tiga i latou.", "and make them rejoice from their sorrow."]]},
  {num:14,words:[["Ou te faamalilie manao o le au faitaulaga i mea lololo,", "And I will satiate the soul of the priests with fatness,"], ["e mălie foi lo'u nuu i a'u mea lelei,", "and my people shall be satisfied with my goodness,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:15,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Ua lagona le leo i Rama,", "A voice was heard in Ramah,"], ["o le auega, o le tagi lotulotu lava;", "lamentation,"], ["ua tagi Rasela ona o lana fanau,", "and bitter weeping;"], ["e le mafai foi ona faanaina o ia ona o lana fanau,", "Rahel weeping for her children refused to be comforted for her children,"], ["auā ua leai i latou.", "because they were not."]]},
  {num:16,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Soia e te tagi,", "Refrain thy voice from weeping,"], ["aua foi le tafe ifo o loimata i ou mata;", "and thine eyes from tears:"], ["auā o loo fetalai mai Ieova,", "for thy work shall be rewarded,"], ["e fai le taui a lau galuega,", "saith the LORD;"], ["e toe foi mai lava i latou ai le nuu o e ita mai.", "and they shall come again from the land of the enemy."]]},
  {num:17,words:[["E fai foi le faamoemoe i lou iuga,", "And there is hope in thine end,"], ["ua fetalai mai ai Ieova,", "saith the LORD,"], ["e toe foi mai lava lau fanau i lo latou laueleele.", "that thy children shall come again to their own border."]]},
  {num:18,words:[["Ua ou faalogo lava ia Efaraima ua faanoanoa o ia,", "I have surely heard Ephraim bemoaning himself thus;"], ["ua faapea , Ua e aoai mai ia te au,", "Thou hast chastised me,"], ["ua aoaiina foi a'u,", "and I was chastised,"], ["e pei o le povi ua le a'oa'oina; ia e faaliliuina a'u,", "as a bullock unaccustomed to the yoke:"], ["ona liliu ai lea o a'u;", "turn thou me,"], ["auā o oe, Ieova e,", "and I shall be turned;"], ["o lo'u Atua oe .", "for thou art the LORD my God."]]},
  {num:19,words:[["Auā na faaliliuina a'u,", "Surely after that I was turned,"], ["mulimuli ane,", "I repented;"], ["ona ou salamo ai lea;", "and after that I was instructed,"], ["na a'oa'oina a'u,", "I smote upon my thigh:"], ["mulimuli ane, ona ou pōpō ai lea i lo'u vae;", "I was ashamed,"], ["na a'u mā,", "yea,"], ["ma a'u masiasi,", "even confounded,"], ["auā na a'u tauave le luma na fai ina o taulealea o a'u.", "because I did bear the reproach of my youth."]]},
  {num:20,words:[["O le atalii pele ea Efaraima ia te au? o le tama ea ia e fiafia i ai? auā talu ina ou tautala ia te ia;", "Is Ephraim my dear son? is he a pleasant child? for since I spake against him,"], ["ua ou matuā manatunatu pea ia te ia;", "I do earnestly remember him still:"], ["o le mea lea ua tagi ai lo'u loto ia te ia;", "therefore my bowels are troubled for him;"], ["ou te matuā alofa lava ia te ia,", "I will surely have mercy upon him,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:21,words:[["Ina faatuina ia mo oe ni faailoga i le ala ,", "Set thee up waymarks,"], ["ina faatu ia mo oe ni laau;", "make thee high heaps:"], ["ia faasaga lou loto i le ala tele,", "set thine heart toward the highway,"], ["o le ala lava na e alu atu ai;", "even the way which thou wentest:"], ["ina foi mai ia,", "turn again,"], ["le taupou o Isaraelu e,", "O virgin of Israel,"], ["ina foi mai ia i ou aai nei.", "turn again to these thy cities."]]},
  {num:22,words:[["E te fealualuai seia afea,", "How long wilt thou go about,"], ["oe na le tama fafine liliu ese? auā ua faia e Ieova le mea fou i le lalolagi,", "O thou backsliding daughter? for the LORD hath created a new thing in the earth,"], ["e siosioina le tane e le fafine.", "A woman shall compass a man."]]},
  {num:23,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["E toe faia e i latou lenei upu i le nuu o Iuta ma ona aai,", "As yet they shall use this speech in the land of Judah and in the cities thereof, when I shall bring again their captivity;"], ["pe a ou faafoisia mai lo latou tafeaga,", "The LORD bless thee,"], ["Ia faamanuia Ieova ia te oe le fale e i ai le amiotonu,", "O habitation of justice,"], ["o le mauga paia.", "and mountain of holiness."]]},
  {num:24,words:[["E nonofo ai foi Iuta ma ona aai uma faatasi,", "And there shall dwell in Judah itself,"], ["o tagata gālue fanua,", "and in all the cities thereof together, husbandmen,"], ["ma ē feoai ma lafu.", "and they that go forth with flocks."]]},
  {num:25,words:[["Auā ua ou faamălie i le tagata ua lailoa,", "For I have satiated the weary soul,"], ["ua ou faamalilieina loto vaivai uma.", "and I have replenished every sorrowful soul."]]},
  {num:26,words:[["Ona ou ala ai lea,", "Upon this I awaked,"], ["ma ou vaai,", "and beheld;"], ["ua mălie lava a'u i a'u moe.", "and my sleep was sweet unto me."]]},
  {num:27,words:[["O loo fetalai mai Ieova,", "Behold,"], ["Faauta,", "the days come,"], ["e oo lava i ona aso ou te totōina ai le fua o tagata ma le fua o manu i le aiga o Isaraelu,", "saith the LORD, that I will sow the house of Israel and the house of Judah with the seed of man,"], ["ma le aiga o Iuta.", "and with the seed of beast."]]},
  {num:28,words:[["E pei ona ou lamalama ia te i latou,", "And it shall come to pass,"], ["ina ia ou liaiina,", "that like as I have watched over them,"], ["ma lepetia,", "to pluck up,"], ["ia ou sŏloia foi,", "and to break down,"], ["ma faaumatia,", "and to throw down, and to destroy,"], ["ma faatigaina;", "and to afflict;"], ["e faapea foi ona ou leoleo ia te i latou,", "so will I watch over them,"], ["ia ou atiina ae,", "to build,"], ["ma totōina,", "and to plant,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:29,words:[["E le toe fai mai i latou i ia ona po,", "In those days they shall say no more,"], ["Ua 'aina e tamā o vine moto,", "The fathers have eaten a sour grape,"], ["a e magiagia ai nifo o le fanau.", "and the children's teeth are set on edge."]]},
  {num:30,words:[["A e taitasi le tagata ma oti ona o ana agasala;", "But every one shall die for his own iniquity:"], ["o tagata uma ua aai vine moto,", "every man that eateth the sour grape,"], ["e taitasi ma magiagia ai ona lava nifo.", "his teeth shall be set on edge."]]},
  {num:31,words:[["O loo fetalai mai Ieova,", "Behold,"], ["Faauta,", "the days come,"], ["e oo i ona aso ou te osia ai le feagaiga fou ma le aiga o Isaraelu,", "saith the LORD, that I will make a new covenant with the house of Israel,"], ["ma le aiga o Iuta.", "and with the house of Judah:"]]},
  {num:32,words:[["E le pei o le feagaiga na ou osia ma o latou tamā i le aso na ou tago ai i o latou lima e aumaia ai i latou mai le nuu o Aikupito;", "Not according to the covenant that I made with their fathers in the day that I took them by the hand to bring them out of the land of Egypt;"], ["o la'u feagaiga lea na latou solia,", "which my covenant they brake,"], ["o a'u foi na ou 'ino'ino ai ia te i latou,", "although I was an husband unto them,"], ["ua fetalai mai ai Ieova;", "saith the LORD:"]]},
  {num:33,words:[["a o lenei le feagaiga ou te osia ma le aiga o Isaraelu,", "But this shall be the covenant that I will make with the house of Israel;"], ["pe a mavae ia aso,", "After those days,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["ou te tuuina la'u tulafono i totonu ia te i latou,", "I will put my law in their inward parts,"], ["ma ou tusi ai i o latou loto;", "and write it in their hearts;"], ["e fai foi a'u mo latou Atua,", "and will be their God,"], ["o i latou foi e fai mo'u nuu.", "and they shall be my people."]]},
  {num:34,words:[["E le toe a'oa'o atu foi le tagata i lē la te tuaoi,", "And they shall teach no more every man his neighbour,"], ["ma le tagata i lona uso,", "and every man his brother,"], ["e faapea atu,", "saying,"], ["Ia outou iloa Ieova;", "Know the LORD:"], ["auā e iloa a'u e i latou uma lava,", "for they shall all know me,"], ["o tagata nuu atoa ma alii,", "from the least of them unto the greatest of them,"], ["o loo fetalai mai ai Ieova;", "saith the LORD:"], ["auā ou te faamagalo i a latou amio leaga,", "for I will forgive their iniquity,"], ["ma ou le toe manatua a latou agasala.", "and I will remember their sin no more."]]},
  {num:35,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["o le ua tuuina le la e fai ma malamalama i le ao, o tulafono foi i le masina ma fetu e fai ma malamalama i le po;", "which giveth the sun for a light by day,"], ["o le e laolao ai le sami pe a ū mai ona peau;", "and the ordinances of the moon and of the stars for a light by night,"], ["o Ieova, o 'au,", "which divideth the sea when the waves thereof roar;"], ["o lona suafa lava lea;", "The LORD of hosts is his name:"]]},
  {num:36,words:[["afai e mavae ia tulafono ai o'u luma,", "If those ordinances depart from before me,"], ["ua fetalai mai ai Ieova, ona mavae ai lea o le fanau a Isaraelu,", "saith the LORD,"], ["ia le toe fai ma nuu i o'u luma e faavavau.", "then the seed of Israel also shall cease from being a nation before me for ever."]]},
  {num:37,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Afai e mafai ona fuatia le lagi i lugā,", "If heaven above can be measured,"], ["afai foi e mafai ona suesueina o faavae o le lalolagi i lalō,", "and the foundations of the earth searched out beneath,"], ["ona ou lafoaiina lea o le fanau uma a Isaraelu ona o mea uma ua latou faia,", "I will also cast off all the seed of Israel for all that they have done,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:38,words:[["Faauta,", "Behold,"], ["e oo i ona aso,", "the days come,"], ["o loo fetalai mai ai Ieova, e faatuina ai le aai mo Ieova,", "saith the LORD,"], ["e afua mai i le 'olo o Hananiali e oo atu i le faitotoa o le tulimanu.", "that the city shall be built to the LORD from the tower of Hananeel unto the gate of the corner."]]},
  {num:39,words:[["E toe alu atu le maea e fua a'i, e ui tonu atu i luga o le mauga o Karepa,", "And the measuring line shall yet go forth over against it upon the hill Gareb,"], ["e faataamilo atu foi i Koata.", "and shall compass about to Goath."]]},
  {num:40,words:[["E faapaiaina foi mo Ieova le vanu uma ua i ai tino o tagata oti,", "And the whole valley of the dead bodies,"], ["ma le lefulefu,", "and of the ashes,"], ["ma fanua uma,", "and all the fields unto the brook of Kidron,"], ["e oo i le alia o Ketarono,", "unto the corner of the horse gate toward the east,"], ["e oo foi i le tulimanu o le faitotoa o solofanua i sasae;", "shall be holy unto the LORD;"], ["e le toe liaiina ia,", "it shall not be plucked up,"], ["e le toe sŏloia foi e oo i le faavavau.", "nor thrown down any more for ever."]]},
];
renderVerseSet(jer_ch_31_Verses, 'jer-ch31-verses');

var jer_ch_32_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova i le sefulu o tausaga o Setekaia le tupu o Iuta,", "The word that came to Jeremiah from the LORD in the tenth year of Zedekiah king of Judah,"], ["o le sefulu ma le valu o tausaga lea o Nepukanesa.", "which was the eighteenth year of Nebuchadrezzar."]]},
  {num:2,words:[["O ona po ia na vagaia ai Ierusalema e le itu taua a le tupu o Papelonia;", "For then the king of Babylon's army besieged Jerusalem: and Jeremiah the prophet was shut up in the court of the prison,"], ["sa puipuia foi Ieremia le perofeta i le lotoā o le fale puipui sa i le fale o le tupu o Iuta.", "which was in the king of Judah's house."]]},
  {num:3,words:[["Auā na puipuia o ia e Setekaia le tupu o Iuta,", "For Zedekiah king of Judah had shut him up,"], ["ua ia faapea,", "saying,"], ["Se a ea le mea ua e vavalo ai,", "Wherefore dost thou prophesy,"], ["ua faapea mai,", "and say,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Faauta,", "Behold,"], ["ou te tuuina atu lenei aai i le lima o le tupu o Papelonia,", "I will give this city into the hand of the king of Babylon,"], ["na te aea;", "and he shall take it;"]]},
  {num:4,words:[["e le sao foi Setekaia le tupu o Iuta ai lima o Kaletaia,", "And Zedekiah king of Judah shall not escape out of the hand of the Chaldeans,"], ["a e tuuina lava o ia i le lima o le tupu o Papelonia,", "but shall surely be delivered into the hand of the king of Babylon,"], ["la te tautala faafesaga'i ma ia,", "and shall speak with him mouth to mouth,"], ["ma la feiloa'i ma ia;", "and his eyes shall behold his eyes;"]]},
  {num:5,words:[["e ta'ita'iina foi e ia o Setekaia i Papelonia,", "And he shall lead Zedekiah to Babylon,"], ["e i ai foi o ia i lea mea seia ou asiasi atu ia te ia,", "and there shall he be until I visit him,"], ["ua fetalai mai ai Ieova;", "saith the LORD: though ye fight with the Chaldeans,"], ["e ui lava ina outou tau ma Kaletaia e le manuia outou.", "ye shall not prosper."]]},
  {num:6,words:[["Ua fai atu Ieremia,", "And Jeremiah said,"], ["Ua oo mai le afioga a Ieova ia te au,", "The word of the LORD came unto me,"], ["ua faapea mai.", "saying,"]]},
  {num:7,words:[["Faauta,", "Behold,"], ["e sau ia te oe o Hanameali, le atalii o Saluma,", "Hanameel the son of Shallum thine uncle shall come unto thee,"], ["o le uso o lou tamā,", "saying,"], ["e faapea mai, Ia e faatau mo oe lo'u fanua o loo i Anatota;", "Buy thee my field that is in Anathoth:"], ["auā ua ia te oe le pule i le faatau e faatau ai.", "for the right of redemption is thine to buy it."]]},
  {num:8,words:[["Ona sau ai lea ia te au i le lotoā o le fale puipui o Hanameali,", "So Hanameel mine uncle's son came to me in the court of the prison according to the word of the LORD,"], ["le atalii o le uso o lo'u tama,", "and said unto me,"], ["e pei o le afioga a Ieova,", "Buy my field,"], ["ua faapea mai ia te au,", "I pray thee,"], ["Se'i e faatau lo'u fanua,", "that is in Anathoth,"], ["o loo i Anatota o i le nuu o Peniamina;", "which is in the country of Benjamin:"], ["auā e āu le pule e fai mou le fanua ,", "for the right of inheritance is thine,"], ["e ou foi le faatau;", "and the redemption is thine;"], ["ina faatau ia mo oe.", "buy it for thyself."], ["Ona ou iloa ai lea, o le afioga a Ieova lea.", "Then I knew that this was the word of the LORD."]]},
  {num:9,words:[["Ona ou faatauina lea mai ia Hanameali,", "And I bought the field of Hanameel my uncle's son,"], ["le atalii o le uso o lo'u tamā,", "that was in Anathoth,"], ["o le fanua o loo i Anatota, ma ou fuatia ia te ia o tupe,", "and weighed him the money,"], ["o sekeli ario e sefulu ma le fitu.", "even seventeen shekels of silver."]]},
  {num:10,words:[["Ona ou tusia lea i le tusi,", "And I subscribed the evidence,"], ["ma ou faamaufaailogaina ai,", "and sealed it,"], ["ma ou amia mai molimau,", "and took witnesses,"], ["ma ou fuatia le ario i le fua faatautau.", "and weighed him the money in the balances."]]},
  {num:11,words:[["ona ou ave ai lea o le tusi o le faatau,", "So I took the evidence of the purchase,"], ["o le ua faamaufaailogaina e tusa ma le poloaiga ma tulafono,", "both that which was sealed according to the law and custom,"], ["atoa ma le ua le faamauina;", "and that which was open:"]]},
  {num:12,words:[["ua ou ave foi le tusi o le faatau ia Paruka,", "And I gave the evidence of the purchase unto Baruch the son of Neriah,"], ["le atalii o Neria, le atalii o Maaseia,", "the son of Maaseiah,"], ["i luma o Hanameali,", "in the sight of Hanameel mine uncle's son,"], ["le atalii o le uso o lo'u tamā, i luma foi o molimau na tusi i le tusi o le faatau,", "and in the presence of the witnesses that subscribed the book of the purchase,"], ["i luma foi o tagata Iuta uma sa nonofo i le lotoā o le fale puipui.", "before all the Jews that sat in the court of the prison."]]},
  {num:13,words:[["Ua ou matuā fai atu foi ia Paruka i o latou luma,", "And I charged Baruch before them,"], ["ua faapea atu,", "saying,"]]},
  {num:14,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Ia e ave nei tusi,", "Take these evidences,"], ["o lenei lava tusi o le faatau,", "this evidence of the purchase,"], ["o le ua faamaufaailogaina,", "both which is sealed,"], ["atoa foi ma lenei tusi ua le faamauina,", "and this evidence which is open;"], ["ia e tuu ai foi i se ipu omea,", "and put them in an earthen vessel,"], ["ina ia tumau i aso e tele;", "that they may continue many days."]]},
  {num:15,words:[["auā o loo faapea ona fetalai mai o Ieova o 'au, le Atua o Isaraelu,", "For thus saith the LORD of hosts,"], ["E toe faatauina i le nuu nei o fale,", "the God of Israel;"], ["ma fanua, ma tovine.", "Houses and fields and vineyards shall be possessed again in this land."]]},
  {num:16,words:[["Ua ou tuuina le tusi o le faatau ia Paruka le atalii o Neria,", "Now when I had delivered the evidence of the purchase unto Baruch the son of Neriah,"], ["mulimuli ane ona ou tatalo atu lea ia Ieova,", "I prayed unto the LORD,"], ["ua faapea atu,", "saying,"]]},
  {num:17,words:[["Aue! le Alii e Ieova, faauta,", "Ah Lord GOD! behold,"], ["o oe na e faia le lagi ma le lalolagi i lou malosi tele,", "thou hast made the heaven and the earth by thy great power and stretched out arm,"], ["ma lou aao faaloaloa, e le faigata foi ia te oe se mea e tasi;", "and there is nothing too hard for thee:"]]},
  {num:18,words:[["ua e alofa i afe o tupulaga ,", "Thou shewest lovingkindness unto thousands,"], ["ua e taui atu foi le amioletonu a tamā i fatafata o a latou fanau pe a mavae atu i latou;", "and recompensest the iniquity of the fathers into the bosom of their children after them:"], ["o le Atua sili,", "the Great,"], ["ma le malosi,", "the Mighty God,"], ["o Ieova o 'au,", "the LORD of hosts,"], ["o lona suafa lea,", "is his name,"]]},
  {num:19,words:[["e sili i faautauta,", "Great in counsel,"], ["e silisili foi i au mea e fai;", "and mighty in work:"], ["auā ua silasila ou fofoga i ala uma o tagata;", "for thine eyes are open upon all the ways of the sons of men:"], ["e tuuina atu i tagata taitasi e tusa ma ona ala,", "to give every one according to his ways,"], ["e tusa foi ma le fua o ana amioga;", "and according to the fruit of his doings:"]]},
  {num:20,words:[["o le na faatuina foi o faailoga ma vavega i le nuu o Aikupito,", "Which hast set signs and wonders in the land of Egypt,"], ["ua oo i le aso nei,", "even unto this day,"], ["ma le nuu o Isaraelu,", "and in Israel,"], ["atoa ma nuu o tagata ese;", "and among other men;"], ["ua e faia foi mo oe le suafa,", "and hast made thee a name,"], ["e pei ona faia i le aso nei.", "as at this day;"]]},
  {num:21,words:[["Na e aumaia foi lou nuu o Isaraelu mai le nuu o Aikupito,", "And hast brought forth thy people Israel out of the land of Egypt with signs,"], ["ma faailoga,", "and with wonders,"], ["ma vavega, ma le aao malosi,", "and with a strong hand,"], ["ma le aao faaloaloa,", "and with a stretched out arm,"], ["ma mea matua matautia.", "and with great terror;"]]},
  {num:22,words:[["Ua e foaiina mai foi ia te i latou lenei nuu,", "And hast given them this land,"], ["na e tauto ai i o latou tamā e foai ia te i latou,", "which thou didst swear to their fathers to give them,"], ["o le nuu o tafe ai le suāsusu ma le meli;", "a land flowing with milk and honey;"]]},
  {num:23,words:[["na latou o mai ai,", "And they came in,"], ["ma fai ai mo latou;", "and possessed it;"], ["a ua latou le faalogo i lou siufofoga,", "but they obeyed not thy voice,"], ["ma latou le savavali e tusa ma au tulafono;", "neither walked in thy law;"], ["ua latou le faia mea uma na e poloai ai ia te i latou ia faia;", "they have done nothing of all that thou commandedst them to do:"], ["o le mea lea ua e faaoo ai nei mea leaga uma ia te i latou.", "therefore thou hast caused all this evil to come upon them:"]]},
  {num:24,words:[["Faauta mai,", "Behold the mounts,"], ["o mea mautietie,", "they are come unto the city to take it;"], ["ua oo mai lava i le aai e aea a'i;", "and the city is given into the hand of the Chaldeans,"], ["ua tuuina foi le aai i lima o Kaletaia,", "that fight against it,"], ["o e ua faasaga tau mai ai,", "because of the sword,"], ["auā o le pelu,", "and of the famine,"], ["ma le oge,", "and of the pestilence:"], ["ma le faamai;", "and what thou hast spoken is come to pass;"], ["o le mea lava na e fetalaia ua oo;", "and,"], ["faauta mai foi,", "behold,"], ["ua e silafia.", "thou seest it."]]},
  {num:25,words:[["A o oe,", "And thou hast said unto me,"], ["le Alii e Ieova, ua e fetalai mai ia te au,", "O Lord GOD,"], ["Ia e faatau le fanua mo oe i tupe,", "Buy thee the field for money,"], ["ma aami atu molimau; a o le aai,", "and take witnesses;"], ["ua tuuina atu lea i lima o Kaletaia.", "for the city is given into the hand of the Chaldeans."]]},
  {num:26,words:[["Ona oo mai ai lea o le afioga a Ieova ia Ieremia,", "Then came the word of the LORD unto Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:27,words:[["Faauta,", "Behold,"], ["o a'u lava o Ieova,", "I am the LORD,"], ["o le Atua o tagata uma;", "the God of all flesh:"], ["pe faigata ea ia te au se mea e tasi?", "is there any thing too hard for me?"]]},
  {num:28,words:[["O lea o loo faapea ona fetalai mai ai o Ieova,", "Therefore thus saith the LORD;"], ["Faauta,", "Behold,"], ["ou te tuuina atu lenei aai i lima o Kaletaia,", "I will give this city into the hand of the Chaldeans,"], ["ma le lima o Nepukanesa le tupu o Papelonia,", "and into the hand of Nebuchadrezzar king of Babylon,"], ["e aea ai foi e ia;", "and he shall take it:"]]},
  {num:29,words:[["e o mai foi Kaletaia,", "And the Chaldeans,"], ["o e tau ma lenei aai,", "that fight against this city,"], ["ma latou faamu lenei aai i le afi,", "shall come and set fire on this city,"], ["e susunuina ai lava e i latou,", "and burn it with the houses,"], ["atoa ma fale na faamuina ai mea manogi i o latou luga ia Paala,", "upon whose roofs they have offered incense unto Baal,"], ["ma latou liligi ifo ai taulaga i mea e inu i atua ese,", "and poured out drink offerings unto other gods,"], ["ina ia latou faaonoono mai ia te au.", "to provoke me to anger."]]},
  {num:30,words:[["Auā ua na o mea leaga ua faia i o'u luma e le fanauga a Isaraelu ma le fanauga a Iuta talu ina o taulelea i latou;", "For the children of Israel and the children of Judah have only done evil before me from their youth:"], ["auā ua na ona faaonoono mai o le fanauga a Isaraelu ia te au i galuega a o latou lima,", "for the children of Israel have only provoked me to anger with the work of their hands,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:31,words:[["Auā ua faia lenei aai ia te au ma mea ou te tiga ai, ma mea ou te ita ai,", "For this city hath been to me as a provocation of mine anger and of my fury from the day that they built it even unto this day;"], ["talu mai le aso na faia ai, ua oo lava i le aso nei, ina ia ou aveeseina ai i o'u luma;", "that I should remove it from before my face,"]]},
  {num:32,words:[["ona o amio leaga uma a le fanauga a Isaraelu,", "Because of all the evil of the children of Israel and of the children of Judah,"], ["ma le fanauga a Iuta,", "which they have done to provoke me to anger,"], ["ua latou faia e faaonoono ai ia te au,", "they,"], ["o i latou,", "their kings,"], ["o latou tupu, o latou alii,", "their princes,"], ["o latou faitaulaga,", "their priests,"], ["ma o latou perofeta,", "and their prophets,"], ["ma tagata Iuta,", "and the men of Judah,"], ["atoa ma e o nonofo i Ierusalema.", "and the inhabitants of Jerusalem."]]},
  {num:33,words:[["Ua u mai ia te au o latou tua,", "And they have turned unto me the back,"], ["a e le o latou mata;", "and not the face:"], ["ua ou a'oa'o atu ia te i latou,", "though I taught them,"], ["ua ou ala a'oa'o atu ai lava,", "rising up early and teaching them,"], ["a ua latou le faalogo lava ina ia talia mea ua a'oa'oina atu ai;", "yet they have not hearkened to receive instruction."]]},
  {num:34,words:[["a ua latou tuuina a latou mea e inosia i le fale ua ta'ua ai lo'u igoa,", "But they set their abominations in the house, which is called by my name,"], ["ina ia latou faaleagaina ai.", "to defile it."]]},
  {num:35,words:[["Ua faia foi e i latou mea maualuluga ia Paala,", "And they built the high places of Baal,"], ["ua i le vanu o le atalii o Hinoma,", "which are in the valley of the son of Hinnom,"], ["ina ia latou faaui ane o latou atalii ma o latou afafine i le afi ia Moloka;", "to cause their sons and their daughters to pass through the fire unto Molech; which I commanded them not,"], ["o le mea lava ou te lei poloai ai ia te i latou,", "neither came it into my mind,"], ["ou te lei manatu foi i ai;", "that they should do this abomination,"], ["ua faia e i latou lenei mea e inosia e faatupuina ai le agasala ia Iuta.", "to cause Judah to sin."]]},
  {num:36,words:[["A o lenei,", "And now therefore thus saith the LORD,"], ["o loo faapea ona fetalai mai o Ieova,", "the God of Israel,"], ["le Atua o Isaraelu,", "concerning this city,"], ["i le aai nei, o loo ua outou fai mai ai,", "whereof ye say,"], ["Ua tuuina atu ia i le lima o le tupu o Papelonia i le pelu,", "It shall be delivered into the hand of the king of Babylon by the sword,"], ["ma le oge,", "and by the famine,"], ["ma le faamai;", "and by the pestilence;"]]},
  {num:37,words:[["faauta,", "Behold,"], ["ou te faapotopoto ia te i latou ai nuu uma ua ou tulia ai i latou i lo'u tiga,", "I will gather them out of all countries,"], ["ma lo'u ita,", "whither I have driven them in mine anger, and in my fury,"], ["ma le ita tele;", "and in great wrath;"], ["ou te faafoisia mai i latou i lenei mea,", "and I will bring them again unto this place,"], ["ma ou faanonofoina ai i latou ma le filemu;", "and I will cause them to dwell safely:"]]},
  {num:38,words:[["e fai foi i latou mo'u nuu,", "And they shall be my people,"], ["e fai foi a'u mo latou Atua.", "and I will be their God:"]]},
  {num:39,words:[["Ou te foaiina atu ia te i latou le loto e tasi,", "And I will give them one heart,"], ["ma le ala e tasi,", "and one way,"], ["ina ia latou matatau ia te au i aso uma lava,", "that they may fear me for ever,"], ["ia lelei ai i latou,", "for the good of them,"], ["atoa foi ma a latou fanau pe a mavae atu i latou;", "and of their children after them:"]]},
  {num:40,words:[["ou te osia foi le feagaiga e faavavau ma i latou,", "And I will make an everlasting covenant with them,"], ["ou te le liliu ese ai ia te i latou,", "that I will not turn away from them,"], ["a ou te agalelei atu ia te i latou;", "to do them good;"], ["ou te tuuina atu foi le mata'u ia te au i o latou loto,", "but I will put my fear in their hearts,"], ["ina ia latou le liliu ese ia te au.", "that they shall not depart from me."]]},
  {num:41,words:[["Ou te fiafia lava ia te i latou, ma ou agalelei atu ia te i latou,", "Yea,"], ["ma ou totōina i latou i lenei nuu ma le faamaoni,", "I will rejoice over them to do them good,"], ["ma lo'u loto atoa, ma lo'u agaga atoa.", "and I will plant them in this land assuredly with my whole heart and with my whole soul."]]},
  {num:42,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD;"], ["E pei ona ou faaoo i lenei nuu lenei malaia tele uma,", "Like as I have brought all this great evil upon this people,"], ["e faapea foi ona ou faaoo ia te i latou le manuia uma ua ou folafolaina ia te i latou.", "so will I bring upon them all the good that I have promised them."]]},
  {num:43,words:[["E faataulia foi fanua i le nuu nei, ua outou faapea mai ai,", "And fields shall be bought in this land,"], ["Ua faatafunaina ia,", "whereof ye say,"], ["e le o i ai se tagata,", "It is desolate without man or beast;"], ["po o se manu; ua tuuina atu ia i lima o Kaletaia.", "it is given into the hand of the Chaldeans."]]},
  {num:44,words:[["E faataulia e i latou fanua i tupe,", "Men shall buy fields for money,"], ["ma latou tusia ai i tusi,", "and subscribe evidences,"], ["ma faamaufaailogaina ai,", "and seal them,"], ["ma aami molimau i le nuu o Peniamina,", "and take witnesses in the land of Benjamin,"], ["ma mea e vagavagai i Ierusalema,", "and in the places about Jerusalem,"], ["ma aai o Iuta,", "and in the cities of Judah,"], ["ma aai i atu mauga,", "and in the cities of the mountains,"], ["ma aai i le itu maulalo,", "and in the cities of the valley,"], ["ma aai i le itu i toga;", "and in the cities of the south:"], ["auā ou te faafoisia lava lo latou tafeaga,", "for I will cause their captivity to return,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
];
renderVerseSet(jer_ch_32_Verses, 'jer-ch32-verses');

var jer_ch_33_Verses = [
  {num:1,words:[["Na o mai foi le afioga a Ieova ia Ieremia,", "Moreover the word of the LORD came unto Jeremiah the second time,"], ["o le atu lua lea, a o puipuia pea o ia i le lotoā o le fale puipui,", "while he was yet shut up in the court of the prison,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova le na te faia,", "Thus saith the LORD the maker thereof,"], ["o Ieova le na te saunia,", "the LORD that formed it,"], ["ina ia faatumauina;", "to establish it;"], ["o Ieova o lona suafa lea;", "the LORD is his name;"]]},
  {num:3,words:[["ia e valaau mai ia te au,", "Call unto me,"], ["ona ou tali atu ai lea ia te oe,", "and I will answer thee,"], ["ma ou faaali atu ia te oe o mea tetele ma le faigata,", "and shew thee great and mighty things,"], ["o mea ua e le iloa.", "which thou knowest not."]]},
  {num:4,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["i fale o lenei aai,", "concerning the houses of this city,"], ["ma fale o tupu o Iuta,", "and concerning the houses of the kings of Judah,"], ["ua sŏloia i mea mautietie,", "which are thrown down by the mounts,"], ["ma le pelu;", "and by the sword;"]]},
  {num:5,words:[["ua latou o mai e tau ma Kaletaia,", "They come to fight with the Chaldeans,"], ["ma faatumu ia te i latou i tino o tagata oti e ua fāsia e a'u i lo'u tiga,", "but it is to fill them with the dead bodies of men,"], ["ma lo'u ita, auā ua 'alo o'u mata i lenei aai,", "whom I have slain in mine anger and in my fury,"], ["ona o a latou amio leaga uma.", "and for all whose wickedness I have hid my face from this city."]]},
  {num:6,words:[["Faauta,", "Behold,"], ["ou te faia se fusi o lona ma'i,", "I will bring it health and cure,"], ["ma se togafiti e malolo a'i; ou te faamalolo lava ia te i latou,", "and I will cure them,"], ["ma ou faaali atu ia te i latou le silisili o le manuia ma le faamaoni.", "and will reveal unto them the abundance of peace and truth."]]},
  {num:7,words:[["Ou te faafoisia foi le tafeaga o Iuta,", "And I will cause the captivity of Judah and the captivity of Israel to return,"], ["ma le tafeaga o Isaraelu,", "and will build them,"], ["ma ou atiina ae i latou e pei o anamua.", "as at the first."]]},
  {num:8,words:[["Ou te faamamā ia te i latou i a latou amioletonu uma,", "And I will cleanse them from all their iniquity,"], ["na latou agasala ai ia te au;", "whereby they have sinned against me;"], ["ou te faamagalo i a latou amioletonu uma,", "and I will pardon all their iniquities,"], ["na latou agasala ai ia te au,", "whereby they have sinned,"], ["ma latou fouvale ai ia te au.", "and whereby they have transgressed against me."]]},
  {num:9,words:[["E fai foi i latou ma igoa fiafia ia te au, e fai foi ma viiga,", "And it shall be to me a name of joy,"], ["ma matagofie i nuu uma o le lalolagi, o e faalogo i mea lelei uma ou te faia ia te i latou;", "a praise and an honour before all the nations of the earth,"], ["latou te fefefe foi, ma latou gatete,", "which shall hear all the good that I do unto them:"], ["auā o mea lelei uma, i le ma le manuia uma ou te faia mo i latou.", "and they shall fear and tremble for all the goodness and for all the prosperity that I procure unto it."]]},
  {num:10,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["E toe lagona i lenei mea ua outou faapea mai ai,", "Again there shall be heard in this place,"], ["Ua faatafunaina ia,", "which ye say shall be desolate without man and without beast,"], ["e le o i ai se tagata,", "even in the cities of Judah,"], ["e le o i ai foi se manu, o aai o Iuta,", "and in the streets of Jerusalem,"], ["o ala foi o Ierusalema o loo faatafunaina nei,", "that are desolate,"], ["e le o i ai se tagata,", "without man,"], ["e leai foi se nofo ai,", "and without inhabitant,"], ["e le o i ai foi se manu,", "and without beast,"]]},
  {num:11,words:[["e lagona ai le leo fiafia ma le leo olioli,", "The voice of joy,"], ["o le leo o le faatoafaiavā ma le leo o le faatoanofotane,", "and the voice of gladness, the voice of the bridegroom,"], ["o le leo o e fai mai,", "and the voice of the bride,"], ["Ia outou vivii atu ia Ieova o 'au,", "the voice of them that shall say,"], ["auā e lelei Ieova,", "Praise the LORD of hosts:"], ["auā e faavavau lava lona alofa;", "for the LORD is good; for his mercy endureth for ever:"], ["o i latou ia o e avatua le taulaga faaneenee i le fale o Ieova.", "and of them that shall bring the sacrifice of praise into the house of the LORD."], ["Auā ou te foafoisia le tafeaga o le nuu,", "For I will cause to return the captivity of the land,"], ["e pei o anamua,", "as at the first,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:12,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts;"], ["O lenei mea, o loo faatafunaina nei,", "Again in this place,"], ["e le o i ai se tagata po o se manu,", "which is desolate without man and without beast,"], ["ma ona aai uma, e i ai mea e nonofo ai leoleo mamoe,", "and in all the cities thereof,"], ["o e ave i ai lafu mamoe e taoto ai.", "shall be an habitation of shepherds causing their flocks to lie down."]]},
  {num:13,words:[["E toe ui ane lafu mamoe i lalo o lima o le na te faitaulia,", "In the cities of the mountains,"], ["o loo fetalai mai ai Ieova,", "in the cities of the vale,"], ["i aai i atu mauga,", "and in the cities of the south,"], ["ma aai i le itu maulalo,", "and in the land of Benjamin,"], ["ma aai i le itu i toga,", "and in the places about Jerusalem,"], ["i le nuu foi o Peniamina,", "and in the cities of Judah,"], ["ma mea e vagavagai i Ierusalema,", "shall the flocks pass again under the hands of him that telleth them,"], ["ma aai o Iuta.", "saith the LORD."]]},
  {num:14,words:[["Faauta,", "Behold,"], ["e oo lava i ona aso,", "the days come,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["ou te faataunuuina ai le upu lelei na ou folafolaina i le aiga o Isaraelu ma le aiga o Iuta.", "that I will perform that good thing which I have promised unto the house of Israel and to the house of Judah."]]},
  {num:15,words:[["O ia ona po,", "In those days,"], ["ma lena lava tausaga,", "and at that time,"], ["ou te faatupuina ai ia Tavita o le La laau amiotonu;", "will I cause the Branch of righteousness to grow up unto David;"], ["e faia foi e ia le faamasinoga ma le amiotonu i le nuu.", "and he shall execute judgment and righteousness in the land."]]},
  {num:16,words:[["O ona po ia e faaolaina ai Iuta,", "In those days shall Judah be saved,"], ["e nofo ai foi Ierusalema ma le filemu;", "and Jerusalem shall dwell safely:"], ["o le igoa foi lenei e ta'ua ai o ia,", "and this is the name wherewith she shall be called,"], ["O Ieova la tatou amiotonu .", "The LORD our righteousness."]]},
  {num:17,words:[["Auā o loo faapea ona fetalai mai Ieova,", "For thus saith the LORD;"], ["E le motu le gafa o Tavita i le nofoālii o le aiga o Isaraelu;", "David shall never want a man to sit upon the throne of the house of Israel;"]]},
  {num:18,words:[["e le motu foi i o'u luma le gafa o le au ositaulaga, o sa Levī,", "Neither shall the priests the Levites want a man before me to offer burnt offerings,"], ["e osi ai taulaga mu,", "and to kindle meat offerings,"], ["ma susunu taulaga i mea e 'ai, ma osi taulaga i aso uma.", "and to do sacrifice continually."]]},
  {num:19,words:[["Na oo mai foi le afioga a Ieova ia Ieremia,", "And the word of the LORD came unto Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:20,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Afai tou te mafaia ona lepeti i la'u feagaiga ma le ao,", "If ye can break my covenant of the day,"], ["ma la'u feagaiga ma le po, ina ia le toe ai se ao,", "and my covenant of the night,"], ["po o se po i ona lava itu aso;", "and that there should not be day and night in their season;"]]},
  {num:21,words:[["ona mafai ai lea ona lepeti o la'u feagaiga ma Tavita la'u auauna,", "Then may also my covenant be broken with David my servant,"], ["ina ia le ia te ia se atalii e fai ma tupu i lona nofoālii;", "that he should not have a son to reign upon his throne;"], ["atoa foi ma sa Levī, le au ositaulaga,", "and with the Levites the priests,"], ["o a'u auauna.", "my ministers."]]},
  {num:22,words:[["E pei ona le mafaitauina o 'au a le lagi,", "As the host of heaven cannot be numbered,"], ["ma ona le mafuatia le oneone o le sami;", "neither the sand of the sea measured:"], ["e faapea ona ou faatoateleina o le fanau a Tavita la'u auauna,", "so will I multiply the seed of David my servant,"], ["ma sa Levī o e auauna ia te au.", "and the Levites that minister unto me."]]},
  {num:23,words:[["Na oo mai foi le afioga a Ieova ia Ieremia,", "Moreover the word of the LORD came to Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:24,words:[["E te le iloa ea mea ua tautala ai lenei nuu,", "Considerest thou not what this people have spoken,"], ["ua faapea,", "saying,"], ["O aiga e lua na filifilia e Ieova,", "The two families which the LORD hath chosen,"], ["ua lafoaiina i latou e ia? Ua latou 'ino'ino foi i lo'u nuu,", "he hath even cast them off? thus they have despised my people,"], ["ina ia le toe fai ma nuu i o latou luma.", "that they should be no more a nation before them."]]},
  {num:25,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Afai ua leai sa'u feagaiga ma le ao ma le po,", "If my covenant be not with day and night,"], ["afai foi ua le faia e a'u tulafono i le lagi ma le lalolagi;", "and if I have not appointed the ordinances of heaven and earth;"]]},
  {num:26,words:[["ona lafoaiina lea e a'u o le fanau a Iakopo,", "Then will I cast away the seed of Jacob,"], ["ma Tavita la'u auauna,", "and David my servant,"], ["ou te le ave foi nisi o ana fanau e fai ma alii e pule i le fanau a Aperaamo,", "so that I will not take any of his seed to be rulers over the seed of Abraham,"], ["ma Isaako,", "Isaac,"], ["ma Iakopo;", "and Jacob:"], ["auā ou te faafoisia mai lo latou tafeaga,", "for I will cause their captivity to return,"], ["ma ou alofa atu ia te i latou.", "and have mercy on them."]]},
];
renderVerseSet(jer_ch_33_Verses, 'jer-ch33-verses');

var jer_ch_34_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova,", "The word which came unto Jeremiah from the LORD,"], ["a o tau ma Ierusalema ma ona aai uma o Nepukanesa le tupu o Papelonia,", "when Nebuchadnezzar king of Babylon, and all his army,"], ["ma lana itu taua uma,", "and all the kingdoms of the earth of his dominion,"], ["ma malo uma o le lalolagi na ia pule i ai,", "and all the people,"], ["ma nuu uma,", "fought against Jerusalem, and against all the cities thereof,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Ina alu ia ma fai atu ia Setekaia le tupu o Iuta,", "Go and speak to Zedekiah king of Judah,"], ["ia faapea atu ia te ia,", "and tell him,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Faauta,", "Behold,"], ["ou te tuuina atu lenei aai i le lima o le tupu o Papelonia,", "I will give this city into the hand of the king of Babylon,"], ["e susunuina ai foi e ia i le afi;", "and he shall burn it with fire:"]]},
  {num:3,words:[["o oe foi e te le sao i lona lima,", "And thou shalt not escape out of his hand,"], ["a e puea lava oe,", "but shalt surely be taken,"], ["ma tuuina i lona lima;", "and delivered into his hand;"], ["e fesilafa'i oulua ma le tupu o Papelonia,", "and thine eyes shall behold the eyes of the king of Babylon,"], ["lua te tautala faafesaga'i ma ia,", "and he shall speak with thee mouth to mouth,"], ["e te maliu atu foi i Papelonia.", "and thou shalt go to Babylon."]]},
  {num:4,words:[["A ia e faafofoga mai i le afioga a Ieova,", "Yet hear the word of the LORD,"], ["Setekaia e,", "O Zedekiah king of Judah;"], ["le tupu o Iuta; o loo faapea ona fetalai mai o Ieova ia te oe,", "Thus saith the LORD of thee,"], ["E te le maliu i le pule;", "Thou shalt not die by the sword:"]]},
  {num:5,words:[["e te maliu ma le filemu;", "But thou shalt die in peace:"], ["e pei ona muina o afi mo ou tamā,", "and with the burnings of thy fathers,"], ["o tupu anamua sa muamua ia te oe,", "the former kings which were before thee,"], ["e faapea foi ona latou muina o le afi mo oe;", "so shall they burn odours for thee;"], ["latou te taufaitagitu'i foi ona o oe, e faapea ,", "and they will lament thee,"], ["Aue! le alii e;", "saying,"], ["auā ua ou fai atu le upu,", "Ah lord! for I have pronounced the word,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:6,words:[["Ona fai atu ai lea o Ieremia le perofeta ia Setekaia le tupu o Iuta ia upu uma i Ierusalema,", "Then Jeremiah the prophet spake all these words unto Zedekiah king of Judah in Jerusalem,"]]},
  {num:7,words:[["ina o tau le itu taua a le tupu o Papelonia ma Ierusalema,", "When the king of Babylon's army fought against Jerusalem,"], ["ma aai uma sa totoe i Iuta,", "and against all the cities of Judah that were left,"], ["o Lakisa ma Aseka;", "against Lachish, and against Azekah:"], ["auā o aai nofo 'olo ia sa totoe i aai o Iuta.", "for these defenced cities remained of the cities of Judah."]]},
  {num:8,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova,", "This is the word that came unto Jeremiah from the LORD,"], ["ina ua mavae ona osia o le feagaiga e Setekaia le tupu ma le nuu uma sa i Ierusalema,", "after that the king Zedekiah had made a covenant with all the people which were at Jerusalem,"], ["e tala'i atu ia te i latou le saolotoga;", "to proclaim liberty unto them;"]]},
  {num:9,words:[["ia latou taitasi ma tuusaolotoina lana auauna tane,", "That every man should let his manservant,"], ["ma lana auauna fafine,", "and every man his maidservant,"], ["o le tane Eperu,", "being an Hebrew or an Hebrewess, go free;"], ["ma le fafine Eperu;", "that none should serve himself of them,"], ["ina ia le faapologaina e so latou se tagata Eperu,", "to wit,"], ["lona uso.", "of a Jew his brother."]]},
  {num:10,words:[["Ua faalogo alii uma,", "Now when all the princes,"], ["ma le nuu uma na faia le feagaiga,", "and all the people, which had entered into the covenant,"], ["ia latou taitasi ma tuusaolotoina lana auauna tane,", "heard that every one should let his manservant,"], ["ma lana auauna fafine,", "and every one his maidservant,"], ["ina ia latou le toe faapologaina i latou;", "go free,"], ["ona latou usiusitai ai lea,", "that none should serve themselves of them any more, then they obeyed,"], ["ma tuuina atu i latou ia o.", "and let them go."]]},
  {num:11,words:[["A e mulimuli ane ua latou toe faafoisia mai auauna tane ma auauna fafine na latou tuusaolotoina;", "But afterward they turned, and caused the servants and the handmaids,"], ["ma latou faapologaina i latou e fai ma auauna tane ma auauna fafine.", "whom they had let go free, to return, and brought them into subjection for servants and for handmaids."]]},
  {num:12,words:[["Ona oo mai ai lea o le afioga a Ieova ia Ieremia mai ia Ieova,", "Therefore the word of the LORD came to Jeremiah from the LORD,"], ["ua faapea mai,", "saying,"]]},
  {num:13,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["O a'u lava, na a'u osia le feagaiga ma o outou tamā i le aso na ou aumai ai i latou mai le nuu o Aikupito,", "I made a covenant with your fathers in the day that I brought them forth out of the land of Egypt,"], ["o le mea sa nofo pologa ai,", "out of the house of bondmen,"], ["ua faapea,", "saying,"]]},
  {num:14,words:[["A atoa tausaga e fitu,", "At the end of seven years let ye go every man his brother an Hebrew,"], ["ia outou taitasi ma tuuina atu e alu lona uso o le Eperu,", "which hath been sold unto thee;"], ["o le na faatauina ia te oe; e auauna o ia ia te oe i tausaga e ono,", "and when he hath served thee six years,"], ["ona e tuusaolotoina ai lea o ia;", "thou shalt let him go free from thee:"], ["a e lei faalogo mai o outou tamā ia te au,", "but your fathers hearkened not unto me,"], ["e lei uai mai foi o latou taliga.", "neither inclined their ear."]]},
  {num:15,words:[["O outou foi,", "And ye were now turned,"], ["na outou liliu mai i ona po nei,", "and had done right in my sight,"], ["ma outou faia le mea tonu i o'u luma, i lo outou tala'i atu le saolotoga o le tasi i le tasi;", "in proclaiming liberty every man to his neighbour;"], ["na outou osia foi le feagaiga i o'u luma i le fale ua ta'ua ai lo'u igoa.", "and ye had made a covenant before me in the house which is called by my name:"]]},
  {num:16,words:[["A ua outou liliu ese,", "But ye turned and polluted my name,"], ["ma faaleagaina lo'u igoa,", "and caused every man his servant,"], ["ma taitasi ma faafoisia mai lana auauna tane,", "and every man his handmaid, whom ye had set at liberty at their pleasure,"], ["ma lana auauna fafine,", "to return,"], ["na tuusaolotoina i la latou faitalia,", "and brought them into subjection,"], ["ua outou faapologaina i latou e fai ma auauna tane ma auauna fafine ia te outou.", "to be unto you for servants and for handmaids."]]},
  {num:17,words:[["O le mea lea o loo faapea ona fetalai mai ai o Ieova,", "Therefore thus saith the LORD;"], ["Ua outou le faalogo mai ia te au e tala'i atu le saolotoga,", "Ye have not hearkened unto me,"], ["o le tagata i lona uso,", "in proclaiming liberty,"], ["ma le tagata i lē la te tuaoi;", "every one to his brother,"], ["faauta,", "and every man to his neighbour:"], ["ua fetalai mai Ieova,", "behold, I proclaim a liberty for you,"], ["Ou te tala'i atu ia te outou le saolotoga,", "saith the LORD,"], ["i le pelu,", "to the sword,"], ["ma le faamai,", "to the pestilence,"], ["ma le oge;", "and to the famine;"], ["ou te tuuina atu foi outou ia faaatuatuvaleina i malo uma o le lalolagi.", "and I will make you to be removed into all the kingdoms of the earth."]]},
  {num:18,words:[["Ou te tuuina atu foi ia tagata ua solia la'u feagaiga,", "And I will give the men that have transgressed my covenant,"], ["o e ua le faataunuuina upu o le feagaiga na latou osia i o'u luma,", "which have not performed the words of the covenant which they had made before me,"], ["o le tamai povi na latou isiluaina,", "when they cut the calf in twain,"], ["ma latou ui ane i le va o mea na isiluaina,", "and passed between the parts thereof,"]]},
  {num:19,words:[["o alii o Iuta,", "The princes of Judah,"], ["ma alii o Ierusalema,", "and the princes of Jerusalem,"], ["o eunuka,", "the eunuchs,"], ["ma faitaulaga,", "and the priests,"], ["ma tagata uma o le nuu,", "and all the people of the land,"], ["na ui ane i le va o le tamai povi na isiluaina;", "which passed between the parts of the calf;"]]},
  {num:20,words:[["ou te tuuina atu lava i latou i lima o e ita ia te i latou,", "I will even give them into the hand of their enemies,"], ["ma lima o e saili e fasioti ia te i latou;", "and into the hand of them that seek their life:"], ["o latou tino foi ua oti e fai ma mea e 'ai i manu felelei,", "and their dead bodies shall be for meat unto the fowls of the heaven,"], ["ma manu e tataa.", "and to the beasts of the earth."]]},
  {num:21,words:[["Ou te tuuina atu foi o Setekaia le tupu o Iuta, ma alii ua ia te ia,", "And Zedekiah king of Judah and his princes will I give into the hand of their enemies,"], ["i lima o e ita ia te i latou,", "and into the hand of them that seek their life,"], ["ma lima o e saili e fasioti ia te i latou,", "and into the hand of the king of Babylon's army,"], ["ma lima o le itu taua a le tupu o Papelonia, o e ua o ae nai ia te outou.", "which are gone up from you."]]},
  {num:22,words:[["Faauta,", "Behold,"], ["ou te fai atu,", "I will command,"], ["ua fetalai mai Ieova, ma ou faafoisia mai i latou i lenei aai;", "saith the LORD,"], ["latou te sii i ai le taua,", "and cause them to return to this city;"], ["latou le aea foi,", "and they shall fight against it,"], ["ma susunuina i le afi; ou te tuuina atu foi o aai o Iuta,", "and take it,"], ["ia faatafunaina,", "and burn it with fire:"], ["ia leai sē nofo ai.", "and I will make the cities of Judah a desolation without an inhabitant."]]},
];
renderVerseSet(jer_ch_34_Verses, 'jer-ch34-verses');

var jer_ch_35_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova, i ona po o Ioakima le atalii o Iosia le tupu o Iuta,", "The word which came unto Jeremiah from the LORD in the days of Jehoiakim the son of Josiah king of Judah,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Ina alu ia oe i le aiga o sa Rakapā,", "Go unto the house of the Rechabites,"], ["ma tautala atu ia te i latou,", "and speak unto them,"], ["ma au mai ia te i latou i le fale o Ieova,", "and bring them into the house of the LORD,"], ["i se tasi potu,", "into one of the chambers,"], ["ma avatu ia te i latou le uaina e inu ai.", "and give them wine to drink."]]},
  {num:3,words:[["Ona ou ave ai lea o Iaasenaia le atalii o Ieremia,", "Then I took Jaazaniah the son of Jeremiah,"], ["le atalii o Havasinia,", "the son of Habaziniah,"], ["ma ona uso,", "and his brethren,"], ["ma ona atalii uma,", "and all his sons,"], ["ma le aiga uma o sa Rakapā;", "and the whole house of the Rechabites;"]]},
  {num:4,words:[["ma ou au mai ia te i latou i le fale o Ieova,", "And I brought them into the house of the LORD,"], ["i le potu o atalii o Hanana le atalii o Iketalia,", "into the chamber of the sons of Hanan,"], ["o le tagata o le Atua,", "the son of Igdaliah, a man of God,"], ["sa tuaoi ma le potu o alii,", "which was by the chamber of the princes,"], ["na i ai i luga o le potu o Maaseia le atalii o Saluma,", "which was above the chamber of Maaseiah the son of Shallum,"], ["o le leoleo o le faitotoa;", "the keeper of the door:"]]},
  {num:5,words:[["ona ou tuuina atu lea i luma o le fanauga a le aiga o sa Rakapā o ipu faaofuofu ua tutumu i uaina,", "And I set before the sons of the house of the Rechabites pots full of wine,"], ["ma ipu e inu ai;", "and cups,"], ["ma a'u fai atu ia te i latou,", "and I said unto them,"], ["Ia outou feinu i le uaina.", "Drink ye wine."]]},
  {num:6,words:[["A ua latou fai mai,", "But they said,"], ["Matou te le inu uaina; auā na poloai mai ia te i matou o Ionatapa le atalii o Rakapa,", "We will drink no wine:"], ["o lo matou tamā,", "for Jonadab the son of Rechab our father commanded us,"], ["ua faapea mai,", "saying,"], ["Aua tou te inu uaina,", "Ye shall drink no wine,"], ["o outou, ma o outou fanau,", "neither ye,"], ["e oo i le faavavau;", "nor your sons for ever:"]]},
  {num:7,words:[["aua foi tou te fai se fale,", "Neither shall ye build house,"], ["aua tou te lulu saito,", "nor sow seed,"], ["aua tou te totō se tovine,", "nor plant vineyard,"], ["aua foi ne'i ia te outou ia mea;", "nor have any:"], ["auā e nonofo outou i fale ie i o outou aso uma;", "but all your days ye shall dwell in tents;"], ["ina ia tele ni aso e ola ai outou i le laueleele tou te āumau ai.", "that ye may live many days in the land where ye be strangers."]]},
  {num:8,words:[["Ua matou usiusitai i le upu a Ionatapa le atalii o Rakapa,", "Thus have we obeyed the voice of Jonadab the son of Rechab our father in all that he hath charged us,"], ["lo matou tamā, i mea uma na ia poloai mai ai ia te i matou,", "to drink no wine all our days,"], ["aua matou te inu uaina i o matou aso uma,", "we,"], ["o i matou,", "our wives,"], ["ma a matou avā, o matou atalii foi,", "our sons,"], ["ma o matou afafine;", "nor our daughters;"]]},
  {num:9,words:[["aua foi matou te fai fale e nonofo ai;", "Nor to build houses for us to dwell in:"], ["e le ia te i matou foi se tovine,", "neither have we vineyard,"], ["po o se fanua,", "nor field,"], ["po o saito;", "nor seed:"]]},
  {num:10,words:[["a ua matou nonofo i fale ie;", "But we have dwelt in tents,"], ["ua matou usiusitai,", "and have obeyed,"], ["ma matou faia e tusa ma mea uma na poloai mai ai Ionatapa lo matou tamā ia te i matou.", "and done according to all that Jonadab our father commanded us."]]},
  {num:11,words:[["Na oo foi ina sau o Nepukanesa le tupu o Papelonia i le nuu,", "But it came to pass,"], ["ona matou faapea ai lea,", "when Nebuchadrezzar king of Babylon came up into the land,"], ["Ina o mai ia,", "that we said, Come,"], ["se'i tatou o i Ierusalema auā o 'au a Kaletaia,", "and let us go to Jerusalem for fear of the army of the Chaldeans,"], ["ma 'au a Suria;", "and for fear of the army of the Syrians:"], ["o le mea lea ua matou nonofo ai i Ierusalema.", "so we dwell at Jerusalem."]]},
  {num:12,words:[["Ona oo mai ai lea o le afioga a Ieova ia Ieremia,", "Then came the word of the LORD unto Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:13,words:[["O loo faapea ona fetalai mai o Ieova o 'au, le Atua o Isaraelu,", "Thus saith the LORD of hosts,"], ["Ia e alu, ma e fai atu i tagata o Iuta,", "the God of Israel;"], ["ma e o nonofo i Ierusalema,", "Go and tell the men of Judah and the inhabitants of Jerusalem,"], ["E le talia ea e outou mea ua a'oa'oina atu, ia faalogo ai i a'u upu? ua fetalai mai ai Ieova.", "Will ye not receive instruction to hearken to my words? saith the LORD."]]},
  {num:14,words:[["O upu a Ionatapa le atalii o Rakapa,", "The words of Jonadab the son of Rechab,"], ["na ia poloai atu ai i ona atalii,", "that he commanded his sons not to drink wine,"], ["e aua le inu uaina, ua tausia lava,", "are performed;"], ["ua latou le inu ai ua oo lava i le aso nei,", "for unto this day they drink none,"], ["auā ua latou usiusitai i le poloaiga a lo latou tamā;", "but obey their father's commandment:"], ["a o a'u nei, ua ou fai atu ia te outou,", "notwithstanding I have spoken unto you,"], ["ua ou ala fai atu lava;", "rising early and speaking;"], ["a ua outou le faalogo mai ia te au.", "but ye hearkened not unto me."]]},
  {num:15,words:[["Ua ou aauina atu foi ia te outou o a'u auauna uma o perofeta,", "I have sent also unto you all my servants the prophets,"], ["ua ou ala aauina lava i latou ,", "rising up early and sending them,"], ["ua faapea atu,", "saying,"], ["Ia outou toe foi mai taitasi le tagata ai lona ala leaga,", "Return ye now every man from his evil way,"], ["ia outou sauni lelei foi a outou amioga,", "and amend your doings,"], ["aua foi tou te mulimuli atu i atua ese e auauna i ai,", "and go not after other gods to serve them,"], ["ona nonofo ai lea o outou i le laueleele na ou foaiina atu ai ia te outou ma o outou tamā;", "and ye shall dwell in the land which I have given to you and to your fathers:"], ["a ua le uai mai o outou taliga,", "but ye have not inclined your ear,"], ["ma outou le faalogo mai ia te au.", "nor hearkened unto me."]]},
  {num:16,words:[["Auā ua tausia e atalii o Ionatapa le atalii o Rakapa le poloaiga a lo latou tamā,", "Because the sons of Jonadab the son of Rechab have performed the commandment of their father,"], ["na ia poloai atu ai ia te i latou; a o lenei nuu,", "which he commanded them;"], ["ua latou le faalogo lava ia te au;", "but this people hath not hearkened unto me:"]]},
  {num:17,words:[["o le mea lea o loo faapea ona fetalai mai ai o Ieova,", "Therefore thus saith the LORD God of hosts,"], ["le Atua o 'au, le Atua o Isaraelu,", "the God of Israel;"], ["Faauta,", "Behold,"], ["ou te faaoo ia Iuta, ma i latou uma o e nonofo i Ierusalema,", "I will bring upon Judah and upon all the inhabitants of Jerusalem all the evil that I have pronounced against them:"], ["le malaia uma na ou fai atu ai e oo ia te i latou;", "because I have spoken unto them,"], ["auā na ou fai atu ia te i latou,", "but they have not heard;"], ["a ua latou le faalogo mai; na ou valaau foi ia te i latou,", "and I have called unto them,"], ["a ua latou le tali mai.", "but they have not answered."]]},
  {num:18,words:[["Ua fai atu foi Ieremia i le aiga o sa Rakapā,", "And Jeremiah said unto the house of the Rechabites,"], ["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Ua outou usiusitai i le poloaiga a Ionatapa lo outou tamā,", "Because ye have obeyed the commandment of Jonadab your father,"], ["ma ua outou tausia ana poloaiga uma,", "and kept all his precepts,"], ["ma ua outou faia e tusa ma mea uma na ia poloai mai ai ia te outou;", "and done according unto all that he hath commanded you:"]]},
  {num:19,words:[["o le mea lea o loo faapea ona fetalai mai ai o Ieova o 'au,", "Therefore thus saith the LORD of hosts,"], ["le Atua o Isaraelu, E le motu le gafa o Ionatapa le atalii o Rakapa,", "the God of Israel;"], ["a e tu mai sona tagata i o'u luma i aso uma lava.", "Jonadab the son of Rechab shall not want a man to stand before me for ever."]]},
];
renderVerseSet(jer_ch_35_Verses, 'jer-ch35-verses');

var jer_ch_36_Verses = [
  {num:1,words:[["O le fa o tausaga o Ioakima le atalii o Iosia le tupu o Iuta,", "And it came to pass in the fourth year of Jehoiakim the son of Josiah king of Judah,"], ["na oo mai ai lenei afioga ia Ieremia mai ia Ieova,", "that this word came unto Jeremiah from the LORD,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["Ia e ave se tusi taai,", "Take thee a roll of a book,"], ["ma e tusi i ai upu uma ua ou fai atu ai ia te oe ia Isaraelu,", "and write therein all the words that I have spoken unto thee against Israel,"], ["ma Iuta,", "and against Judah,"], ["ma nuu uma,", "and against all the nations,"], ["e afua i ona po na ou tautala atu ai ia te oe,", "from the day I spake unto thee,"], ["ona po lava o Iosia,", "from the days of Josiah,"], ["e oo i le aso nei.", "even unto this day."]]},
  {num:3,words:[["Atonu e faalogo le aiga o Iuta i le malaia uma ou te manatu e faaoo ia te i latou;", "It may be that the house of Judah will hear all the evil which I purpose to do unto them;"], ["ina ia latou toe foi mai, taitasi le tagata ai lona ala leaga,", "that they may return every man from his evil way;"], ["ma ou faamagaloina atu i la latou amioletonu ma la latou agasala.", "that I may forgive their iniquity and their sin."]]},
  {num:4,words:[["Ona valaau ai lea o Ieremia ia Paruka le atalii o Neria;", "Then Jeremiah called Baruch the son of Neriah:"], ["ua tusia foi i le tusi taai e Paruka mai le fofoga o Ieremia o afioga uma a Ieova,", "and Baruch wrote from the mouth of Jeremiah all the words of the LORD, which he had spoken unto him,"], ["na ia fetalai mai ai ia te ia.", "upon a roll of a book."]]},
  {num:5,words:[["Ua fai atu foi Ieremia ia Paruka,", "And Jeremiah commanded Baruch,"], ["ua faapea atu,", "saying,"], ["Ua puipuia a'u;", "I am shut up;"], ["ou te le mafai ona alu atu i le fale o Ieova;", "I cannot go into the house of the LORD:"]]},
  {num:6,words:[["a ia e alu,", "Therefore go thou,"], ["ma faitau i le tusi taai,", "and read in the roll,"], ["ua e tusia mai lo'u gutu,", "which thou hast written from my mouth,"], ["o afioga a Ieova i luma o le nuu i le fale o Ieova i le aso e anapopogi ai;", "the words of the LORD in the ears of the people in the LORD'S house upon the fasting day:"], ["e te faitauina foi i luma o Iuta uma o e o mai mai o latou aai.", "and also thou shalt read them in the ears of all Judah that come out of their cities."]]},
  {num:7,words:[["Atonu latou te faapauu ma tatalo i luma o Ieova,", "It may be they will present their supplication before the LORD,"], ["ma latou toe foi mai, taitasi le tagata ai lona ala leaga;", "and will return every one from his evil way:"], ["auā ua tele le tiga ma le toasa ua fetalai mai ai Ieova i lenei nuu.", "for great is the anger and the fury that the LORD hath pronounced against this people."]]},
  {num:8,words:[["Ua faia foi e Paruka le atalii o Neria e tusa ma mea uma na fai atu ai Ieremia le perofeta;", "And Baruch the son of Neriah did according to all that Jeremiah the prophet commanded him,"], ["ua ia faitau i le tusi o afioga a Ieova i le fale o Ieova.", "reading in the book the words of the LORD in the LORD'S house."]]},
  {num:9,words:[["O le lima o tausaga o Ioakima le atalii o Iosia le tupu o Iuta,", "And it came to pass in the fifth year of Jehoiakim the son of Josiah king of Judah,"], ["o le iva o masina,", "in the ninth month,"], ["ua latou tala'i atu ai le anapogi i luma o Ieova i tagata uma o i Ierusalema,", "that they proclaimed a fast before the LORD to all the people in Jerusalem,"], ["ma tagata uma na o mai i Ierusalema mai aai o Iuta.", "and to all the people that came from the cities of Judah unto Jerusalem."]]},
  {num:10,words:[["Ona faitau ai lea o Paruka i le tusi,", "Then read Baruch in the book the words of Jeremiah in the house of the LORD,"], ["a o faalogo ai le nuu uma,", "in the chamber of Gemariah the son of Shaphan the scribe,"], ["o upu a Ieremia i le fale o Ieova, i le potu o Kimaria le atalii o Safana le tusiupu,", "in the higher court,"], ["i le lotoā i luga,", "at the entry of the new gate of the LORD'S house,"], ["i le mea e ui ai i le faitotoa fou o le fale o Ieova.", "in the ears of all the people."]]},
  {num:11,words:[["Ua faalogo Mekaio le atalii o Kimaria,", "When Michaiah the son of Gemariah,"], ["le atalii o Safana,", "the son of Shaphan,"], ["i afioga uma a Ieova nai le tusi;", "had heard out of the book all the words of the LORD,"]]},
  {num:12,words:[["ona alu ifo ai lea o ia i le fale o le tupu,", "Then he went down into the king's house,"], ["i le potu o le tusiupu;", "into the scribe's chamber:"], ["faauta foi,", "and,"], ["sa nonofo ai o alii uma,", "lo,"], ["o Elisama le tusiupu,", "all the princes sat there, even Elishama the scribe,"], ["ma Tilaia le atalii o Semaia,", "and Delaiah the son of Shemaiah,"], ["ma Elenatana le atalii o Akepora,", "and Elnathan the son of Achbor,"], ["ma Kimaria le atalii o Safana,", "and Gemariah the son of Shaphan,"], ["ma Setekaia le atalii o Hanania,", "and Zedekiah the son of Hananiah,"], ["ma alii uma.", "and all the princes."]]},
  {num:13,words:[["Ona ta'u atu ai lea e Mekaio ia te i latou o upu uma na ia faalogo ai,", "Then Michaiah declared unto them all the words that he had heard,"], ["ina o faitau e Paruka le tusi i luma o le nuu.", "when Baruch read the book in the ears of the people."]]},
  {num:14,words:[["Ona auina atu ai lea e alii uma o Ieuti le atalii o Netania,", "Therefore all the princes sent Jehudi the son of Nethaniah,"], ["le atalii o Selemia,", "the son of Shelemiah,"], ["le atalii o Kusi,", "the son of Cushi,"], ["ia Paruka,", "unto Baruch,"], ["ua faapea atu,", "saying,"], ["Ia e au mai i lou lima le tusi taai sa e faitauina i luma o le nuu,", "Take in thine hand the roll wherein thou hast read in the ears of the people,"], ["ma e sau. Ona ave ai lea e Paruka le atalii o Neria le tusi taai i lona lima,", "and come. So Baruch the son of Neriah took the roll in his hand,"], ["ma ua alu atu ia te i latou.", "and came unto them."]]},
  {num:15,words:[["Ona latou fai mai ai lea ia te ia,", "And they said unto him,"], ["Se'i e nofo i lalo,", "Sit down now,"], ["ma faitau mai a o matou faalogo atu. I le ua faitau ai e Paruka o faalogo mai i latou.", "and read it in our ears. So Baruch read it in their ears."]]},
  {num:16,words:[["Ua latou faalogo i ia upu uma,", "Now it came to pass,"], ["ona latou fefefe ai lea,", "when they had heard all the words,"], ["o le tasi ma le tasi,", "they were afraid both one and other,"], ["ma latou fai mai ia Paruka,", "and said unto Baruch,"], ["Matou te ta'u atu lava ia upu uma i le tupu.", "We will surely tell the king of all these words."]]},
  {num:17,words:[["Ua latou fesili mai foi ia Paruka,", "And they asked Baruch,"], ["ua faapea mai,", "saying,"], ["Ina ta'u mai ia ia te i matou,", "Tell us now,"], ["pe na faapefea ea ona e tusia o ia upu uma mai lona fofoga?", "How didst thou write all these words at his mouth?"]]},
  {num:18,words:[["Ona fai atu ai lea o Paruka ia te i latou,", "Then Baruch answered them,"], ["Na ia fai mai ia te au ia upu uma ai ona fofoga,", "He pronounced all these words unto me with his mouth,"], ["ona ou tusia ai lea i le tusi i le vaitusi.", "and I wrote them with ink in the book."]]},
  {num:19,words:[["Ona fai mai ai lea o alii ia Paruka,", "Then said the princes unto Baruch,"], ["Ina alu ia,", "Go,"], ["lua te lalafi,", "hide thee,"], ["oulua ma Ieremia,", "thou and Jeremiah;"], ["aua ne'i iloa e se tasi po o fea lua te i ai.", "and let no man know where ye be."]]},
  {num:20,words:[["Ua latou o atu i le tupu i le lotoā,", "And they went in to the king into the court,"], ["a ua latou tuu le tusi taai i le potu o Elisama le tusiupu;", "but they laid up the roll in the chamber of Elishama the scribe,"], ["ua latou faaali atu foi ia upu uma i luma o le tupu.", "and told all the words in the ears of the king."]]},
  {num:21,words:[["Ona auina atu ai lea e le tupu o Ieuti e aami atu le tusi taai;", "So the king sent Jehudi to fetch the roll:"], ["i le ua au mai ai e ia ai le potu o Elisama le tusiupu; ona faitau ai lea e Ieuti i luma o le tupu,", "and he took it out of Elishama the scribe's chamber. And Jehudi read it in the ears of the king,"], ["ma luma o alii uma o e na tutū i tafatafa o le tupu.", "and in the ears of all the princes which stood beside the king."]]},
  {num:22,words:[["Sa nofo foi le tupu i le fale o le tau maalili i le iva o masina,", "Now the king sat in the winterhouse in the ninth month:"], ["sa mu foi le afi i le taigaafi i ona luma.", "and there was a fire on the hearth burning before him."]]},
  {num:23,words:[["Ua oo ina ua faitaulia e Ieuti ni atu upu se tolu pe fa,", "And it came to pass,"], ["ona titipi ai lea e ia i le polo o le tusi upu,", "that when Jehudi had read three or four leaves,"], ["ma na lafo i le afi sa i le taigaafi,", "he cut it with the penknife, and cast it into the fire that was on the hearth,"], ["ua oo ina faaumatia le tusi taai uma i le afi sa i le taigaafi.", "until all the roll was consumed in the fire that was on the hearth."]]},
  {num:24,words:[["E lei fefefe i latou,", "Yet they were not afraid,"], ["e lei saeia foi e i latou o latou ofu,", "nor rent their garments,"], ["o le tupu, ma ana auauna uma,", "neither the king,"], ["na faalogo i ia upu uma.", "nor any of his servants that heard all these words."]]},
  {num:25,words:[["A e peitai na aioi atu Elenatana, ma Tilaia,", "Nevertheless Elnathan and Delaiah and Gemariah had made intercession to the king that he would not burn the roll:"], ["ma Kimaria i le tupu, aua na te susunuina le tusi taai; a e lei faalogo o ia ia te i latou.", "but he would not hear them."]]},
  {num:26,words:[["A ua fai atu le tupu ia Ieramaelu le atalii o le tupu,", "But the king commanded Jerahmeel the son of Hammelech,"], ["ma Seraia le atalii o Aserielu,", "and Seraiah the son of Azriel,"], ["ma Selemia le atalii o Apitelu, latou te pupue ia Paruka le tusiupu,", "and Shelemiah the son of Abdeel,"], ["ma Ieremia le perofeta;", "to take Baruch the scribe and Jeremiah the prophet:"], ["a ua natia i laua e Ieova.", "but the LORD hid them."]]},
  {num:27,words:[["Ona oo mai ai lea o le afioga a Ieova ia Ieremia,", "Then the word of the LORD came to Jeremiah,"], ["ina ua uma ona susunuina e le tupu o le tusi taai,", "after that the king had burned the roll,"], ["ma upu na tusia e Paruka mai le gutu o Ieremia,", "and the words which Baruch wrote at the mouth of Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:28,words:[["Ina toe ave ia e oe se isi tusi taai,", "Take thee again another roll,"], ["ma e tusi i ai upu muamua uma na i ai i le tusi taai muamua,", "and write in it all the former words that were in the first roll,"], ["na susunuina e Ioakima le tupu o Iuta.", "which Jehoiakim the king of Judah hath burned."]]},
  {num:29,words:[["E te fai atu foi ia Ioakima le tupu o Iuta,", "And thou shalt say to Jehoiakim king of Judah,"], ["O loo faapea ona fai mai o Ieova,", "Thus saith the LORD;"], ["Ua e susunuina lena tusi taai,", "Thou hast burned this roll,"], ["ua e faapea mai,", "saying,"], ["Se a ea le mea na e tusia ai, ua faapea,", "Why hast thou written therein,"], ["E sau lava le tupu o Papelonia,", "saying,"], ["ma faaumatia lenei nuu,", "The king of Babylon shall certainly come and destroy this land,"], ["ma aveeseina ai tagata atoa foi ma manu?", "and shall cause to cease from thence man and beast?"]]},
  {num:30,words:[["O le mea lea o loo faapea ona fetalai mai o Ieova ia Ioakima le tupu o Iuta,", "Therefore thus saith the LORD of Jehoiakim king of Judah;"], ["E le ia te ia se tasi e tietie i le nofoālii o Tavita;", "He shall have none to sit upon the throne of David:"], ["e tuulafoaiina foi lona tino ua oti i le vevela i le ao,", "and his dead body shall be cast out in the day to the heat,"], ["ma le mālulu i le po.", "and in the night to the frost."]]},
  {num:31,words:[["Ou te taui atu foi ia te ia, ma ana fanau,", "And I will punish him and his seed and his servants for their iniquity;"], ["ma ana auauna,", "and I will bring upon them,"], ["a latou amioletonu;", "and upon the inhabitants of Jerusalem,"], ["ou te faaoo foi ia te i latou, ma e o nonofo i Ierusalema,", "and upon the men of Judah,"], ["ma tagata o Iuta, le malaia uma na ou fai atu ai ia te i latou;", "all the evil that I have pronounced against them;"], ["a ua latou le faalogo mai.", "but they hearkened not."]]},
  {num:32,words:[["Ona ave ai lea e Ieremia o se isi tusi taai,", "Then took Jeremiah another roll,"], ["ma na avatu ai i le tusiupu,", "and gave it to Baruch the scribe,"], ["o Paruka le atalii o Neria; ua tusi i ai foi e ia mai le gutu o Ieremia,", "the son of Neriah;"], ["o upu uma o le tusi na susunuina i le afi e Ioakima le tupu o Iuta;", "who wrote therein from the mouth of Jeremiah all the words of the book which Jehoiakim king of Judah had burned in the fire:"], ["ua toe faaopoopoina foi i ai nisi upu faapea e tele.", "and there were added besides unto them many like words."]]},
];
renderVerseSet(jer_ch_36_Verses, 'jer-ch36-verses');

var jer_ch_37_Verses = [
  {num:1,words:[["Ua pule foi Setekaia le tupu le atalii o Iosia e sui a'i Konia le atalii o Ioakima,", "And king Zedekiah the son of Josiah reigned instead of Coniah the son of Jehoiakim,"], ["ua tofia foi o ia e fai ma tupu i le nuu o Iuta e Nepukanesa le tupu o Papelonia.", "whom Nebuchadrezzar king of Babylon made king in the land of Judah."]]},
  {num:2,words:[["A e le faalogo o ia,", "But neither he,"], ["po o ana auauna,", "nor his servants,"], ["po o tagata o le nuu,", "nor the people of the land,"], ["i afioga a Ieova,", "did hearken unto the words of the LORD,"], ["na ia fetalai mai i le perofeta o Ieremia.", "which he spake by the prophet Jeremiah."]]},
  {num:3,words:[["Ua auina mai e Setekaia le tupu o Iukali le atalii o Selemia, ma Sefanaia le atalii o Maaseia le faitaulaga,", "And Zedekiah the king sent Jehucal the son of Shelemiah and Zephaniah the son of Maaseiah the priest to the prophet Jeremiah,"], ["ia Ieremia le perofeta,", "saying,"], ["ua faapea mai, Ia e faatoga mo i matou ia Ieova lo tatou Atua.", "Pray now unto the LORD our God for us."]]},
  {num:4,words:[["A ua fealuai faasa'oloto Ieremia i le nuu;", "Now Jeremiah came in and went out among the people:"], ["auā e lei tuuina atu o ia e i latou i le fale puipui.", "for they had not put him into prison."]]},
  {num:5,words:[["Ua o mai le itu taua a Farao mai Aikupito;", "Then Pharaoh's army was come forth out of Egypt:"], ["ua faalogo foi Kaletaia e na vagaia Ierusalema i le tala ia te i latou,", "and when the Chaldeans that besieged Jerusalem heard tidings of them,"], ["ona latou o ese ai lea i Ierusalema.", "they departed from Jerusalem."]]},
  {num:6,words:[["Ona oo mai ai lea o le afioga a Ieova ia Ieremia le perofeta,", "Then came the word of the LORD unto the prophet Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:7,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Ia faapea ona outou fai atu i le tupu o Iuta,", "Thus shall ye say to the king of Judah,"], ["o le na auina mai outou ia te au e fesili mai ia te au,", "that sent you unto me to enquire of me;"], ["Faauta,", "Behold,"], ["o le itu taua a Farao,", "Pharaoh's army,"], ["o loo ua o mai e fesoasoani ia te outou,", "which is come forth to help you,"], ["e foi atu i latou i lo latou nuu o Aikupito.", "shall return to Egypt into their own land."]]},
  {num:8,words:[["A e toe foi mai Kaletaia,", "And the Chaldeans shall come again,"], ["ma latou tau ma le aai nei,", "and fight against this city,"], ["e aea ai foi e i latou,", "and take it,"], ["ma latou susunuina ai i le afi.", "and burn it with fire."]]},
  {num:9,words:[["O loo faapea ona fetalai mai o Ieova. Aua ne'i olegia outou e outou,", "Thus saith the LORD;"], ["e faapea,", "Deceive not yourselves,"], ["E matuā o ese Kaletaia ia te i tatou;", "saying, The Chaldeans shall surely depart from us:"], ["auā latou te le o ese lava.", "for they shall not depart."]]},
  {num:10,words:[["Auā pe afai ana fāsia e outou le itu taua uma a Kaletaia o e ua tau ma outou,", "For though ye had smitten the whole army of the Chaldeans that fight against you,"], ["ma ua totoe ia te i latou na o tagata manunua,", "and there remained but wounded men among them,"], ["latou te tutū taitasi i lona fale ie,", "yet should they rise up every man in his tent,"], ["ma latou susunuina lenei aai i le afi.", "and burn this city with fire."]]},
  {num:11,words:[["Ua o ese le itu taua a Kaletaia i Ierusalema ona o le itu taua a Farao,", "And it came to pass, that when the army of the Chaldeans was broken up from Jerusalem for fear of Pharaoh's army,"]]},
  {num:12,words:[["ona alu atu ai lea o Ieremia nai Ierusalema, e alu i le nuu o Peniamina,", "Then Jeremiah went forth out of Jerusalem to go into the land of Benjamin,"], ["ia maua e ia lona tofi i lea mea i totonu o le nuu.", "to separate himself thence in the midst of the people."]]},
  {num:13,words:[["Ua i ai foi o ia i le faitotoa o Peniamina,", "And when he was in the gate of Benjamin,"], ["ua i ai foi le alii leoleo,", "a captain of the ward was there,"], ["o lona igoa o Iria,", "whose name was Irijah,"], ["le atalii o Selemia,", "the son of Shelemiah,"], ["o le atalii o Hanania;", "the son of Hananiah;"], ["ona pue ai lea o ia ia Ieremia le perofeta,", "and he took Jeremiah the prophet,"], ["ua faapea atu,", "saying,"], ["O le a e sola ia Kaletaia.", "Thou fallest away to the Chaldeans."]]},
  {num:14,words:[["A ua fai atu Ieremia,", "Then said Jeremiah,"], ["Tala pepelo;", "It is false;"], ["ou te le sola ia Kaletaia. A e le faalogo o ia ia te ia;", "I fall not away to the Chaldeans. But he hearkened not to him:"], ["a ua pue Iria ia Ieremia,", "so Irijah took Jeremiah,"], ["ma au mai ia te ia i alii.", "and brought him to the princes."]]},
  {num:15,words:[["Ua ita foi alii ia Ieremia,", "Wherefore the princes were wroth with Jeremiah,"], ["ma latou fasi ia te ia,", "and smote him,"], ["ma tuuina atu o ia i le fale puipui i le fale o Ionatana le tusiupu;", "and put him in prison in the house of Jonathan the scribe:"], ["auā na latou faia lea ma fale puipui.", "for they had made that the prison."]]},
  {num:16,words:[["Ua ulu atu Ieremia i le fale puipui i ana lava ua i ai,", "When Jeremiah was entered into the dungeon, and into the cabins,"], ["ua nofo foi Ieremia i lea mea i aso e tele;", "and Jeremiah had remained there many days;"]]},
  {num:17,words:[["ona aau mai lea e Setekaia le tupu nisi e aami ia te ia;", "Then Zedekiah the king sent,"], ["ua fesili faalilolilo foi le tupu ia te ia i lona fale,", "and took him out: and the king asked him secretly in his house,"], ["ua faapea mai,", "and said,"], ["Pe ai ea se afioga mai ia Ieova Ona fai atu ai lea o Ieremia,", "Is there any word from the LORD? And Jeremiah said,"], ["E i ai lava;", "There is:"], ["ua fai atu foi o ia,", "for, said he,"], ["E tuuina oe i le lima o le tupu o Papelonia.", "thou shalt be delivered into the hand of the king of Babylon."]]},
  {num:18,words:[["Ua fai atu foi Ieremia ia Setekaia le tupu,", "Moreover Jeremiah said unto king Zedekiah,"], ["Se a ea se mea ua ou agaleaga ai ia te oe,", "What have I offended against thee,"], ["po o au auauna,", "or against thy servants,"], ["po o lenei nuu,", "or against this people,"], ["ina ua outou tuuina o a'u i le fale puipui?", "that ye have put me in prison?"]]},
  {num:19,words:[["O fea o i ai foi a outou perofeta,", "Where are now your prophets which prophesied unto you,"], ["na vavalo ia te outou,", "saying,"], ["ua faapea,", "The king of Babylon shall not come against you,"], ["E le sau le tupu o Papelonia e tau ma outou ma le nuu nei?", "nor against this land?"]]},
  {num:20,words:[["O lenei,", "Therefore hear now,"], ["le alii e le tupu,", "I pray thee, O my lord the king:"], ["ia e faafofoga mai,", "let my supplication,"], ["ia paū atu i ou luma la'u faatoga;", "I pray thee,"], ["aua ne'i e faafoi atu ia te au i le fale o Ionatana le tusiupu,", "be accepted before thee; that thou cause me not to return to the house of Jonathan the scribe,"], ["ne'i ou oti ai.", "lest I die there."]]},
  {num:21,words:[["Ona poloai ane lea o Setekaia le tupu ia latou tuuina o Ieremia i le lotoā o le fale puipui,", "Then Zedekiah the king commanded that they should commit Jeremiah into the court of the prison,"], ["ia avatu foi ia te ia i lea aso ma lea aso se potoi areto mai le ala o e fai areto,", "and that they should give him daily a piece of bread out of the bakers' street,"], ["seia uma le areto uma lava o i le aai. Ona nofo ai lea o Ieremia i le lotoā o le fale puipui.", "until all the bread in the city were spent. Thus Jeremiah remained in the court of the prison."]]},
];
renderVerseSet(jer_ch_37_Verses, 'jer-ch37-verses');

var jer_ch_38_Verses = [
  {num:1,words:[["Ua faalogo Sefatia le atalii o Matana,", "Then Shephatiah the son of Mattan,"], ["ma Ketalia le atalii o Pasura,", "and Gedaliah the son of Pashur,"], ["ma Iukali le atalii o Selemia,", "and Jucal the son of Shelemiah,"], ["ma Pasura le atalii o Malekia,", "and Pashur the son of Malchiah,"], ["i upu ua fai atu ai e Ieremia i le nuu uma,", "heard the words that Jeremiah had spoken unto all the people,"], ["ua faapea atu,", "saying,"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova. O lē nofo i le aai nei e oti ia i le pelu,", "Thus saith the LORD,"], ["ma le oge,", "He that remaineth in this city shall die by the sword,"], ["ma le faamai;", "by the famine, and by the pestilence:"], ["a o lē alu atu i tagata o Kaletaia e ola ia;", "but he that goeth forth to the Chaldeans shall live;"], ["e avea foi lona ola ma ana vete,", "for he shall have his life for a prey,"], ["e ola foi ia.", "and shall live."]]},
  {num:3,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["E tuuina lava lenei aai i lima o le itu taua a le tupu o Papelonia,", "This city shall surely be given into the hand of the king of Babylon's army,"], ["latou te aea ai.", "which shall take it."]]},
  {num:4,words:[["Ona fai atu ai lea o alii i le tupu,", "Therefore the princes said unto the king,"], ["Ia fasioti lava lenei tagata;", "We beseech thee,"], ["auā lava o ia lē faavaivaia lima o tagata tau o e totoe i lenei aai,", "let this man be put to death:"], ["ma lima o le nuu uma,", "for thus he weakeneth the hands of the men of war that remain in this city, and the hands of all the people,"], ["i lona tautala atu ia te i latou e tusa ma ia upu;", "in speaking such words unto them:"], ["auā e le saili lenei tagata ia manuia lenei nuu,", "for this man seeketh not the welfare of this people,"], ["a ia malaia.", "but the hurt."]]},
  {num:5,words:[["Ona fai mai ai lea o Setekaia le tupu,", "Then Zedekiah the king said,"], ["Faauta,", "Behold,"], ["o loo i o outou lima o ia;", "he is in your hand:"], ["auā e le mafai i le tupu se mea pe a le tatau ia te outou.", "for the king is not he that can do any thing against you."]]},
  {num:6,words:[["Ona latou fetagofi ai lea ia Ieremia,", "Then took they Jeremiah,"], ["ma tuuina atu o ia i le lua a Malekia le atalii o le tupu,", "and cast him into the dungeon of Malchiah the son of Hammelech,"], ["sa i le lotoā o le fale puipui;", "that was in the court of the prison:"], ["ua latou tuutuu ifo ia Ieremia i maea. E leai foi se vai i le lua,", "and they let down Jeremiah with cords. And in the dungeon there was no water,"], ["na o palapala;", "but mire:"], ["ua goto foi Ieremia i le palapala.", "so Jeremiah sunk in the mire."]]},
  {num:7,words:[["Ua faalogo Epetemeleka le tagata Aitiope,", "Now when Ebed-melech the Ethiopian,"], ["o le eunuka e i le fale o le tupu,", "one of the eunuchs which was in the king's house,"], ["ua tuuina ifo Ieremia i le lua,", "heard that they had put Jeremiah in the dungeon;"], ["ua nofo foi le tupu i le faitotoa o Peniamina,", "the king then sitting in the gate of Benjamin;"]]},
  {num:8,words:[["ona alu atu ai lea o Epetemeleka ai le fale o le tupu,", "Ebed-melech went forth out of the king's house,"], ["ua tautala atu i le tupu,", "and spake to the king,"], ["ua faapea atu,", "saying,"]]},
  {num:9,words:[["Le alii e le tupu,", "My lord the king,"], ["ua amio leaga ia tagata i mea uma ua latou faia ia Ieremia le perofeta,", "these men have done evil in all that they have done to Jeremiah the prophet,"], ["o le ua latou tuuina ifo i le lua;", "whom they have cast into the dungeon;"], ["e oti foi o ia i le mea ua i ai i le fia 'ai;", "and he is like to die for hunger in the place where he is:"], ["auā e leai ni areto o totoe i le aai.", "for there is no more bread in the city."]]},
  {num:10,words:[["Ona fai atu ai lea o le tupu ia Epetemeleka le Aitiope,", "Then the king commanded Ebed-melech the Ethiopian,"], ["ua faapea atu,", "saying,"], ["Tou te o ma oe tagata e toatolugafulu, ai le mea nei,", "Take from hence thirty men with thee,"], ["ma aveina ae Ieremia le perofeta ai le lua,", "and take up Jeremiah the prophet out of the dungeon,"], ["manū o lei oti o ia.", "before he die."]]},
  {num:11,words:[["Ona o ai lea o Epetemeleka ma ia tagata,", "So Ebed-melech took the men with him,"], ["ua latou o atu i le fale o le tupu i lalo o le mea e teu ai oloa,", "and went into the house of the king under the treasury,"], ["ma latou au mai mai lea mea ie pala masaesae ma ofu pala masaesae,", "and took thence old cast clouts and old rotten rags,"], ["ua latou tuuina ifo ia mea i maea ia Ieremia i le lua.", "and let them down by cords into the dungeon to Jeremiah."]]},
  {num:12,words:[["Ua fai ane foi Epetemeleka le Aitiope ia Ieremia,", "And Ebed-melech the Ethiopian said unto Jeremiah,"], ["Ia e tuu na ie pala masaesae ma ofu masaesae i lalo o ou aoao i maea. Ona faapea ai lea ona fai e Ieremia.", "Put now these old cast clouts and rotten rags under thine armholes under the cords. And Jeremiah did so."]]},
  {num:13,words:[["Ona latou sisi ai lea ia Ieremia i maea,", "So they drew up Jeremiah with cords,"], ["ma avae ia te ia ai le lua;", "and took him up out of the dungeon:"], ["ona nofo ai lea o Ieremia i le lotoā o le fale puipui.", "and Jeremiah remained in the court of the prison."]]},
  {num:14,words:[["Ona feauina lea e Setekaia le tupu,", "Then Zedekiah the king sent,"], ["ma na aami atu ia Ieremia le perofeta e sau ia te ia,", "and took Jeremiah the prophet unto him into the third entry that is in the house of the LORD:"], ["i lona tolu o faitotoa i le fale o Ieova; ua fai atu foi le tupu ia Ieremia,", "and the king said unto Jeremiah,"], ["Ou te fesili atu ia te oe i se mea;", "I will ask thee a thing;"], ["aua e te natia se mea ia te au.", "hide nothing from me."]]},
  {num:15,words:[["Ona fai mai ai lea o Ieremia ia Setekaia,", "Then Jeremiah said unto Zedekiah,"], ["Afai ou te ta'uatua ia te oe,", "If I declare it unto thee,"], ["e te le fasiotia ea a'u? afai foi ou te faatonuina atu ia te oe,", "wilt thou not surely put me to death? and if I give thee counsel,"], ["e te le faalogo mai ia te au.", "wilt thou not hearken unto me?"]]},
  {num:16,words:[["Ona tauto faalilolilo ai lea o Setekaia le tupu ia Ieremia,", "So Zedekiah the king sware secretly unto Jeremiah,"], ["ua faapea,", "saying,"], ["O loo soifua Ieova,", "As the LORD liveth,"], ["o le na faia i taua nei,", "that made us this soul,"], ["ou te le fasiotia oe,", "I will not put thee to death,"], ["ou te le tuuina atu foi oe i lima o ia tagata ua saili e fasiotia oe.", "neither will I give thee into the hand of these men that seek thy life."]]},
  {num:17,words:[["Ona fai mai ai lea o Ieremia ia Setekaia,", "Then said Jeremiah unto Zedekiah,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["le Atua o 'au,", "the God of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Afai e te matuā alu atu i alii mai le tupu o Papelonia,", "If thou wilt assuredly go forth unto the king of Babylon's princes,"], ["ona soifua ai lea o oe,", "then thy soul shall live,"], ["e le faamuina foi lenei aai i le afi;", "and this city shall not be burned with fire;"], ["a e soifua oe,", "and thou shalt live,"], ["atoa foi ma lou aiga.", "and thine house:"]]},
  {num:18,words:[["A e afai e te le alu atu i alii mai le tupu o Papelonia,", "But if thou wilt not go forth to the king of Babylon's princes,"], ["ona tuuina atu ai lea o lenei aai i lima o Kaletaia,", "then shall this city be given into the hand of the Chaldeans,"], ["ma latou faamuina i le afi,", "and they shall burn it with fire,"], ["o oe foi e te le sao i o latou lima.", "and thou shalt not escape out of their hand."]]},
  {num:19,words:[["Ona fai atu ai lea o Setekaia le tupu ia Ieremia,", "And Zedekiah the king said unto Jeremiah,"], ["Ou te fefe i tagata Iuta ua sosola atu i Kaletaia,", "I am afraid of the Jews that are fallen to the Chaldeans,"], ["ne'i latou tuuina atu a'u i o latou lima,", "lest they deliver me into their hand,"], ["ma latou faaleaga ia te au.", "and they mock me."]]},
  {num:20,words:[["A ua fai mai Ieremia,", "But Jeremiah said,"], ["E le tuuina atu oe e i latou.", "They shall not deliver thee."], ["Ia e faafofoga mai i le siufofoga o Ieova ou te fai atu ai ia te oe;", "Obey, I beseech thee,"], ["ona manuia ai lea o oe,", "the voice of the LORD, which I speak unto thee:"], ["ma e soifua.", "so it shall be well unto thee, and thy soul shall live."]]},
  {num:21,words:[["A e afai e te le mafai ona maliu atu,", "But if thou refuse to go forth,"], ["o lenei le upu ua faailoa mai ai e Ieova ia te au;", "this is the word that the LORD hath shewed me:"]]},
  {num:22,words:[["faauta foi,", "And,"], ["o fafine uma ua totoe i le fale o le tupu o Iuta,", "behold,"], ["e ta'ita'iina i latou i alii mai le tupu o Papelonia,", "all the women that are left in the king of Judah's house shall be brought forth to the king of Babylon's princes,"], ["latou te fai ane foi,", "and those women shall say,"], ["Na faaosoina oe e au uo,", "Thy friends have set thee on,"], ["ua latou manumalo foi ia te oe;", "and have prevailed against thee:"], ["ua goto ou vae i le palapala,", "thy feet are sunk in the mire,"], ["a ua tuumuli i latou.", "and they are turned away back."]]},
  {num:23,words:[["E aveina atu foi au avā uma ma au fanau ia Kaletaia;", "So they shall bring out all thy wives and thy children to the Chaldeans:"], ["o oe foi e le sao oe i o latou lima,", "and thou shalt not escape out of their hand,"], ["a e puea oe e le lima o le tupu o Papelonia;", "but shalt be taken by the hand of the king of Babylon:"], ["o oe foi e mu ai lenei aai i le afi.", "and thou shalt cause this city to be burned with fire."]]},
  {num:24,words:[["Ona fai atu ai lea o Setekaia ia Ieremia,", "Then said Zedekiah unto Jeremiah,"], ["Aua ne'i iloa e se tasi o ia upu,", "Let no man know of these words,"], ["ona e le oti ai lea.", "and thou shalt not die."]]},
  {num:25,words:[["Pe afai foi e faalogo alii ua ta tautalatala ma oe,", "But if the princes hear that I have talked with thee,"], ["ma latou o ane ia te oe,", "and they come unto thee,"], ["ma fai ane ia te oe,", "and say unto thee,"], ["Ina ta'u mai ia ia te i matou o mea na e fai atu ai i le tupu,", "Declare unto us now what thou hast said unto the king,"], ["aua le natia ia te i matou,", "hide it not from us,"], ["ona matou le fasioti ai lea ia te oe;", "and we will not put thee to death;"], ["pe se a foi le mea na fai mai ai le tupu ia te oe;", "also what the king said unto thee:"]]},
  {num:26,words:[["ona e fai atu ai lea ia te i latou,", "Then thou shalt say unto them,"], ["Na a'u fai la'u faatoga i luma o le tupu,", "I presented my supplication before the king,"], ["aua na te faafoisia a'u i le fale o Ionatana,", "that he would not cause me to return to Jonathan's house,"], ["ne'i ou oti i lea mea.", "to die there."]]},
  {num:27,words:[["Ona o mai ai lea o alii uma ia Ieremia,", "Then came all the princes unto Jeremiah,"], ["ma fesili mai ia te ia; ona ta'u atu ai lea o ia ia te i latou,", "and asked him:"], ["e tusa ma ia upu uma na fai mai ai le tupu.", "and he told them according to all these words that the king had commanded."], ["Ona latou o ese ai lea ia te ia ua le toe tautala;", "So they left off speaking with him;"], ["auā na le lagona se tasi le tautalaga.", "for the matter was not perceived."]]},
  {num:28,words:[["Ua nofo Ieremia i le lotoā o le fale puipui ua oo i le aso na aea ai Ierusalema;", "So Jeremiah abode in the court of the prison until the day that Jerusalem was taken:"], ["na i ai foi o ia ina ua aea Ierusalema.", "and he was there when Jerusalem was taken."]]},
];
renderVerseSet(jer_ch_38_Verses, 'jer-ch38-verses');

var jer_ch_39_Verses = [
  {num:1,words:[["O le iva o tausaga o Setekaia le tupu o Iuta, o le sefulu o masina,", "In the ninth year of Zedekiah king of Judah,"], ["na o mai ai Nepukanesa le tupu o Papelonia,", "in the tenth month,"], ["ma lana itu taua uma,", "came Nebuchadrezzar king of Babylon and all his army against Jerusalem,"], ["i Ierusalema, ma latou vagaia.", "and they besieged it."]]},
  {num:2,words:[["O le tausaga o Setekaia e sefulu ma le tasi,", "And in the eleventh year of Zedekiah,"], ["o le fa o masina,", "in the fourth month,"], ["ma le aso iva o le masina,", "the ninth day of the month,"], ["na lepetia ai le aai.", "the city was broken up."]]},
  {num:3,words:[["Ona o mai ai lea o alii uma ua i le tupu o Papelonia,", "And all the princes of the king of Babylon came in,"], ["ma latou nonofo i le faitotoa i totonu,", "and sat in the middle gate, even Nergal-sharezer,"], ["o Nekala-saresa,", "Samgar-nebo,"], ["o Samekanepo,", "Sarsechim,"], ["o Sasekimo o le matai o eunuka,", "Rab-saris,"], ["o Nekala-saresa o le matai o makoi,", "Nergal-sharezer, Rab-mag,"], ["ma nisi alii uma ua i le tupu o Papelonia.", "with all the residue of the princes of the king of Babylon."]]},
  {num:4,words:[["Ua iloa i latou e Setekaia le tupu o Iuta,", "And it came to pass,"], ["ma 'au uma,", "that when Zedekiah the king of Judah saw them, and all the men of war,"], ["ona latou sosola ai lea,", "then they fled,"], ["ma latou tuua le aai i le po,", "and went forth out of the city by night,"], ["ua ui i le ala o le fanua o le tupu i le faitotoa i le va o pa e lua;", "by the way of the king's garden, by the gate betwixt the two walls:"], ["ua alu atu foi o ia i le ala i le eleele laugatasi.", "and he went out the way of the plain."]]},
  {num:5,words:[["Ona tuliloa ai lea e le itu taua a Kaletaia ia te i latou,", "But the Chaldeans' army pursued after them,"], ["ua latou maua atu ia Setekaia i le eleele laugatasi o Ieriko;", "and overtook Zedekiah in the plains of Jericho:"], ["ua latou pue ia te ia, ona latou avatu ai lea o ia ia Nepukanesa le tupu o Papelonia i Ripelu,", "and when they had taken him,"], ["i le nuu o Amato,", "they brought him up to Nebuchadnezzar king of Babylon to Riblah in the land of Hamath,"], ["ona faasala ai lea o ia ia te ia.", "where he gave judgment upon him."]]},
  {num:6,words:[["Ua fasiotia foi e le tupu o Papelonia o atalii o Setekaia i ona luma i Ripelu;", "Then the king of Babylon slew the sons of Zedekiah in Riblah before his eyes:"], ["ua fasiotia foi e le tupu o Papelonia o alii uma o Iuta.", "also the king of Babylon slew all the nobles of Judah."]]},
  {num:7,words:[["Ua ia faatauaso foi ia Setekaia,", "Moreover he put out Zedekiah's eyes, and bound him with chains,"], ["ma fusifusi ia te ia i faamau 'apa memea e lua e ave ia te ia i Papelonia.", "to carry him to Babylon."]]},
  {num:8,words:[["Ua susunuina foi e Kaletaia le fale o le tupu,", "And the Chaldeans burned the king's house,"], ["ma fale o le nuu i le afi,", "and the houses of the people, with fire,"], ["ma latou sŏloia le pa o Ierusalema.", "and brake down the walls of Jerusalem."]]},
  {num:9,words:[["A o e na totoe o le nuu sa i ai pea i le aai,", "Then Nebuzar-adan the captain of the guard carried away captive into Babylon the remnant of the people that remained in the city,"], ["ma e na sosola na sosola ia te ia,", "and those that fell away,"], ["ma e na totoe o le nuu sa i ai pea, na tāfea i latou i Papelonia e Nepusatana,", "that fell to him,"], ["lē pule i le 'au e faafeao.", "with the rest of the people that remained."]]},
  {num:10,words:[["A ua tuua i le nuu o Iuta e Nepusatana lē pule i le 'au e faafeao,", "But Nebuzar-adan the captain of the guard left of the poor of the people,"], ["nisi o le nuu o e matitiva,", "which had nothing,"], ["e leai sa latou mea,", "in the land of Judah,"], ["ua ia foai atu foi ia te i latou o tovine ma fanua i lea aso.", "and gave them vineyards and fields at the same time."]]},
  {num:11,words:[["Na poloai foi Nepukanesa le tupu o Papelonia ia Nepusatana lē pule i le 'au e faafeao ia Ieremia,", "Now Nebuchadrezzar king of Babylon gave charge concerning Jeremiah to Nebuzar-adan the captain of the guard,"], ["ua faapea atu,", "saying,"]]},
  {num:12,words:[["Ia e ave ia te ia,", "Take him,"], ["ia e tausi foi ia te ia,", "and look well to him,"], ["aua ne'i fai se mea leaga ia te ia; a e pei ona fai mai o ia ia te oe,", "and do him no harm;"], ["ia faapea ona e fai ia te ia.", "but do unto him even as he shall say unto thee."]]},
  {num:13,words:[["Ua aauina atu foi nisi e Nepusatana lē pule i le 'au e faafeao,", "So Nebuzar-adan the captain of the guard sent, and Nebushasban,"], ["ma Nepusapana o le matai o eunuka,", "Rab-saris,"], ["ma Nekala-saresa o le matai o makoi,", "and Nergal-sharezer,"], ["ma alii uma ua i le tupu o Papelonia;", "Rab-mag, and all the king of Babylon's princes;"]]},
  {num:14,words:[["ua latou aauina atu,", "Even they sent,"], ["ma latou aami atu ia Ieremia ai le lotoā o le fale puipui,", "and took Jeremiah out of the court of the prison,"], ["ona latou tuuina atu lea o ia ia Ketalia le atalii o Aikamo, le atalii o Safana,", "and committed him unto Gedaliah the son of Ahikam the son of Shaphan,"], ["ia na au mai ia te ia i le fale;", "that he should carry him home:"], ["ona nofo ai lea o ia faatasi ma le nuu.", "so he dwelt among the people."]]},
  {num:15,words:[["Na oo mai le afioga a Ieova ia Ieremia,", "Now the word of the LORD came unto Jeremiah,"], ["ina o puipuia o ia i le lotoā o le fale puipui,", "while he was shut up in the court of the prison,"], ["ua faapea mai,", "saying,"]]},
  {num:16,words:[["Ina alu ia,", "Go and speak to Ebed-melech the Ethiopian,"], ["ma e fai atu ia Epetemeleka le Aitiope,", "saying,"], ["ia faapea atu,", "Thus saith the LORD of hosts,"], ["O loo faapea ona fetalai mai o Ieova o 'au,", "the God of Israel;"], ["le Atua o Isaraelu, Faauta,", "Behold,"], ["ou te faaoo a'u upu i lenei aai ia malaia,", "I will bring my words upon this city for evil,"], ["a e le ina ia manuia;", "and not for good;"], ["e oo foi ia i ou luma i lea aso.", "and they shall be accomplished in that day before thee."]]},
  {num:17,words:[["A e ou te laveai ia te oe i lea aso,", "But I will deliver thee in that day,"], ["o loo fetalai mai ai Ieova,", "saith the LORD:"], ["e le tuuina foi oe i lima o tagata ua e fefe ai.", "and thou shalt not be given into the hand of the men of whom thou art afraid."]]},
  {num:18,words:[["Auā ou te faasaoina lava oe,", "For I will surely deliver thee,"], ["e te le oti foi i le pelu,", "and thou shalt not fall by the sword,"], ["a e avea lou ola māu vete;", "but thy life shall be for a prey unto thee:"], ["auā ua e faatuatua ia te au,", "because thou hast put thy trust in me,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
];
renderVerseSet(jer_ch_39_Verses, 'jer-ch39-verses');

var jer_ch_40_Verses = [
  {num:1,words:[["O le afioga na oo mai ia Ieremia mai ia Ieova,", "The word that came to Jeremiah from the LORD,"], ["ina ua mavae ona tuuina atu o ia mai Rama e Nepusatana lē pule i le 'au e faafeao,", "after that Nebuzar-adan the captain of the guard had let him go from Ramah,"], ["ina o maua o ia e ia,", "when he had taken him being bound in chains among all that were carried away captive of Jerusalem and Judah,"], ["a o fusifusia o ia i maea uamea faatasi ma le tafeaga uma a Ierusalema ma Iuta e na tāfea i Papelonia.", "which were carried away captive unto Babylon."]]},
  {num:2,words:[["Ona ave ai lea e lē pule i le 'au e faafeao ia Ieremia, ma ua faapea mai ia te ia,", "And the captain of the guard took Jeremiah,"], ["O Ieova,", "and said unto him,"], ["lou Atua, na fetalai mai lenei malaia i lenei mea.", "The LORD thy God hath pronounced this evil upon this place."]]},
  {num:3,words:[["O Ieova foi ua faaoo ai,", "Now the LORD hath brought it,"], ["ma na faia e pei ona fetalai mai ai o ia;", "and done according as he hath said:"], ["auā na outou agasala ia Ieova,", "because ye have sinned against the LORD,"], ["ma outou le faalogo i lona siufofoga,", "and have not obeyed his voice,"], ["o le mea lea ua oo ai ia te outou lenei mea.", "therefore this thing is come upon you."]]},
  {num:4,words:[["O lenei,", "And now,"], ["faauta mai,", "behold,"], ["ua ou tatalaina oe i lenei aso ai maea uamea sa i ou lima. Afai e lelei ia te oe ona ta o ma a'u i Papelonia,", "I loose thee this day from the chains which were upon thine hand. If it seem good unto thee to come with me into Babylon,"], ["sau ia,", "come;"], ["ou te tausi ia te oe;", "and I will look well unto thee:"], ["a e afai e leaga ia te oe ona ta o ma a'u i Papelonia,", "but if it seem ill unto thee to come with me into Babylon,"], ["soia;", "forbear:"], ["ina vaai atu ia,", "behold,"], ["o loo i ou luma le nuu uma;", "all the land is before thee:"], ["o le mea e lelei ma tatau ia te oe ona alu i ai,", "whither it seemeth good and convenient for thee to go,"], ["o le mea lea ia e alu i ai.", "thither go."]]},
  {num:5,words:[["A o lei tali atu o ia, na ia faapea mai ,", "Now while he was not yet gone back,"], ["Ina foi atu ia ia Ketalia le atalii o Aikamo,", "he said,"], ["o le atalii lea o Safana,", "Go back also to Gedaliah the son of Ahikam the son of Shaphan,"], ["o le ua tofia e le tupu o Papelonia e pule i aai o Iuta, ma ia e nofo ma ia faatasi ma le nuu;", "whom the king of Babylon hath made governor over the cities of Judah,"], ["a le o lea, o le mea e tatau ia te oe ona e alu i ai,", "and dwell with him among the people:"], ["ina alu lava ia i ai.", "or go wheresoever it seemeth convenient unto thee to go."], ["Ona foai mai ai lea ia te ia e lē pule i le 'au e faafeao o mea e 'ai, ma se mea alofa,", "So the captain of the guard gave him victuals and a reward,"], ["ma na tuuina o ia e alu.", "and let him go."]]},
  {num:6,words:[["Ona alu ai lea o Ieremia ia Ketalia le atalii o Aikamo i Mesepa; ua nofo foi ma ia,", "Then went Jeremiah unto Gedaliah the son of Ahikam to Mizpah;"], ["faatasi ma le nuu o e na totoe i le nuu.", "and dwelt with him among the people that were left in the land."]]},
  {num:7,words:[["O alii uma na ave 'au o e sa i le vao,", "Now when all the captains of the forces which were in the fields,"], ["o i latou ma o latou tagata,", "even they and their men,"], ["ua faalogo i latou ua tofia e le tupu o Papelonia o Ketalia le atalii o Aikamo e pule i le nuu,", "heard that the king of Babylon had made Gedaliah the son of Ahikam governor in the land,"], ["ua na tofia foi o ia e pule i tane,", "and had committed unto him men,"], ["ma fafine,", "and women,"], ["ma tama iti,", "and children,"], ["o isi foi o e matitiva o le nuu,", "and of the poor of the land,"], ["o i latou na le tāfea i Papelonia;", "of them that were not carried away captive to Babylon;"]]},
  {num:8,words:[["ona latou o mai ai lea ia Ketalia i Mesepa,", "Then they came to Gedaliah to Mizpah,"], ["o Isamaeli le atalii o Netanaia,", "even Ishmael the son of Nethaniah,"], ["ma Ioanana ma Ionatana o atalii o Karea,", "and Johanan and Jonathan the sons of Kareah,"], ["ma Seraia le atalii o Tanumeta,", "and Seraiah the son of Tanhumeth,"], ["o atalii foi o Efai le Netopa,", "and the sons of Ephai the Netophathite,"], ["ma Iaasenaia le atalii o le Maaka,", "and Jezaniah the son of a Maachathite,"], ["o i latou ma o latou tagata.", "they and their men."]]},
  {num:9,words:[["Ona tauto ai lea o Ketalia le atalii o Aikamo,", "And Gedaliah the son of Ahikam the son of Shaphan sware unto them and to their men,"], ["le atalii o Safana ia te i latou ma o latou tagata,", "saying,"], ["ua faapea atu, Aua tou te fefefe i auauna ia Kaletaia;", "Fear not to serve the Chaldeans:"], ["ia outou nonofo i le nuu,", "dwell in the land,"], ["ma auauna i le tupu o Papelonia,", "and serve the king of Babylon,"], ["ona manuia ai lea o outou.", "and it shall be well with you."]]},
  {num:10,words:[["O a'u nei foi,", "As for me,"], ["faauta,", "behold,"], ["ou te nofo i Mesepa,", "I will dwell at Mizpah to serve the Chaldeans,"], ["e tu ai i luma o Kaletaia o e o mai ia te i matou;", "which will come unto us:"], ["a o outou,", "but ye,"], ["ia outou faapotopoto uaina,", "gather ye wine,"], ["ma fua otata,", "and summer fruits,"], ["ma suāuu,", "and oil,"], ["ma tuu ai i a outou fagu,", "and put them in your vessels,"], ["ia outou nonofo foi i a outou aai ua outou maua.", "and dwell in your cities that ye have taken."]]},
  {num:11,words:[["O tagata Iuta uma foi na i ai i Moapi,", "Likewise when all the Jews that were in Moab,"], ["ma le nuu o le fanauga a Amoni,", "and among the Ammonites,"], ["ma Etoma, ma e na i ai i nuu uma,", "and in Edom,"], ["ua latou faalogo ua tuua e le tupu o Papelonia e na totoe o Iuta,", "and that were in all the countries,"], ["ma ua tofia e ia e pule ia te i latou o Ketalia le atalii o Aikamo,", "heard that the king of Babylon had left a remnant of Judah,"], ["le atalii o Safana;", "and that he had set over them Gedaliah the son of Ahikam the son of Shaphan;"]]},
  {num:12,words:[["ona foi mai ai lea o Iuta uma i mea uma na tulia ai i latou,", "Even all the Jews returned out of all places whither they were driven, and came to the land of Judah,"], ["ma latou o mai i le nuu o Iuta ia Ketalia i Mesepa,", "to Gedaliah,"], ["ma latou faapotopoto i uaina ma fua otata e matua tele.", "unto Mizpah, and gathered wine and summer fruits very much."]]},
  {num:13,words:[["O Ioanana foi le atalii o Karea,", "Moreover Johanan the son of Kareah,"], ["ma alii uma na ave 'au, sa i le vao,", "and all the captains of the forces that were in the fields,"], ["ua latou o mai ia Ketalia ia Mesepa;", "came to Gedaliah to Mizpah,"]]},
  {num:14,words:[["ona latou fai mai lea ia te ia, Ua e silafia lava ea ua auina mai e Paaliso le tupu o le fanauga a Amoni,", "And said unto him,"], ["o Isamaeli le atalii o Netanaia e fasioti ia te oe? A e lei talia la latou tala e Ketalia le atalii o Aikamo.", "Dost thou certainly know that Baalis the king of the Ammonites hath sent Ishmael the son of Nethaniah to slay thee? But Gedaliah the son of Ahikam believed them not."]]},
  {num:15,words:[["Ona fai faalilolilo mai ai lea o Ioanana le atalii o Karea ia Ketalia i Mesepa,", "Then Johanan the son of Kareah spake to Gedaliah in Mizpah secretly,"], ["ua faapea mai,", "saying,"], ["Se'i ou alu,", "Let me go,"], ["ma ou fasi ia Isamaeli le atalii o Netanaia,", "I pray thee,"], ["e le iloa foi e se tasi;", "and I will slay Ishmael the son of Nethaniah, and no man shall know it:"], ["se a ea le mea na te fasioti ai ia te oe,", "wherefore should he slay thee,"], ["e faataapeapeina ai Iuta uma ua faapotopotoina ia te oe,", "that all the Jews which are gathered unto thee should be scattered,"], ["e faaumatia foi o Iuta ua totoe?", "and the remnant in Judah perish?"]]},
  {num:16,words:[["Ona fai atu ai lea o Ketalia le atalii o Aikamo ia Ioanana le atalii o Karea,", "But Gedaliah the son of Ahikam said unto Johanan the son of Kareah,"], ["Aua e te fai lena mea;", "Thou shalt not do this thing:"], ["auā o le mea pepelo ua e fai mai ai ia Isamaeli.", "for thou speakest falsely of Ishmael."]]},
];
renderVerseSet(jer_ch_40_Verses, 'jer-ch40-verses');

var jer_ch_41_Verses = [
  {num:1,words:[["Ua oo i le fitu o masina,", "Now it came to pass in the seventh month,"], ["ona o mai ai lea o Isamaeli le atalii o Netanaia,", "that Ishmael the son of Nethaniah the son of Elishama,"], ["le atalii o Elisama,", "of the seed royal,"], ["o le aiga to tino o le tupu, ma alii sa i le tupu,", "and the princes of the king,"], ["ma tagata e toasefulu faatasi ma ia,", "even ten men with him,"], ["ia Ketalia le atalii o Aikamo i Mesepa;", "came unto Gedaliah the son of Ahikam to Mizpah;"], ["ua latou aai foi faatasi i lea mea i Mesepa.", "and there they did eat bread together in Mizpah."]]},
  {num:2,words:[["Ona tulai ai lea o Isamaeli le atalii o Netanaia,", "Then arose Ishmael the son of Nethaniah,"], ["ma ia tagata e toasefulu na ia te ia,", "and the ten men that were with him,"], ["ma latou fasi ia Ketalia le atalii o Aikamo le atalii o Safana,", "and smote Gedaliah the son of Ahikam the son of Shaphan with the sword,"], ["i le pelu,", "and slew him,"], ["na fasiotia e i latou o ia na tofia e le tupu o Papelonia e pule i le nuu.", "whom the king of Babylon had made governor over the land."]]},
  {num:3,words:[["Ua fasia foi e Isamaeli o Iuta uma sa ia Ketalia i Mesepa,", "Ishmael also slew all the Jews that were with him,"], ["ma Kaletaia,", "even with Gedaliah,"], ["o tagata tau,", "at Mizpah, and the Chaldeans that were found there,"], ["ua latou maua i lea mea.", "and the men of war."]]},
  {num:4,words:[["Ua oo i le lua o aso talu ona fasiotia e ia o Ketalia,", "And it came to pass the second day after he had slain Gedaliah,"], ["ma ua le iloa e se tasi;", "and no man knew it,"]]},
  {num:5,words:[["ona o mai ai lea o tagata mai Sekema,", "That there came certain from Shechem,"], ["ma Sailo,", "from Shiloh,"], ["ma Samaria,", "and from Samaria,"], ["o tagata e toavalugafulu,", "even fourscore men,"], ["ua tafi a latou 'ava,", "having their beards shaven,"], ["ma ua saei o latou ofu,", "and their clothes rent,"], ["ua selei foi i latou e i latou,", "and having cut themselves,"], ["sa i o latou lima o taulaga i mea e 'ai ma pulu lipano,", "with offerings and incense in their hand,"], ["e avatua i le fale o Ieova.", "to bring them to the house of the LORD."]]},
  {num:6,words:[["Ona alu atu ai lea ai Mesepa o Isamaeli le atalii e Netanaia,", "And Ishmael the son of Nethaniah went forth from Mizpah to meet them,"], ["e faafetaiai ia i latou,", "weeping all along as he went:"], ["ua savali ia ma tagi fano;", "and it came to pass,"], ["ua oo ina fetaiai o ia ma i latou,", "as he met them,"], ["ona fai atu ai lea o ia ia te i latou,", "he said unto them,"], ["Ina o mai ia ia Ketalia le atalii o Aikamo.", "Come to Gedaliah the son of Ahikam."]]},
  {num:7,words:[["Na oo foi i latou i totonu o le aai,", "And it was so, when they came into the midst of the city,"], ["ona fasiotia ai lea o i latou e Isamaeli le atalii o Netanaia ma lafo ia te i latou i totonu o le lua,", "that Ishmael the son of Nethaniah slew them,"], ["o ia lava,", "and cast them into the midst of the pit,"], ["ma tagata na ia te ia.", "he, and the men that were with him."]]},
  {num:8,words:[["A e peitai sa ia te i latou o tagata e taosefulu,", "But ten men were found among them that said unto Ishmael,"], ["na fai mai ia Isamaeli,", "Slay us not:"], ["Aua e te fasiotia i matou; auā ua ia te i matou mea ua natia i le vao,", "for we have treasures in the field,"], ["o saito,", "of wheat,"], ["ma karite,", "and of barley,"], ["ma suāuu, ma meli;", "and of oil,"], ["ona tuu lea e ia,", "and of honey. So he forbare,"], ["ua na le fasiotia i latou faatasi ma o latou uso.", "and slew them not among their brethren."]]},
  {num:9,words:[["O le lua foi na lafo i ai e Isamaeli tino o tagata oti uma na ia fasia ona o Ketalia,", "Now the pit wherein Ishmael had cast all the dead bodies of the men,"], ["o le lua lea na faia e Asa e tupu,", "whom he had slain because of Gedaliah,"], ["ona o Paasa le tupu o Isaraelu;", "was it which Asa the king had made for fear of Baasha king of Israel:"], ["na faatumuina ai e Isamaeli le atalii o Netanaia i e na fasia.", "and Ishmael the son of Nethaniah filled it with them that were slain."]]},
  {num:10,words:[["Ona ave ai lea faatagataotaua e Isamaeli o e na totoe uma o le nuu na i Mesepa,", "Then Ishmael carried away captive all the residue of the people that were in Mizpah,"], ["o afafine foi o le tupu,", "even the king's daughters,"], ["ma le nuu uma na totoe i Mesepa,", "and all the people that remained in Mizpah,"], ["na tuuina atu e Nepusatana le pule i le 'au e faafeao ia Ketalia le atalii o Aikamo e pule ai;", "whom Nebuzar-adan the captain of the guard had committed to Gedaliah the son of Ahikam:"], ["ua ave i latou faatagataotaua e Isamaeli le atalii o Netanaia,", "and Ishmael the son of Nethaniah carried them away captive,"], ["ua alu atu foi ia e sopoia atu i le fanauga a Amoni.", "and departed to go over to the Ammonites."]]},
  {num:11,words:[["A ua faalogo e Ioanana le atalii o Karea,", "But when Johanan the son of Kareah,"], ["ma alii uma sa ia te ia na ave 'au,", "and all the captains of the forces that were with him,"], ["i le leaga uma na faia e Isamaeli le atalii o Netanaia,", "heard of all the evil that Ishmael the son of Nethaniah had done,"]]},
  {num:12,words:[["ona latou ave ai lea o tagata uma,", "Then they took all the men,"], ["ma latou o e tau ma Isamaeli le atalii o Netanaia,", "and went to fight with Ishmael the son of Nethaniah,"], ["na latou maua foi o ia e lata ane i le vai tele i Kipeona.", "and found him by the great waters that are in Gibeon."]]},
  {num:13,words:[["Ua iloa e le nuu uma sa ia Isamaeli,", "Now it came to pass,"], ["o Ioanana le atalii o Karea,", "that when all the people which were with Ishmael saw Johanan the son of Kareah,"], ["ma alii uma sa ia te ia na ave 'au,", "and all the captains of the forces that were with him,"], ["ona latou fiafia ai lea.", "then they were glad."]]},
  {num:14,words:[["Ua liliu mai foi le nuu uma na ave faatagataotaua e Isamaeli ai Mesepa, ma latou foi mai,", "So all the people that Ishmael had carried away captive from Mizpah cast about and returned,"], ["ma o mai ia Ioanana le atalii o Karea.", "and went unto Johanan the son of Kareah."]]},
  {num:15,words:[["A ua sola Isamaeli le atalii o Netanaia ma tagata e toavalu ai Ioanana,", "But Ishmael the son of Nethaniah escaped from Johanan with eight men,"], ["ua alu atu foi ia i le fanauga a Amoni.", "and went to the Ammonites."]]},
  {num:16,words:[["Ona ave ai lea e Ioanana le atalii o Karea,", "Then took Johanan the son of Kareah,"], ["ma alii uma sa ia te ia na ave 'au,", "and all the captains of the forces that were with him,"], ["o e na totoe uma o le nuu,", "all the remnant of the people whom he had recovered from Ishmael the son of Nethaniah,"], ["o e na ia faafoisia mai ai ia Isamaeli le atalii o Netanaia nai Mesepa,", "from Mizpah,"], ["ina ua uma ona fasia e ia o Ketalia le atalii o Aikamo,", "after that he had slain Gedaliah the son of Ahikam,"], ["o toa malolosi,", "even mighty men of war,"], ["ma fafine,", "and the women,"], ["ma tama iti,", "and the children,"], ["ma eunuka,", "and the eunuchs,"], ["o e na ia faafoisia mai mai Kipeona;", "whom he had brought again from Gibeon:"]]},
  {num:17,words:[["ona latou o ai lea,", "And they departed,"], ["ma latou nonofo i le fale o Kimeama,", "and dwelt in the habitation of Chimham,"], ["o loo lata ane i Peteleema,", "which is by Beth-lehem,"], ["o le a o atu lava i Aikupito,", "to go to enter into Egypt,"]]},
  {num:18,words:[["ona o Kaletaia;", "Because of the Chaldeans:"], ["auā sa fefefe i latou ia te i latou,", "for they were afraid of them,"], ["ona ua fasia e Isamaeli le atalii o Netanaia o Ketalia le atalii o Aikamo,", "because Ishmael the son of Nethaniah had slain Gedaliah the son of Ahikam,"], ["o le na tofia e le tupu o Papelonia e pule i le nuu.", "whom the king of Babylon made governor in the land."]]},
];
renderVerseSet(jer_ch_41_Verses, 'jer-ch41-verses');

var jer_ch_42_Verses = [
  {num:1,words:[["-2 Ua faalatalata mai alii uma na ave 'au, ma Ioanana le atalii o Karea,", "Then all the captains of the forces,"], ["ma Iaasenaia le atalii o Hosaia, ma le nuu uma, o tagata nuu atoa ma alii,", "and Johanan the son of Kareah,"], ["ma latou fai mai ia Ieremia le perofeta, Se'i paū atu i ou luma la matou faatoga,", "and Jezaniah the son of Hoshaiah,"], ["ma ia e tatalo ia Ieova lou Atua mo i matou, o i matou nei uma o e totoe; auā o i matou o totoe e toaitiiti,", "and all the people from the least even unto the greatest,"], ["sa toatele, e pei ona sisila ou fofoga ia te i matou;", "came near,"]]},
  {num:2,words:[["And", ""], ["said", ""], ["unto", ""], ["Jeremiah", ""], ["the", ""], ["prophet,", ""], ["Let,", ""], ["we", ""], ["beseech", ""], ["thee,", ""], ["our", ""], ["supplication", ""], ["be", ""], ["accepted", ""], ["before", ""], ["thee,", ""], ["and", ""], ["pray", ""], ["for", ""], ["us", ""], ["unto", ""], ["the", ""], ["LORD", ""], ["thy", ""], ["God,", ""], ["even", ""], ["for", ""], ["all", ""], ["this", ""], ["remnant;", ""], ["(for", ""], ["we", ""], ["are", ""], ["left", ""], ["but", ""], ["a", ""], ["few", ""], ["of", ""], ["many,", ""], ["as", ""], ["thine", ""], ["eyes", ""], ["do", ""], ["behold", ""], ["us:)", ""]]},
  {num:3,words:[["ina ia faasino mai ia te i matou e Ieova lou Atua se ala matou te savavali ai,", "That the LORD thy God may shew us the way wherein we may walk,"], ["ma se mea matou te faia.", "and the thing that we may do."]]},
  {num:4,words:[["Ona fai atu ai lea o Ieremia le perofeta ia te i latou,", "Then Jeremiah the prophet said unto them,"], ["Ua ou faalogo lava,", "I have heard you; behold,"], ["faauta mai,", "I will pray unto the LORD your God according to your words;"], ["ou te tatalo ia Ieova lo outou Atua e tusa ma a outou upu;", "and it shall come to pass,"], ["o upu uma foi e tali mai ai Ieova ia te outou ou te ta'u atu ai ia te outou;", "that whatsoever thing the LORD shall answer you, I will declare it unto you;"], ["ou te le natia se upu ia te outou.", "I will keep nothing back from you."]]},
  {num:5,words:[["Ona latou fai mai ai lea ia Ieremia,", "Then they said to Jeremiah,"], ["Ia fai Ieova ma molimau moni ma le faamaoni ia te i tatou,", "The LORD be a true and faithful witness between us,"], ["pe afai matou te le faia lava e tusa ma mea uma e auina mai ai oe e Ieova lou Atua ia te i matou.", "if we do not even according to all things for the which the LORD thy God shall send thee to us."]]},
  {num:6,words:[["Pe lelei,", "Whether it be good,"], ["pe leaga,", "or whether it be evil,"], ["matou te faalogo lava i le siufofoga o Ieova lo tatou Atua,", "we will obey the voice of the LORD our God, to whom we send thee;"], ["matou te auina atu ai oe ia te ia;", "that it may be well with us,"], ["ina ia manuia i matou pe a matou faalogo i le siufofoga o Ieova lo tatou Atua.", "when we obey the voice of the LORD our God."]]},
  {num:7,words:[["Ua mavae po e sefulu,", "And it came to pass after ten days,"], ["ona oo mai ai lea o le afioga a Ieova ia Ieremia.", "that the word of the LORD came unto Jeremiah."]]},
  {num:8,words:[["Ona valaau ai lea o ia ia Ioanana le atalii o Karea,", "Then called he Johanan the son of Kareah,"], ["ma alii uma ua ia te ia na ave 'au, ma le nuu uma,", "and all the captains of the forces which were with him,"], ["o tagata nuu atoa ma alii;", "and all the people from the least even to the greatest,"]]},
  {num:9,words:[["ua fai atu foi o ia ia te i latou,", "And said unto them,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["o le na outou auina atu ai a'u e momoli atu la outou faatoga i ona luma;", "unto whom ye sent me to present your supplication before him;"]]},
  {num:10,words:[["afai tou te nonofo pea i lenei nuu,", "If ye will still abide in this land,"], ["ona ou atiina ae lea o outou,", "then will I build you,"], ["a e ou te le lepetia;", "and not pull you down,"], ["ou te totōina foi outou,", "and I will plant you,"], ["a e ou te le liaiina;", "and not pluck you up:"], ["auā ua ou salamo i le malaia ua ou faia ia te outou.", "for I repent me of the evil that I have done unto you."]]},
  {num:11,words:[["Aua tou te fefefe i le tupu o Papelonia,", "Be not afraid of the king of Babylon,"], ["o le ua outou fefefe i ai;", "of whom ye are afraid;"], ["aua lava tou te fefefe ia te ia,", "be not afraid of him,"], ["o loo fetalai mai ai Ieova;", "saith the LORD:"], ["auā ou te ia te outou e faaola ia te outou,", "for I am with you to save you,"], ["ma laveai ia te outou ai lona lima.", "and to deliver you from his hand."]]},
  {num:12,words:[["Ou te alofa ia te outou,", "And I will shew mercies unto you,"], ["e alofa mai ai o ia ia te outou,", "that he may have mercy upon you,"], ["ma faafoisia outou i lo outou laueleele.", "and cause you to return to your own land."]]},
  {num:13,words:[["A e afai tou te fai mai,", "But if ye say,"], ["Matou te le nonofo i lenei nuu;", "We will not dwell in this land,"], ["e le faalogo foi outou i le siufofoga o Ieova lo outou Atua,", "neither obey the voice of the LORD your God,"]]},
  {num:14,words:[["o loo faapea outou ,", "Saying,"], ["E leai lava;", "No;"], ["a e matou te o i le nuu o Aikupito,", "but we will go into the land of Egypt,"], ["matou te le iloa ai taua,", "where we shall see no war,"], ["ma matou le lagona ai le leo o le pu,", "nor hear the sound of the trumpet,"], ["matou te le oge foi i mea e 'ai;", "nor have hunger of bread;"], ["matou te nonofo foi i lea mea;", "and there will we dwell:"]]},
  {num:15,words:[["o le mea lea ia outou faalogologo mai ai nei i le afioga a Ieova,", "And now therefore hear the word of the LORD,"], ["o outou o e totoe o Iuta,", "ye remnant of Judah;"], ["o loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Afai tou te matuā faasaga outou e o atu i Aikupito,", "If ye wholly set your faces to enter into Egypt,"], ["ma outou o atu ai e āumau ai;", "and go to sojourn there;"]]},
  {num:16,words:[["ona maua ai lea o outou e le pelu ua outou matatau ai i lea mea,", "Then it shall come to pass,"], ["o le nuu o Aikupito lava;", "that the sword, which ye feared,"], ["o le oge foi ua outou atuatuvale ai,", "shall overtake you there in the land of Egypt,"], ["e maua ai lava outou i lea mea,", "and the famine,"], ["o Aikupito lava;", "whereof ye were afraid, shall follow close after you there in Egypt;"], ["tou te oti foi i lea mea.", "and there ye shall die."]]},
  {num:17,words:[["E faapea tagata uma latou te faasaga e o atu i Aikupito,", "So shall it be with all the men that set their faces to go into Egypt to sojourn there;"], ["e āumau ai i lea mea; e oti i latou i le pelu,", "they shall die by the sword,"], ["ma le oge,", "by the famine,"], ["ma le faamai; e leai so latou e toe,", "and by the pestilence:"], ["pe sao i le malaia ou te faaoo ai i luga ia te i latou.", "and none of them shall remain or escape from the evil that I will bring upon them."]]},
  {num:18,words:[["Auā o loo faapea ona fetalai mai o Ieova o 'au,", "For thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["E pei ona ou liligi ifo lo'u tiga ma lo'u ita i luga o e sa nonofo i Ierusalema,", "As mine anger and my fury hath been poured forth upon the inhabitants of Jerusalem;"], ["e faapea foi ona ou liligi ifo lo'u ita i luga ia te outou,", "so shall my fury be poured forth upon you,"], ["pe a o atu outou i Aikupito;", "when ye shall enter into Egypt:"], ["e fai foi outou ma faafanoga,", "and ye shall be an execration,"], ["ma mea e ofo ai,", "and an astonishment,"], ["e fai a'i foi fetuu,", "and a curse,"], ["ma luma;", "and a reproach;"], ["e le toe iloa foi e outou lenei mea.", "and ye shall see this place no more."]]},
  {num:19,words:[["Ua fetalai mai Ieova ia te outou o e totoe o Iuta,", "The LORD hath said concerning you,"], ["Aua tou te o i Aikupito;", "O ye remnant of Judah;"], ["ia outou iloa lava,", "Go ye not into Egypt:"], ["ua ou matuā fai atu ia te outou i le aso nei.", "know certainly that I have admonished you this day."]]},
  {num:20,words:[["Auā ua sese outou tou te tigaina ai,", "For ye dissembled in your hearts,"], ["ina ua outou auina atu o a'u ia Ieova lo outou Atua,", "when ye sent me unto the LORD your God,"], ["ua faapea mai,", "saying,"], ["Ina tatalo ia mo i matou ia Ieova lo tatou Atua;", "Pray for us unto the LORD our God;"], ["e pei o mea uma foi e fetalai mai ai Ieova lo tatou Atua,", "and according unto all that the LORD our God shall say,"], ["ia faapea ona e ta'u mai ai ia te i matou,", "so declare unto us,"], ["ona matou faia lea.", "and we will do it."]]},
  {num:21,words:[["Ua ou ta'u atu ai foi ia te outou i le aso nei;", "And now I have this day declared it to you;"], ["a e peitai ua outou le faalogo i le siufofoga o Ieova lo outou Atua,", "but ye have not obeyed the voice of the LORD your God,"], ["i se mea e tasi na auina mai ai a'u e ia ia te outou.", "nor any thing for the which he hath sent me unto you."]]},
  {num:22,words:[["O lenei, ia outou iloa lava,", "Now therefore know certainly that ye shall die by the sword,"], ["e oti outou i le pelu, ma le oge,", "by the famine,"], ["ma le faamai,", "and by the pestilence,"], ["i le mea tou te fia o atu i ai, e āumau ai.", "in the place whither ye desire to go and to sojourn."]]},
];
renderVerseSet(jer_ch_42_Verses, 'jer-ch42-verses');

var jer_ch_43_Verses = [
  {num:1,words:[["Ua uma ona tautala atu o Ieremia i le nuu uma i upu uma a Ieova lo latou Atua,", "And it came to pass,"], ["na auina mai ai o ia e Ieova lo latou Atua ia te i latou,", "that when Jeremiah had made an end of speaking unto all the people all the words of the LORD their God, for which the LORD their God had sent him to them,"], ["o ia upu uma lava,", "even all these words,"]]},
  {num:2,words:[["ona fai mai ai lea o Asaraia le atalii o Hosaia,", "Then spake Azariah the son of Hoshaiah,"], ["ma Ioanana le atalii o Karea,", "and Johanan the son of Kareah,"], ["ma tagata faamaualuluga uma,", "and all the proud men,"], ["ua faapea mai ia Ieremia, O le pepelo ua e fai mai ai;", "saying unto Jeremiah,"], ["e lei auina mai oe e Ieova lo tatou Atua,", "Thou speakest falsely:"], ["ia faapea mai,", "the LORD our God hath not sent thee to say,"], ["Aua tou te o atu i Aikupito e āumau ai;", "Go not into Egypt to sojourn there:"]]},
  {num:3,words:[["a o Paruka le atalii o Neria,", "But Baruch the son of Neriah setteth thee on against us,"], ["ua ia faaosoina oe ia te i matou,", "for to deliver us into the hand of the Chaldeans,"], ["ina ia tuuina atu i matou i lima o Kaletaia, e fasioti i matou,", "that they might put us to death,"], ["ma tāfea i matou i Papelonia.", "and carry us away captives into Babylon."]]},
  {num:4,words:[["O lenei,", "So Johanan the son of Kareah,"], ["ua le faalogo Ioanana le atalii o Karea,", "and all the captains of the forces,"], ["ma alii uma na ave 'au, ma le nuu uma,", "and all the people,"], ["i le siufofoga o Ieova,", "obeyed not the voice of the LORD,"], ["ia latou nonofo i le nuu o Iuta;", "to dwell in the land of Judah."]]},
  {num:5,words:[["a o Ioanana le atalii o Karea,", "But Johanan the son of Kareah,"], ["ma alii uma na ave 'au,", "and all the captains of the forces,"], ["ua latou ave i e na totoe uma o Iuta,", "took all the remnant of Judah, that were returned from all nations,"], ["o e na foi mai ai nuu uma na tulia ai i latou,", "whither they had been driven,"], ["e nonofo i le nuu o Iuta;", "to dwell in the land of Judah;"]]},
  {num:6,words:[["o tane,", "Even men,"], ["ma fafine,", "and women,"], ["ma tama iti,", "and children,"], ["ma afafine o le tupu, ma tagata uma na tuua e Nepusatana le pule i le 'au e faafeao ia Ketalia le atalii o Aikamo,", "and the king's daughters,"], ["le atalii o Safana,", "and every person that Nebuzar-adan the captain of the guard had left with Gedaliah the son of Ahikam the son of Shaphan,"], ["atoa ma Ieremia le perofeta,", "and Jeremiah the prophet,"], ["ma Paruka le atalii o Neria.", "and Baruch the son of Neriah."]]},
  {num:7,words:[["Ona latou o atu ai lea i le nuu o Aikupito;", "So they came into the land of Egypt:"], ["auā na latou le faalogo i le siufofoga o Ieova;", "for they obeyed not the voice of the LORD:"], ["ua oo atu lava i latou i Tapenesa.", "thus came they even to Tahpanhes."]]},
  {num:8,words:[["Ona oo mai ai lea o le afioga a Ieova ia Ieremia i Tapenesa,", "Then came the word of the LORD unto Jeremiah in Tahpanhes,"], ["ua faapea mai,", "saying,"]]},
  {num:9,words:[["Ina ave ia i ou lima ni maa tetele,", "Take great stones in thine hand,"], ["ma tanu ai i le paluga panisina i le mea e tunu ai maaomea,", "and hide them in the clay in the brickkiln,"], ["o loo i ai i le mea e ui ai i le fale o Farao i Tapenesa,", "which is at the entry of Pharaoh's house in Tahpanhes,"], ["i luma o tagata o Iuta;", "in the sight of the men of Judah;"]]},
  {num:10,words:[["ia e fai atu foi ia te i latou,", "And say unto them,"], ["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Faauta,", "Behold, I will send and take Nebuchadrezzar the king of Babylon,"], ["ou te auina atu e aami la'u auauna o Nepukanesa le tupu o Papelonia,", "my servant,"], ["ma ou tuuina lona nofoālii i luga o ia maa ua ou tanua;", "and will set his throne upon these stones that I have hid;"], ["na te fofola foi lona ie matagofie i o latou luga.", "and he shall spread his royal pavilion over them."]]},
  {num:11,words:[["E sau foi o ia, na te fasia le nuu o Aikupito;", "And when he cometh,"], ["na te tuuina atu foi o e ua tofia ia oti,", "he shall smite the land of Egypt,"], ["i le oti, ma e ua tofia i le tafeaga,", "and deliver such as are for death to death;"], ["ia tāfea,", "and such as are for captivity to captivity;"], ["ma e ua tofia i le pelu, ia oti i le pelu.", "and such as are for the sword to the sword."]]},
  {num:12,words:[["Ou te tŭtŭ foi le afi i fale o atua o Aikupito;", "And I will kindle a fire in the houses of the gods of Egypt;"], ["na te susunuina foi i latou,", "and he shall burn them,"], ["ma avea i latou o tagata o taua;", "and carry them away captives:"], ["na te taaia foi le nuu o Aikupito,", "and he shall array himself with the land of Egypt,"], ["e pei ona taaia e le leoleo mamoe lona ofu;", "as a shepherd putteth on his garment;"], ["e alu ese foi o ia i lea mea ma le filemu.", "and he shall go forth from thence in peace."]]},
  {num:13,words:[["Na te tu'ininiia foi tupua o le fale o le la,", "He shall break also the images of Beth-shemesh,"], ["o loo i ai i le nuu o Aikupito; o fale foi o atua o Aikupito,", "that is in the land of Egypt;"], ["na te susunuina i le afi.", "and the houses of the gods of the Egyptians shall he burn with fire."]]},
];
renderVerseSet(jer_ch_43_Verses, 'jer-ch43-verses');

var jer_ch_44_Verses = [
  {num:1,words:[["O le upu na oo mai ia Ieremia ia Iuta uma sa nonofo i le nuu o Aikupito,", "The word that came to Jeremiah concerning all the Jews which dwell in the land of Egypt,"], ["sa nonofo i Mekatala,", "which dwell at Migdol,"], ["ma Tapenesa,", "and at Tahpanhes,"], ["ma Nafi,", "and at Noph,"], ["ma le nuu o Patoro,", "and in the country of Pathros,"], ["ua faapea mai,", "saying,"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Ua outou vaaia le malaia uma na ou faaoo i luga o Ierusalema,", "Ye have seen all the evil that I have brought upon Jerusalem,"], ["ma luga o aai uma o Iuta;", "and upon all the cities of Judah; and,"], ["faauta foi,", "behold,"], ["ua faatafunaina i le aso nei,", "this day they are a desolation,"], ["e leai foi se tagata ua nofo ai;", "and no man dwelleth therein,"]]},
  {num:3,words:[["ona o a latou amio leaga na latou faia,", "Because of their wickedness which they have committed to provoke me to anger,"], ["e faaonoono mai ai ia te au,", "in that they went to burn incense,"], ["ina ua latou ō e faamu mea manogi e auauna ai i atua ese,", "and to serve other gods,"], ["o e na latou le iloa,", "whom they knew not,"], ["o i latou,", "neither they,"], ["po o outou,", "ye,"], ["po o outou tamā.", "nor your fathers."]]},
  {num:4,words:[["Na a'u aauina atu foi ia te outou a'u auauna uma o perofeta,", "Howbeit I sent unto you all my servants the prophets,"], ["na ou ala aauina atu i latou ,", "rising early and sending them,"], ["ua faapea atu,", "saying,"], ["Aua lava ne'i outou faia lena mea inosia,", "Oh,"], ["o le mea lava ou te 'ino'ino i ai.", "do not this abominable thing that I hate."]]},
  {num:5,words:[["A e lei faalogo mai i latou,", "But they hearkened not,"], ["ma ua le uai mai o latou taliga, ina ia liliu mai i a latou amio leaga,", "nor inclined their ear to turn from their wickedness,"], ["aua le faamu mea manogi i atua ese.", "to burn no incense unto other gods."]]},
  {num:6,words:[["O lea ua liligiina ifo ai lo'u ita ma lo'u tiga, ma ua mu ai i aai o Iuta,", "Wherefore my fury and mine anger was poured forth,"], ["ma ala o Ierusalema;", "and was kindled in the cities of Judah and in the streets of Jerusalem;"], ["ua faatafunaina foi ia,", "and they are wasted and desolate,"], ["ua tuufua, e pei ona fai i le aso nei.", "as at this day."]]},
  {num:7,words:[["O lenei,", "Therefore now thus saith the LORD,"], ["o loo faapea ona fetalai mai o Ieova,", "the God of hosts,"], ["le Atua o 'au,", "the God of Israel;"], ["le Atua o Isaraelu,", "Wherefore commit ye this great evil against your souls,"], ["Se a le mea ua outou fai ai le leaga tele e malaia ai outou, ia faaumatia ia te outou le tane ma le fafine,", "to cut off from you man and woman,"], ["o le tama itiiti ma le tama meamea,", "child and suckling,"], ["ai totonu o Iuta,", "out of Judah,"], ["ina ia le faatotoeina ni o outou;", "to leave you none to remain;"]]},
  {num:8,words:[["ina ua outou faaonoono mai ia te au i mea ua faia e o outou lima,", "In that ye provoke me unto wrath with the works of your hands,"], ["ua faamu mea manogi i atua ese i le nuu o Aikupito,", "burning incense unto other gods in the land of Egypt,"], ["ua outou o i ai e āumau ai,", "whither ye be gone to dwell,"], ["ina ia faaumatia outou,", "that ye might cut yourselves off,"], ["ma ia fai outou ma faafanoga e fai a'i luma foi i nuu uma o le lalolagi?", "and that ye might be a curse and a reproach among all the nations of the earth?"]]},
  {num:9,words:[["Po ua galo ea ia te outou amio leaga a o outou tamā,", "Have ye forgotten the wickedness of your fathers,"], ["ma amio leaga a tupu o Iuta,", "and the wickedness of the kings of Judah,"], ["ma amio leaga a latou avā,", "and the wickedness of their wives,"], ["ma o outou amio leaga,", "and your own wickedness,"], ["ma amio leaga a outou avā,", "and the wickedness of your wives,"], ["na latou faia i le nuu o Iuta,", "which they have committed in the land of Judah,"], ["ma ala o Ierusalema?", "and in the streets of Jerusalem?"]]},
  {num:10,words:[["E le tigaina o latou loto e oo i le aso nei,", "They are not humbled even unto this day,"], ["ma latou le fefefe,", "neither have they feared,"], ["ma latou le savavali i la'u tulafono, ma a'u sauniga,", "nor walked in my law,"], ["na ou tuuina atu i o outou luma,", "nor in my statutes,"], ["ma luma o outou tamā.", "that I set before you and before your fathers."]]},
  {num:11,words:[["O le mea lea o loo faapea ona fetalai mai ai o Ieova o 'au,", "Therefore thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Faauta,", "Behold,"], ["ou te faasaga o'u mata ia te outou e malaia ai outou,", "I will set my face against you for evil,"], ["ina ia faaumatia Iuta uma.", "and to cut off all Judah."]]},
  {num:12,words:[["Ou te ave foi i e o totoe o Iuta,", "And I will take the remnant of Judah,"], ["o e ua faasaga o latou mata e o atu i le nuu o Aikupito e āumau ai,", "that have set their faces to go into the land of Egypt to sojourn there,"], ["e faaumatia foi i latou uma i le nuu o Aikupito;", "and they shall all be consumed,"], ["e oti i latou i le pelu ma le oge,", "and fall in the land of Egypt;"], ["e faaumatia i latou,", "they shall even be consumed by the sword and by the famine:"], ["o tagatānuu atoa ma alii;", "they shall die, from the least even unto the greatest,"], ["e oti i latou i le pelu ma le oge;", "by the sword and by the famine:"], ["e fai foi i latou ma faafanoga,", "and they shall be an execration,"], ["ma mea e ofo ai,", "and an astonishment,"], ["ma mea e fetuu ai,", "and a curse,"], ["ma fai a'i luma.", "and a reproach."]]},
  {num:13,words:[["Auā ou te taui atu i e o nonofo i le nuu o Aikupito,", "For I will punish them that dwell in the land of Egypt,"], ["e pei ona ou taui atu i Ierusalema i le pelu,", "as I have punished Jerusalem,"], ["ma le oge,", "by the sword, by the famine,"], ["ma le faamai;", "and by the pestilence:"]]},
  {num:14,words:[["o e na totoe o Iuta,", "So that none of the remnant of Judah,"], ["na o mai e āumau i lenei mea i le nuu o Aikupito,", "which are gone into the land of Egypt to sojourn there,"], ["e leai se tasi e sao pe totoe, e toe foi atu i le nuu o Iuta,", "shall escape or remain,"], ["o le mea ua latou mananao tele ai e toe foi atu e nonofo ai;", "that they should return into the land of Judah,"], ["auā e leai ni e foi atu,", "to the which they have a desire to return to dwell there:"], ["na o e sosola lava.", "for none shall return but such as shall escape."]]},
  {num:15,words:[["Ona tali mai ai lea ia Ieremia o tagata uma o e na iloa ua faamuina mea manogi e a latou avā i atua ese,", "Then all the men which knew that their wives had burned incense unto other gods,"], ["ma fafine uma na tutū mai,", "and all the women that stood by,"], ["o le faapotopotoga tele,", "a great multitude, even all the people that dwelt in the land of Egypt,"], ["o le nuu uma foi sa nonofo i le nuu o Aikupito,", "in Pathros,"], ["i Patoro,", "answered Jeremiah,"], ["ua faapea mai,", "saying,"]]},
  {num:16,words:[["O le upu ua e fai mai ai ia te i matou i le suafa o Ieova,", "As for the word that thou hast spoken unto us in the name of the LORD,"], ["matou te le faalogo ai lava ia te oe;", "we will not hearken unto thee."]]},
  {num:17,words:[["a e peitai matou te faia lava mea uma ua matou fai atu ai,", "But we will certainly do whatsoever thing goeth forth out of our own mouth,"], ["e faamu mea manogi i le tupu fafine o le lagi,", "to burn incense unto the queen of heaven,"], ["ma sasaa i ai taulaga i mea e inu,", "and to pour out drink offerings unto her,"], ["e pei ona matou faia,", "as we have done,"], ["o i matou,", "we,"], ["ma o matou tamā,", "and our fathers,"], ["o matou tupu,", "our kings,"], ["ma o matou alii,", "and our princes,"], ["i aai o Iuta,", "in the cities of Judah,"], ["ma ala o Ierusalema;", "and in the streets of Jerusalem:"], ["auā o ona po ia sa maoona ai i matou i mea e 'ai,", "for then had we plenty of victuals,"], ["sa manuia foi,", "and were well,"], ["ma matou le iloa se malaia.", "and saw no evil."]]},
  {num:18,words:[["A e talu ina matou tuua ona faamu o mea manogi i le tupu fafine o le lagi,", "But since we left off to burn incense to the queen of heaven,"], ["ma sasaa atu ia te ia taulaga i mea e inu,", "and to pour out drink offerings unto her,"], ["ua matou matitiva i mea uma,", "we have wanted all things,"], ["ua faaumatia foi i matou i le pelu ma le oge.", "and have been consumed by the sword and by the famine."]]},
  {num:19,words:[["Na matou faamu mea manogi i le tupu fafine o le lagi,", "And when we burned incense to the queen of heaven,"], ["ma matou sasaa ia te ia taulaga i mea e inu,", "and poured out drink offerings unto her,"], ["sa le i ai ea a matou tane ina ua matou faia mo ia ni faapāpā areto e auauna ia te ia,", "did we make her cakes to worship her, and pour out drink offerings unto her,"], ["ma matou sasaa ia te ia taulaga i mea e inu?", "without our men?"]]},
  {num:20,words:[["Ona fai atu ai lea o Ieremia i le nuu uma,", "Then Jeremiah said unto all the people,"], ["o tane,", "to the men,"], ["ma fafine,", "and to the women,"], ["ma le nuu uma e na tali mai ia te ia i lea upu,", "and to all the people which had given him that answer,"], ["ua faapea atu,", "saying,"]]},
  {num:21,words:[["O mea manogi na outou faamuina i aai o Iuta,", "The incense that ye burned in the cities of Judah,"], ["ma ala o Ierusalema,", "and in the streets of Jerusalem, ye,"], ["o outou,", "and your fathers,"], ["ma o outou tamā,", "your kings,"], ["ma o outou tupu,", "and your princes,"], ["ma o outou alii,", "and the people of the land, did not the LORD remember them,"], ["ma tagata o le nuu na le manatua ea e Ieova lea mea? na le mafaufau ea o ia i ai?", "and came it not into his mind?"]]},
  {num:22,words:[["Na le toe lavā onosai Ieova,", "So that the LORD could no longer bear,"], ["ona o le leaga o a outou amioga,", "because of the evil of your doings,"], ["ona o mea inosia na outou faia;", "and because of the abominations which ye have committed;"], ["o le mea lea ua fai ai lo outou nuu ma mea gaogao,", "therefore is your land a desolation,"], ["ma mea e ofo ai,", "and an astonishment,"], ["ma faafanoga,", "and a curse,"], ["e leai sē nofo ai,", "without an inhabitant,"], ["e pei ona fai i le aso nei.", "as at this day."]]},
  {num:23,words:[["Auā ua outou faamu mea manogi,", "Because ye have burned incense,"], ["auā foi ua outou agasala ia Ieova,", "and because ye have sinned against the LORD,"], ["ma ua outou le faalogo i le siufofoga o Ieova,", "and have not obeyed the voice of the LORD,"], ["ma outou le savavali i lana tulafono,", "nor walked in his law,"], ["ma ana sauniga,", "nor in his statutes,"], ["ma ana poloaiga;", "nor in his testimonies;"], ["o mea ia ua oo ai lenei malaia ia te outou,", "therefore this evil is happened unto you,"], ["e pei ona fai i le aso nei.", "as at this day."]]},
  {num:24,words:[["Ua fai atu foi Ieremia i le nuu uma,", "Moreover Jeremiah said unto all the people,"], ["ma fafine uma,", "and to all the women,"], ["Ina faalogologo mai ia i le afioga a Ieova, o outou Iuta uma,", "Hear the word of the LORD,"], ["o i le nuu o Aikupito;", "all Judah that are in the land of Egypt:"]]},
  {num:25,words:[["o loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["ua faapea mai,", "saying;"], ["O outou ma a outou avā,", "Ye and your wives have both spoken with your mouths,"], ["ua outou tautala mai i o outou gutu,", "and fulfilled with your hand,"], ["ua faataunuuina foi i o outou lima, ua faapea mai,", "saying,"], ["Matou te faia lava a matou tautoga ua matou tauto ai,", "We will surely perform our vows that we have vowed,"], ["e faamu mea manogi i le tupu fafine o le lagi,", "to burn incense to the queen of heaven,"], ["ma sasaa ia te ia taulaga i mea e inu;", "and to pour out drink offerings unto her:"], ["e faatumauina lava e outou a outou tautoga,", "ye will surely accomplish your vows,"], ["e matuā faia foi e outou a outou tautoga.", "and surely perform your vows."]]},
  {num:26,words:[["O le mea lea ia faalogologo mai i le afioga a Ieova,", "Therefore hear ye the word of the LORD,"], ["o outou Iuta uma o e o nonofo i le nuu o Aikupito;", "all Judah that dwell in the land of Egypt;"], ["Faauta,", "Behold,"], ["ua ou tauto a'u i lo'u igoa tele,", "I have sworn by my great name,"], ["o loo fetalai mai ai Ieova,", "saith the LORD,"], ["e le toe ta'ua lo'u igoa i le gutu o se tasi tagata o Iuta o loo i ai i le nuu o Aikupito uma,", "that my name shall no more be named in the mouth of any man of Judah in all the land of Egypt,"], ["e faapea,", "saying,"], ["O loo soifua le Alii o Ieova.", "The Lord GOD liveth."]]},
  {num:27,words:[["Faauta,", "Behold,"], ["ou te mataala ia malaia i latou,", "I will watch over them for evil,"], ["a e le ina ia manuia; e faaumatia tagata uma o Iuta o e o i le nuu o Aikupito i le pelu,", "and not for good:"], ["ma le faamai,", "and all the men of Judah that are in the land of Egypt shall be consumed by the sword and by the famine,"], ["seia faaumatia lava i latou.", "until there be an end of them."]]},
  {num:28,words:[["A o e sao i le pelu latou te foi atu nai le nuu o Aikupito i le nuu o Iuta,", "Yet a small number that escape the sword shall return out of the land of Egypt into the land of Judah,"], ["e toaitiiti i latou;", "and all the remnant of Judah,"], ["e iloa foi e Iuta uma o e totoe, e ua o atu i le nuu o Aikupito e āumau ai,", "that are gone into the land of Egypt to sojourn there,"], ["po o upu a ai e taunuu,", "shall know whose words shall stand,"], ["po o a'u,", "mine,"], ["po o a latou.", "or their's."]]},
  {num:29,words:[["O lenei foi le faailoga ia te outou,", "And this shall be a sign unto you,"], ["ua fetalai mai ai Ieova,", "saith the LORD,"], ["e tauia outou e a'u i lenei mea,", "that I will punish you in this place,"], ["ina ia outou iloa e matuā taunuu a'u upu ia te outou ia malaia ai outou .", "that ye may know that my words shall surely stand against you for evil:"]]},
  {num:30,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Faauta,", "Behold,"], ["ou te tuuina atu Farao Hofero le tupu o Aikupito i lima o e ua ita mai ia te ia,", "I will give Pharaoh-hophra king of Egypt into the hand of his enemies,"], ["ma lima o e saili e fasioti ia te ia;", "and into the hand of them that seek his life;"], ["e pei ona ou tuuina atu o Setekaia le tupu o Iuta i le lima o Nepukanesa le tupu o Papelonia,", "as I gave Zedekiah king of Judah into the hand of Nebuchadrezzar king of Babylon,"], ["o le na ita mai ia te ia,", "his enemy,"], ["ma na saili e fasioti ia te ia.", "and that sought his life."]]},
];
renderVerseSet(jer_ch_44_Verses, 'jer-ch44-verses');

var jer_ch_45_Verses = [
  {num:1,words:[["O le upu na fai atu ai Ieremia le perofeta ia Paruka le atalii o Neria ina o tusia e ia ia upu mai le gutu o Ieremia i le tusi,", "The word that Jeremiah the prophet spake unto Baruch the son of Neriah,"], ["i le fa o tausaga o Ioakima le atalii o Iosia le tupu o Iuta,", "when he had written these words in a book at the mouth of Jeremiah, in the fourth year of Jehoiakim the son of Josiah king of Judah,"], ["ua faapea atu,", "saying,"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova le Atua o Isaraelu ia te oe,", "Thus saith the LORD, the God of Israel,"], ["Paruka;", "unto thee, O Baruch;"]]},
  {num:3,words:[["na e faapea,", "Thou didst say,"], ["Oi talofa ia te au! auā ua faaopoopoina e Ieova le faanoanoa i lo'u tiga;", "Woe is me now! for the LORD hath added grief to my sorrow;"], ["ua ou lailoa i lo'u mapuitiga,", "I fainted in my sighing,"], ["ou te le maua foi sina mapu.", "and I find no rest."]]},
  {num:4,words:[["Ia faapea ona e fai atu ia te ia,", "Thus shalt thou say unto him,"], ["O loo faapea ona fetalai mai o Ieova, Faauta,", "The LORD saith thus;"], ["o le mea na ou atiina ae,", "Behold,"], ["ou te lepetia,", "that which I have built will I break down,"], ["o le mea foi na ou totōina, ou te liaiina,", "and that which I have planted I will pluck up,"], ["o lenei nuu uma lava lea.", "even this whole land."]]},
  {num:5,words:[["O oe foi,", "And seekest thou great things for thyself? seek them not:"], ["ua e saili ea mo oe mea tetele? Aua e te sailia;", "for,"], ["auā faauta,", "behold,"], ["ou te faaoo le malaia i luga o tagata uma,", "I will bring evil upon all flesh,"], ["ua fetalai mai ai Ieova;", "saith the LORD:"], ["a ou te avatu ia te oe lou ola e fai ma vete i mea uma e te alu i ai.", "but thy life will I give unto thee for a prey in all places whither thou goest."]]},
];
renderVerseSet(jer_ch_45_Verses, 'jer-ch45-verses');

var jer_ch_46_Verses = [
  {num:1,words:[["O le afioga a Ieova na oo mai ia Ieremia le perofeta i mea a oo i nuu ese,", "The word of the LORD which came to Jeremiah the prophet against the Gentiles;"]]},
  {num:2,words:[["o Aikupito ma le itu taua a Farao Neko le tupu o Aikupito,", "Against Egypt,"], ["sa latalata ane i le vaitafe o Eufirate i Karekimisa,", "against the army of Pharaoh-necho king of Egypt, which was by the river Euphrates in Carchemish,"], ["o e na fasia e Nepukanesa le tupu o Papelonia i le fa o tausaga o Ioakima le atalii o Iosia le tupu o Iuta.", "which Nebuchadrezzar king of Babylon smote in the fourth year of Jehoiakim the son of Josiah king of Judah."]]},
  {num:3,words:[["Ina sauni ia e outou le talita ma le talipupuni,", "Order ye the buckler and shield,"], ["ma faalatalata atu i le taua.", "and draw near to battle."]]},
  {num:4,words:[["Ina nonoa ia solofanua i kariota;", "Harness the horses;"], ["ma ia tietie outou i solofanua,", "and get up,"], ["ma tutū atu ma o outou puloutau;", "ye horsemen, and stand forth with your helmets;"], ["ina faapupula ia o tao,", "furbish the spears,"], ["ma ia oofu i ofutau uamea.", "and put on the brigandines."]]},
  {num:5,words:[["O le a ea le mea ua ou iloa atu ai i latou ua matautuia? Ua liutuaina,", "Wherefore have I seen them dismayed and turned away back? and their mighty ones are beaten down,"], ["ua fasia foi o latou toa,", "and are fled apace,"], ["ma ua alu lo latou tuli, ua latou le tepa i tua;", "and look not back:"], ["o i ai le mata'u i itu uma,", "for fear was round about,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:6,words:[["E le sola le tagata tele vave,", "Let not the swift flee away,"], ["e le sao foi le toa;", "nor the mighty man escape;"], ["e tausuai i latou, ma latou pauu i le itu i matu,", "they shall stumble,"], ["e lata ane i le vaitafe o Eufirate.", "and fall toward the north by the river Euphrates."]]},
  {num:7,words:[["O ai ea lenei ua alu ae e pei ona oso o se vaitafe,", "Who is this that cometh up as a flood,"], ["ua fāti tetele mai lona vai e pei o tafega?", "whose waters are moved as the rivers?"]]},
  {num:8,words:[["O loo alu ae Aikupito e pei ona oso o se vaitafe,", "Egypt riseth up like a flood,"], ["ua fāti tetele mai lona vai e pei o tafega;", "and his waters are moved like the rivers;"], ["ua faapea foi o ia, Ou te alu ae,", "and he saith,"], ["ou te ufitia le lalolagi;", "I will go up,"], ["ou te faaumatia le aai,", "and will cover the earth;"], ["ma e o nonofo ai.", "I will destroy the city and the inhabitants thereof."]]},
  {num:9,words:[["Ina tietie ia outou i solofanua;", "Come up,"], ["ma ia matuā feasofai kariota;", "ye horses;"], ["ina o atu ia o toa;", "and rage,"], ["o tagata Aitiope,", "ye chariots;"], ["ma Futu,", "and let the mighty men come forth; the Ethiopians and the Libyans,"], ["o e masani ma le talita;", "that handle the shield;"], ["ma Luti,", "and the Lydians,"], ["o e masani ona lolo'u o le aufana.", "that handle and bend the bow."]]},
  {num:10,words:[["Auā o le aso lenei o le Alii o Ieova o 'au,", "For this is the day of the Lord GOD of hosts,"], ["o le aso o le taui ma sui,", "a day of vengeance,"], ["e taui atu ai i e ua ita ia te ia; e 'ai foi le pelu,", "that he may avenge him of his adversaries:"], ["ma ma'ona,", "and the sword shall devour,"], ["ma onā i o latou toto;", "and it shall be satiate and made drunk with their blood:"], ["auāo loo i le Alii o Ieova o 'au ona fai o le taulaga i le nuu i le itu i matu e lata ane i le vaitafe o Eufirate.", "for the Lord GOD of hosts hath a sacrifice in the north country by the river Euphrates."]]},
  {num:11,words:[["Le taupou e,", "Go up into Gilead,"], ["le tama teine a Aikupito,", "and take balm,"], ["ina alu ae ia oe i Kiliata,", "O virgin,"], ["ma au mai pulu pasama;", "the daughter of Egypt:"], ["ua e faateleina vailaau a e fai fua;", "in vain shalt thou use many medicines;"], ["e leai se togafiti e malolo ai oe.", "for thou shalt not be cured."]]},
  {num:12,words:[["Ua lagona e nuu ese lou faamaina,", "The nations have heard of thy shame,"], ["ua tumu foi le lalolagi i lau alaga;", "and thy cry hath filled the land:"], ["auā ua tausuai le toa i le toa,", "for the mighty man hath stumbled against the mighty,"], ["ua pauu faatasi i laua.", "and they are fallen both together."]]},
  {num:13,words:[["O le afioga na fetalai mai ai Ieova ia Ieremia le perofeta,", "The word that the LORD spake to Jeremiah the prophet,"], ["ina ua sau o Nepukanesa le tupu o Papelonia e fasi le nuu o Aikupito.", "how Nebuchadrezzar king of Babylon should come and smite the land of Egypt."]]},
  {num:14,words:[["Ia outou ta'u atu i Aikupito,", "Declare ye in Egypt,"], ["ma faailoa atu i Mekatala,", "and publish in Migdol,"], ["ma faailoa atu i Nafi,", "and publish in Noph and in Tahpanhes:"], ["ma Tapanesa; ia outou faapea atu,", "say ye,"], ["Ina tu mai ia,", "Stand fast,"], ["ma ia e sauni;", "and prepare thee;"], ["auā e 'ai e le pelu i ou itu uma.", "for the sword shall devour round about thee."]]},
  {num:15,words:[["O le a ea le mea ua taatitia ai e ua malolosi ua ia te oe? e lei tutū i latou,", "Why are thy valiant men swept away? they stood not,"], ["auā ua tuleia i latou e Ieova.", "because the LORD did drive them."]]},
  {num:16,words:[["Ua faatoateleina e ia o e ua tausuai,", "He made many to fall,"], ["ua pauu lava i latou le tasi i luga o le tasi;", "yea,"], ["ona latou faapea ai lea,", "one fell upon another:"], ["Ina tulai ia,", "and they said, Arise,"], ["se'i tatou foi atu i lo tatou nuu,", "and let us go again to our own people,"], ["ma le laueleele na fananau ai i tatou,", "and to the land of our nativity,"], ["ona o le pelu saua.", "from the oppressing sword."]]},
  {num:17,words:[["Na latou alalaga i lea mea,", "They did cry there,"], ["O Farao le tupu o Aikupito, ua malaia,", "Pharaoh king of Egypt is but a noise;"], ["ua mavae ona po na atofaina.", "he hath passed the time appointed."]]},
  {num:18,words:[["O loo fetalai mai le Tupu,", "As I live,"], ["o Ieova o 'au lona suafa,", "saith the King,"], ["Ou te ola a'u,", "whose name is the LORD of hosts,"], ["e sau ia,", "Surely as Tabor is among the mountains,"], ["e pei o Tapora i le atu mauga,", "and as Carmel by the sea,"], ["ma Karamelu i tai.", "so shall he come."]]},
  {num:19,words:[["O oe na le tama fafine ua nofo i Aikupito, ina sauni ia o mea e alu ma oe i le tafeaga;", "O thou daughter dwelling in Egypt,"], ["auā e gaogao Nafi,", "furnish thyself to go into captivity:"], ["ma faatafunaina, e leai se nofo ai.", "for Noph shall be waste and desolate without an inhabitant."]]},
  {num:20,words:[["O Aikupito o le povi fafine e matuā tino lelei,", "Egypt is like a very fair heifer, but destruction cometh;"], ["a e oo mai lava le malaia mai le itu i matu.", "it cometh out of the north."]]},
  {num:21,words:[["O ona tagata foi na faaoloatauaina,", "Also her hired men are in the midst of her like fatted bullocks;"], ["o loo i totonu ia te ia e pei ni povi ai le fale povi;", "for they also are turned back,"], ["a ua liutuaina lava i latou, ua latou sosola faatasi,", "and are fled away together:"], ["ua latou le tutū;", "they did not stand,"], ["auā ua oo mai ia te i latou le aso o lo latou malaia,", "because the day of their calamity was come upon them,"], ["o ona po e asia mai ai i latou.", "and the time of their visitation."]]},
  {num:22,words:[["E alu atu lona leo e pei se gata;", "The voice thereof shall go like a serpent;"], ["auā latou te o mai ma 'au,", "for they shall march with an army,"], ["ma latou o mai ia te ia ma mătau,", "and come against her with axes,"], ["e pei o tagata ta laau.", "as hewers of wood."]]},
  {num:23,words:[["Latou te ta lona vao,", "They shall cut down her forest,"], ["ua fetalai mai ai Ieova,", "saith the LORD,"], ["auā e le masuesueina;", "though it cannot be searched;"], ["auā e sili ona tele i latou i sē akerise,", "because they are more than the grasshoppers,"], ["e le mafaitaulia foi i latou.", "and are innumerable."]]},
  {num:24,words:[["Ua faamaina le tama fafine a Aikupito;", "The daughter of Egypt shall be confounded;"], ["e tuuina atu foi o ia i lima o tagata mai le itu i matu.", "she shall be delivered into the hand of the people of the north."]]},
  {num:25,words:[["O loo fetalai mai Ieova o 'au,", "The LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["Faauta,", "saith;"], ["ou te taui atu ia Amoni i No,", "Behold,"], ["ma Farao,", "I will punish the multitude of No, and Pharaoh,"], ["ma Aikupito,", "and Egypt,"], ["ma ona atua,", "with their gods,"], ["ma ona tupu;", "and their kings;"], ["o Farao lava,", "even Pharaoh,"], ["ma i latou o e faatuatua ia te ia;", "and all them that trust in him:"]]},
  {num:26,words:[["ou te tuuina atu foi i latou i lima o e saili e fasioti ia te i latou,", "And I will deliver them into the hand of those that seek their lives,"], ["ma le lima o Nepukanesa le tupu o Papelonia,", "and into the hand of Nebuchadrezzar king of Babylon,"], ["ma lima o ana auauna;", "and into the hand of his servants:"], ["e mulimuli ane ona toe āina ai lea,", "and afterward it shall be inhabited,"], ["e pei o ona po anamua,", "as in the days of old,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:27,words:[["A o oe;", "But fear not thou,"], ["Iakopo e,", "O my servant Jacob,"], ["la'u auauna,", "and be not dismayed,"], ["aua e te fefe;", "O Israel:"], ["aua foi e te mata'u o oe Isaraelu e,", "for,"], ["auā faauta,", "behold,"], ["ou te faaola ia te oe ai le nuu mamao,", "I will save thee from afar off,"], ["ma lau fanau ai le nuu ua tāfea ai i latou;", "and thy seed from the land of their captivity;"], ["e foi mai lava Iakopo,", "and Jacob shall return,"], ["e toto'a foi o ia ma nofo filemu,", "and be in rest and at ease,"], ["e leai foi se tasi e faamatau ia te ia .", "and none shall make him afraid."]]},
  {num:28,words:[["O oe Iakopo e,", "Fear thou not,"], ["la'u auauna,", "O Jacob my servant,"], ["ua fetalai mai Ieova,", "saith the LORD:"], ["aua e te fefe;", "for I am with thee;"], ["auā ou te ia te oe; e ui lava ina ou matuā faaumatia nuu uma ua ou tulia ai oe,", "for I will make a full end of all the nations whither I have driven thee:"], ["a e ou te le matuā faaumatia oe;", "but I will not make a full end of thee,"], ["ou te aoai faatatau foi ia te oe,", "but correct thee in measure;"], ["a e ou te le matuā faasaoina oe.", "yet will I not leave thee wholly unpunished."]]},
];
renderVerseSet(jer_ch_46_Verses, 'jer-ch46-verses');

var jer_ch_47_Verses = [
  {num:1,words:[["O le afioga a Ieova ua oo mai ia Ieremia le perofeta ia Filisitia,", "The word of the LORD that came to Jeremiah the prophet against the Philistines,"], ["a o le fasia Kasa e Farao.", "before that Pharaoh smote Gaza."]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Faauta,", "Behold,"], ["e oso mai le vai mai le itu i matu,", "waters rise up out of the north,"], ["e fai foi ma vaitafe e lofia ai;", "and shall be an overflowing flood,"], ["e lofia ai le nuu,", "and shall overflow the land,"], ["ma mea ua tumu ai,", "and all that is therein;"], ["o le aai foi,", "the city,"], ["ma e o nonofo ai;", "and them that dwell therein:"], ["ona alalaga ai lea o tagata,", "then the men shall cry,"], ["ma uio atoa uma o e nonofo i le nuu.", "and all the inhabitants of the land shall howl."]]},
  {num:3,words:[["Ona o le pāō o le pāūū o atigivae o ona solofanua malolosi,", "At the noise of the stamping of the hoofs of his strong horses,"], ["ma le osooso o ona kariota,", "at the rushing of his chariots,"], ["ma le taalili o ana mea taavavale, e le tetepa i tua o tamā i a latou fanau,", "and at the rumbling of his wheels,"], ["auā e vaivai o latou lima;", "the fathers shall not look back to their children for feebleness of hands;"]]},
  {num:4,words:[["ona o le aso o le a oo mai e faatafunaina ai Filisitia uma,", "Because of the day that cometh to spoil all the Philistines,"], ["e vavaeeseina fesoasoani uma ua totoe i Turo ma Saitonu;", "and to cut off from Tyrus and Zidon every helper that remaineth:"], ["auā e faatafunaina e Ieova o Filisitia,", "for the LORD will spoil the Philistines,"], ["o e ua totoe o le nuu tuloto o Kafetori.", "the remnant of the country of Caphtor."]]},
  {num:5,words:[["Ua selemamāina ulu o e i Kasa;", "Baldness is come upon Gaza;"], ["ua faaumatia Asekelona ma e o totoe i lo latou vanu;", "Ashkelon is cut off with the remnant of their valley:"], ["e te selei ea ia te oe seia afea?", "how long wilt thou cut thyself?"]]},
  {num:6,words:[["Aue! le pelu a Ieova e,", "O thou sword of the LORD,"], ["e te le mapu ea seia afea? ia e foi atu i lou faamoega,", "how long will it be ere thou be quiet? put up thyself into thy scabbard,"], ["ina malolo ia,", "rest,"], ["ma ia e alāla.", "and be still."]]},
  {num:7,words:[["Pe faapefea ona e mapu? auā o Ieova ua ia fai atu i ai e tau ma Asekelona,", "How can it be quiet,"], ["ma nuu tu matafaga,", "seeing the LORD hath given it a charge against Ashkelon,"], ["ua ia totofi i ai i lea mea.", "and against the sea shore? there hath he appointed it."]]},
];
renderVerseSet(jer_ch_47_Verses, 'jer-ch47-verses');

var jer_ch_48_Verses = [
  {num:1,words:[["O loo faapea ona fetalai mai o Ieova o 'au, le Atua o Isaraelu,", "Against Moab thus saith the LORD of hosts,"], ["ia Moapi,", "the God of Israel;"], ["Oi talofa ia Nepo! auā ua faatafunaina ia; ua faamaina Kiriataima,", "Woe unto Nebo! for it is spoiled:"], ["ua aea;", "Kiriathaim is confounded and taken:"], ["ua faamaina Mesekavo, ma ua faamatautia.", "Misgab is confounded and dismayed."]]},
  {num:2,words:[["E le toe viia Hesepona e Moapi, ua fai togafiti i latou e malaia ai o ia;", "There shall be no more praise of Moab:"], ["ua latou faapea ,", "in Heshbon they have devised evil against it;"], ["Ina o mai ia,", "come,"], ["ia tatou faaumatia o ia, ia le toe fai ma nuu;", "and let us cut it off from being a nation. Also thou shalt be cut down,"], ["Matameni e, e fano lava oe;", "O Madmen;"], ["e mulimuli atu le pelu ia te oe.", "the sword shall pursue thee."]]},
  {num:3,words:[["O le leo o le alaga mai Horonaima,", "A voice of crying shall be from Horonaim,"], ["o i ai le faatafunaga ma le malaia tele.", "spoiling and great destruction."]]},
  {num:4,words:[["Ua malaia Moapi;", "Moab is destroyed;"], ["ua pa mai le alaga a ona tama iti.", "her little ones have caused a cry to be heard."]]},
  {num:5,words:[["Auā ua latou o ae lava i le aega o Luita o fetagisi; o le ifo a'i foi mai Horonaima,", "For in the going up of Luhith continual weeping shall go up;"], ["ua lagona ai e ua ita mai le alaga ina ua malaia.", "for in the going down of Horonaim the enemies have heard a cry of destruction."]]},
  {num:6,words:[["Ina sosola ia,", "Flee,"], ["ia sao outou,", "save your lives,"], ["ma ia avea outou e pei o le tula i le vao.", "and be like the heath in the wilderness."]]},
  {num:7,words:[["Ua e faatuatua i mea ua e faia, ma au oloa,", "For because thou hast trusted in thy works and in thy treasures,"], ["o le mea lea e puea ai lava oe;", "thou shalt also be taken:"], ["e alu atu foi Kimosa i le tafeaga, o ana faitaulaga ma ona alii faatasi ma ia.", "and Chemosh shall go forth into captivity with his priests and his princes together."]]},
  {num:8,words:[["E sau foi le na te faatafunaina i aai uma,", "And the spoiler shall come upon every city,"], ["e leai se aai e sao;", "and no city shall escape:"], ["e fano foi le vanu,", "the valley also shall perish,"], ["e faaumatia foi le eleele laugatasi,", "and the plain shall be destroyed,"], ["auā ua fetalai mai ai Ieova.", "as the LORD hath spoken."]]},
  {num:9,words:[["Ia fai ni apaau mo Moapi,", "Give wings unto Moab,"], ["ina ia lele o ia ma alu ese;", "that it may flee and get away:"], ["auā e fai ma faatafunaga ona aai,", "for the cities thereof shall be desolate,"], ["e leai se nofo ai.", "without any to dwell therein."]]},
  {num:10,words:[["Ia faafanoina le na te faia le galuega a Ieova ma le faavaivai,", "Cursed be he that doeth the work of the LORD deceitfully,"], ["ia faafanoina le ua taofia lana pelu ai le toto.", "and cursed be he that keepeth back his sword from blood."]]},
  {num:11,words:[["Ua nofo filemu Moapi talu ina o taulealea o ia,", "Moab hath been at ease from his youth,"], ["ua nofo o ia i luga o lona 'alu,", "and he hath settled on his lees,"], ["e lei fesaaa'iina o ia ai lea ipu i lea ipu,", "and hath not been emptied from vessel to vessel,"], ["e lei alu foi o ia i se tafeaga;", "neither hath he gone into captivity:"], ["o le mea lea ua tumau ai lona nanamu,", "therefore his taste remained in him,"], ["ua le liua lona manogi.", "and his scent is not changed."]]},
  {num:12,words:[["O le mea lea faauta,", "Therefore,"], ["e oo ai i ona po,", "behold, the days come,"], ["ua fetalai mai Ieova,", "saith the LORD,"], ["ou te aauina atu ai ia te ia nisi latou te faataoto ia te ia,", "that I will send unto him wanderers,"], ["ma saa ai ana ipu,", "that shall cause him to wander, and shall empty his vessels,"], ["ma taei i ona fagu.", "and break their bottles."]]},
  {num:13,words:[["E mā foi Moapi ia Kimosa, e pei ona mā o le aiga o Isaraelu ia Peteli,", "And Moab shall be ashamed of Chemosh,"], ["o lo latou faatuatuaga.", "as the house of Israel was ashamed of Beth-el their confidence."]]},
  {num:14,words:[["Pe faapefea ona outou fai mai, O toa i matou,", "How say ye,"], ["o tagata malolosi e tau ai le taua?", "We are mighty and strong men for the war?"]]},
  {num:15,words:[["Ua faatafunaina Moapi,", "Moab is spoiled,"], ["ma ua o ae ona aai;", "and gone up out of her cities,"], ["o ona taulelea foi na filifilia ua o ifo i latou ia fasiotia,", "and his chosen young men are gone down to the slaughter,"], ["o loo fetalai mai ai le Tupu,", "saith the King,"], ["o Ieova o 'au lona suafa.", "whose name is the LORD of hosts."]]},
  {num:16,words:[["O le malaia o Moapi ua latalata ona oo mai,", "The calamity of Moab is near to come,"], ["o le mea foi e leaga ai o ia e vave mai lava lea.", "and his affliction hasteth fast."]]},
  {num:17,words:[["O outou uma o e vagavagai ia te ia,", "All ye that are about him,"], ["ia outou faanoanoa ona o ia;", "bemoan him;"], ["o outou uma foi o e iloa lona igoa,", "and all ye that know his name,"], ["ia outou faapea atu,", "say,"], ["E! ua gausia le tootoo malosi,", "How is the strong staff broken,"], ["o le laau matagofie.", "and the beautiful rod!"]]},
  {num:18,words:[["O oe na le tama fafine ua nofo i Tipona,", "Thou daughter that dost inhabit Dibon,"], ["ina alu ifo ia ai le mamalu,", "come down from thy glory,"], ["ma nofo i le nuu naumati;", "and sit in thirst;"], ["auā e alu ae ia te oe lē faatafunaina Moapi,", "for the spoiler of Moab shall come upon thee,"], ["na te faaumatia ou 'olo.", "and he shall destroy thy strong holds."]]},
  {num:19,words:[["O oe na ua nofo i Aroeru,", "O inhabitant of Aroer,"], ["ia e tu i le ala,", "stand by the way,"], ["ma vaai atu;", "and espy;"], ["fesili atu i le ua sola,", "ask him that fleeth,"], ["ma le ua sao,", "and her that escapeth,"], ["ia faapea atu,", "and say,"], ["Po o le a ea le mea ua fai?", "What is done?"]]},
  {num:20,words:[["Ua faamaina Moapi;", "Moab is confounded;"], ["auā ua lafoia o ia;", "for it is broken down:"], ["ina uio ia outou ma alalaga;", "howl and cry;"], ["ina ta'uina atu i Arinona,", "tell ye it in Arnon,"], ["ua faatafunaina Moapi,", "that Moab is spoiled,"]]},
  {num:21,words:[["ua oo foi le sala i le eleele laugatasi;", "And judgment is come upon the plain country;"], ["o Holona,", "upon Holon,"], ["ma Iaesa,", "and upon Jahazah,"], ["ma Mefata,", "and upon Mephaath,"]]},
  {num:22,words:[["ma Tipona,", "And upon Dibon,"], ["ma Nepo,", "and upon Nebo,"], ["ma Petetipelata,", "and upon Beth-diblathaim,"]]},
  {num:23,words:[["ma Kiriataima,", "And upon Kiriathaim,"], ["ma Petekamulo,", "and upon Beth-gamul,"], ["ma Petemeona,", "and upon Beth-meon,"]]},
  {num:24,words:[["ma Kiriota,", "And upon Kerioth,"], ["ma Posara,", "and upon Bozrah,"], ["ma aai uma i le nuu o Moapi, e ua mamao,", "and upon all the cities of the land of Moab,"], ["ma e ua lata mai.", "far or near."]]},
  {num:25,words:[["Ua vavaeeseina le nifo o Moapi,", "The horn of Moab is cut off,"], ["ma lona lima ua gausia,", "and his arm is broken,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:26,words:[["Ia outou faainu ia te ia ia onā;", "Make ye him drunken:"], ["auā ua ia faamaualuga ia Ieova;", "for he magnified himself against the LORD:"], ["e taafili Moapi i lona puaiga,", "Moab also shall wallow in his vomit,"], ["e fai lava o ia ma tauemuga.", "and he also shall be in derision."]]},
  {num:27,words:[["E lei faia ea Isaraelu ma tauemuga ia te oe? na maua ea o ia faatasi ma tagata gaoi? auā e iloga ona e tautala ia te ia,", "For was not Israel a derision unto thee? was he found among thieves? for since thou spakest of him,"], ["ua e lialiai lou ulu .", "thou skippedst for joy."]]},
  {num:28,words:[["O outou o e nonofo i Moapi,", "O ye that dwell in Moab,"], ["ia outou tuua aai,", "leave the cities,"], ["ma outou mau i le papa; ia pei o le lupe foi outou,", "and dwell in the rock,"], ["o le ua fai lona ofaga i itu o le gutu o le lua.", "and be like the dove that maketh her nest in the sides of the hole's mouth."]]},
  {num:29,words:[["Ua matou faalogo i le faamaualuga o Moapi,", "We have heard the pride of Moab,"], ["o lona matuā faamaualuga ma lona faasausili,", "(he is exceeding proud) his loftiness,"], ["ma lona faasiasia,", "and his arrogancy,"], ["ma lona faamaualuga,", "and his pride,"], ["ma le faafefeteina o lona loto.", "and the haughtiness of his heart."]]},
  {num:30,words:[["O loo fetalai mai Ieova,", "I know his wrath,"], ["O a'u nei ua ou iloa lona ita,", "saith the LORD;"], ["a e faatauvaa lava;", "but it shall not be so;"], ["o ana mea faatauvaa e le faia lava ia.", "his lies shall not so effect it."]]},
  {num:31,words:[["O le mea lea ou te uio ai ona o Moapi,", "Therefore will I howl for Moab,"], ["ma ou alaga ona o Moapi uma;", "and I will cry out for all Moab;"], ["e oi o ia ona o tagata o Kiriaresa.", "mine heart shall mourn for the men of Kir-heres."]]},
  {num:32,words:[["Le vine e o Sepema,", "O vine of Sibmah,"], ["ou te tagi ona o oe ma le tagi o Iasaru;", "I will weep for thee with the weeping of Jazer:"], ["ua sopoia le sami e ou moemoe, ua oo atu i le sami o Iasaru;", "thy plants are gone over the sea,"], ["ua osofia e le na te faatafunaina ou fua otata,", "they reach even to the sea of Jazer:"], ["ma lou taugāvine.", "the spoiler is fallen upon thy summer fruits and upon thy vintage."]]},
  {num:33,words:[["Ua aveesea le fiafia ma le olioli i le fanua lafulemu,", "And joy and gladness is taken from the plentiful field,"], ["o le nuu o Moapi lea;", "and from the land of Moab;"], ["ua ou faaiuina le uaina i le soligāvine;", "and I have caused wine to fail from the winepresses:"], ["e le solia ma le alaga fiafia;", "none shall tread with shouting;"], ["o le alaga fiafia e le se alaga fiafia lea.", "their shouting shall be no shouting."]]},
  {num:34,words:[["Ona o le alaga a Hesepona ua latou fevalaauai e oo i Eleale,", "From the cry of Heshbon even unto Elealeh,"], ["e oo lava i Iaesa,", "and even unto Jahaz,"], ["e afua mai i Soara e oo i Horonaima,", "have they uttered their voice, from Zoar even unto Horonaim,"], ["o le povi fafine ua tolu ona tausaga;", "as an heifer of three years old:"], ["auā ua avea le vai o Nimara lava ma mea naumati.", "for the waters also of Nimrim shall be desolate."]]},
  {num:35,words:[["Ua fetalai mai Ieova,", "Moreover I will cause to cease in Moab,"], ["ou te faaumatia i Moapi,", "saith the LORD,"], ["lē fai taulaga i le mea maualuga,", "him that offereth in the high places,"], ["ma lē faamu mea manogi i ona atua.", "and him that burneth incense to his gods."]]},
  {num:36,words:[["O le mea lea e tagi ai lo'u loto e pei o fagufagu ona o Moapi,", "Therefore mine heart shall sound for Moab like pipes,"], ["e tagi ai foi lo'u loto e pei o fagufagu ona o tagata o Kiriaresa;", "and mine heart shall sound like pipes for the men of Kir-heres:"], ["auā o le tele o mea na na maua ua fano.", "because the riches that he hath gotten are perished."]]},
  {num:37,words:[["Auā ua selemamāina o latou ulu uma,", "For every head shall be bald,"], ["ma ua sala 'ava uma;", "and every beard clipped:"], ["ua selei foi lima uma,", "upon all the hands shall be cuttings,"], ["ua fusia sulugatiti i ie talatala.", "and upon the loins sackcloth."]]},
  {num:38,words:[["E pa le lauaitu i luga o fale uma i Moapi,", "There shall be lamentation generally upon all the housetops of Moab,"], ["ma ona malae uma;", "and in the streets thereof:"], ["auā ua ou nutililiia Moapi, e pei o se ipu e le fiafia i ai,", "for I have broken Moab like a vessel wherein is no pleasure,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:39,words:[["Latou te uio e faapea ,", "They shall howl, saying,"], ["E! ua faatafunaina o ia. E! ua liutuaina Moapi ma le mā. E fai foi Moapi ma tauemuga ma mea e matatau ai ia te i latou i ona itu uma.", "How is it broken down! how hath Moab turned the back with shame! so shall Moab be a derision and a dismaying to all them about him."]]},
  {num:40,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD;"], ["Faauta,", "Behold, he shall fly as an eagle,"], ["e lele o ia e pei o le aeto ma fālō ona apaau i luga o Moapi.", "and shall spread his wings over Moab."]]},
  {num:41,words:[["Ua aea Kiriota,", "Kerioth is taken,"], ["ua maua foi 'olo,", "and the strong holds are surprised,"], ["e avea loto o toa o Moapi i lea lava aso e pei o le loto o le fafine ua faatiga.", "and the mighty men's hearts in Moab at that day shall be as the heart of a woman in her pangs."]]},
  {num:42,words:[["E faaumatia Moapi, e le fai ma nuu,", "And Moab shall be destroyed from being a people,"], ["auā na ia faamaualuga ia Ieova.", "because he hath magnified himself against the LORD."]]},
  {num:43,words:[["E ia te oe lē nofo i Moapi,", "Fear, and the pit,"], ["le mata'u ma le lua,", "and the snare,"], ["ma le mailei,", "shall be upon thee,"], ["ua fetalai mai ai Ieova.", "O inhabitant of Moab, saith the LORD."]]},
  {num:44,words:[["O le ua sola i le mata'u e paū ia i le lua;", "He that fleeth from the fear shall fall into the pit; and he that getteth up out of the pit shall be taken in the snare:"], ["o le ua alu ae ai le lua e lāvea o ia i le mailei;", "for I will bring upon it,"], ["auā ou te faaoo ia Moapi lava le tausaga e tauia mai ai i latou,", "even upon Moab,"], ["ua fetalai mai ai Ieova.", "the year of their visitation, saith the LORD."]]},
  {num:45,words:[["O i latou na sosola,", "They that fled stood under the shadow of Heshbon because of the force:"], ["ua latou tutū i le paolo o Hesepona, ua leai so latou malosi;", "but a fire shall come forth out of Heshbon,"], ["a ua alu atu le afi ai Hesepona,", "and a flame from the midst of Sihon,"], ["ma le afi mumū mai totonu o Sekono, ua mu ai le itu o Moapi,", "and shall devour the corner of Moab,"], ["ma le tumuai o tagata vāvāō.", "and the crown of the head of the tumultuous ones."]]},
  {num:46,words:[["Moapi e,", "Woe be unto thee,"], ["oi talofa ia te oe! ua faaumatia le nuu o Kimosa;", "O Moab! the people of Chemosh perisheth:"], ["auā ua avea ou atalii i le tafeaga,", "for thy sons are taken captives,"], ["ma ou afafine i le tafeaga.", "and thy daughters captives."]]},
  {num:47,words:[["A e peitai ou te faafoisia le tafeaga a Moapi i ona po amuli,", "Yet will I bring again the captivity of Moab in the latter days,"], ["ua fetalai mai ai Ieova. Ona gata lea o le faasalaina o Moapi.", "saith the LORD. Thus far is the judgment of Moab."]]},
];
renderVerseSet(jer_ch_48_Verses, 'jer-ch48-verses');

var jer_ch_49_Verses = [
  {num:1,words:[["Ua faapea ona fetalai mai o Ieova i le fanauga a Amoni,", "Concerning the Ammonites,"], ["E leai ea ni atalii o Isaraelu? e leai ea sona suli? Se a foi le mea ua fai ai Kato e Malekama mona,", "thus saith the LORD; Hath Israel no sons? hath he no heir? why then doth their king inherit Gad,"], ["ua nonofo foi ona tagata i ona aai?", "and his people dwell in his cities?"]]},
  {num:2,words:[["O le mea lea faauta,", "Therefore,"], ["e oo ai i ona po,", "behold,"], ["ua fetalai mai ai Ieova, ou te faafaalogoina le alaga o le taua i Rapa,", "the days come,"], ["o le aai o le fanauga a Amoni;", "saith the LORD,"], ["e fai ia ma mea mautietie,", "that I will cause an alarm of war to be heard in Rabbah of the Ammonites;"], ["o le faatafunaga lava,", "and it shall be a desolate heap,"], ["e susunuina ona faoa aai i le afi; ona fai ai lea e Isaraelu o i latou mona,", "and her daughters shall be burned with fire:"], ["o e sa fai o ia mo i latou,", "then shall Israel be heir unto them that were his heirs,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:3,words:[["Hesepona e,", "Howl,"], ["ina uio ia,", "O Heshbon,"], ["auā ua faatafunaina o Ai;", "for Ai is spoiled:"], ["ina alalaga ia,", "cry,"], ["outou tama fafine o Rapa,", "ye daughters of Rabbah,"], ["ina lavalava ia o outou i ie talatala;", "gird you with sackcloth;"], ["ina taufaitagitu'i ia,", "lament,"], ["ma fetaufetuliai i aupa;", "and run to and fro by the hedges;"], ["auā e alu Malekama i le tafeaga,", "for their king shall go into captivity,"], ["o ona faitaulaga atoa ma ona alii faatasi ma ia.", "and his priests and his princes together."]]},
  {num:4,words:[["Se a le mea ua e mitamita ai i vanu,", "Wherefore gloriest thou in the valleys,"], ["o lou vanu ua tafe,", "thy flowing valley,"], ["o oe na le tama fafine ua liliu ese? o lē faatuatua i ana oloa,", "O backsliding daughter? that trusted in her treasures,"], ["ua faapea mai ,", "saying,"], ["O ai ea e sau ia te au?", "Who shall come unto me?"]]},
  {num:5,words:[["Ua fetalai mai le Alii,", "Behold,"], ["o Ieova o 'au,", "I will bring a fear upon thee,"], ["Faauta, ou te faaoo ia te oe le mata'u,", "saith the Lord GOD of hosts,"], ["mai ia te i latou o i ou itu uma lava;", "from all those that be about thee;"], ["e tulia foi outou e taitoatasi i le mea ua i ona luma;", "and ye shall be driven out every man right forth;"], ["e leai foi se tasi e faapotopoto i e ua sosola.", "and none shall gather up him that wandereth."]]},
  {num:6,words:[["E mulimuli ane ona ou faafoisia mai lea o le tafeaga o le fanauga a Amoni,", "And afterward I will bring again the captivity of the children of Ammon,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:7,words:[["O loo faapea ona fetalai mai o Ieova o 'au ia Etoma,", "Concerning Edom, thus saith the LORD of hosts;"], ["E le toe ai ea se poto i Timanu? ua fano ea le faautauta ai tagata mafaufau? ua mavae ea lo latou poto?", "Is wisdom no more in Teman? is counsel perished from the prudent? is their wisdom vanished?"]]},
  {num:8,words:[["O outou o e nonofo i Titana,", "Flee ye,"], ["ina sosola ia outou,", "turn back,"], ["ina liliu ia,", "dwell deep,"], ["ia outou nonofo i mea maulalo;", "O inhabitants of Dedan;"], ["auā ou te faaoo le malaia o Esau i ona luga,", "for I will bring the calamity of Esau upon him,"], ["o ona po lava ou te taui atu ai ia te ia.", "the time that I will visit him."]]},
  {num:9,words:[["Ana o atu ia te oe o e tau vine,", "If grapegatherers come to thee,"], ["po ua latou le faatotoe ea ni toe fuifui vine? ana o atu ia te oe o e gaoi i le po,", "would they not leave some gleaning grapes? if thieves by night,"], ["po ua latou le faaumatia ea mea e tusa ia i latou?", "they will destroy till they have enough."]]},
  {num:10,words:[["Auā ua ou suena Esau,", "But I have made Esau bare,"], ["ua ou faaalia foi ana mea lilo,", "I have uncovered his secret places,"], ["na te le mafaia ona lafi;", "and he shall not be able to hide himself:"], ["ua faaumatia lana fanau,", "his seed is spoiled,"], ["ma ona uso,", "and his brethren,"], ["ma i latou sa tuaoi ma ia;", "and his neighbours,"], ["o ia foi ua leai.", "and he is not."]]},
  {num:11,words:[["Ina tuua ia au tama ua aumatuā,", "Leave thy fatherless children,"], ["ou te faaola ia te i latou;", "I will preserve them alive;"], ["ia faatuatua mai foi ia te au ou fafine ua oti a latou tane.", "and let thy widows trust in me."]]},
  {num:12,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD;"], ["Faauta, o i latou e le tatau ona latou inu i le ipu,", "Behold,"], ["ua latou inu ai lava;", "they whose judgment was not to drink of the cup have assuredly drunken;"], ["a o oe, e faasaoina ea oe? e le faasaoina lava oe,", "and art thou he that shall altogether go unpunished? thou shalt not go unpunished,"], ["auā e te matuā inu lava.", "but thou shalt surely drink of it."]]},
  {num:13,words:[["Auā ou te tauto lava a'u ia te au,", "For I have sworn by myself,"], ["ua fetalai mai ai Ieova,", "saith the LORD,"], ["e fai lava Posara ma mea e ofo ai,", "that Bozrah shall become a desolation,"], ["ma fai a'i luma,", "a reproach,"], ["ma mea gaogao,", "a waste,"], ["ma faafanoga;", "and a curse;"], ["e fai foi ona aai uma ma faatafunaga e faavavau.", "and all the cities thereof shall be perpetual wastes."]]},
  {num:14,words:[["Ua ou faalogo i le tala mai ia Ieova,", "I have heard a rumour from the LORD,"], ["ua auina atu foi le sāvali i nuu ese,", "and an ambassador is sent unto the heathen,"], ["ua faapea atu ,", "saying,"], ["Ina faapotopoto ia outou,", "Gather ye together,"], ["ma ia outou o mai ia te ia,", "and come against her,"], ["ma ia tulai atu outou e tau ai le taua.", "and rise up to the battle."]]},
  {num:15,words:[["Auā faauta,", "For,"], ["ua ou faia oe ia faatauvaa i nuu,", "lo, I will make thee small among the heathen,"], ["ia inosia oe e tagata.", "and despised among men."]]},
  {num:16,words:[["O lou matautia,", "Thy terribleness hath deceived thee,"], ["ma le faamaualuga o lou loto ua faaseseina ai oe,", "and the pride of thine heart,"], ["o oe o loo nofo i ana o le papa,", "O thou that dwellest in the clefts of the rock,"], ["o le ua nofoia ai le mea maualuga o le mauga;", "that holdest the height of the hill:"], ["e ui ina maualuga le mea e te tuu ai lou ofaga e pei o le aeto,", "though thou shouldest make thy nest as high as the eagle,"], ["ou te lafo ia te oe i lalo i lea mea,", "I will bring thee down from thence,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:17,words:[["E fai foi Etoma ma faatafunaga;", "Also Edom shall be a desolation:"], ["o i latou uma e ui ane ai e taitasi ma ofo,", "every one that goeth by it shall be astonished,"], ["ma uisa i ona mala uma.", "and shall hiss at all the plagues thereof."]]},
  {num:18,words:[["E pei o le faaumatia o Sotoma mo Komoro,", "As in the overthrow of Sodom and Gomorrah and the neighbour cities thereof,"], ["ma e sa latou tuaoi,", "saith the LORD,"], ["o loo faapea mai ai Ieova, e le nofo ai se tasi i lea mea,", "no man shall abide there,"], ["e le mau ai foi se atalii o se tagata.", "neither shall a son of man dwell in it."]]},
  {num:19,words:[["Faauta,", "Behold,"], ["e alu ae o ia e pei o le leona ai le matagofie o Ioritana,", "he shall come up like a lion from the swelling of Jordan against the habitation of the strong:"], ["i le mea malosi e mau ai; auā ou te faaoso ia te ia ia faavave ona alu ese o ia ia te ia,", "but I will suddenly make him run away from her:"], ["e pei o le emo o le mata;", "and who is a chosen man,"], ["o ai foi le tagata filifilia ou te tofia e tau ma ia? auā po o ai ea e tusa ma a'u? o ai foi e atofa ni aso ia te au? o ai foi lena leoleo mamoe e mafai ona tu i o'u luma?", "that I may appoint over her? for who is like me? and who will appoint me the time? and who is that shepherd that will stand before me?"]]},
  {num:20,words:[["O le mea lea ia outou faalogologo mai ai i le pule a Ieova ua ia pule ai ia Etoma,", "Therefore hear the counsel of the LORD,"], ["ma ona mafaufauga ua ia mafaufau ai ia leaga ai e o nonofo i Tamanu,", "that he hath taken against Edom;"], ["E moni,", "and his purposes,"], ["e tosina i latou e le aupito itiiti o le lafu mamoe;", "that he hath purposed against the inhabitants of Teman:"], ["e moni,", "Surely the least of the flock shall draw them out:"], ["na te faatafunaina i o latou luga le mea latou te mau ai.", "surely he shall make their habitations desolate with them."]]},
  {num:21,words:[["O le taalili o lo latou paū ua luluina ai le lalolagi;", "The earth is moved at the noise of their fall,"], ["o le leo foi o lona alaga ua lagona lea i le sami Ulaula.", "at the cry the noise thereof was heard in the Red sea."]]},
  {num:22,words:[["Faauta,", "Behold,"], ["e alu ae o ia ma lele e pei o le aeto,", "he shall come up and fly as the eagle,"], ["e fālō foi e ia ona apaau i luga o Posara; e avea foi loto o toa o Etoma i lea lava aso,", "and spread his wings over Bozrah:"], ["e pei o le loto o le fafine ua faatiga.", "and at that day shall the heart of the mighty men of Edom be as the heart of a woman in her pangs."]]},
  {num:23,words:[["O le upu ia Tamaseko. Ua faamaina Amato,", "Concerning Damascus. Hamath is confounded,"], ["ma Arepa;", "and Arpad:"], ["auā ua latou faalogo i le tala leaga;", "for they have heard evil tidings:"], ["ua liu suāvai i latou;", "they are fainthearted;"], ["o loo i le sami le atuatuvale;", "there is sorrow on the sea;"], ["e le mafai ona to'a filemu.", "it cannot be quiet."]]},
  {num:24,words:[["Ua faavaivai Tamaseko,", "Damascus is waxed feeble,"], ["ua liliu o ia a sola,", "and turneth herself to flee,"], ["ua maua o ia i le mata'u;", "and fear hath seized on her:"], ["ua maua foi o ia i le puapuaga ma le faatiga,", "anguish and sorrows have taken her,"], ["e pei o le fafine o le a fanau.", "as a woman in travail."]]},
  {num:25,words:[["Pe faapefea ona le tuua le aai sa viia,", "How is the city of praise not left,"], ["le aai na ou fiafia i ai?", "the city of my joy!"]]},
  {num:26,words:[["O le mea lea e pauu ai ona taulelea i ona malae,", "Therefore her young men shall fall in her streets,"], ["e fano foi i lea lava aso ona tagata tau uma,", "and all the men of war shall be cut off in that day,"], ["ua fetalai mai ai Ieova o 'au.", "saith the LORD of hosts."]]},
  {num:27,words:[["Ou te faamu foi le afi i le pa o Tamaseko,", "And I will kindle a fire in the wall of Damascus,"], ["e faaumatia ai foi maota o Peniata.", "and it shall consume the palaces of Ben-hadad."]]},
  {num:28,words:[["O loo faapea ona fetalai mai o Ieova ia Kitara,", "Concerning Kedar,"], ["ma malo o Hasora,", "and concerning the kingdoms of Hazor,"], ["e na fasia e Nepukanesa le tupu o Papelonia,", "which Nebuchadrezzar king of Babylon shall smite, thus saith the LORD;"], ["Ina tulai ia outou,", "Arise ye,"], ["ia o ae i Kitara,", "go up to Kedar,"], ["ma ia outou faaumatia tagata i sasae.", "and spoil the men of the east."]]},
  {num:29,words:[["Latou te faoa o latou fale ie ma o latou lafu mamoe;", "Their tents and their flocks shall they take away:"], ["latou te avea foi mo i latou o latou ie puipui,", "they shall take to themselves their curtains,"], ["ma a latou mea uma,", "and all their vessels,"], ["ma a latou kamela;", "and their camels;"], ["e alalaga foi i latou ona o i latou,", "and they shall cry unto them,"], ["O i ai le mata'u i itu uma.", "Fear is on every side."]]},
  {num:30,words:[["O outou o e nonofo i Hasora,", "Flee,"], ["ina sosola ia,", "get you far off,"], ["ia outou matuā sosola lava,", "dwell deep,"], ["ia outou nonofo i mea maulalo,", "O ye inhabitants of Hazor,"], ["o loo fetalai mai ai Ieova;", "saith the LORD;"], ["auā ua pulea outou e Nepukanesa le tupu o Papelonia,", "for Nebuchadrezzar king of Babylon hath taken counsel against you,"], ["ua na mafaufau foi i se togafiti e leaga ai outou.", "and hath conceived a purpose against you."]]},
  {num:31,words:[["Ina tulai ia,", "Arise,"], ["ma ia outou o ae i le nuu ua filemu,", "get you up unto the wealthy nation,"], ["o e nonofo faatalanoa, ua fetalai mai ai Ieova,", "that dwelleth without care,"], ["e leai ni o latou puipui,", "saith the LORD,"], ["e leai foi ni faamau faalava,", "which have neither gates nor bars,"], ["ua nonofo i latou na o i latou lava.", "which dwell alone."]]},
  {num:32,words:[["O a latou kamela foi e fai ia ma vete,", "And their camels shall be a booty,"], ["ma a latou lafu e tele e fai ma mea faoa;", "and the multitude of their cattle a spoil:"], ["ou te faataapeapeina foi i mata matagi uma o i latou o e sala a latou pito 'ava;", "and I will scatter into all winds them that are in the utmost corners;"], ["ou te aumaia foi lo latou malaia ai ona itu uma,", "and I will bring their calamity from all sides thereof,"], ["o loo fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:33,words:[["E fai foi Hasora ma mea e fale ai luko,", "And Hazor shall be a dwelling for dragons,"], ["o le faatafunaga e oo i le faavavau;", "and a desolation for ever:"], ["e le nofo ai se tagata i lea mea,", "there shall no man abide there,"], ["e le mau ai foi se atalii o se tagata.", "nor any son of man dwell in it."]]},
  {num:34,words:[["O le afioga a Ieova na oo mai ia Ieremia le perofeta ia Elama, i le amataga o le nofoaiga a Setekaia le tupu o Iuta,", "The word of the LORD that came to Jeremiah the prophet against Elam in the beginning of the reign of Zedekiah king of Judah,"], ["ua faapea mai,", "saying,"]]},
  {num:35,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts;"], ["Faauta,", "Behold,"], ["ou te gausia le aufana a Elama,", "I will break the bow of Elam,"], ["o le mea sili lea e malolosi ai i latou.", "the chief of their might."]]},
  {num:36,words:[["Ou te aumaia foi matagi e fa mai itu e fa o le lagi i luga o Elama,", "And upon Elam will I bring the four winds from the four quarters of heaven,"], ["ma ou faataapeapeina i latou i ia matāmatagi uma;", "and will scatter them toward all those winds;"], ["e leai foi se nuu e le oo atu i ai tagata Elama ua tulia.", "and there shall be no nation whither the outcasts of Elam shall not come."]]},
  {num:37,words:[["Ou te faamatatau foi Elama i luma o e ita mai ia te i latou,", "For I will cause Elam to be dismayed before their enemies,"], ["ma luma o e saili e fasioti ia te i latou;", "and before them that seek their life:"], ["ou te faaoo le malaia i o latou luga,", "and I will bring evil upon them,"], ["o lo'u ita tele,", "even my fierce anger,"], ["ua fetalai mai ai Ieova;", "saith the LORD;"], ["ou te aveina atu foi le pelu e mulimuli atu ia te i latou,", "and I will send the sword after them,"], ["seia ou faaumatia i latou.", "till I have consumed them:"]]},
  {num:38,words:[["Ou te tuuina lo'u nofoālii i Elama,", "And I will set my throne in Elam,"], ["ou te faaumatia foi i lea mea le tupu ma alii,", "and will destroy from thence the king and the princes,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:39,words:[["A e oo i ona po amuli,", "But it shall come to pass in the latter days,"], ["ona ou faafoisia mai ai lea o le tafeaga a Elama,", "that I will bring again the captivity of Elam,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
];
renderVerseSet(jer_ch_49_Verses, 'jer-ch49-verses');

var jer_ch_50_Verses = [
  {num:1,words:[["O le afioga na fetalai mai ai Ieova ia Papelonia ma le nuu o Kaletaia, na aumaia e le perofeta o Ieremia.", "The word that the LORD spake against Babylon and against the land of the Chaldeans by Jeremiah the prophet."]]},
  {num:2,words:[["Ina ta'u atu ia outou i atu nuu,", "Declare ye among the nations,"], ["ma faailoa atu ai;", "and publish,"], ["sii i luga foi le tagavai;", "and set up a standard;"], ["ina faailoa atu ia,", "publish,"], ["aua le natia;", "and conceal not:"], ["ia outou faapea atu,", "say,"], ["Ua aea Papelonia,", "Babylon is taken,"], ["ua faamaina Pele,", "Bel is confounded,"], ["ua matautuia Merota;", "Merodach is broken in pieces;"], ["ua faamaina ona tupua,", "her idols are confounded,"], ["ua matautuia ana tupua.", "her images are broken in pieces."]]},
  {num:3,words:[["Auā e alu ae e tau ma ia le nuu ai le itu i matu,", "For out of the north there cometh up a nation against her,"], ["o le na te faia lona laueleele ma faatafunaga,", "which shall make her land desolate,"], ["e leai foi se nofo ai;", "and none shall dwell therein: they shall remove,"], ["ua sosola tagata atoa ma manu,", "they shall depart,"], ["ua latou ō.", "both man and beast."]]},
  {num:4,words:[["O na ona po,", "In those days,"], ["ma lena tausaga,", "and in that time,"], ["ua fetalai mai Ieova,", "saith the LORD,"], ["e o mai ai le fanauga a Isaraelu,", "the children of Israel shall come,"], ["o i latou ma le fanauga a Iuta faatasi,", "they and the children of Judah together,"], ["latou te fetagisi fano mai;", "going and weeping:"], ["latou te o ane,", "they shall go,"], ["ma saili ia Ieova lo latou Atua.", "and seek the LORD their God."]]},
  {num:5,words:[["Latou te fesili i le ala i Siona, o faasaga mai iinei o latou mata,", "They shall ask the way to Zion with their faces thitherward,"], ["ua faapea ,", "saying,"], ["Ina o mai ia,", "Come,"], ["se'i faatasi atu i tatou ia Ieova i le feagaiga e faavavau, e le galo lava.", "and let us join ourselves to the LORD in a perpetual covenant that shall not be forgotten."]]},
  {num:6,words:[["O lo'u nuu ua se lafu mamoe ua sē i latou;", "My people hath been lost sheep:"], ["ua faaseseina i latou e o latou leoleo,", "their shepherds have caused them to go astray,"], ["ma latou faaliliuina i latou i le atu mauga;", "they have turned them away on the mountains:"], ["ua latou feoai i lea mauga ma lea mauga,", "they have gone from mountain to hill,"], ["ua galo ia i latou le mea sa latou taooto ai.", "they have forgotten their restingplace."]]},
  {num:7,words:[["O i latou uma na maua i latou,", "All that found them have devoured them:"], ["ua latou 'aina i latou;", "and their adversaries said,"], ["na fai ane foi o e na saua mai ia te i latou,", "We offend not,"], ["Matou te le nofo sala, auā ua latou agasala ia Ieova,", "because they have sinned against the LORD,"], ["o le mea e mau ai lē amiotonu,", "the habitation of justice,"], ["o Ieova,", "even the LORD,"], ["o le faamoemoe o latou tamā.", "the hope of their fathers."]]},
  {num:8,words:[["Ina sosola ia ai totonu o Papelonia,", "Remove out of the midst of Babylon,"], ["ma o atu ai nai le laueleele o Kaletaia;", "and go forth out of the land of the Chaldeans,"], ["ia outou faapei o 'oti poa i luma o le lafu.", "and be as the he goats before the flocks."]]},
  {num:9,words:[["Auā faauta,", "For,"], ["ou te faaosoina,", "lo,"], ["ma aveina ae le faapotopotoga o atu nuu tetele mai le nuu i le itu i matu,", "I will raise and cause to come up against Babylon an assembly of great nations from the north country:"], ["e tau ma Papelonia; latou te sauniuni e tau ma ia;", "and they shall set themselves in array against her;"], ["e aea foi o ia ai lena mea;", "from thence she shall be taken:"], ["o a latou u fanafana e pei o u fanafana a le toa poto;", "their arrows shall be as of a mighty expert man;"], ["ua le foi fua mai.", "none shall return in vain."]]},
  {num:10,words:[["E fai foi Kaletaia ma vete;", "And Chaldea shall be a spoil:"], ["e malilie atoa uma o e vetea o ia,", "all that spoil her shall be satisfied,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:11,words:[["Auā na outou fiafia,", "Because ye were glad,"], ["auā na outou olioli,", "because ye rejoiced,"], ["o outou na vetea lo'u tofi;", "O ye destroyers of mine heritage,"], ["auā ua outou osooso e pei o le povi fafine i le vao,", "because ye are grown fat as the heifer at grass,"], ["ma outou tagi e pei o solofanua malolosi;", "and bellow as bulls;"]]},
  {num:12,words:[["e matuā ma lo outou tinā;", "Your mother shall be sore confounded;"], ["e masiasi lava le na fanauina outou;", "she that bare you shall be ashamed:"], ["faauta,", "behold, the hindermost of the nations shall be a wilderness,"], ["e fai le nuu aupito mulimuli ma vao lafulafua ma nuu naumati,", "a dry land,"], ["ma toafa.", "and a desert."]]},
  {num:13,words:[["E le āina ia ona o le toasa o Ieova,", "Because of the wrath of the LORD it shall not be inhabited,"], ["a e faatafunaina uma lava;", "but it shall be wholly desolate:"], ["o i latou uma o e ui ane i Papelonia e taitasi ma ofo,", "every one that goeth by Babylon shall be astonished,"], ["ma uisa i ona mala uma.", "and hiss at all her plagues."]]},
  {num:14,words:[["Ina sauniuni ia outou e tau ma Papelonia i ona itu uma;", "Put yourselves in array against Babylon round about:"], ["o outou uma o e lolo'u aufana,", "all ye that bend the bow,"], ["ina fanafana atu ia ia te ia,", "shoot at her,"], ["aua ne'i tuu ni u fanafana;", "spare no arrows:"], ["auā ua na agasala ia Ieova.", "for she hath sinned against the LORD."]]},
  {num:15,words:[["Ia outou alalaga ia te ia i ona itu uma;", "Shout against her round about:"], ["ua na tuuina mai lona lima;", "she hath given her hand:"], ["ua pauu ona faavae,", "her foundations are fallen,"], ["ua sŏloia ona pa;", "her walls are thrown down:"], ["auā o le taui ma sui lenei a Ioeva;", "for it is the vengeance of the LORD:"], ["ia outou taui atu ia te ia;", "take vengeance upon her;"], ["e pei ona faia e ia,", "as she hath done,"], ["ia faapea ona outou faia ia te ia.", "do unto her."]]},
  {num:16,words:[["Ia vavaeeseina i Papelonia lē lulu saito, atoa foi ma lē tago i le selesaito,", "Cut off the sower from Babylon,"], ["i ona po o le seleselega;", "and him that handleth the sickle in the time of harvest:"], ["latou te taitasi ma liliu i lona lava nuu,", "for fear of the oppressing sword they shall turn every one to his people,"], ["latou te taitasi foi ma sola i lona lava laueleele, ai luma o le pelu saua.", "and they shall flee every one to his own land."]]},
  {num:17,words:[["O Isaraelu o le lafu mamoe o ia ua faataapeapeina; ua tulia o ia e leona;", "Israel is a scattered sheep;"], ["o lē na muai 'ai ia te ia, o le tupu o Asuria lea;", "the lions have driven him away:"], ["a o lē mulimuli,", "first the king of Assyria hath devoured him;"], ["o lenei tupu o Papelonia o Nepukanesa lea, ua pagugu e ia ona ivi.", "and last this Nebuchadrezzar king of Babylon hath broken his bones."]]},
  {num:18,words:[["O le mea lea o loo faapea ona fetalai mai ai o Ieova o 'au,", "Therefore thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["Faauta,", "Behold,"], ["ou te taui atu i le tupu o Papelonia ma lona nuu,", "I will punish the king of Babylon and his land,"], ["e pei ona ou taui atu i le tupu o Asuria.", "as I have punished the king of Assyria."]]},
  {num:19,words:[["Ou te faafoisia Isaraelu i le mea na ia mau ai;", "And I will bring Israel again to his habitation,"], ["e 'ai o ia i Karamelu ma Vasana,", "and he shall feed on Carmel and Bashan,"], ["e ma'ona foi o ia i le mauga o Efaraima ma Kiliata.", "and his soul shall be satisfied upon mount Ephraim and Gilead."]]},
  {num:20,words:[["O na ona po,", "In those days,"], ["ma lena tausaga,", "and in that time,"], ["ua fetalai mai Ieova e sailia ai le amioletonu a Isaraelu,", "saith the LORD,"], ["a e leai;", "the iniquity of Israel shall be sought for, and there shall be none;"], ["e sailia foi agasala a Iuta,", "and the sins of Judah,"], ["a e le maua;", "and they shall not be found:"], ["auā ou te faamagaloina atu ia te i latou o e ua faatotoeina e a'u.", "for I will pardon them whom I reserve."]]},
  {num:21,words:[["Ina alu ae ia i le nuu o Merataimo e tau ma ia,", "Go up against the land of Merathaim,"], ["ma e o nonofo i Pekota;", "even against it,"], ["ia e faatafunaina ma matuā faaumatia o mulimuli atu ia te i latou,", "and against the inhabitants of Pekod: waste and utterly destroy after them,"], ["ua fetalai mai ai Ieova;", "saith the LORD,"], ["ia e faia foi i ai e tusa ma mea uma na ou fai atu ai ia te oe.", "and do according to all that I have commanded thee."]]},
  {num:22,words:[["O loo i le nuu le vāvāō o le taua,", "A sound of battle is in the land,"], ["ma le olopalaina e tele.", "and of great destruction."]]},
  {num:23,words:[["E! ua gauia ma nutililiia le samala o le lalolagi uma. E! ua avea Papelonia ma mea e ofo ai i atu nuu.", "How is the hammer of the whole earth cut asunder and broken! how is Babylon become a desolation among the nations!"]]},
  {num:24,words:[["Papelonia e,", "I have laid a snare for thee,"], ["ua ou tuu le mailei mo oe,", "and thou art also taken,"], ["ua maua ai oe,", "O Babylon,"], ["a ua e le iloa;", "and thou wast not aware:"], ["ua maua oe,", "thou art found,"], ["ua puea foi,", "and also caught,"], ["auā na e sii le taua ia Ieova.", "because thou hast striven against the LORD."]]},
  {num:25,words:[["Ua tatalaina e Ieova lana mea e teu ai auupega ,", "The LORD hath opened his armoury,"], ["ua na au mai ai auupega o lona toasa;", "and hath brought forth the weapons of his indignation:"], ["auā o le galuega lena ua i le Alii o Ieova o 'au i le nuu o Kaletaia.", "for this is the work of the Lord GOD of hosts in the land of the Chaldeans."]]},
  {num:26,words:[["Ina o mai ia ia te ia ai mea aupito mamao,", "Come against her from the utmost border,"], ["ina tatalaina ia ona fale e tuu ai mea e 'ai;", "open her storehouses:"], ["ia outou faafaupue ia te ia ia pei o faupuegā saito ,", "cast her up as heaps,"], ["ma matuā faaumatia o ia;", "and destroy her utterly:"], ["aua ne'i ai se mea e totoe ia te ia.", "let nothing of her be left."]]},
  {num:27,words:[["Ina faaumatia ia o ana povi poa taanoa uma,", "Slay all her bullocks;"], ["ia latou o ifo ia fasia;", "let them go down to the slaughter:"], ["oi talofa ia te i latou! auā ua oo mai lo latou aso,", "woe unto them! for their day is come,"], ["o ona po e tauia ai i latou.", "the time of their visitation."]]},
  {num:28,words:[["O le alaga o e ua sosola ma ua sao ai le nuu o Papelonia,", "The voice of them that flee and escape out of the land of Babylon,"], ["e ta'u atu i Siona le taui ma sui a Ieova lo tatou Atua,", "to declare in Zion the vengeance of the LORD our God,"], ["o le taui ma sui ona o lona malumalu.", "the vengeance of his temple."]]},
  {num:29,words:[["Ia faalaei 'au i e fanafana u e tau ma Papelonia,", "Call together the archers against Babylon:"], ["o i latou uma o e lolo'u le aufana;", "all ye that bend the bow,"], ["ia outou to lauapi e vagavagai ia te ia,", "camp against it round about;"], ["aua ne'i ai sē sao;", "let none thereof escape:"], ["ia outou taui atu ia te ia e tusa ma ana galuega;", "recompense her according to her work;"], ["e pei o mea uma na ia faia,", "according to all that she hath done,"], ["ia faapea ona outou faia ia te ia;", "do unto her:"], ["auā ua faamaualuga o ia ia Ieova,", "for she hath been proud against the LORD,"], ["le Paia o Isaraelu.", "against the Holy One of Israel."]]},
  {num:30,words:[["O le mea lea e pauu ai o ona taulelea i ona malae,", "Therefore shall her young men fall in the streets,"], ["e fano foi i lea lava aso ona tagata tau uma,", "and all her men of war shall be cut off in that day,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:31,words:[["O oe na le ua faamaualuga,", "Behold,"], ["faauta,", "I am against thee,"], ["ou te faia oe mo'u fili, ua fetalai mai ai le Alii,", "O thou most proud,"], ["o Ieova o 'au;", "saith the Lord GOD of hosts:"], ["auā ua oo mai lou aso,", "for thy day is come,"], ["o ona po ou te taui atu ai ia te oe.", "the time that I will visit thee."]]},
  {num:32,words:[["E tausuai ma paū le ua faamaualuga,", "And the most proud shall stumble and fall,"], ["e leai foi se na te faatulai ia te ia;", "and none shall raise him up:"], ["ou te faamuina le afi i ona aai,", "and I will kindle a fire in his cities,"], ["e susunuina ai ona itu uma.", "and it shall devour all round about him."]]},
  {num:33,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts;"], ["Na sauaina faatasi le fanauga a Isaraelu ma le fanauga a Iuta;", "The children of Israel and the children of Judah were oppressed together:"], ["o i latou uma e na avea i latou o tagata o taua na latou taofi mau ia te i latou;", "and all that took them captives held them fast;"], ["ua latou le mafafai ona tuuina i latou ia ō.", "they refused to let them go."]]},
  {num:34,words:[["E malosi le na te togiolaina i latou,", "Their Redeemer is strong;"], ["o Ieova o 'au o lona suafa lea;", "the LORD of hosts is his name:"], ["e matuā faia e ia la latou finauga,", "he shall throughly plead their cause,"], ["ina ia faanofofilemuina e ia le lalolagi,", "that he may give rest to the land,"], ["ia faagateteina foi e o nonofo i Papelonia.", "and disquiet the inhabitants of Babylon."]]},
  {num:35,words:[["Ua fetalai mai Ieova,", "A sword is upon the Chaldeans,"], ["E oo le pelu ia Kaletaia,", "saith the LORD,"], ["ma ē nonofo i Papelonia,", "and upon the inhabitants of Babylon,"], ["ma ona alii,", "and upon her princes,"], ["ma ona tagata popoto.", "and upon her wise men."]]},
  {num:36,words:[["O le pelu i e pepelo,", "A sword is upon the liars;"], ["e faavālea foi i latou;", "and they shall dote:"], ["o le pelu i ona toa,", "a sword is upon her mighty men;"], ["e matatau ai foi i latou.", "and they shall be dismayed."]]},
  {num:37,words:[["O le pelu i ana solofanua,", "A sword is upon their horses,"], ["ma ona kariota,", "and upon their chariots,"], ["ma tagata eseese uma ua i totonu ia te ia;", "and upon all the mingled people that are in the midst of her;"], ["e avea foi i latou ma fafine;", "and they shall become as women:"], ["o le pelu i ana oloa,", "a sword is upon her treasures;"], ["e vetea foi ia.", "and they shall be robbed."]]},
  {num:38,words:[["E oo le vevela i lona vai,", "A drought is upon her waters;"], ["ona mate ai lea;", "and they shall be dried up:"], ["auā o le nuu lava lea o tupua ua ta,", "for it is the land of graven images,"], ["ua latou mitamita vale foi i mea matautia.", "and they are mad upon their idols."]]},
  {num:39,words:[["O le mea lea e nonofo ai manu feai o le vao,", "Therefore the wild beasts of the desert with the wild beasts of the islands shall dwell there,"], ["faatasi ma aie,", "and the owls shall dwell therein:"], ["e mau ai foi iaena; e le toe āina e faavavau;", "and it shall be no more inhabited for ever;"], ["e le mau ai lava se tasi i lea tupulaga ma lea tupulaga.", "neither shall it be dwelt in from generation to generation."]]},
  {num:40,words:[["E pei o le faaumatia e le Atua o Sotoma ma Komoro,", "As God overthrew Sodom and Gomorrah and the neighbour cities thereof,"], ["ma e na latou tuaoi,", "saith the LORD;"], ["o loo fetalai mai ai Ieova, e le nofo ai se tasi,", "so shall no man abide there,"], ["e le mau ai foi se atalii o se tagata.", "neither shall any son of man dwell therein."]]},
  {num:41,words:[["Faauta,", "Behold,"], ["e o mai le nuu ai le itu i matu,", "a people shall come from the north,"], ["o le nuu tele;", "and a great nation,"], ["e faaosoina foi tupu e toatele ai tuluiga o le lalolagi.", "and many kings shall be raised up from the coasts of the earth."]]},
  {num:42,words:[["Latou te 'u'u le aufana ma le tao;", "They shall hold the bow and the lance:"], ["ua saua i latou,", "they are cruel,"], ["ma latou le alolofa;", "and will not shew mercy:"], ["e taalili o latou leo e pei o le sami,", "their voice shall roar like the sea,"], ["ua latou tietie i solofanua,", "and they shall ride upon horses, every one put in array,"], ["o sauniuni e pei o tagata e ō i le taua,", "like a man to the battle,"], ["ina ia tau ma oe,", "against thee,"], ["le tama fafine Papelonia.", "O daughter of Babylon."]]},
  {num:43,words:[["Ua faalogo le tupu o Papelonia i le tala ia te i latou,", "The king of Babylon hath heard the report of them,"], ["ona vaivai ai lea o ona lima;", "and his hands waxed feeble:"], ["ua maua foi o ia i le puapuaga,", "anguish took hold of him,"], ["o le tiga foi e pei o se fafine o le a fanau.", "and pangs as of a woman in travail."]]},
  {num:44,words:[["Faauta,", "Behold,"], ["e alu ae o ia e pei o le leona ai le matagofie o Ioritana,", "he shall come up like a lion from the swelling of Jordan unto the habitation of the strong:"], ["i le mea malosi e mau ai; a e ou te faaoso ia te i latou ia faavave ona o ese ia te ia,", "but I will make them suddenly run away from her:"], ["e pei o le emo o le mata;", "and who is a chosen man,"], ["o ai foi le tagata filifilia ou te tofia e tau ma ia? auā po o ai ea e tusa ma a'u? o ai foi e atofa ni aso ia te au? o ai foi lena leoleo mamoe e mafai ona tu i o'u luma?", "that I may appoint over her? for who is like me? and who will appoint me the time? and who is that shepherd that will stand before me?"]]},
  {num:45,words:[["O le mea lea ia outou faalogologo mai ai i le pule a Ieova ua ia pule ai ia Papelonia,", "Therefore hear ye the counsel of the LORD,"], ["ma ona mafaufauga ua ia mafaufau ai ia leaga ai le nuu o Kaletaia,", "that he hath taken against Babylon;"], ["E moni,", "and his purposes,"], ["e tosina i latou e le aupito itiiti o le lafu mamoe;", "that he hath purposed against the land of the Chaldeans:"], ["e moni,", "Surely the least of the flock shall draw them out:"], ["na te faatafunaina i o latou luga le mea e mau ai.", "surely he shall make their habitation desolate with them."]]},
  {num:46,words:[["O le taalili ina ua maua Papelonia, ua luluina ai le lalolagi,", "At the noise of the taking of Babylon the earth is moved,"], ["ua lagona foi le alaga i nuu ese.", "and the cry is heard among the nations."]]},
];
renderVerseSet(jer_ch_50_Verses, 'jer-ch50-verses');

var jer_ch_51_Verses = [
  {num:1,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD;"], ["Faauta,", "Behold,"], ["ou te faaosoina le matagi e faaumatia ai Papelonia,", "I will raise up against Babylon, and against them that dwell in the midst of them that rise up against me,"], ["atoa foi ma i latou o e nonofo i totonu o e laga mai ia te au.", "a destroying wind;"]]},
  {num:2,words:[["Ou te aauina atu i Papelonia o e faasavili saito ,", "And will send unto Babylon fanners,"], ["latou te faasaviligia o ia,", "that shall fan her,"], ["ma matuā sasaaina atu lona nuu;", "and shall empty her land:"], ["auā latou te tau ma ia i ona itu uma i le aso o le malaia.", "for in the day of trouble they shall be against her round about."]]},
  {num:3,words:[["Ia lolo'u le tagata fanafana u lana aufana,", "Against him that bendeth let the archer bend his bow,"], ["e fana atu ai i le ua lolo'u mai lana aufana,", "and against him that lifteth himself up in his brigandine:"], ["ma le ua mitamita i lona ofutau uamea; aua foi ne'i faasaoina ona taulelea;", "and spare ye not her young men;"], ["ia matuā faaumatia ana 'au uma lava.", "destroy ye utterly all her host."]]},
  {num:4,words:[["E pauu foi e ua fasiotia i le nuu o Kaletaia,", "Thus the slain shall fall in the land of the Chaldeans,"], ["ma e ua tu'ia ua ati e pauu i ona ala.", "and they that are thrust through in her streets."]]},
  {num:5,words:[["Auā e ui lava ina tumu lo latou nuu i le agasala i le Paia o Isaraelu,", "For Israel hath not been forsaken,"], ["e le tuua Isaraelu,", "nor Judah of his God,"], ["po o Iuta e lona Atua,", "of the LORD of hosts;"], ["o Ieova o 'au.", "though their land was filled with sin against the Holy One of Israel."]]},
  {num:6,words:[["Ina sosola ia outou ai totonu o Papelonia,", "Flee out of the midst of Babylon,"], ["ia taitasi ma faasaoina lona ola;", "and deliver every man his soul:"], ["aua ne'i fano outou i lana agasala;", "be not cut off in her iniquity;"], ["auā o le tausaga lenei o le taui ma sui a Ieova;", "for this is the time of the LORD'S vengeance;"], ["na te taui atu ai ia te ia lona taui.", "he will render unto her a recompence."]]},
  {num:7,words:[["O Papelonia o le ipu auro lea i le aao o Ieova,", "Babylon hath been a golden cup in the LORD'S hand,"], ["ua onā ai le lalolagi uma;", "that made all the earth drunken:"], ["ua feinu nuu i lona uaina;", "the nations have drunken of her wine;"], ["o le mea lea ua faavalea ai nuu.", "therefore the nations are mad."]]},
  {num:8,words:[["Ua faafuasei ona paū o Papelonia,", "Babylon is suddenly fallen and destroyed:"], ["ua momomo;", "howl for her;"], ["ina uio ia outou ona o ia; ina avatu ia ni pulu pasama i lona tiga,", "take balm for her pain,"], ["atonu e malolo ai o ia.", "if so be she may be healed."]]},
  {num:9,words:[["Na tatou fofoina Papelonia,", "We would have healed Babylon,"], ["a e lei malolo ai o ia;", "but she is not healed:"], ["ina tatou tuua ia o ia;", "forsake her,"], ["ma taitasi ma alu i lona nuu;", "and let us go every one into his own country:"], ["auā o lana sala ua pai atu i le lagi,", "for her judgment reacheth unto heaven,"], ["ua maualuga e oo i ao.", "and is lifted up even to the skies."]]},
  {num:10,words:[["Ua faaalia e Ieova la tatou amiotonu;", "The LORD hath brought forth our righteousness:"], ["ina o mai ia,", "come,"], ["se'i tatou ta'uta'u atu i Siona le galuega a Ieova lo tatou Atua.", "and let us declare in Zion the work of the LORD our God."]]},
  {num:11,words:[["Ina faapupulaina ia o u fanafana;", "Make bright the arrows;"], ["ina faatumuina ia o talita;", "gather the shields:"], ["ua faaosoina e Ieova loto o tupu o Metai;", "the LORD hath raised up the spirit of the kings of the Medes:"], ["auā o lona finagalo e tau ma Papelonia,", "for his device is against Babylon,"], ["ia faaumatia ia;", "to destroy it;"], ["auā o le taui ma sui lenei a Ieova,", "because it is the vengeance of the LORD,"], ["o le taui ma sui lava ona o lona malumalu.", "the vengeance of his temple."]]},
  {num:12,words:[["Ina sii ia i luga o le tagavai i pa o Papelonia,", "Set up the standard upon the walls of Babylon,"], ["ia faamalosia le leoleoga,", "make the watch strong,"], ["ia tofia tagata leoleo, ia tofia 'au e tanu;", "set up the watchmen,"], ["auā ua finagalo lava Ieova,", "prepare the ambushes:"], ["ma na faia le mea na ia fetalai mai ai i e o nonofo i Papelonia.", "for the LORD hath both devised and done that which he spake against the inhabitants of Babylon."]]},
  {num:13,words:[["O oe na le mau i le vai tele,", "O thou that dwellest upon many waters,"], ["ua tamaoaiga i oloa,", "abundant in treasures,"], ["ua oo mai lou iuga,", "thine end is come,"], ["le fua o lou matapeapea.", "and the measure of thy covetousness."]]},
  {num:14,words:[["Ua tauto Ieova o 'au ia te ia lava,", "The LORD of hosts hath sworn by himself,"], ["ua faapea ,", "saying,"], ["E moni, ou te faatumuina oe i tagata,", "Surely I will fill thee with men,"], ["e pei o le sē aleka;", "as with caterpillers;"], ["e pa foi la latou alaga ia te oe.", "and they shall lift up a shout against thee."]]},
  {num:15,words:[["Na faia e ia le lalolagi i lona mana,", "He hath made the earth by his power,"], ["na faatumauina e ia le atu laulau i lona poto,", "he hath established the world by his wisdom,"], ["na fofolaina foi e ia o le lagi i lona faautauta.", "and hath stretched out the heaven by his understanding."]]},
  {num:16,words:[["Ua tŭlei mai lona siufofoga,", "When he uttereth his voice,"], ["ona tele ai lea o le vai i le lagi;", "there is a multitude of waters in the heavens;"], ["e avae foi e ia o le ausa mai tuluiga o le lalolagi;", "and he causeth the vapours to ascend from the ends of the earth:"], ["e faia e ia le uila atoa ma le ua,", "he maketh lightnings with rain,"], ["e aumaia foi e ia le matagi mai ana mea e teu ai oloa.", "and bringeth forth the wind out of his treasures."]]},
  {num:17,words:[["Ua taitasi ma valea tagata uma e leai so latou poto;", "Every man is brutish by his knowledge;"], ["ua taitasi ma faamaina foi tufuga fai mea uamea,", "every founder is confounded by the graven image:"], ["ona o le tupua ua ta; auā o le mea pepelo lana tupua uamea,", "for his molten image is falsehood,"], ["e leai foi se mānava ia te i latou.", "and there is no breath in them."]]},
  {num:18,words:[["E faatauvaa ia mea,", "They are vanity,"], ["o le galuega e tauemua;", "the work of errors:"], ["e fano lava i latou i ona po e tauia ai i latou.", "in the time of their visitation they shall perish."]]},
  {num:19,words:[["E le pei o ia mea le tofi o Iakopo;", "The portion of Jacob is not like them;"], ["auā o ia lava na faia mea uma;", "for he is the former of all things:"], ["o Isaraelu foi o le tootoo o lona tofi lea; o Ieova o 'au,", "and Israel is the rod of his inheritance:"], ["o lona suafa lea.", "the LORD of hosts is his name."]]},
  {num:20,words:[["O oe o la'u uatogi,", "Thou art my battle axe and weapons of war:"], ["o le auupega o le taua; o oe ua ou tu'imomomoina ai nuu;", "for with thee will I break in pieces the nations,"], ["o oe foi ua ou faaumatia ai malo;", "and with thee will I destroy kingdoms;"]]},
  {num:21,words:[["o oe foi ua ou tu'imomomoina ai le solofanua ma lē tietie ai;", "And with thee will I break in pieces the horse and his rider;"], ["o oe foi ua ou tu'imomomoina ai le kariota ma lē tietie ai;", "and with thee will I break in pieces the chariot and his rider;"]]},
  {num:22,words:[["o oe foi ua ou tu'imomomoina ai le tane ma le fafine;", "With thee also will I break in pieces man and woman;"], ["o oe foi ua ou tu'imomomoina ai le toeaina ma le tama itiiti;", "and with thee will I break in pieces old and young;"], ["o oe foi ua ou tu'imomomoina ai le taulealea ma le taupou;", "and with thee will I break in pieces the young man and the maid;"]]},
  {num:23,words:[["o oe foi ua ou tu'imomomoina ai le leoleo mamoe ma lana lafu;", "I will also break in pieces with thee the shepherd and his flock;"], ["o oe foi ua ou tu'imomomoina ai le tagata galue fanua ma ana povi e lua;", "and with thee will I break in pieces the husbandman and his yoke of oxen;"], ["o oe foi ua ou tu'imomomoina ai ta'ita'i ma faipule.", "and with thee will I break in pieces captains and rulers."]]},
  {num:24,words:[["Ua ou tauia foi i Papelonia, ma i latou uma o e nonofo i Kaletaia,", "And I will render unto Babylon and to all the inhabitants of Chaldea all their evil that they have done in Zion in your sight,"], ["la latou amio leaga uma ua latou faia i Siona i o outou luma, ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:25,words:[["Faauta,", "Behold,"], ["ou te faia oe mo'u fili,", "I am against thee,"], ["o loo fetalai mai ai Ieova,", "O destroying mountain,"], ["o oe na le mauga na te faaumatia;", "saith the LORD,"], ["o le faaumatia ai le lalolagi uma;", "which destroyest all the earth:"], ["ou te faaloaloa lo'u lima i luga ia te oe,", "and I will stretch out mine hand upon thee,"], ["ma ou fuli ifo ia te oe mai papa,", "and roll thee down from the rocks,"], ["ma ou faia oe ma mauga ua mu.", "and will make thee a burnt mountain."]]},
  {num:26,words:[["Latou te le avea se maa ia te oe e fai ma tulimanu,", "And they shall not take of thee a stone for a corner,"], ["po o se maa e fai ma faavae;", "nor a stone for foundations;"], ["auā e fai oe ma faatafunaga e faavavau,", "but thou shalt be desolate for ever,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:27,words:[["Ia outou sii i luga le tagavai i le lalolagi,", "Set ye up a standard in the land,"], ["ia ilia le pu i nuu,", "blow the trumpet among the nations,"], ["ia outou sauniuni nuu e tau ma ia,", "prepare the nations against her,"], ["ia faalaei'au i malo o Ararata,", "call together against her the kingdoms of Ararat,"], ["ma Meni,", "Minni,"], ["ma Asekeneso e tau ma ia;", "and Ashchenaz;"], ["ma ia tofia alii e pule i 'au e tau ma ia;", "appoint a captain against her;"], ["ia o ae foi solofanua e pei o le sē aleka taufulufulu.", "cause the horses to come up as the rough caterpillers."]]},
  {num:28,words:[["Ia sauniuni nuu e tau ma ia,", "Prepare against her the nations with the kings of the Medes,"], ["o tupu o Metai,", "the captains thereof,"], ["ma ona ta'ita'i, ma ona faipule uma,", "and all the rulers thereof,"], ["ma le nuu uma ua ia pule i ai.", "and all the land of his dominion."]]},
  {num:29,words:[["E gatete le laueleele ma le tiga;", "And the land shall tremble and sorrow:"], ["auā e tumau le pule a Ieova i Papelonia, e fai le nuu o Papelonia ma faatafunaga,", "for every purpose of the LORD shall be performed against Babylon,"], ["e leai se nofo ai.", "to make the land of Babylon a desolation without an inhabitant."]]},
  {num:30,words:[["Ua tuua le taua e toa o Papelonia,", "The mighty men of Babylon have forborn to fight,"], ["ua latou nonofo i 'olo;", "they have remained in their holds:"], ["ua mavae lo latou malosi;", "their might hath failed;"], ["ua avea i latou ua ni fafine;", "they became as women:"], ["ua susunuina ana mea e mau ai;", "they have burned her dwellingplaces;"], ["ua gauia ona faamau faalava.", "her bars are broken."]]},
  {num:31,words:[["E momo'e le tagata tele vave e faafetaiai i le tagata tele vave,", "One post shall run to meet another,"], ["o lē ave feau foi e faafetaiai i le ave feau,", "and one messenger to meet another,"], ["e ta'u atu i le tupu o Papelonia ua matuā aea lana aai;", "to shew the king of Babylon that his city is taken at one end,"]]},
  {num:32,words:[["ua maua foi ala,", "And that the passages are stopped,"], ["ua faamuina u i le afi,", "and the reeds they have burned with fire,"], ["ua atuatuvale tagata tau.", "and the men of war are affrighted."]]},
  {num:33,words:[["Auā o loo faapea ona fetalai mai o Ieova o 'au,", "For thus saith the LORD of hosts,"], ["le Atua o Isaraelu,", "the God of Israel;"], ["O le tama fafine a Papelonia e pei o le mea e soli ai saito o ia i ona po e solia ai;", "The daughter of Babylon is like a threshingfloor, it is time to thresh her:"], ["e toe itiiti ane,", "yet a little while,"], ["ona oo ai lea i ona po e selesele ai ia te ia.", "and the time of her harvest shall come."]]},
  {num:34,words:[["Ua 'aina a'u,", "Nebuchadrezzar the king of Babylon hath devoured me,"], ["ua faaumatia e Nepukanesa le tupu o Papelonia,", "he hath crushed me,"], ["ua faia a'u e ia ma ipu e le i'o,", "he hath made me an empty vessel,"], ["ua na foloina a'u e pei o le tanimo,", "he hath swallowed me up like a dragon,"], ["ua na faatumuina lona manava i a'u mea faafiafia;", "he hath filled his belly with my delicates,"], ["ua na tulia lava a'u.", "he hath cast me out."]]},
  {num:35,words:[["E fai ane le ua nofo i Siona,", "The violence done to me and to my flesh be upon Babylon,"], ["O le sauaina o a'u ma lo'u tino ia i luga o Papelonia lea;", "shall the inhabitant of Zion say;"], ["e fai ane foi Ierusalema,", "and my blood upon the inhabitants of Chaldea,"], ["Ia i luga o e nonofo i Kaletaia lo'u toto.", "shall Jerusalem say."]]},
  {num:36,words:[["O le mea lea o loo faapea ona fetalai mai ai o Ieova,", "Therefore thus saith the LORD;"], ["Faauta,", "Behold,"], ["ou te faia lau finauga,", "I will plead thy cause,"], ["ou te matuā taui foi ma sui ona o oe;", "and take vengeance for thee;"], ["ou te faamateina lona vai,", "and I will dry up her sea,"], ["ma faamatutuina lona vaipuna.", "and make her springs dry."]]},
  {num:37,words:[["E fai foi Papelonia ma faupuega maa,", "And Babylon shall become heaps,"], ["o le mea e fale ai luko,", "a dwellingplace for dragons,"], ["o le mea foi e ofo ai,", "an astonishment,"], ["ma uisa ai,", "and an hissing,"], ["e leai foi sē nofo ai.", "without an inhabitant."]]},
  {num:38,words:[["Latou te fetagisi faatasi e pei o leona taanoa,", "They shall roar together like lions:"], ["latou te leo tetele foi e pei o tamai leona.", "they shall yell as lions' whelps."]]},
  {num:39,words:[["Ou te saunia a latou tausamiga a o vevela i latou,", "In their heat I will make their feasts,"], ["ou te faainu foi ia te i latou ia onā,", "and I will make them drunken,"], ["ina ia latou olioli,", "that they may rejoice,"], ["ma momoe i le moe e faavavau,", "and sleep a perpetual sleep,"], ["ma latou le ala mai,", "and not wake,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:40,words:[["Ou te aveina ifo i latou e pei o tamai mamoe ia fasia,", "I will bring them down like lambs to the slaughter,"], ["e pei o mamoe poa foi ma 'oti poa.", "like rams with he goats."]]},
  {num:41,words:[["E! ua aea Sesaka; ua maua le na viia e le lalolagi uma. E! ua avea Papelonia ma mea e ofo ai nuu.", "How is Sheshach taken! and how is the praise of the whole earth surprised! how is Babylon become an astonishment among the nations!"]]},
  {num:42,words:[["Ua alu ae le vai i luga o Papelonia;", "The sea is come up upon Babylon:"], ["ua ufitia o ia i le tele o ona peau.", "she is covered with the multitude of the waves thereof."]]},
  {num:43,words:[["Ua fai ona aai ma faatafunaga,", "Her cities are a desolation,"], ["o le fanua naumati,", "a dry land,"], ["ma le lafulafua;", "and a wilderness,"], ["o le nuu e leai se tagata e nofo ai,", "a land wherein no man dwelleth,"], ["e le ui ane ai foi se atalii o se tagata.", "neither doth any son of man pass thereby."]]},
  {num:44,words:[["Ou te taui atu ia Pele i Papelonia;", "And I will punish Bel in Babylon,"], ["ou te to ae i lona gutu le mea na ia foloina;", "and I will bring forth out of his mouth that which he hath swallowed up:"], ["e le toe gasolo atu foi ia te ia o nuu;", "and the nations shall not flow together any more unto him: yea,"], ["e solo i lalo foi le pa o Papelonia.", "the wall of Babylon shall fall."]]},
  {num:45,words:[["Lo'u nuu e,", "My people,"], ["ina o ese atu ia i totonu ia te ia,", "go ye out of the midst of her,"], ["ma ia taitasi ma faasaoina lona ola ai le toasa tele o Ieova.", "and deliver ye every man his soul from the fierce anger of the LORD."]]},
  {num:46,words:[["Aua ne'i faavaivai o outou loto,", "And lest your heart faint,"], ["aua ne'i outou fefefe i le tala e lagona i le nuu;", "and ye fear for the rumour that shall be heard in the land;"], ["auā e sau le tala i lea tausaga,", "a rumour shall both come one year,"], ["e mulimuli ane foi le tala i le tasi tausaga,", "and after that in another year shall come a rumour,"], ["e i ai foi le saua i le nuu,", "and violence in the land,"], ["e tauva lea faipule ma lea faipule.", "ruler against ruler."]]},
  {num:47,words:[["O le mea lea faauta,", "Therefore, behold,"], ["e oo mai ai ona po ou te taui atu ai i tupua ua ta a Papelonia;", "the days come,"], ["e faamaina lona nuu uma;", "that I will do judgment upon the graven images of Babylon:"], ["e pauu foi i totonu ia te ia ona tagata uma ua fasiotia.", "and her whole land shall be confounded, and all her slain shall fall in the midst of her."]]},
  {num:48,words:[["Ona alalaga fiafia ai lea o le lagi,", "Then the heaven and the earth,"], ["ma le lalolagi,", "and all that is therein,"], ["ma mea uma ua i ai, ona o Papelonia;", "shall sing for Babylon:"], ["auā e o mai ia te ia tagata faatafuna mai le itu i matu,", "for the spoilers shall come unto her from the north,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:49,words:[["E paū lava Papelonia, outou tagata o Isaraelu ua fasia;", "As Babylon hath caused the slain of Israel to fall,"], ["e pauu foi faatasi ma Papelonia o tagata ua fasia i nuu uma lava.", "so at Babylon shall fall the slain of all the earth."]]},
  {num:50,words:[["O outou ua sao i le pelu,", "Ye that have escaped the sword,"], ["ina o ia outou,", "go away,"], ["aua le tutū;", "stand not still:"], ["ia outou manatua Ieova ai le nuu mamao,", "remember the LORD afar off,"], ["ia outou manatunatu foi i Ierusalema.", "and let Jerusalem come into your mind."]]},
  {num:51,words:[["Ua faamaina i matou,", "We are confounded,"], ["auā ua matou faalogo i le luma;", "because we have heard reproach:"], ["ua ufitia o matou tama i le masiasi;", "shame hath covered our faces:"], ["auā ua ulu atu tagata ese i mea paia i le fale o Ieova.", "for strangers are come into the sanctuaries of the LORD'S house."]]},
  {num:52,words:[["O le mea lea faauta,", "Wherefore,"], ["e oo mai ai ona po,", "behold,"], ["ua fetalai mai Ieova,", "the days come, saith the LORD,"], ["ou te taui atu ai i ona tupua ua ta;", "that I will do judgment upon her graven images:"], ["e feoi foi tagata manunua i lona nuu uma.", "and through all her land the wounded shall groan."]]},
  {num:53,words:[["E ui lava ina alu ae o Papelonia i le lagi,", "Though Babylon should mount up to heaven,"], ["e ui lava ina teua foi e ia le 'olo i le mea maualuga e malosi ai o ia,", "and though she should fortify the height of her strength,"], ["a e o atu mai ia te au o e faatafuna ia te ia,", "yet from me shall spoilers come unto her,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:54,words:[["O le leo o le alaga mai Papelonia,", "A sound of a cry cometh from Babylon,"], ["ma le olopalaina tele mai le nuu o Kaletaia;", "and great destruction from the land of the Chaldeans:"]]},
  {num:55,words:[["auā ua faatafunaina Papelonia e Ieova,", "Because the LORD hath spoiled Babylon,"], ["ma ua faaumatia e ia le leo tele nai ia te ia;", "and destroyed out of her the great voice;"], ["ua taalili mai ona galu e pei o le vai e tele,", "when her waves do roar like great waters,"], ["ua vagana mai o latou leo;", "a noise of their voice is uttered:"]]},
  {num:56,words:[["auā ua oo ia te ia,", "Because the spoiler is come upon her,"], ["o Papelonia lava, o le na te faatafunaina;", "even upon Babylon,"], ["ua puea ona tagata totoa,", "and her mighty men are taken,"], ["ua gauia a latou aufana; auā o Ieova le Atua o ia e taui atu,", "every one of their bows is broken:"], ["e matuā taui atu e ia.", "for the LORD God of recompences shall surely requite."]]},
  {num:57,words:[["Ou te faainu ia onā ona alii,", "And I will make drunk her princes,"], ["ma ona tagata popoto,", "and her wise men,"], ["ma ona ta'ita'i,", "her captains,"], ["ma ona faipule,", "and her rulers,"], ["ma ona toa; latou te momoe i le moe e faavavau,", "and her mighty men:"], ["ma latou le ala mai,", "and they shall sleep a perpetual sleep,"], ["ua fetalai mai ai le Tupu,", "and not wake,"], ["o Ieova o 'au,", "saith the King,"], ["o lona suafa lea.", "whose name is the LORD of hosts."]]},
  {num:58,words:[["O loo faapea ona fetalai mai o Ieova o 'au,", "Thus saith the LORD of hosts;"], ["E matuā sŏloia i lalo pa o Papelonia lautele e susunuina i le afi ona puipui maualuluga;", "The broad walls of Babylon shall be utterly broken,"], ["o nuu e galulue fua i latou,", "and her high gates shall be burned with fire; and the people shall labour in vain,"], ["o tagata foi e galulue ma le afi,", "and the folk in the fire,"], ["ma lailoa i latou.", "and they shall be weary."]]},
  {num:59,words:[["O le upu na fai atu ai Ieremia le perofeta ia Seraia le atalii o Neria,", "The word which Jeremiah the prophet commanded Seraiah the son of Neriah,"], ["le atalii o Maaseia, ina ua alu atu o ia faatasi ma Setekaia le tupu o Iuta i Papelonia,", "the son of Maaseiah,"], ["i le fa o tausaga o lana nofoaiga.", "when he went with Zedekiah the king of Judah into Babylon in the fourth year of his reign."], ["O Seraia foi o le alii filemu ia.", "And this Seraiah was a quiet prince."]]},
  {num:60,words:[["Na tusia e Ieremia i le tusi e tasi o le malaia uma o le a oo i Papelonia,", "So Jeremiah wrote in a book all the evil that should come upon Babylon,"], ["o ia upu uma ua tusia ia Papelonia.", "even all these words that are written against Babylon."]]},
  {num:61,words:[["Ua fai atu foi Ieremia ia Seraia,", "And Jeremiah said to Seraiah,"], ["A ē oo i Papelonia,", "When thou comest to Babylon,"], ["ma e vaai,", "and shalt see,"], ["ma faitau i nei upu uma,", "and shalt read all these words;"]]},
  {num:62,words:[["ona e fai atu ai lea,", "Then shalt thou say,"], ["Ieova e,", "O LORD,"], ["ua e fetalai mai i lenei mea ina ia faaumatia,", "thou hast spoken against this place, to cut it off,"], ["ina ia leai sē nofo ai,", "that none shall remain in it,"], ["o se tagata po o se manu,", "neither man nor beast,"], ["a e fai ia ma faatafunaga e faavavau.", "but that it shall be desolate for ever."]]},
  {num:63,words:[["A uma foi ona e faitauina o lenei tusi,", "And it shall be,"], ["ia e nonoa ai se maa,", "when thou hast made an end of reading this book, that thou shalt bind a stone to it,"], ["ma lafoina i totonu o Eufirate;", "and cast it into the midst of Euphrates:"]]},
  {num:64,words:[["e te fai atu foi,", "And thou shalt say,"], ["E faapea ona goto o Papelonia,", "Thus shall Babylon sink,"], ["ma lē toe ea i le malaia ou te faaoo ai i ona luga;", "and shall not rise from the evil that I will bring upon her:"], ["e lailoa foi i latou. Ona gata lea o upu a Ieremia.", "and they shall be weary. Thus far are the words of Jeremiah."]]},
];
renderVerseSet(jer_ch_51_Verses, 'jer-ch51-verses');

var jer_ch_52_Verses = [
  {num:1,words:[["O le tausaga o Setekaia e luafulu ma le tasi na fai ai o ia ma tupu; e sefulu ma le tasi tausaga na fai ai o ia ma tupu i Ierusalema;", "Zedekiah was one and twenty years old when he began to reign,"], ["o le igoa o lona tinā o Hamutala, le afafine o Ieremia le Lipena.", "and he reigned eleven years in Jerusalem. And his mother's name was Hamutal the daughter of Jeremiah of Libnah."]]},
  {num:2,words:[["Na ia faia le amio leaga i luma o Ieova,", "And he did that which was evil in the eyes of the LORD,"], ["pei o mea uma na faia e Ioakima.", "according to all that Jehoiakim had done."]]},
  {num:3,words:[["Auā o le toasa o Ieova ia Ierusalema ma Iuta,", "For through the anger of the LORD it came to pass in Jerusalem and Judah,"], ["ua iu ai ina lafoaiina i latou ai ona luma,", "till he had cast them out from his presence,"], ["na foua ai foi le tupu o Papelonia e Setekaia.", "that Zedekiah rebelled against the king of Babylon."]]},
  {num:4,words:[["O le iva o tausaga o lana nofoaiga o le sefulu o masina,", "And it came to pass in the ninth year of his reign,"], ["o le aso e sefulu o le masina,", "in the tenth month,"], ["na sau ai Nepukanesa,", "in the tenth day of the month,"], ["le tupu o Papelonia,", "that Nebuchadrezzar king of Babylon came,"], ["i Ierusalema,", "he and all his army,"], ["o ia ma ana 'au uma;", "against Jerusalem,"], ["ua to lauapi foi e tau ma ia,", "and pitched against it,"], ["ua latou fai foi 'olo e vagaia a'i.", "and built forts against it round about."]]},
  {num:5,words:[["Na vagaia le aai ua oo i le sefulu ma le tasi o tausaga o le tupu o Setekaia.", "So the city was besieged unto the eleventh year of king Zedekiah."]]},
  {num:6,words:[["O le fa o masina foi,", "And in the fourth month,"], ["o le aso iva o le masina na velavela ai le oge i le aai,", "in the ninth day of the month, the famine was sore in the city,"], ["ua leai foi se mea e 'ai mā tagata o le nuu.", "so that there was no bread for the people of the land."]]},
  {num:7,words:[["Na lepetia le aai,", "Then the city was broken up,"], ["ona sosola ai lea o 'au uma,", "and all the men of war fled,"], ["ma latou tuua le aai i le po, ua ui i le ala i le faitotoa i le va o pa e lua,", "and went forth out of the city by night by the way of the gate between the two walls,"], ["e latalata i le fanua o le tupu;", "which was by the king's garden;"], ["(na vagaia foi le aai e Kaletaia;", "(now the Chaldeans were by the city round about:"], [") na latou o foi i le ala i le eleele laugatasi.", ") and they went by the way of the plain."]]},
  {num:8,words:[["Ona tuliloa ai lea e le itu taua a Kaletaia i le tupu,", "But the army of the Chaldeans pursued after the king,"], ["ma latou maua atu ia Setekaia i le eleele laugatasi o Ieriko;", "and overtook Zedekiah in the plains of Jericho;"], ["na taapeape foi lana itu taua uma na ia te ia.", "and all his army was scattered from him."]]},
  {num:9,words:[["Ona latou pue ai lea i le tupu,", "Then they took the king,"], ["ma avatu ia te ia i le tupu o Papelonia i Ripelu, i le nuu o Amato;", "and carried him up unto the king of Babylon to Riblah in the land of Hamath;"], ["ona faasala ai lea o ia ia te ia.", "where he gave judgment upon him."]]},
  {num:10,words:[["Ua fasioti foi e le tupu o Papelonia i atalii o Setekaia i ona luma;", "And the king of Babylon slew the sons of Zedekiah before his eyes:"], ["ua ia fasioti foi i alii uma o Iuta i Ripelu.", "he slew also all the princes of Judah in Riblah."]]},
  {num:11,words:[["Ua ia faatauaso foi ia Setekaia,", "Then he put out the eyes of Zedekiah;"], ["ma fusifusi ia te ia i faamau 'apa memea e lua;", "and the king of Babylon bound him in chains,"], ["ua ave foi ia te ia e le tupu o Papelonia i Papelonia, ma na tuuina atu ia te ia i le fale puipui,", "and carried him to Babylon,"], ["ua oo lava i le aso na oti ai o ia.", "and put him in prison till the day of his death."]]},
  {num:12,words:[["O le lima o masina,", "Now in the fifth month,"], ["o le aso e sefulu o le masina,", "in the tenth day of the month,"], ["o le tausaga e sefulu ma le iva lea o le tupu o Nepukanesa,", "which was the nineteenth year of Nebuchadrezzar king of Babylon,"], ["o le tupu o Papelonia,", "came Nebuzar-adan,"], ["na sau ai i Ierusalema o Nepusatana,", "captain of the guard,"], ["lē pule i le 'au e faafeao,", "which served the king of Babylon,"], ["o le na tu i luma o le tupu o Papelonia;", "into Jerusalem,"]]},
  {num:13,words:[["na ia susunuina le fale o Ieova,", "And burned the house of the LORD,"], ["ma le fale o le tupu,", "and the king's house;"], ["atoa ma fale uma o Ierusalema;", "and all the houses of Jerusalem, and all the houses of the great men,"], ["o fale tetele uma foi ua susunuina e ia i le afi.", "burned he with fire:"]]},
  {num:14,words:[["Na sŏloia foi pa uma na faataaliolioina ai Ierusalema e 'au uma a Kaletaia,", "And all the army of the Chaldeans, that were with the captain of the guard,"], ["sa i le na pule i le 'au e faafeao.", "brake down all the walls of Jerusalem round about."]]},
  {num:15,words:[["O isi foi o e matitiva o le nuu,", "Then Nebuzar-adan the captain of the guard carried away captive certain of the poor of the people,"], ["ma e na totoe o le nuu sa i ai pea i le aai,", "and the residue of the people that remained in the city,"], ["ma e na sosola, na sosola atu i le tupu o Papelonia,", "and those that fell away,"], ["ma e na totoe o le vao tagata,", "that fell to the king of Babylon,"], ["na tāfea i latou e Nepusatana lē pule i le 'au e faafeao.", "and the rest of the multitude."]]},
  {num:16,words:[["A ua tuua e Nepusatana lē pule i le 'au e faafeao, nisi o e matitiva o le nuu, e fai ma teu vine, ma ē galulue i le fanua.", "But Nebuzar-adan the captain of the guard left certain of the poor of the land for vinedressers and for husbandmen."]]},
  {num:17,words:[["O pou 'apa memea foi sa i le fale o Ieova,", "Also the pillars of brass that were in the house of the LORD,"], ["ma tuugā tanoa ,", "and the bases,"], ["atoa ma le vai 'apa memea sa i le fale o Ieova,", "and the brasen sea that was in the house of the LORD,"], ["na taei e Kaletaia,", "the Chaldeans brake,"], ["ma latou ave le 'apa memea uma i Papelonia.", "and carried all the brass of them to Babylon."]]},
  {num:18,words:[["Na latou ave foi o ulo,", "The caldrons also,"], ["ma suo,", "and the shovels,"], ["ma selelamepa,", "and the snuffers, and the bowls,"], ["ma ipu,", "and the spoons,"], ["ma ipu e asu a'i,", "and all the vessels of brass wherewith they ministered,"], ["atoa ma mea 'apa memea uma lava na latou fai a'i sauniga.", "took they away."]]},
  {num:19,words:[["O tanoa foi,", "And the basons,"], ["ma salefu,", "and the firepans,"], ["ma ipu,", "and the bowls,"], ["ma ulo,", "and the caldrons,"], ["ma tuugā lamepa,", "and the candlesticks,"], ["ma ipu e asu a'i,", "and the spoons,"], ["ma ipu e sasaa a'i;", "and the cups;"], ["o le auro o mea na faia i auro,", "that which was of gold in gold,"], ["ma le ario o mea na faia i ario,", "and that which was of silver in silver,"], ["na ave e le alii e pule i le 'au e faafeao.", "took the captain of the guard away."]]},
  {num:20,words:[["O pou e lua,", "The two pillars,"], ["o le vai e tasi,", "one sea,"], ["ma povi 'apa memea e sefulu ma le lua sa i lalo, ma le tuugā tanoa ,", "and twelve brasen bulls that were under the bases,"], ["na faia e le tupu o Solomona mo le fale o Ieova;", "which king Solomon had made in the house of the LORD:"], ["ua le fuatia lava le mamafa o 'apa memea o na mea uma.", "the brass of all these vessels was without weight."]]},
  {num:21,words:[["O pou foi,", "And concerning the pillars,"], ["o le umi o le tasi pou o kupita e sefulu ma le valu;", "the height of one pillar was eighteen cubits;"], ["o le fua foi na faataaliolio ai, e sefulu ma le lua o kupita ia;", "and a fillet of twelve cubits did compass it;"], ["o lona mafiafia e tusa lea ma le lautele o le alofilima;", "and the thickness thereof was four fingers:"], ["sa faaōō lava.", "it was hollow."]]},
  {num:22,words:[["O le kapetala 'apa memea foi na i ona luga; o le umi o le tasi kapetala e lima kupita,", "And a chapiter of brass was upon it;"], ["o le mea faaupega atoa ma rimoni sa i le kapetala e faataaliolio ai,", "and the height of one chapiter was five cubits,"], ["o 'apa memea uma ia;", "with network and pomegranates upon the chapiters round about,"], ["e faapei o ia mea foi sa i ai i lona lua o pou, atoa foi ma rimoni.", "all of brass. The second pillar also and the pomegranates were like unto these."]]},
  {num:23,words:[["Na i ai foi rimoni e ivagafulu ma le ono i itu; o rimoni uma sa i luga o le mea faaupega,", "And there were ninety and six pomegranates on a side;"], ["e tasi le selau o faataaliolio ai.", "and all the pomegranates upon the network were an hundred round about."]]},
  {num:24,words:[["Na ave foi e le alii e pule i le 'au e faafeao o Seraia le faitaulaga sili,", "And the captain of the guard took Seraiah the chief priest,"], ["ma Sefanaia le faitaulaga e aupito ane ia te ia,", "and Zephaniah the second priest,"], ["atoa ma leoleo o faitotoa e toatolu;", "and the three keepers of the door:"]]},
  {num:25,words:[["na ia ave foi nai le aai le tasi auauna sili na tofia e pule i 'au;", "He took also out of the city an eunuch,"], ["ma tagata e toafitu o e na iloa fofoga o le tupu,", "which had the charge of the men of war;"], ["na maua i latou i le aai;", "and seven men of them that were near the king's person,"], ["ma le alii sili i e tusi'au,", "which were found in the city; and the principal scribe of the host,"], ["o le na faapotopoto i tagata o le nuu;", "who mustered the people of the land;"], ["atoa ma tagata o le nuu e toaonogafulu,", "and threescore men of the people of the land,"], ["sa maua i latou i totonu o le aai.", "that were found in the midst of the city."]]},
  {num:26,words:[["Na ave foi i latou e Nepusatana lē pule i le 'au e faafeao,", "So Nebuzar-adan the captain of the guard took them,"], ["ma na avatua i latou i le tupu o Papelonia i Ripelu.", "and brought them to the king of Babylon to Riblah."]]},
  {num:27,words:[["Ona fasia ai lea o i latou e le tupu o Papelonia, ua na fasioti ia te i latou i Ripelu,", "And the king of Babylon smote them,"], ["i le nuu o Amato, na tāfea foi Iuta nai lo latou laueleele.", "and put them to death in Riblah in the land of Hamath. Thus Judah was carried away captive out of his own land."]]},
  {num:28,words:[["O le nuu lenei na tāfea ia Nepukanesa;", "This is the people whom Nebuchadrezzar carried away captive:"], ["o le fitu o tausaga na tāfea ai tagata Iuta e tolu o afe ma le toaluafulu ma le toatolu.", "in the seventh year three thousand Jews and three and twenty:"]]},
  {num:29,words:[["O le tausaga o Nepukanesa e sefulu ma le valu, na tāfea ai nai Ierusalema, o tagata e toavalugalau ma le toatolugafulu ma le toalua.", "In the eighteenth year of Nebuchadrezzar he carried away captive from Jerusalem eight hundred thirty and two persons:"]]},
  {num:30,words:[["O le lua sefulu ma le tolu o tausaga o Nepukanesa na tāfea ai ia Nepusatana lē pule i le 'au e faafeao,", "In the three and twentieth year of Nebuchadrezzar Nebuzar-adan the captain of the guard carried away captive of the Jews seven hundred forty and five persons:"], ["o tagata Iuta e toafitu galau ma le fa o sefulu ma le toalima. O le atoa o tagata e toafa gaafe ma le toaono galau.", "all the persons were four thousand and six hundred."]]},
  {num:31,words:[["Ua oo i le tolugafulu ma le fitu o tausaga o le tafeaga a Ioakina le tupu o Iuta,", "And it came to pass in the seven and thirtieth year of the captivity of Jehoiachin king of Judah,"], ["o le sefulu ma le lua foi o masina, o le aso e luafulu ma le lima o le masina,", "in the twelfth month,"], ["ona faaeaina ai lea o le ulu o Ioakina le tupu o Iuta e Evilemarota,", "in the five and twentieth day of the month,"], ["le tupu o Papelonia, i le tausaga na fai ai o ia ma tupu,", "that Evil-merodach king of Babylon in the first year of his reign lifted up the head of Jehoiachin king of Judah,"], ["ma na aumaia o ia nai le fale puipui;", "and brought him forth out of prison,"]]},
  {num:32,words:[["na ia tautala ma le alofa ia te ia,", "And spake kindly unto him,"], ["ua tuu atu foi lona nofoālii ia sili i nofoālii o tupu na ia te ia i Papelonia;", "and set his throne above the throne of the kings that were with him in Babylon,"]]},
  {num:33,words:[["na ia sui foi ona ofu sa ofu ai i le fale puipui;", "And changed his prison garments:"], ["na 'ai foi o ia e le aunoa i ona luma i aso uma o lona ola.", "and he did continually eat bread before him all the days of his life."]]},
  {num:34,words:[["O lana tufaaga foi,", "And for his diet,"], ["o le tufaaga e le aunoa,", "there was a continual diet given him of the king of Babylon,"], ["na tuuina atu ia te ia e le tupu o Papelonia i lea aso ma lea aso, ua oo lava i le aso o lona oti,", "every day a portion until the day of his death,"], ["o aso uma o lona ola.", "all the days of his life."]]},
];
renderVerseSet(jer_ch_52_Verses, 'jer-ch52-verses');

})();